import React, { useState, useEffect } from "react";
import { MDBIcon, MDBInput } from "mdbreact";
import "./password.css";

const PasswordInput = ({
  password,
  setPassword,
  isLocked,
  setIsLocked,
  setPasswordStatus,
  hasIcon = false,
  label,
  isProfile = false,
}) => {
  const [strength, setStrength] = useState(0);
  const [passwordStrength, setPasswordStrength] = useState("");
  const [showInstructions, setShowInstructions] = useState(true);
  const [instrucColor, setInstrucColor] = useState({
    length: false,
    uppercase: false,
    lowercase: false,
    number: false,
    specialChar: false
  })

  const checkPasswordStrength = (_password) => {
    let currStrength = 0;
    if (_password === "") {
      setInstrucColor({
        lowercase: false,
        uppercase: false,
        number: false,
        special: false,
        length: false,
      });
      setStrength(0);
      return "Weak";
    }

    
    if (_password.length >= 8) {
      setInstrucColor((prev) => ({ ...prev, length: true }))
      currStrength += 1;
    }else {
      setInstrucColor((prev) => ({...prev, length: false}))
    }

    if (/[A-Z]/.test(_password)) {
      setInstrucColor((prev) => ({ ...prev, uppercase: true }))
      currStrength += 1;
    }else {
      setInstrucColor((prev) => ({...prev, uppercase: false}))
    }

    if (/[a-z]/.test(_password)) {
      setInstrucColor((prev) => ({ ...prev, lowercase: true }))
      currStrength += 1;
    }else {
      setInstrucColor((prev) => ({...prev, lowercase: false}))
    }

    if (/[0-9]/.test(_password)) {
      setInstrucColor((prev) => ({ ...prev, number: true }))
      currStrength += 1;
    }else {
      setInstrucColor((prev) => ({ ...prev, number: false }))
    }

    if (/[^A-Za-z0-9]/.test(_password)) {
      setInstrucColor((prev) => ({ ...prev, specialChar: true }))
      currStrength += 1;
    }else {
      setInstrucColor((prev) => ({ ...prev, specialChar: false }))
    }

    setStrength(currStrength);

    switch (currStrength) {
      case 5:
        setPasswordStatus(false);
        return "Strong";
      case 4:
        setPasswordStatus(false);
        return "Good";
      case 3:
        setPasswordStatus(false);
        return "Medium";
      default:
        setPasswordStatus(true);
        return "Weak";
    }
  };

  useEffect(() => {
      setPasswordStrength(checkPasswordStrength(password));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [password]);

  return (
    <div>
      <MDBInput
        style={{
          borderBottom: "1px solid black",
          color: "black",
          maxWidth: isProfile ? "70%" : "auto",
        }}
        className="pb-0"
        label={label}
        name="password"
        icon={isLocked ? "lock" : "unlock"}
        iconClass="customInputPasswordIcon"
        minLength={8}
        value={password}
        onChange={(e) => {
          setPassword(e.target.value);
          setPasswordStrength(checkPasswordStrength(e.target.value));
        }}
        type={isLocked ? "password" : "text"}
        onIconMouseEnter={() => {
          if (hasIcon) {
            setIsLocked(!isLocked);
          }
        }}
        onIconMouseLeave={() => {
          if (hasIcon) {
            setIsLocked(!isLocked);
          }
        }}
        onFocus={() => setShowInstructions(true)}
        onBlur={() => setShowInstructions(false)}
        required
      >
        <button
          className="isLock-eye"
          type="button"
          onClick={() => setIsLocked(!isLocked)}
        >
          <MDBIcon icon={isLocked ? "eye-slash" : "eye"} />
        </button>
      </MDBInput>
      <div
        className="password-meter"
        style={{
          display: "flex",
          height: "5px",
          marginTop: "10px",
          gap: "2px",
        }}
      >
        <div
          className="rounded"
          style={{
            background: `${strength <= 3 || strength > 3 ? "#ff4d4d" : "#ddd"}`,
            flex: "1",
            marginLeft: "40px",
          }}
        />
        <div
          className="rounded"
          style={{
            background: `${strength >= 3 ? "#ffd633" : "#ddd"}`,
            flex: "1",
          }}
        />
        <div
          className="rounded"
          style={{
            background: `${strength >= 4 ? "#00b300" : "#ddd"}`,
            flex: "1",
          }}
        />
        <div
          className="rounded"
          style={{
            background: `${strength >= 5 ? "#009900" : "#ddd"}`,
            flex: "1",
          }}
        />
        {passwordStrength && (
          <div
            className={`password-strength ${passwordStrength.toLowerCase()}`}
            style={{
              textAlign: "center",
              alignSelf: "center",
              marginLeft: "20px",
              fontWeight: "normal",
            }}
          >
            {passwordStrength}
          </div>
        )}
      </div>
      {showInstructions && (
        <div className="password-instructions">
          <p>Password should contain:</p> 
          <ul className="instruc">
            <li className={`${instrucColor.length ? 'text-success': 'text-danger'}`}>At least 8 characters long</li>
            <li className={`${instrucColor.uppercase ? 'text-success': 'text-danger'}`}>At least one uppercase letter</li>
            <li className={`${instrucColor.lowercase ? 'text-success': 'text-danger'}`}>At least one lowercase letter</li>
            <li className={`${instrucColor.number ? 'text-success': 'text-danger'}`}>At least one number</li>
            <li className={`${instrucColor.specialChar ? 'text-success': 'text-danger'}`}>At least one special character</li>
          </ul>
        </div>
      )}
      
    </div>
  );
};

export default PasswordInput;
