import React, { useEffect, useState } from "react";
import {
  MDBBtn,
  MDBModal,
  MDBModalBody,
  MDBIcon,
  MDBModalHeader,
  MDBModalFooter,
} from "mdbreact";
import { useDispatch, useSelector } from "react-redux";
import { SAVE } from "../../../../../services/redux/slices/admission/employees";
import Information from "./information";
import AccountInformation from "./accountInformation";

const _form = {
  fullName: {
    fname: "",
    mname: "",
    lname: "",
    suffix: "",
  },
  position: "",
  role: "",
  mobile: "",
  dob: "",
  civil: "",
  isMale: false,
  motherTounge: "",

  address: {
    isSame: true,
    permanent: {
      region: "REGION III (CENTRAL LUZON)",
      province: "NUEVA ECIJA",
      city: "GENERAL TINIO (PAPAYA)",
      barangay: "Pias",
      street: "",
      no: "",
      code: "",
    },
    current: {
      region: "REGION III (CENTRAL LUZON)",
      province: "NUEVA ECIJA",
      city: "GENERAL TINIO (PAPAYA)",
      barangay: "Pias",
      street: "",
      no: "",
      code: "",
    },
  },
  birthplace: "",
  email: "",
  password: "",
  suffix: "N/A",
  wasBanned: false,
  haveEnrollmentAccess: false,
};

export default function Modal({ show, toggle, selected, willCreate }) {
  const { token } = useSelector(({ auth }) => auth),
    { isLoading } = useSelector(({ rooms }) => rooms),
    [form, setForm] = useState(_form),
    dispatch = useDispatch();

  useEffect(() => {
    if (!willCreate && selected._id) setForm(selected);
  }, [willCreate, selected]);

  const handleSubmit = (e) => {
    e.preventDefault();

    const { password = "", confirmPassword = "", address } = form;

    if (password !== confirmPassword)
      return (document.getElementById("warningMessage").innerHTML =
        "Password and Confirm Password is not match!");

    var updatedForm = form;
    if (address.isSame) {
      updatedForm = {
        ...form,
        address: { ...form.address, permanent: form.address?.current },
      };
    }
    dispatch(SAVE({ data: updatedForm, token }));

    document.getElementById("warningMessage").innerHTML = "";

    setForm(_form);
    toggle();
  };

  const handleClose = () => {
    setForm(_form);
    toggle();
  };

  const handleChange = (key, value, objKey) => {
    if (!objKey) {
      return setForm((prev) => ({ ...prev, [key]: value }));
    }
    setForm((prev) => ({ ...prev, [key]: { ...prev[key], [objKey]: value } }));
  };

  const defaultDisplayInWarning = "";
  return (
    <MDBModal
      isOpen={show}
      toggle={toggle}
      backdrop
      disableFocusTrap={false}
      size="xl"
    >
      <MDBModalHeader
        toggle={handleClose}
        className="light-blue darken-3 white-text"
      >
        <MDBIcon icon="user" className="mr-2" />
        Applicant Registration
      </MDBModalHeader>
      <form onSubmit={handleSubmit}>
        <MDBModalBody className="mb-0 p-4">
          <Information handleChange={handleChange} form={form} />
          <AccountInformation
            handleChange={handleChange}
            form={form}
            defaultDisplayInWarning={defaultDisplayInWarning}
          />
        </MDBModalBody>
        <MDBModalFooter>
          <MDBBtn
            type="submit"
            disabled={isLoading}
            color="primary"
            className="mb-2 float-right"
          >
            {!willCreate ? "Update" : "Submit"}
          </MDBBtn>
        </MDBModalFooter>
      </form>
    </MDBModal>
  );
}
