import React from "react";
import { MDBIcon, MDBModal, MDBModalBody, MDBModalHeader } from "mdbreact";
import MultipleChoice from "../entranceExam/exam/viewQuestions/type/multipleChoice";
import MatchingType from "../../student/matchingType";
import Identification from "../entranceExam/exam/viewQuestions/type/identification";
const TYPES = {
  mc: "Multiple Choice",
  matching: "Matching Type",
  identification: "Identification",
};
export default function ViewQuestion({ show, toggle, selected }) {
  return (
    <MDBModal
      isOpen={show}
      toggle={toggle}
      size={selected.type === "matching" ? "xl" : "lg"}
    >
      <MDBModalHeader
        toggle={() => toggle()}
        className="light-blue darken-3 white-text"
      >
        <MDBIcon icon="clipboard-list" className="mr-2" />
        {TYPES[selected.type]}
      </MDBModalHeader>
      <MDBModalBody className="mb-0">
        {selected.type === "mc" ? (
          <MultipleChoice question={selected} isMultiple={false} />
        ) : selected.type === "matching" ? (
          <MatchingType
            question={selected}
            isView={true}
            haveIndexOfQuestion={false}
          />
        ) : (
          <Identification question={selected} isMultiple={false} />
        )}
      </MDBModalBody>
    </MDBModal>
  );
}
