import { MDBContainer, MDBCollapse, MDBCollapseHeader } from "mdbreact";
import React, { useState } from "react";

const FAQ = () => {
  const [activeId, setActiveId] = useState(-1);
  const [didHoverId, setDidHoverId] = useState(-1);
  const frequentQuestions = [
    {
      question: "How do I enroll in the system?",
      answer:
        "The enrollment form will automatically appear on your dashboard after you log in.",
    },
    {
      question: "What documents are required for enrollment?",
      answer:
        "Required documents include a completed application form, a copy of your PSA birth certificate, Form 137, report card, and a 2x2 photo.",
    },
    {
      question: "Can I change my selected course after enrolling?",
      answer:
        "No, you cannot change your selected course after submitting your enrollment form.",
    },
    {
      question: "Is there an entrance exam?",
      answer:
        "Yes, an entrance exam is required if you want to enroll as an ICT student.",
    },
    {
      question: "What happens after I complete the registration?",
      answer:
        "After registration, you will need to wait for the registrar to review and activate your account. You will be notified once your account is activated and you can proceed with enrollment.",
    },
  ];

  return (
    <div
      className="vh-100 vw-100"
      style={{ background: "#eee", paddingTop: "5rem" }}
    >
      <MDBContainer>
        <h2 className="text-center my-5 font-weight-bold">
          Frequently Asked Questions
        </h2>
        {frequentQuestions.map((q, index) => {
          const textColor =
            activeId !== index
              ? didHoverId === index
                ? "text-primary"
                : "text-black"
              : "text-white";

          const bgBorder =
            activeId === index
              ? " bg-info transition"
              : didHoverId === index
              ? "rounded border border-info bg-transparent ease-out"
              : "bg-transparent ease-out";

          return (
            <div
              key={index}
              className="mt-2"
              onMouseLeave={() => setDidHoverId(-1)}
              onMouseEnter={() => setDidHoverId(index)}
            >
              <MDBCollapseHeader
                className={bgBorder}
                onClick={() => {
                  setActiveId((prev) => (prev === index ? -1 : index));
                }}
              >
                <div className="d-flex justify-content-between">
                  <label className={textColor}>{`${index + 1}. ${
                    q.question || "--"
                  }`}</label>
                  <div className="d-flex align-items-center">
                    <i
                      style={{
                        rotate: `${activeId === index ? 0 : 90}deg`,
                      }}
                      className={`fa fa-angle-down transition-all ${textColor}`}
                    />
                  </div>
                </div>
              </MDBCollapseHeader>
              <MDBCollapse
                id={`collapse-${index}`}
                isOpen={index === activeId}
                className="border border-black"
              >
                <h5 className="p-3">{q.answer}</h5>
              </MDBCollapse>
            </div>
          );
        })}
      </MDBContainer>
    </div>
  );
};

export default FAQ;
