import React, { useState } from "react";
import "./orgChart.css";
import { MDBAvatar } from "mdbreact";
import { ENDPOINT } from "../../../../services/utilities";

/** 
 *  OrganizationTable - A representation of an organization's hierarchy.
 * @param {Array<Object>} organization - List of organization members.
 
 * @example
 * const org = [
 *   {
 *     _id: 1,
 *     name: "John Smith",
 *     title: "CEO",
 *     department: "Executive",
 *     reportsTo: null,
 *   },
 *   {
 *     _id: 2,
 *     name: "Susan Johnson",
 *     title: "CFO",
 *     department: "Finance",
 *     reportsTo: 1,
 *   },
 *   {
 *     _id: 3,
 *     name: "James Williams",
 *     title: "COO",
 *     department: "Operations",
 *     reportsTo: 1,
 *   },
 *   {
 *     _id: 4,
 *     name: "Emily Davis",
 *     title: "CTO",
 *     department: "Technology",
 *     reportsTo: 1,
 *   }
 * ];
 * 
 */
const OrganizationTable = ({ members }) => {
  const [expandedMembers, setExpandedMembers] = useState({});

  const toggleWrap = (id) => {
    setExpandedMembers((prev) => ({
      ...prev,
      [id]: !prev[id],
    }));
  };

  const renderMembers = (headMember) => {
    const subordinates = members.filter(
      (member) => headMember._id === member.reportsTo
    );

    return (
      <table key={headMember._id} className="table-org">
        <tbody className="tbody-org">
          <tr className="tr-org">
            <td className="td-org" colSpan={subordinates.length * 2 || 1}>
              <div className="node-org">
                <div className="main-org">
                  <div className="description-org font-weight-bold">
                    {headMember?.position || ""}
                  </div>

                  <div className="img-cont-org">
                    {/* <span className='title-org'>{headMember?.title || ""}</span> */}
                    <MDBAvatar
                      tag="img"
                      alt={
                        headMember.fullName?.fname + headMember.fullName?.lname
                      }
                      src={`${ENDPOINT}/assets/profile/${headMember.email}.jpg`}
                      className="z-depth-1 mb-3 mx-auto rounded img-without-shadow rounded-circle"
                      onError={(e) => {
                        e.target.onerror = null;
                        e.target.src =
                          "https://mdbcdn.b-cdn.net/img/new/avatars/1.webp";
                      }}
                      style={{
                        width: "100%",
                        height: "140px",
                        objectFit: "contain",
                      }}
                    />
                  </div>
                  <div
                    className={`name-org ${
                      expandedMembers[headMember._id] ? "wrap" : "nowrap"
                    }`}
                    onClick={() => toggleWrap(headMember._id)}
                  >
                    {headMember.fullName?.fname +
                      " " +
                      headMember.fullName?.lname}
                  </div>
                </div>
              </div>
            </td>
          </tr>

          {subordinates.length > 0 && (
            <React.Fragment key={`${subordinates.length}-lines`}>
              <tr className="lines-org tr-org" key={`${headMember._id}-line`}>
                <td className="td-org" colSpan={subordinates.length * 2}>
                  <div className="downLine-org"></div>
                </td>
              </tr>

              <tr className="lines-org tr-org">
                {subordinates.map((_, index) =>
                  subordinates.length === 1 ? (
                    <React.Fragment key={`${index + 2}-line`}>
                      <td className="td-org rightLine-org"></td>
                      <td className="td-org leftLine-org"></td>
                    </React.Fragment>
                  ) : index === 0 ? (
                    <React.Fragment key={`${index + 2}-line`}>
                      <td className="td-org rightLine-org"></td>
                      <td className="td-org leftLine-org topline-org"></td>
                    </React.Fragment>
                  ) : index + 1 === subordinates.length ? (
                    <React.Fragment key={`${index + 2}-line`}>
                      <td className="td-org rightLine-org topline-org"></td>
                      <td className="td-org leftLine-org"></td>
                    </React.Fragment>
                  ) : (
                    <React.Fragment key={`${index + 2}-line`}>
                      <td className="td-org rightLine-org topline-org"></td>
                      <td className="td-org leftLine-org topline-org"></td>
                    </React.Fragment>
                  )
                )}
              </tr>
              <tr className="tr-org">
                {subordinates.map((subordinate, i) => (
                  <td
                    className="td-org"
                    colSpan={(subordinates.length * 2) / subordinates.length}
                    key={`${i}-subordinate`}
                  >
                    {renderMembers(subordinate)}
                  </td>
                ))}
              </tr>
            </React.Fragment>
          )}
        </tbody>
      </table>
    );
  };

  // Top-level members (heads of departments)
  // Top level no one to report to
  // note if admin or principal or top level members, set reportsTo to null
  const heads = members.filter((member) => !member.reportsTo);
  
  return (
    <div className="container-org" >
      <div ></div>
      {heads.map((headMember) => renderMembers(headMember))}
      <div  className="text-bottom-org">LMBNHS</div>
    </div>
  );
};

export default OrganizationTable;
