const coordinates = ({
  containerPos,
  questionRefs,
  answerRefs,
  questionIndex,
  answerIndex,
  isAdd = true,
}) => {
  if (questionRefs.length === 0 && answerRefs.length === 0) return false;
  const questionPos =
    questionRefs.current[questionIndex]?.getBoundingClientRect() || {};
  const answerPos =
    answerRefs.current[answerIndex]?.getBoundingClientRect() || {};

  const startX = questionPos.right - containerPos.left + window.scrollX;
  const endX = answerPos.left - containerPos.left + window.scrollX;

  const scrollYOffset = isAdd ? window.scrollY : 0;

  const startY =
    questionPos.top + questionPos.height / 2 - containerPos.top + scrollYOffset;

  const endY =
    answerPos.top + answerPos.height / 2 - containerPos.top + scrollYOffset;

  return {
    x1: startX,
    y1: startY,
    x2: endX,
    y2: endY,
    answerIndex,
    questionIndex,
  };
};

export default coordinates;
