import React from "react";
import { MDBRow, MDBCol } from "mdbreact";
import CustomSelect from "../../../../components/customSelect";

function Level({
  levels,
  sections,
  strands,
  subjects,
  semesters,
  form,
  setForm,
}) {
  const key = JSON.stringify(form);
  return (
    <MDBRow>
      <MDBCol>
        <CustomSelect
          choices={levels}
          preValue={form.lvl}
          label={"Grade Level"}
          key={`${key}-level`}
          className="m-0 p-0"
          addTextLeft="Grade -"
          onChange={(value) => setForm({ ...form, lvl: Number(value) })}
        />
        {/* <label className="w-100">
          <span className="text-primary">Grade Level</span>
          <select
            className="form-control bg-light"
            value={form?.lvl}
            onChange={(e) => setForm({ ...form, lvl: Number(e.target.value) })}
          >
            {levels.length > 0 &&
              levels.map((level, index) => (
                <option key={index} value={level}>
                  {level}
                </option>
              ))}
          </select>
        </label> */}
      </MDBCol>
      {form?.lvl > 10 && (
        <>
          <MDBCol>
            <CustomSelect
              choices={strands}
              key={`${key}-strand`}
              preValue={form.strand}
              label={"Strand"}
              className="m-0 p-0"
              onChange={(value) => setForm({ ...form, strand: value })}
            />
            {/* <label className="w-100">
              <span className="text-primary">Strand</span>

              <select
                className="form-control bg-light "
                value={form.strand}
                onChange={(e) => setForm({ ...form, strand: e.target.value })}
              >
                {strands.length > 0 &&
                  strands.map((str, index) => (
                    <option key={index} value={str}>
                      {str}
                    </option>
                  ))}
              </select>
            </label> */}
          </MDBCol>
        </>
      )}
      <MDBCol>
        <CustomSelect
          choices={sections}
          key={`${key}-section`}
          preValue={form.section}
          label={"Section"}
          className="m-0 p-0"
          texts="name"
          values="_id"
          onChange={(value) => setForm({ ...form, section: value })}
        />
        {/* <label className="w-100">
          <span className="text-primary">Section</span>
          <select
            className="form-control bg-light"
            value={form.section}
            onChange={(e) => setForm({ ...form, section: e.target.value })}
          >
            {sections.length > 0 &&
              sections.map(({ name, _id }, index) => (
                <option key={index} value={_id}>
                  {name}
                </option>
              ))}
          </select>
        </label> */}
      </MDBCol>
      {form.lvl > 10 && (
        <MDBCol>
          <CustomSelect
            choices={semesters}
            key={`${key}-semester`}
            preValue={form.semester}
            label={"Semester"}
            className="m-0 p-0"
            onChange={(value) => setForm({ ...form, semester: value })}
          />
          {/* <label className="w-100">
            <span className="text-primary">Semester</span>
            <select
              className="form-control bg-light "
              value={form.semester}
              onChange={(e) => setForm({ ...form, semester: e.target.value })}
            >
              {semesters.length > 0 &&
                semesters.map((_semester, index) => (
                  <option key={index} value={_semester}>
                    {_semester}
                  </option>
                ))}
            </select>
          </label> */}
        </MDBCol>
      )}
      <MDBCol>
        <CustomSelect
          choices={subjects}
          key={`${key}-subject`}
          preValue={form.subject}
          label={"Subject"}
          className="m-0 p-0"
          texts="name"
          values="_id"
          onChange={(value) => setForm({ ...form, subject: value })}
        />
        {/* <label className="w-100">
          <div className="d-flex align-items-center">
            <span className="text-primary">Subject</span>
          </div>
          <select
            className="form-control bg-light"
            value={form.subject}
            onChange={(e) => setForm({ ...form, subject: e.target.value })}
          >
            {subjects.length > 0 &&
              subjects.map(({ name, _id }, index) => (
                <option key={index} value={_id}>
                  {name}
                </option>
              ))}
          </select>
        </label> */}
      </MDBCol>
    </MDBRow>
  );
}

export default Level;
