import checkerFunction from "../../../../../widgets/checkSchedule";
const { scheduleIsValid, subjectIsDuplicate } = checkerFunction;

const converterDays = {
  M: "Monday",
  T: "Tuesday",
  W: "Wednesday",
  TH: "Thursday",
  F: "Friday",
};
const validate = {
  subject: ({ schedules, form, pickDays }) => {
    const { isBreakTime = false } = form;
    if (isBreakTime) return false;

    const sections = schedules.filter(
      ({ section = {}, subject = {}, isBreakTime = false }) =>
        section?._id === form?.section &&
        subject?._id === form?.subject &&
        !isBreakTime
    );

    var subjectConflict = subjectIsDuplicate(sections, pickDays);

    return subjectConflict;
  },
  instructor: ({
    schedules,
    pickDays,
    hourStart,
    hourEnd,
    minStart,
    minEnd,
    form,
  }) => {
    const instrucScheds = schedules.filter(
      ({ instructor: ins, isBreakTime = false }) =>
        ins?._id === form?.instructor && !isBreakTime
    );

    var instructorConflict = scheduleIsValid(
      instrucScheds,
      pickDays,
      hourStart,
      hourEnd,
      minStart,
      minEnd,
      form
    );

    return { ...instructorConflict, instructorConflict: true };
  },
  section: ({
    schedules,
    pickDays,
    hourStart,
    hourEnd,
    minStart,
    minEnd,
    form,
  }) => {
    const sectionScheds = schedules.filter(
      ({ section, isBreakTime = false }) =>
        section?._id === form.section && !isBreakTime
    );
    var sectionConflict = scheduleIsValid(
      sectionScheds,
      pickDays,
      hourStart,
      hourEnd,
      minStart,
      minEnd,
      form
    );

    return sectionConflict;
  },

  schedulePick: ({
    pickDays,
    hourStart,
    hourEnd,
    minStart,
    form,
    minEnd,
    schedulePick,
  }) => {
    var { isConflict } = scheduleIsValid(
      schedulePick,
      pickDays,
      hourStart,
      hourEnd,
      minStart,
      minEnd,
      form
    );

    return isConflict;
  },

  subjectPick: ({ schedules, pickDays, form }) => {
    const { isBreakTime = false } = form;

    if (isBreakTime) return false;

    const collections = schedules.filter(
      ({ subject, isBreakTime = false }) =>
        subject._id === form.subject && !isBreakTime
    );

    var isDuplicate = subjectIsDuplicate(collections, pickDays);

    return isDuplicate;
  },

  breakTime: ({
    schedules = [],
    schedulePick = [],
    pickDays,
    hourStart,
    hourEnd,
    minStart,
    minEnd,
    form,
    willCreate = true,
  }) => {
    const getBreakTimes = (scheds) =>
      [...scheds].filter(({ isBreakTime = false }) => isBreakTime === true);

    const schedulesBreakTime = [
      ...getBreakTimes(
        schedules.filter(({ section = {} }) => section._id === form.section)
      ),
    ];

    const breakTimeScheds = willCreate
      ? [...getBreakTimes(schedulePick), ...schedulesBreakTime]
      : [...schedulesBreakTime];

    if (breakTimeScheds.length === 0) return { isConflict: false };
    var days = form.isBreakTime ? [...pickDays] : [];

    breakTimeScheds.forEach((element) => {
      const { schedules = [] } = element;
      schedules.forEach((element) => {
        const { days: oldDays } = element;
        days = [...days, ...oldDays];
      });
    });

    //para lagyan ng count yung bawat day para malaman ko kung meron bang dalawang breaktime sa isang araw
    const daysCount = days.reduce((acc, curr) => {
      const index = acc.findIndex(({ name }) => name === curr);
      if (index > -1) {
        const findAcc = acc[index];
        acc[index] = { ...findAcc, count: findAcc.count + 1 };
      } else {
        acc.push({ name: curr, count: 1 });
      }

      return acc;
    }, []);

    const have2CountDays =
      daysCount.find(({ count = 0 }) => count >= 3) || false;

    if (have2CountDays) {
      return {
        isConflict: true,
        message: `Only 2 schedules are allowed, and there's a conflict on ${
          converterDays[have2CountDays.name]
        }`,
      };
    }

    var conflict = scheduleIsValid(
      breakTimeScheds,
      pickDays,
      hourStart,
      hourEnd,
      minStart,
      minEnd,
      form
    );

    console.log(conflict.day);

    return {
      ...conflict,
      message: `The selected time on ${
        converterDays[conflict.day]
      } is already set as break time. Please choose a different time.`,
    };
  },
};

export default validate;
