import React, { useState } from "react";
import { MDBTable, MDBBtn, MDBIcon } from "mdbreact";

import Rows from "../../../../../widgets/pagination/rows";
import PaginationButtons from "../../../../../widgets/pagination/buttons";
import { fullName, handlePagination } from "../../../../../services/utilities";
const Table = ({ participants, handleViewAnswer }) => {
  const [max, setMax] = useState(5),
    [page, setPage] = useState(1);

  const fontWeight = { fontWeight: 400 };

  return (
    <>
      <MDBTable>
        <thead>
          <tr>
            <th>#</th>
            <th>Student</th>
            <th className="text-center">Score</th>
            <th className="text-center">Passing Score</th>
            <th className="text-center">Status</th>
            <th className="text-center">Action</th>
          </tr>
        </thead>
        <tbody>
          {handlePagination(participants, page, max).map(
            (participant, index) => {
              const { student, exam, score = 0 } = participant;
              const isPassed = score >= exam.passingScore;
              return (
                <tr key={index}>
                  <td>{index + 1}</td>
                  <td style={fontWeight}>{fullName(student.fullName)}</td>
                  <td style={fontWeight} className="text-center">
                    {`${score} / ${exam?.questions?.length}`}
                  </td>
                  <td style={fontWeight} className="text-center">
                    {exam?.passingScore}
                  </td>
                  <td
                    className={`font-weight-bold text-center ${
                      isPassed ? "text-success" : "text-danger"
                    }`}
                  >
                    {isPassed ? "PASSED" : "FAILED"}
                  </td>
                  <td className="text-center">
                    <MDBBtn
                      size="sm"
                      color="warning"
                      rounded
                      onClick={() => handleViewAnswer(participant)}
                    >
                      <MDBIcon icon="clipboard-list" />
                    </MDBBtn>
                  </td>
                </tr>
              );
            }
          )}
        </tbody>
      </MDBTable>
      <Rows max={max} setMax={setMax} />
      <PaginationButtons
        page={page}
        setPage={setPage}
        array={participants}
        max={max}
      />
    </>
  );
};

export default Table;
