import React from "react";
import { MDBIcon } from "mdbreact";
import "./replied.css";

const ReplyMessage = ({ message, messageByYou, scrollToReplyMessage }) => {
  const { replied } = message;
  const { isImage = false, images = [] } = replied;
  const repliedToSelf = replied?.sender?._id === message.sender?._id;

  const getFirstName = (_fullName) => {
    return _fullName?.fname || "--";
  };

  const formatedTitleReplied = () => {
    if (messageByYou) {
      if (repliedToSelf) {
        return `You replied to yourself `;
      } else {
        return `Your replied to ${getFirstName(replied?.sender?.fullName)}`;
      }
    } else {
      return `${getFirstName(message?.sender?.fullName)} replied to ${
        repliedToSelf ? "themself" : "you"
      }  `;
    }
  };

  return (
    <>
      <p
        className={`${
          !messageByYou ? " reply-receiver-title" : " reply-sender-title"
        }  `}
      >
        <MDBIcon icon="reply" className="mr-1 reply-chat-icon-title" />
        {formatedTitleReplied()}
      </p>
      <div
        style={{ ...(!messageByYou && { marginLeft: "2rem" }) }}
        className="cursor-pointer"
        onClick={() => scrollToReplyMessage(replied)}
      >
        {!isImage ? (
          <p className={`replied-txt baseMsg`}>{replied?.text}</p>
        ) : (
          <img
            src={images[0]}
            alt={message._id}
            height={60}
            width={80}
            style={{
              borderRadius: "10px",
              marginBottom: "-15px",
              objectFit: "contain",
            }}
          />
        )}
      </div>
    </>
  );
};

export default ReplyMessage;
