import React, { useEffect } from "react";
import "./App.css";
import { Switch, useLocation, Route } from "react-router-dom";
import Platforms from "./pages/platforms";
import { useDispatch, useSelector } from "react-redux";
import { VALIDATEREFRESH } from "./services/redux/slices/auth";
import HeroPage from "./pages/home";
import CEO from "./components/coe";

export default function App() {
  const { auth, token } = useSelector(({ auth }) => auth),
    location = useLocation(),
    dispatch = useDispatch(),
    heroPaths = [
      "/organizational-chart",
      "/",
      "/about-us",
      "/terms-and-policy",
      "/faqs",
    ];

  useEffect(() => {
    if (!auth._id && token) {
      dispatch(VALIDATEREFRESH(token));
    }
  }, [auth, token, dispatch]);

  const heroPath = location.pathname;

  return (
    <Switch>
      {/* <Route path="/" exact component={Home} /> */}
      <Route path="/CEO" exact component={CEO} />
      {heroPaths.includes(heroPath) ? <HeroPage /> : <Platforms />}
    </Switch>
  );
}
