import React from "react";
import { MDBBtn } from "mdbreact";
const PROGRESS = {
  shs: "Senior High School",
  jhs: "Junior High School",
};
const Rules = ({ setHasStart = () => {}, exam }) => {
  return (
    <>
      <div className="d-flex align-items-center justify-content-center">
        {/* <MDBIcon icon="clipboard-list" className="mr-3" size="2x" /> */}
        <h1
          className="text-center mt-2 font-weight-bold"
          style={{
            fontFamily: "Times New Roman, Times, serif",
          }}
        >
          {PROGRESS[exam?.progress]}
        </h1>
      </div>
      <div
        style={{
          padding: "20px",
          lineHeight: "1.6",
          fontFamily: "Arial, sans-serif",
        }}
      >
        <h2 style={{ fontWeight: "bold", fontSize: "26px", color: "#333" }}>
          Please read the following rules carefully before proceeding:
        </h2>
        <p
          style={{
            fontSize: "18px",
            marginTop: "15px",
          }}
        >
          1. <strong>Timed Questions</strong> - Each question has a set
          duration. Once the time is up, the system will automatically move to
          the next question, even if you haven’t answered.
        </p>
        <p style={{ fontSize: "18px", marginTop: "15px" }}>
          2. <strong>No Going Back</strong> - You cannot return to previous
          questions once you move on, so be sure to answer carefully.
        </p>
        <p style={{ fontSize: "18px", marginTop: "15px" }}>
          3. <strong>No Cheating</strong> - To maintain exam integrity, you are
          not allowed to open a new tab or window during the exam. If you do,
          the exam will automatically submit, and you will not be able to
          continue.
        </p>
        <p style={{ fontSize: "18px", marginTop: "15px" }}>
          4. <strong>Focus and Time Management</strong> - Stay focused and
          manage your time wisely. Make sure to answer each question within the
          allotted time.
        </p>

        <div className="text-center">
          <h5>Good luck on your exam!</h5>
          <MDBBtn color="success" onClick={() => setHasStart(true)}>
            Start
          </MDBBtn>
        </div>
      </div>
    </>
  );
};

export default Rules;
