import React, { useCallback, useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { MDBCard, MDBCardBody, MDBView } from "mdbreact";
import { useToasts } from "react-toast-notifications";
import {
  BROWSE,
  DESTROY,
  RESET,
} from "../../../../services/redux/slices/registrar/questionBank";
import SwitchView from "./../../../../widgets/view";
import Modal from "./modal";
import Search from "../../../../widgets/search";
import MultipleDestroy from "../../../../widgets/multipleDestroy";
import TableLoading from "../../../../widgets/tableLoading";
import Table from "./table";
const PROGRESS = {
  JHS: "Junior High School",
  SHS: "Senior High School",
};
const QuestionBank = () => {
  const { token } = useSelector(({ auth }) => auth),
    { collections, message, isSuccess, isLoading } = useSelector(
      ({ questionBank }) => questionBank
    ),
    [active, setActive] = useState("mc"),
    [progress, setProgress] = useState([]),
    [activeProgress, setActiveProgress] = useState("JHS"),
    [container, setContainer] = useState([]),
    [filterByProgress, setFilterByProgress] = useState([]),
    [questionBank, setQuestionBank] = useState([]),
    [selected, setSelected] = useState({}),
    [didSearch, setDidSearch] = useState(false),
    [show, setShow] = useState(false),
    [willCreate, setWillCreate] = useState(true),
    { addToast } = useToasts(),
    dispatch = useDispatch();

  useEffect(() => {
    dispatch(BROWSE({ token }));
    return () => dispatch(RESET());
  }, [dispatch, token]);

  const handleFilter = useCallback((baseKey = "", baseValue, array) => {
    return [...array].filter(
      (obj) => obj[baseKey].toLowerCase() === baseValue.toLowerCase()
    );
  }, []);

  useEffect(() => {
    if (message) {
      addToast(message, {
        appearance: isSuccess ? "success" : "error",
      });
    }
  }, [isSuccess, message, addToast]);

  useEffect(() => {
    const haveJHS = collections.some(({ progress }) => progress === "JHS");
    const haveSHS = collections.some(({ progress }) => progress === "SHS");

    const activeProgress = [];
    if (haveJHS) activeProgress.push("JHS");
    if (haveSHS) activeProgress.push("SHS");
    // const defaultProgress = activeProgress[0] || "";
    // setActiveProgress(defaultProgress);
    setProgress(activeProgress);
  }, [collections]);

  useEffect(() => {
    if (activeProgress) {
      const _filterByProgress = handleFilter(
        "progress",
        activeProgress,
        collections
      );
      setFilterByProgress(_filterByProgress);
    }
  }, [activeProgress, collections, handleFilter]);

  useEffect(() => {
    if (activeProgress && filterByProgress.length > 0) {
      const _questionBank = handleFilter("type", active, filterByProgress);
      setQuestionBank(_questionBank);
    }
  }, [active, filterByProgress, activeProgress, handleFilter]);

  // useEffect(() => {
  //   const filterQuestion = collections.filter(
  //     ({ type }) => type.toLowerCase() === active
  //   );
  //   setQuestionBank(filterQuestion);
  // }, [collections, active]);

  const handleUpdate = () => {
    if (container.length === 1) {
      setSelected(container[0]);
      setWillCreate(false);
      setShow(true);
    } else {
      addToast("Please Select 1 Item", {
        appearance: "warning",
      });
    }
  };

  const handleDelete = () => {
    MultipleDestroy(
      dispatch,
      DESTROY,
      token,
      container,
      addToast,
      setContainer
    );
  };

  const handleSearch = () => {};

  return (
    <>
      <MDBCard narrow className="pb-3">
        <MDBView
          cascade
          className="gradient-card-header blue-gradient py-2 mx-4 d-flex justify-content-between align-items-center"
        >
          <span className="ml-3">
            <i>Question Bank </i>
          </span>
          {!isLoading && (
            <select
              className="form-control w-25 ml-5 bg-light"
              value={activeProgress}
              onChange={({ target }) => setActiveProgress(target.value)}
            >
              {progress.map((prog, index) => (
                <option key={index} value={prog}>
                  {PROGRESS[prog]}
                </option>
              ))}
            </select>
          )}
          <Search
            didSearch={didSearch}
            handleSearch={handleSearch}
            setShow={setShow}
            array={collections}
            setArray={setQuestionBank}
            setDidSearch={setDidSearch}
            handleUpdate={handleUpdate}
            handleDelete={handleDelete}
          />
        </MDBView>
        <MDBCardBody>
          {!isLoading ? (
            <>
              <SwitchView
                active={active}
                setActive={setActive}
                array={filterByProgress}
                _key="type"
                titles={[
                  { text: "Multiple Choice", value: "mc" },
                  { text: "Identification", value: "identification" },
                  { text: "Matching Type", value: "matching" },
                ]}
              />
              <Table
                questionBank={questionBank}
                container={container}
                setContainer={setContainer}
              />
            </>
          ) : (
            <TableLoading />
          )}
        </MDBCardBody>
      </MDBCard>
      <Modal
        toggle={() => {
          if (!willCreate) {
            setWillCreate(true);
            setSelected({});
          }
          setShow(false);
        }}
        show={show}
        setContainer={setContainer}
        selected={selected}
        setActiveProgress={setActiveProgress}
        collections={collections}
        willCreate={willCreate}
        activeProgress={activeProgress}
      />
    </>
  );
};

export default QuestionBank;
