//action Messages
const acMessages = {
  removeParentScrollY: () => {
    document.body.classList.remove("overflow-y-scroll");
    document.body.style.overflowY = "hidden";

    return () => {
      document.body.style.overflowY = "";
      document.body.classList.add("overflow-y-scroll");
    };
  },
  calculateWidth: (windowWidth) => {
    if (windowWidth < 600) return windowWidth * 0.9; // Small devices
    if (windowWidth < 1400) return windowWidth * 0.54;

    if (windowWidth < 1600) return windowWidth * 0.44;
    if (windowWidth < 1800) return windowWidth * 0.46; // Large devices
    return windowWidth * 0.49; // Extra large devices
  },

  resizeHeight: (setHeight, setWidth = () => {}) => {
    const handleResize = () => {
      setHeight(window.innerHeight - 120);
      setWidth(acMessages.calculateWidth(window.innerWidth));
    };

    window.addEventListener("resize", handleResize);
    return () => {
      window.removeEventListener("resize", handleResize);
    };
  },

  visibleChecker: (setIsVisible) => {
    const handleVisibilityChange = () => {
      setIsVisible(!document.hidden);
    };

    document.addEventListener("visibilitychange", handleVisibilityChange);

    return () => {
      document.removeEventListener("visibilitychange", handleVisibilityChange);
    };
  },
  notSeen: (messages, user) => {
    if (messages.length === 0) return [];
    const _messages = [...messages];
    return _messages.filter((msg) => {
      const { receiver, isSeen = false } = msg;
      return receiver._id === user._id && !isSeen;
    });
  },

  seen: ({ dispatch, messages, UPDATE, student, token }) => {
    var notSeenMessages = [];
    if (Array.isArray(messages)) {
      notSeenMessages = messages;
    } else {
      notSeenMessages = [messages];
    }
    dispatch(
      UPDATE({
        token,
        data: { student, messages: notSeenMessages },
      })
    );
  },

  profileChecker: ({
    messages,
    dispatch,
    token,
    UPDATE,
    student,
    isAgent = false,
  }) => {
    const _messages = messages.map((msg) => msg);
    const lastMessages = _messages.sort(
      (a, b) => new Date(b.createdAt) - new Date(a.createdAt)
    );
    const lastMessage = lastMessages[0];
    const lastMessageCreatedAt = lastMessage?.createdAt;
    const diffInMilliseconds = new Date() - new Date(lastMessageCreatedAt);
    const diffInMinutes = diffInMilliseconds / (1000 * 60);
    const baseKey = isAgent ? "receiver" : "sender";
    // const baseKey = isAgent ? "sender" : "receiver";
    // const baseKey = "receiver";
    if (!lastMessageCreatedAt) return false;
    if (diffInMinutes <= 5) {
      if (!lastMessage) return false;
      if (student._id !== lastMessage[baseKey]?._id) return false;
      dispatch(
        UPDATE({
          token,
          data: {
            lastMessage: { ...lastMessage, showProfile: false },
            student,
          },
        })
      );
    }
  },
};

export default acMessages;
