import React, { useEffect, useMemo, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import {
  MDBCard,
  MDBCardBody,
  MDBCol,
  MDBContainer,
  MDBRow,
  MDBTypography,
} from "mdbreact";

import { BROWSE } from "../../../../services/redux/slices/resources/batches";
import { GETUSER } from "../../../../services/redux/slices/auth";

import { RESET } from "../../../../services/redux/slices/student/credentials";

import "./enrollment form/index.css";

import EnrollmentForm from "./enrollment form";
import DropCard from "./enrollment form/cards/dropOutCard";
import ApprovedCard from "./enrollment form/cards/approvedCard";
import PendingCard from "./enrollment form/cards/pendingCard";
import RejectCard from "./enrollment form/cards/rejectCard";
import FailCard from "./enrollment form/cards/failedCard";
import { useToasts } from "react-toast-notifications";
import { ENDPOINT } from "../../../../services/utilities";
import GraduateCard from "./enrollment form/cards/graduateCard";

export default function Dashboard() {
  const { auth, token, information } = useSelector(({ auth }) => auth);
  const { fullName, isMale, address, mobile, birthplace, dob } = auth;
  const { status } = information?.enrolleeData ?? {};
  const { enrolleeData } = information || {};
  const { collections } = useSelector(({ batches }) => batches);
  const { isSuccess, message } = useSelector(({ credentials }) => credentials);
  const card = information?.grades || [];
  const infoBatches = information?.batches;
  const enrolleeDataBatch = enrolleeData?.batch;
  const [state, setState] = useState({
    enrollmentStatus: status,
    openBatch: [],
    student: [],
    batchStatus: "",
    isNewStudent: true,
    resolveIssue: false,
    isJhsOpen: false,
    isShsOpen: false,
    showForm: false,
    newStudentButReject: false,
    rejectStudent: false,
    oldPendingMsg: false,
    isDrop: false,
    graduate: false,
  });

  const dispatch = useDispatch();
  const { addToast } = useToasts();
  const [picture, setPicture] = useState(null);
  const [remarks, setRemarks] = useState(0);

  useEffect(() => {
    if (auth) {
      setPicture(
        `${ENDPOINT}/assets/documents/${auth.email}-${auth._id}/studentPicture-${auth.email}.jpg`
      );
    }
  }, [auth]);

  useEffect(() => {
    let isMounted = true;

    if (message === "View Updated") return;
    if (message && isMounted) {
      addToast(message, {
        appearance: isSuccess ? "success" : "error",
      });

      if (isSuccess) {
        setState((prevState) => ({
          ...prevState,
          showForm: false,
        }));

        dispatch(GETUSER({ token }));
        dispatch(RESET());

        localStorage.removeItem("data");
      }
    }

    return () => {
      isMounted = false;
      dispatch(RESET());
    };
  }, [message, dispatch, token, isSuccess, state.showForm, addToast]);

  useEffect(() => {
    let isMounted = true;

    if (token && isMounted) {
      dispatch(BROWSE({ token }));
    }

    return () => {
      isMounted = false;
      dispatch(RESET());
    };
  }, [dispatch, token]);

  useEffect(() => {
    if(collections.length > 0) {
      const activeBatches = collections.filter(item => item.status === "ACTIVE") || [];
      setState((prev) => ({
        ...prev,
        openBatch: activeBatches
      }))
    }
  }, [collections])
  
  useEffect(() => {
    setState((prev) => ({
      ...prev,
      isNewStudent: information.isFreshman
    }))
  }, [information])

  useEffect(() => {
    let isMounted = true;
    if (enrolleeData && isMounted) {
      setState((prevState) => ({
        ...prevState,
        isDrop: enrolleeData.wasDrop,
        student: information,
        resolveIssue: false,
        enrollmentStatus: enrolleeData?.status,
        isNewStudent: information.isFreshman,
      }));
    }

    return () => {
      isMounted = false;
    };
  }, [information, state.showForm, enrolleeData]);

  /* refactoring starts from here */
  const findBatchByProgress = (batches, progress) => 
    batches.find(item => item.progress === progress) || {};
  
  const isGraduatingStudent = (enrolleeData, currentBatch, openShsBatch) => {
    return (
      enrolleeData?.status === "APPROVED" &&
      enrolleeData?.lvl === 12 &&
      enrolleeData?.batch.semester === "2nd" &&
      currentBatch.sy !== openShsBatch?.sy
    );
  };
  
  const isEligibleForGrade11 = (status, enrolleeData, openShsBatch, currentBatch) => {
    return (
      status === "APPROVED" &&
      enrolleeData?.lvl === 10 &&
      Object.keys(openShsBatch).length > 0 &&
      currentBatch.sy !== openShsBatch?.sy &&
      openShsBatch?.semester === "1st"
    );
  };

useEffect(() => {
    let isMounted = true;

    // Get active batches
    const activeBatches = state.openBatch;
    if (activeBatches.length === 0) return;

    // Find relevant batches
    const currentProgress = enrolleeData?.progress || "jhs";
    const currentBatch = findBatchByProgress(activeBatches, currentProgress);
    const shsBatch = findBatchByProgress(activeBatches, "shs");

    // Initial state updates
    const initialState = {
      openBatch: activeBatches,
      batchStatus: activeBatches[0]?.status
    };

    const updateState = (newState) => {
      if (isMounted) {
        setState(prevState => ({
          ...prevState,
          ...newState
        }));
      }
    };

    // Handle different enrollment scenarios
    const handleEnrollmentScenarios = () => {
      // Case 1: No active batches
      if (!activeBatches.length) {
        return updateState({
          showForm: false,
          resolveIssue: false
        });
      }

      // Case 2: Student is dropping
      if (enrolleeDataBatch?._id !== currentBatch?._id && state.isDrop) {
        return updateState({
          showForm: true,
          oldPendingMsg: ""
        });
      }

      // Case 3: Graduating student
      if (isGraduatingStudent(enrolleeData, enrolleeDataBatch, shsBatch)) {
        return updateState({
          showForm: false,
          graduate: true
        });
      }

      // Case 4: Grade 11 enrollment eligibility
      if (isEligibleForGrade11(state.enrollmentStatus, enrolleeData, shsBatch, enrolleeDataBatch)) {
        return updateState({
          showForm: true
        });
      }

      // Case 5: Rejected student with new batch
      if (enrolleeDataBatch?._id !== currentBatch?._id && 
          state.enrollmentStatus === "REJECT" && 
          currentBatch?._id !== undefined) {
        
        if (enrolleeData?.batch.semester !== currentBatch?.semester && 
            enrolleeData?.batch.semester !== undefined) {
          return updateState({ showForm: false });
        }
        
        return updateState({
          rejectStudent: true,
          showForm: true
        });
      }

      // Case 6: Pending student
      const isPendingInCurrentBatch = activeBatches.some(
        item => item._id === enrolleeDataBatch?._id
      );

      if (state.enrollmentStatus === "PENDING" && isPendingInCurrentBatch) {
        return updateState({
          showForm: false,
          oldPendingMsg: ""
        });
      }

      // Case 7: New student
      if (state.isNewStudent && (state?.enrollmentStatus !== "APPROVED" || state.enrollmentStatus === "PENDING")) {
        const newStudentState = {
          showForm: true,
          resolveIssue: true,
          isJhsOpen: currentBatch?.progress === "jhs",
          isShsOpen: currentBatch?.progress === "shs"
        };
        return updateState(newStudentState);
      }

      // Case 8: Level-specific updates
      if (Object.keys(currentBatch).length > 0) {
        if (enrolleeData?.lvl <= 10) {
          return updateState({ isJhsOpen: true });
        } else if (enrolleeDataBatch?.semester === currentBatch?.semester && 
                    enrolleeDataBatch._id !== currentBatch?._id) {
          return updateState({ isShsOpen: true });
        }
      }

      // Case 9: Previously dropped student
      if (enrolleeData?.wasDrop) {
        return updateState({ showForm: true });
      }

      // Case 10: Approved student scenarios
      if (state.enrollmentStatus === "APPROVED") {
        const isNewBatchAvailable = enrolleeDataBatch?._id !== currentBatch?._id && 
                                  currentBatch?._id !== undefined;
        
        if (isNewBatchAvailable) {
          return updateState({
            showForm: true,
            oldPendingMsg: ""
          });
        }

        if (!state.isDrop) {
          return updateState({
            showForm: false,
            oldPendingMsg: ""
          });
        }
      }

      // Case 11: Rejected student in same progress
      if (currentBatch?.progress === enrolleeData?.progress && 
          state.enrollmentStatus === "REJECT") {
        return updateState({
          showForm: true,
          oldPendingMsg: ""
        });
      }

      // Case 12: New rejected student
      if (enrolleeDataBatch?._id === currentBatch?._id && 
          infoBatches.length === 1 && 
          state.enrollmentStatus === "REJECT") {
        return updateState({
          showForm: true,
          newStudentButReject: true
        });
      }

      // Case 13: Pending student with new batch
      if (state.enrollmentStatus === "PENDING" && 
          enrolleeDataBatch?._id !== currentBatch?._id) {
        if (enrolleeDataBatch?.semester === currentBatch?.semester) {
          return updateState({
            showForm: true,
            oldPendingMsg: ""
          });
        } else {
          return updateState({
            showForm: false,
            oldPendingMsg: `Dear ${isMale ? "Mr." : "Ms."} ${
              fullName.fname + " " + fullName.lname
            }, your previous pending enrollment request has been archived. Please wait the start of the new enrollment period to reapply.`
          });
        }
      }
    };
  
      // Execute enrollment logic
      handleEnrollmentScenarios();
      updateState(initialState);
  
      return () => {
        isMounted = false;
      };
    }, [
      state.openBatch,
      state.isNewStudent,
      state.enrollmentStatus,
      enrolleeDataBatch,
      infoBatches,
      fullName.fname,
      fullName.lname,
      isMale,
      enrolleeData,
      state.isDrop,
  ]);
  /* refactoring ends here */

  const getRemarks = useMemo(() => {
    
    const { enrolleeData } = information;
    if (card.length === 0) return 0;
    
    if (collections.length === 0) return 0;
    const currentBatch = collections.find((batch) =>  batch._id === enrolleeData.batch?._id)
    let result = card.find((crd) => crd.batch?._id === currentBatch._id)

    if (!result) return 0;
    const { grades, semester } = result;

    if (grades.length === 0) return 0;

    const calculateAverage = (grades) => {
      const total = grades.reduce((acc, grade) => acc + grade, 0);
      return total / grades.length;
    };

    const getGrades = (data) => {
      return data.map(
        (grade) =>
          (grade.firstQuarter +
            grade.secondQuarter +
            (grade.thirdQuarter || 0) +
            (grade.fourthQuarter || 0)) /
          (grade.thirdQuarter !== undefined && grade.fourthQuarter !== undefined
            ? 4
            : 2)
      );
    };

    if (semester === "2nd") {
      let secondSemGrades = getGrades(grades);
      if (secondSemGrades.length === 0) return 0;

      let gradesFirstSem = card.find(
        (data) =>
          data.semester === "1st" &&
          parseInt(data.lvl) === parseInt(enrolleeData.lvl) &&
          data.strand === enrolleeData.strand
      );

      let { grades: gradesFsem } = gradesFirstSem;
      let firstSemGrades = getGrades(gradesFsem);
      if (firstSemGrades.length === 0) return 0;

      let total2nd = calculateAverage(secondSemGrades);
      let total1st = calculateAverage(firstSemGrades);

      return (total1st + total2nd) / 2;
    }

    let gradesArr = getGrades(grades);
    let total = calculateAverage(gradesArr);
    return total;
  }, [information, card, collections]);

  useEffect(() => {
    const _remarks = getRemarks;
    setRemarks(_remarks);
  }, [getRemarks]);

  return (
    <MDBContainer>
      {state.showForm && state.resolveIssue && (
        <EnrollmentForm
          auth={auth}
          token={token}
          batches={collections}
          status={state.batchStatus}
          back={state.resolveIssue && !state.isNewStudent}
          setBack={() => {
            setState((prevState) => ({
              ...prevState,
              resolveIssue: false,
            }));
          }}
          isNewReject={state.newStudentButReject}
          isNewStudent={state.isNewStudent}
          studentData={{
            ...state.student,
            isPassedInExam: auth?.isPassedInExam || false,
            fullName,
            isMale,
            address,
            mobile,
            birthplace,
            dob,
          }}
          batch={state.openBatch}
          enrolleeID={state.resolveIssue ? enrolleeData?._id : 0}
          isDrop={state.isDrop}
          remarks={remarks}
        />
      )}

      <MDBCard className="text-center">
        {!state.showForm &&
          state.openBatch.length === 0 &&
          !state.enrollmentStatus && (
            <MDBCardBody>
              <MDBRow>
                <MDBCol>
                  Currently no open Enrollment{" "}
                  {state.isShsOpen
                    ? "for Senior High School"
                    : state.isJhsOpen
                    ? "for Junior High School"
                    : ""}
                </MDBCol>
              </MDBRow>
            </MDBCardBody>
          )}

        {state.enrollmentStatus === "PENDING" &&
        !state.oldPendingMsg &&
        !state.resolveIssue ? (
          <PendingCard isMale={isMale} fullName={fullName} />
        ) : state.enrollmentStatus === "REJECT" &&
          !state.oldPendingMsg &&
          !state.resolveIssue ? (
          <RejectCard
            isMale={isMale}
            fullName={fullName}
            student={information}
            setResolveIssue={(prev) => {
              setState((prevState) => ({
                ...prevState,
                resolveIssue: prev,
              }));
            }}
            canEnroll={state.showForm}
            rejected={state.rejectStudent}
          />
        ) : state.isDrop && !state.resolveIssue ? (
          <DropCard
            setResolveIssue={(prev) => {
              setState((prevState) => ({
                ...prevState,
                showForm: prev,
                resolveIssue: prev,
              }));
            }}
            student={information}
            fullName={fullName}
            auth={auth}
            mobile={mobile}
            address={address}
            picture={picture}
            isEnrollmentOpen={state.showForm}
          />
        ) : state.enrollmentStatus === "APPROVED" &&
          !state.isDrop &&
          !state.resolveIssue &&
          (remarks > 75 || remarks === 0) &&
          !state.graduate ? (
          <ApprovedCard
            isMale={isMale}
            fullName={fullName}
            openForm={(prev) => {
              setState((prevState) => ({
                ...prevState,
                showForm: prev,
                resolveIssue: prev,
              }));
            }}
            showForm={state.showForm}
          />
        ) : state.enrollmentStatus !== "PENDING" &&
          remarks < 75 &&
          remarks !== 0 &&
          !state.isDrop &&
          !state.resolveIssue &&
          !state.graduate ? (
          <FailCard
            student={information}
            fullName={fullName}
            auth={auth}
            grades={remarks}
            picture={picture}
            openForm={(prev) => {
              setState((prevState) => ({
                ...prevState,
                resolveIssue: prev,
              }));
            }}
            showBtn={state.showForm}
          />
        ) : state.graduate ? (
          <GraduateCard isMale={isMale} fullName={fullName} />
        ) : (
          state.oldPendingMsg && (
            <MDBTypography
              className="mb-0 text-black-100"
              noteColor="warning"
              note
              noteTitle="Reminder: "
            >
              No schedule. Please wait until your request enrollment form is
              approved
            </MDBTypography>
          )
        )}
      </MDBCard>
    </MDBContainer>
  );
}
