import React, { useEffect, useState } from "react";
import {
  MDBCard,
  MDBCardBody,
  MDBCol,
  MDBRow,
  MDBTypography,
  MDBView,
} from "mdbreact";
import { useDispatch, useSelector } from "react-redux";
import {
  BROWSE,
  SECTIONS,
  UPDATE,
  SectionsWithStudents,
  RESET,
} from "../../../../services/redux/slices/admission/enrollees";
import { useToasts } from "react-toast-notifications";

import Table from "./table";
import Search from "../../../../widgets/search";
import TableLoading from "../../../../widgets/tableLoading";
import ViewEnrollee from "../../../../widgets/viewEnrollee";

import handleForm from "../../../../widgets/form";
import Level from "../../../../widgets/form/level";
import APPROVED from "../../../../widgets/desicionForEnrollees/approved";
import Sections from "./sections";
import { fullName } from "../../../../services/utilities";
const { StoreDefualtValueForForm } = handleForm;
const _form = {
  levels: [],
  level: 7,
  specializations: [],
  specialization: "",
  strands: [],
  strand: "",
  semesters: [],
  semester: "",
  sections: [],
  section: "",
  ictOnly: false,
};

export default function Enrollees({ props }) {
  const { token, information, auth } = useSelector(({ auth }) => auth),
    {
      collections,
      message,
      isSuccess,
      sections,
      enrolleesLoading: isLoading,
      sectionsWithStudents,
    } = useSelector(({ enrollees }) => enrollees),
    [enrollees, setEnrollees] = useState([]),
    [container, setContainer] = useState([]),
    [sectionsCollections, setSectionsCollections] = useState([]),
    [divisions, setDivisions] = useState([]),
    [selected, setSelected] = useState({}),
    [form, setForm] = useState(_form),
    [isView, setIsView] = useState(false),
    [isSelectAll, setIsSelectAll] = useState(false),
    [didSearch, setDidSearch] = useState(false),
    [isDragging, setIsDragging] = useState(false),
    dispatch = useDispatch(),
    { addToast } = useToasts();
  // const isLoading = true;
  useEffect(() => {
    if (message) {
      addToast(message, {
        appearance: isSuccess ? "success" : "error",
      });
    }
  }, [isSuccess, message, addToast]);

  useEffect(() => {
    // Scroll to the top of the page or a specific element
    window.scrollTo(0, 0);
  }, [isView]);

  useEffect(() => {
    if (token && props) {
      dispatch(
        BROWSE({
          token,
          data: { batches: information.batches, status: props },
        })
      );
      return () => dispatch(RESET());
    }
  }, [dispatch, token, information, props]);

  useEffect(() => {
    dispatch(
      SectionsWithStudents({
        token,
        data: {
          batches: information.batches,
          lvl: form.level || 7,
          strand: form.strand || "",
          isICT: form?.isICT || false,
        },
      })
    );
    // return () => dispatch(RESET_SECTIONS());
  }, [information, token, dispatch, form.level, form.strand, form.isICT]);

  useEffect(() => {
    setSectionsCollections(sectionsWithStudents);
  }, [sectionsWithStudents]);

  useEffect(() => {
    if (divisions.length === 0) {
      dispatch(
        SECTIONS({
          token,
          data: {
            batches: information.batches,
            getAllSections: true,
          },
        })
      );
    }
  }, [dispatch, information.batches, token, divisions]);

  useEffect(() => {
    setDivisions(sections);
  }, [sections]);

  const isSection = props === "APPROVED" ? true : false;

  useEffect(() => {
    if (!didSearch) {
      StoreDefualtValueForForm({
        form: {
          level: form.level,
          strand: form.strand,
          specialization: form.specialization,
          section: form.section,
          ictOnly: form.ictOnly,
        },
        setForm,
        collections,
        setArray: setEnrollees,
        isRegistrar: isSection,
        setIsSelectAll,
      });
    }
  }, [
    props,
    collections,
    form.level,
    form.strand,
    form.specialization,
    form.section,
    form.ictOnly,
    didSearch,
    isSection,
  ]);

  useEffect(() => {
    setForm((prev) => ({ ...prev, ictOnly: false }));
  }, [form.level]);

  const handleSearch = (e) => {
    e.preventDefault();

    const key = e.target.searchKey.value.toUpperCase();

    const result = collections.filter(({ student }) =>
      Object.values(student.fullName).some((value) =>
        value.toUpperCase().includes(key)
      )
    );
    setEnrollees(result);

    setDidSearch(true);
  };

  const handleMultipleApproved = () => {
    if (container.length <= 1) {
      addToast("Please Select more than 1 student", {
        appearance: "warning",
      });
    } else {
      const _divisions = divisions.filter(({ lvl, strand }) =>
        container[0].lvl <= 10
          ? lvl === container[0].lvl
          : strand === container[0].strand && lvl === container[0].lvl
      );
      APPROVED({
        sections: _divisions,
        array: container,
        auth,
        token,
        dispatch,
        UPDATE,
      });
    }
  };

  const handleDragStart = (e, enrollee) => {
    setIsDragging(true);

    e.dataTransfer.setData("application/json", JSON.stringify({ enrollee }));

    const dragPreview = document.createElement("div");
    dragPreview.style.position = "absolute";
    dragPreview.style.top = "-9999px";
    dragPreview.style.fontWeight = "500";
    dragPreview.style.fontSize = "1.2rem";
    dragPreview.style.borderRadius = "10px";
    dragPreview.style.padding = "5px";
    dragPreview.style.backgroundColor = "#f0f0f0";
    dragPreview.textContent =
      fullName(enrollee.student?.fullName) || "Dragging...";

    document.body.appendChild(dragPreview);

    e.dataTransfer.setDragImage(dragPreview, 0, 0);

    setTimeout(() => document.body.removeChild(dragPreview), 0);
  };

  const handleDragEnd = () => {
    setIsDragging(false);
  };

  return (
    <>
      {props === "PENDING" && !isView && (
        <MDBRow
          className="d-flex justify-content-end"
          style={{ position: "absolute", top: "60px", left: "0", right: "0" }}
        >
          <MDBCol md="3">
            <MDBTypography
              variant="h2"
              className="mb-0 text-black mt-4 ml-3"
              noteColor="success"
              note
              noteTitle="Instruction: "
            >
              Drag selected enrollee to a section
            </MDBTypography>
          </MDBCol>
        </MDBRow>
      )}
      {!isView ? (
        <MDBRow className="m-0 p-0" style={{ marginTop: "-20rem" }}>
          <MDBCol md={props === "PENDING" ? "9" : "12"}>
            <MDBCard narrow className="pb-3">
              <MDBView
                cascade
                className="gradient-card-header blue-gradient py-2 mx-4 d-flex justify-content-between align-items-center"
              >
                <span className="ml-3 ">
                  <i>{props} ENROLLEES </i>
                </span>

                <Search
                  handleSearch={handleSearch}
                  didSearch={didSearch}
                  setDidSearch={setDidSearch}
                  array={collections}
                  setArray={setEnrollees}
                  isRegistrar={true}
                  handleView={handleMultipleApproved}
                  disableMultipleApproved={props === "PENDING" ? false : true}
                />
              </MDBView>
              <MDBCardBody>
                {isLoading ? (
                  <TableLoading width={200} />
                ) : (
                  <>
                    {enrollees.length > 0 ? (
                      <>
                        {!didSearch ? (
                          <>
                            <Level
                              form={form}
                              setForm={setForm}
                              disableSemester={true}
                              disabedICT={isSection}
                              isRegistrar={
                                props === "APPROVED"
                                  ? form.level === 1
                                    ? false
                                    : true
                                  : isSection
                              }
                              disableSemesterInRegistar={true}
                            />
                            <Table
                              collections={collections}
                              isSelectAll={isSelectAll}
                              setIsSelectAll={setIsSelectAll}
                              lvlKey={form.level}
                              form={form}
                              enrollees={enrollees}
                              handleDragStart={handleDragStart}
                              handleDragEnd={handleDragEnd}
                              container={container}
                              sections={sectionsWithStudents}
                              setContainer={setContainer}
                              isSection={isSection}
                              setSelected={setSelected}
                              setIsView={setIsView}
                              isDragging={isDragging}
                              props={props}
                              isShowAll={form.level === 1 ? true : false}
                              divisions={divisions}
                            />
                          </>
                        ) : (
                          <Table
                            didSearch={didSearch}
                            enrollees={enrollees}
                            setSelected={setSelected}
                            setIsView={setIsView}
                            container={container}
                            handleDragStart={handleDragStart}
                            handleDragEnd={handleDragEnd}
                            form={form}
                            isDragging={isDragging}
                            setContainer={setContainer}
                            isSelectAll={isSelectAll}
                            setIsSelectAll={setIsSelectAll}
                            sections={sectionsWithStudents}
                            isSection={isSection}
                            props={props}
                            isShowAll={form.level === 1 ? true : false}
                            divisions={divisions}
                          />
                        )}
                      </>
                    ) : (
                      <h5 className="text-center">No Record.</h5>
                    )}
                  </>
                )}
              </MDBCardBody>
            </MDBCard>
          </MDBCol>
          {props === "PENDING" && (
            <MDBCol md="3" className="px-0 ">
              <div className="position-relative w-100">
                <Sections
                  params={{
                    isIct: form.isIct,
                    strand: form.strand,
                    lvl: form.level,
                    container,
                  }}
                  setContainer={setContainer}
                  setIsSelectAll={setIsSelectAll}
                  sections={sectionsCollections}
                  collections={sectionsWithStudents}
                  setSections={setSectionsCollections}
                />
              </div>
            </MDBCol>
          )}
        </MDBRow>
      ) : (
        <ViewEnrollee
          selected={selected}
          divisions={sections.filter(({ lvl, strand }) =>
            selected.lvl > 10
              ? selected.lvl === lvl && strand === selected.strand
              : lvl === selected.lvl
          )}
          setIsView={setIsView}
          props={props}
          haveMargin={props === "PENDING"}
        />
      )}
    </>
  );
}
