import React, { useState, useEffect } from "react";
import SideNavigation from "../../components/sidebar";
import TopNavigation from "../../components/topbar";
import Routes from "../Routes";
import { socket } from "../../services/utilities";
import "./loading.css";
import { useLocation } from "react-router";
import { useSelector } from "react-redux";

const breakWidth = 1400;
export default function Platforms() {
  const { role } = useSelector(({ auth }) => auth),
    [windowWidth, setWindowWidth] = useState(window.innerWidth),
    [sideNavToggled, setSideNavToggled] = useState(false),
    [margin, setMargin] = useState("8rem 5%"),
    [dynamicLeftPadding, setDynamicLeftPadding] = useState(""),
    location = useLocation();

  const handleResize = () => setWindowWidth(window.innerWidth);

  useEffect(() => {
    socket.on("me", (_) => console.log("Socket connected."));

    return () => socket.off("me");
  }, []);

  useEffect(() => {
    if (windowWidth > breakWidth) {
      setDynamicLeftPadding("240px");
    } else {
      setDynamicLeftPadding("0");
    }
  }, [windowWidth]);

  useEffect(() => {
    window.addEventListener("resize", handleResize);

    return () => {
      window.removeEventListener("resize", handleResize);
    };
  }, []);

  const toggleSideNav = () => {
    if (windowWidth < breakWidth) {
      setSideNavToggled(!sideNavToggled);
    }
  };

  const pathname = location.pathname;

  const basePath = pathname.split("/");
  // Combine the necessary segments to form the desired path
  const desiredPath = `${basePath[1]}/${basePath[2]}`;

  useEffect(() => {
    if (role.name) {
      if (role.name === "AGENT") {
        if (location.pathname === "/support") {
          setMargin("6rem 6% 0 6%");
        } else {
          setMargin("6rem 6%");
        }
      } else if (role.name === "STUDENT") {
        if (location.pathname === "/support") {
          setMargin("6rem 6% 0 6%");
        } else {
          setMargin("6rem 6%");
        }
      } else {
        if (desiredPath === "enrollees/pending") {
          setMargin("8rem 2%");
        } else {
          setMargin("8rem 5%");
        }
      }
    }
  }, [role, location, desiredPath]);

  return (
    <div className="app">
      <SideNavigation
        breakWidth={breakWidth}
        style={{ transition: "all .3s" }}
        triggerOpening={sideNavToggled}
        onLinkClick={toggleSideNav}
      />
      <div className="flexible-content white-skin">
        <TopNavigation
          toggle={windowWidth < breakWidth}
          onSideNavToggleClick={toggleSideNav}
          className="white-skin"
        />
        <main
          style={{
            paddingLeft: dynamicLeftPadding,
            margin: `${margin}`,
          }}
        >
          {/* <ProgressCheck /> */}
          {/* <Login show={show} /> */}
          <Routes />
        </main>
      </div>
    </div>
  );
}
