import React, { useCallback, useEffect, useState } from "react";
import {
  MDBBtn,
  MDBModal,
  MDBModalBody,
  MDBIcon,
  MDBModalHeader,
  MDBRow,
  MDBCol,
  MDBInput,
  MDBDatePicker,
  MDBTypography,
} from "mdbreact";
import {
  SAVE,
  UPDATE,
} from "../../../../../../services/redux/slices/registrar/entranceExam";
import moment from "moment";
import WarningMessage from "./warningMessage";
import { useDispatch, useSelector } from "react-redux";

export default function Details({
  show = false,
  willCreate = false,
  selectedDepartment = "",
  activeBatch = {},
  selected = {},
  questions = [],
  toggle = () => {},
  mainToggle = () => {},
}) {
  const { token, auth } = useSelector(({ auth }) => auth),
    [passingScore, setPassingScore] = useState(0),
    [duration, setDuration] = useState(30),
    [overAllDuration, setOverAllDuration] = useState(""),
    [date, setDate] = useState(moment().toDate()),
    [startTime, setStartTime] = useState(0),
    [isValid, setIsValid] = useState({
      time: true,
      duration: true,
      passingScore: true,
    }),
    [endTime, setEndTime] = useState(0),
    dispatch = useDispatch();

  const getTimeDifference = useCallback((_startTime, _endTime) => {
    if (_startTime && _endTime) {
      const timeToMinutes = (time) => {
        const [hours, minutes] = time.split(":").map(Number);
        return hours * 60 + minutes;
      };
      const startMinutes = timeToMinutes(_startTime);
      const endMinutes = timeToMinutes(_endTime);
      const difference = endMinutes - startMinutes;
      return difference;
    }
  }, []);

  const convertSeconds = useCallback((totalSeconds) => {
    const hours = Math.floor(totalSeconds / 3600);
    const minutes = Math.floor((totalSeconds % 3600) / 60);
    // const remainingSeconds = totalSeconds % 60;
    const hourText = hours ? (hours > 1 ? "Hours" : "Hour") : "";
    const minText = minutes ? (minutes > 1 ? "Minutes" : "Minute") : "";
    // const seconds = remainingSeconds ? (remainingSeconds > 1 ? "a" : "Minute") : "";

    return ` ${hourText ? `${`${hours} ${hourText}`}` : ""} ${`${
      hourText ? " and " : ""
    } ${minText ? ` ${minutes} ${minText}` : ""}`}`;
  }, []);

  useEffect(() => {
    if (!willCreate) {
      setDuration(selected?.duration);
      setStartTime(selected?.startTime);
      setEndTime(selected?.endTime);
      setDate(selected?.date ? moment(selected.date).toDate() : null);
      setPassingScore(selected?.passingScore);
    }
  }, [willCreate, selected]);

  useEffect(() => {
    setOverAllDuration(convertSeconds(duration * questions.length));
  }, [duration, questions, convertSeconds]);

  console.log(overAllDuration);

  useEffect(() => {
    if (startTime && endTime) {
      setIsValid((prev) => ({
        ...prev,
        time: getTimeDifference(startTime, endTime) >= 60,
      }));
    }
  }, [getTimeDifference, startTime, endTime]);

  useEffect(() => {
    const minimumPassingScore = Math.floor(questions.length / 2);
    setIsValid((prev) => ({
      ...prev,
      passingScore: passingScore >= minimumPassingScore,
    }));
  }, [passingScore, questions]);

  useEffect(() => {
    setIsValid((prev) => ({
      ...prev,
      duration: duration >= 30,
    }));
  }, [duration]);

  useEffect(() => {
    const _passingScore = Math.floor(questions.length / 2);
    if (willCreate) {
      setPassingScore(_passingScore);
    } else {
      const { passingScore: oldPassingScore } = selected;
      if (
        oldPassingScore >= _passingScore &&
        _passingScore <= oldPassingScore
      ) {
        setPassingScore(oldPassingScore);
      } else {
        setPassingScore(_passingScore);
      }
    }
  }, [questions, willCreate, selected]);

  const formatDate = (date) => {
    if (moment(date, moment.ISO_8601, true).isValid()) {
      return moment(date).format("YYYY-MM-DD");
    } else {
      return "";
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const questionIDS = [...questions].map(({ _id }) => _id);
    const details = {
      batch: activeBatch._id,
      createdBy: auth._id,
      date,
      startTime,
      endTime,
      passingScore,
      duration,
      progress: selectedDepartment.toLowerCase(),
      questions: questionIDS,
    };
    if (willCreate) {
      dispatch(
        SAVE({
          token,
          data: details,
        })
      );
    } else {
      dispatch(UPDATE({ token, data: { ...selected, ...details } }));
    }

    toggle();
    mainToggle();
  };
  const isDisabled = Object.values(isValid).includes(false);
  return (
    <MDBModal isOpen={show} toggle={toggle} size="lg">
      <MDBModalHeader
        toggle={toggle}
        className="light-blue darken-3 white-text"
      >
        <MDBIcon icon="list-alt" className="mr-2" />
        Details
      </MDBModalHeader>
      <MDBModalBody className="mb-0">
        <form onSubmit={handleSubmit}>
          <MDBRow>
            <MDBCol>
              <label>
                <small className="grey-text">Date</small>
                <MDBDatePicker
                  className="m-0 mt-2 p-0"
                  getValue={(value) => setDate(value)}
                  value={date}
                  required
                  minDate={formatDate(moment().toDate())}
                />
              </label>
            </MDBCol>
            <MDBCol>
              <MDBInput
                type="time"
                label="Start Time"
                value={startTime}
                required
                onChange={({ target }) => setStartTime(target.value)}
              />
            </MDBCol>
            <MDBCol>
              <MDBInput
                type="time"
                label="End Time"
                required
                value={endTime}
                onChange={({ target }) => setEndTime(target.value)}
              />
            </MDBCol>
          </MDBRow>
          <MDBRow>
            <MDBCol>
              <MDBInput
                label="Number of Questions"
                type="number"
                readOnly
                value={questions.length}
              />
            </MDBCol>
            <MDBCol>
              <MDBInput
                label="Passing Score"
                type="number"
                required
                value={String(passingScore)}
                onChange={({ target }) => {
                  const numericValue = target.value.replace(/\D/g, "");
                  setPassingScore(Number(numericValue));
                }}
              />
            </MDBCol>
            <MDBCol>
              <MDBInput
                label="Duration in seconds per question"
                type="number"
                required
                min="30"
                value={String(duration)}
                onChange={({ target }) => {
                  const numericValue = target.value.replace(/\D/g, "");
                  setDuration(Number(numericValue));
                }}
              />
            </MDBCol>
          </MDBRow>

          <div
            className={`mb-1-half d-flex align-items-center justify-content-${"between"}`}
          >
            {isDisabled && <WarningMessage isValid={isValid} />}
            {!isDisabled && (
              <MDBTypography
                variant="h2"
                className="mb-0 text-black"
                noteColor="success"
                note
                noteTitle="Overall Duration: "
              >
                {overAllDuration}
              </MDBTypography>
            )}
            <MDBBtn
              type="submit"
              color="primary"
              className="mb-2 float-right"
              disabled={isDisabled}
            >
              {willCreate ? "Publish" : "Update"}
            </MDBBtn>
          </div>
        </form>
      </MDBModalBody>
    </MDBModal>
  );
}
