import React from "react";
import { MDBIcon } from "mdbreact";
import { fullName } from "../../../services/utilities";
import { useSelector } from "react-redux";

const Replied = ({ selectedMsg, handleResetReplied }) => {
  const { auth } = useSelector(({ auth }) => auth);
  const messageByYou = auth._id === selectedMsg?.sender?._id;
  return (
    <>
      {selectedMsg._id && (
        <div className="reply-container">
          <div className="d-flex flex-column ml-2">
            <span className="replying-header">
              Replying to{" "}
              {messageByYou
                ? "yourself"
                : fullName(selectedMsg?.sender?.fullName)}
            </span>
            <span className=" replying-txt">
              {selectedMsg.isImage ? "Image" : selectedMsg.text}
            </span>
          </div>
          <MDBIcon
            icon="times"
            className="mr-4 cursor-pointer"
            onClick={handleResetReplied}
          />
        </div>
      )}
    </>
  );
};

export default Replied;
