import { MDBCol, MDBIcon, MDBInput, MDBRow } from "mdbreact";
import React, { useState } from "react";

import "./account.css";
import PasswordInput from "../../../components/passwordInput";

const AccoutDetails = ({ handleChange, passwordStatus, setOpenTerms, accept, userDetails}) => {
  const [maxLength, setMaxLength] = useState(11);
  const [isLocked, setIsLocked] = useState({
    password: true,
    confirmPassword: true,
  });
  const [_accept, setAccept] = useState(accept)

  const handleContactChange = (value) => {
    if (value.startsWith("0")) {
      setMaxLength(11);
    } else if (value.startsWith("6")) {
      setMaxLength(12);
    }

    const val = value.replace(/\D/g, "");
    handleChange("mobile", val);
  };

  const openTemsAndCond = () => {
    setOpenTerms(true)
  }

  return (
    <>
      <MDBRow className="p-2 ml-3 m-2">
        <MDBCol className="account">
          <MDBInput
            name="mobile"
            label={
              <span
                className="d-flex"
                dangerouslySetInnerHTML={{
                  __html:
                    '<div class="red-text" style = "font-size: 25px; font-weight: bolder; height: 25px; display: flex; flex-direction: column-reverse;" >*</div>Mobile number',
                }}
              />
            }
            icon="mobile"
            type="tel"
            labelClass="black-text"
            iconClass="black-text"
            onChange={(e) => handleContactChange(e.target.value)}
            required
            min={1}
            maxLength={maxLength}
            pattern="[0-9]*"
            inputMode="numeric"
            value={userDetails.mobile || ""}
          />
        </MDBCol>
      </MDBRow>
      <MDBRow className="p-2 ml-3 m-2">
        <MDBCol className="account">
          <MDBInput
            label={
              <span
                className="d-flex"
                dangerouslySetInnerHTML={{
                  __html:
                    '<div class="red-text" style = "font-size: 25px; font-weight: bolder; height: 25px; display: flex; flex-direction: column-reverse;" >*</div>E-mail Address',
                }}
              />
            }
            icon="envelope"
            type="email"
            labelClass="black-text"
            iconClass="black-text"
            onChange={(e) => handleChange("email", e.target.value)}
            required
            name="email"
            value={userDetails.email || ""}
          />
        </MDBCol>
      </MDBRow>
      <MDBRow className="p-2 ml-3 m-2">
        <MDBCol className="account">
          <PasswordInput 
            password={userDetails.password || ""}
            setPassword={(value) => {
              handleChange("password", value);
            }}
            isLocked={isLocked.password}
            setIsLocked={(val) => {
              setIsLocked({...isLocked, password: val})
            }}
            setPasswordStatus={passwordStatus}
            hasIcon={true}
            label={"Password"}
          />
        </MDBCol>
      </MDBRow>
      <MDBRow className="p-2 ml-3 m-2">
        <MDBCol className="account">
          <MDBInput
            label={
              <span
                className="d-flex"
                dangerouslySetInnerHTML={{
                  __html:
                    '<div class="red-text" style = "font-size: 25px; font-weight: bolder; height: 25px; display: flex; flex-direction: column-reverse;" >*</div>Confirm your password',
                }}
              />
            }
            minLength={8}
            icon={isLocked.confirmPassword ? "lock" : "unlock"}
            onIconMouseEnter={() =>
              setIsLocked({ ...isLocked, confirmPassword: false })
            }
            onIconMouseLeave={() =>
              setIsLocked({ ...isLocked, confirmPassword: true })
            }
            type={isLocked.confirmPassword ? "password" : "text"}
            labelClass="black-text"
            iconClass="black-text"
            name="confirmPassword"
            onChange={(e) => {
              const value = e.target.value;
              handleChange("confirmPassword", value);
            }}
            value={userDetails.confirmPassword || ""}
            required
          >
            <button className="isLock-eye" type="button" onClick={() => setIsLocked({ ...isLocked, confirmPassword: !isLocked.confirmPassword})}>
                <MDBIcon icon={isLocked.confirmPassword ? "eye-slash" : "eye"} />
            </button>
          </MDBInput>
        </MDBCol>
      </MDBRow>
      <MDBRow className="p-2 ml-3 m-2">
        <MDBCol className="d-flex flex-row align-content-center justify-content-center">
          <MDBInput
            label="I read and agree with the "
            type="checkbox"
            id="agreement"
            labelClass="black-text"
            checked={_accept}
            onChange={()=> setAccept(!_accept)}
            required
          />
            <span
              onClick={openTemsAndCond}
              className="ml-1 text-primary"
            >
              Terms and Conditions
            </span>
        </MDBCol>
      </MDBRow>
    </>
  );
};

export default AccoutDetails;
