import React, { useEffect, useState } from "react";
import { MDBCard, MDBCardBody, MDBView } from "mdbreact";
import { useDispatch, useSelector } from "react-redux";
import {
  BROWSE,
  DESTROY,
} from "../../../../../services/redux/slices/registrar/entranceExam";
import { useToasts } from "react-toast-notifications";
import Swal from "sweetalert2";
import Search from "../../../../../widgets/search";
import "./entranceExam.css";
import Table from "./table";
import SwitchView from "../../../../../widgets/view";
import ViewQuestions from "./viewQuestions";
import SelecQuestions from "./selectQuetions";

const PROGRESS = {
  shs: "Senior High School",
  jhs: "Junior High School",
};
const EntranceExamV2 = () => {
  const { token, information } = useSelector(({ auth }) => auth),
    { collections, isLoading, message, isSuccess } = useSelector(
      ({ entranceExam }) => entranceExam
    ),
    [entranceExam, setEntranceExam] = useState([]),
    [container, setContainer] = useState([]),
    [selected, setSelected] = useState({}),
    [selectedDepartment, setSelectedDepartment] = useState(""),
    [activeProgress, setActiveProgress] = useState("jhs"),
    [show, setShow] = useState(false),
    [willCreate, setWillCreate] = useState(true),
    [didSearch, setDidSearch] = useState(false),
    [viewQuestions, setViewQuestions] = useState(false),
    dispatch = useDispatch(),
    { addToast } = useToasts();

  useEffect(() => {
    dispatch(BROWSE({ token }));
  }, [dispatch, token]);

  useEffect(() => {
    if (!!collections && activeProgress) {
      const _collections = [...collections].filter(
        ({ progress }) => progress.toLowerCase() === activeProgress
      );

      setEntranceExam(_collections);
      setSelected({});
      setContainer([]);
      setWillCreate(true);
    }
  }, [collections, activeProgress]);

  useEffect(() => {
    if (message) {
      addToast(message, {
        appearance: isSuccess ? "success" : "error",
      });
    }
  }, [isSuccess, message, addToast]);

  const getBatchByProgress = (progress) => {
    const currentBatches = [...information.previousBatches].filter(
      ({ status = "" }) => status === "ACTIVE" || status === "INACTIVE"
    );
    return currentBatches.find(({ progress: p }) => p === progress);
  };

  const entranceExamCheckerByBatch = (batch) => {
    const _entranceExam = [...entranceExam];
    return _entranceExam.some(
      ({ batch: b }) => b.sy === batch.sy && batch.progress === b.progress
    );
  };

  const handleADD = () => {
    const batchForSHS = getBatchByProgress("shs");
    const batchForJHS = getBatchByProgress("jhs");
    const activeBatches = [
      entranceExamCheckerByBatch(batchForSHS) === false ? batchForSHS : null,
      entranceExamCheckerByBatch(batchForJHS) === false ? batchForJHS : null,
    ].filter((batch) => batch !== null);

    if (activeBatches.length === 0) {
      return Swal.fire({
        title: "Notice",
        text: "You cannot create a new entrance exam at this time, as an exam has already been established for the current junior high school and senior high school batch. Thank you for your understanding!",
        icon: "warning",
        confirmButtonText: "OK",
      });
    }

    if (activeBatches.length === 1) {
      setSelectedDepartment(activeBatches[0].progress.toUpperCase());
      return setShow(true);
    }
    Swal.fire({
      title: "Select Exam Department",
      html: `
        <form id="exam-form">
       <label for="exam-level">Please select the department for which you are creating the entrance exam?</label>
       <select id="exam-level" class="swal2-input form-control">
      <option value="" disabled selected>Select Department</option>
      ${
        entranceExamCheckerByBatch(batchForJHS) === false
          ? '<option value="JHS">Junior High School</option>'
          : ""
      }
      ${
        entranceExamCheckerByBatch(batchForSHS) === false
          ? '<option value="SHS">Senior High School</option>'
          : ""
      }
    </select>
    </form>
      `,
      showCancelButton: true,
      confirmButtonText: "Confirm",
      cancelButtonText: "Cancel",
      preConfirm: () => {
        const examLevel = document.getElementById("exam-level").value;
        if (!examLevel) {
          Swal.showValidationMessage("Please select a department");
          return false;
        }
        return examLevel;
      },
    }).then((result) => {
      if (result.isConfirmed) {
        setSelectedDepartment(result.value);
        setShow(true);
      }
    });
  };

  const handleSearch = () => {};
  const handleUpdate = () => {
    if (container.length === 1) {
      setSelected(container[0]);
      setSelectedDepartment(container[0].batch.progress.toUpperCase());
      setWillCreate(false);
      setShow(true);
    } else {
      addToast("Please Select 1 Entrance Exam", {
        appearance: "warning",
      });
    }
  };
  const handleDelete = () => {
    if (container.length === 0)
      return addToast("Please Select 1 Entrance Exam", {
        appearance: "warning",
      });

    Swal.fire({
      title: "Are you sure?",
      text: "You won't be able to revert this!",
      icon: "warning",
      showCancelButton: true,
      confirmButtonColor: "#d33",
      cancelButtonColor: "#3085d6",
      confirmButtonText: "Yes, delete it!",
      cancelButtonText: "Cancel",
    }).then((result) => {
      if (result.isConfirmed) {
        dispatch(DESTROY({ token, data: container }));
      }
    });
  };

  return (
    <>
      {!show ? (
        <>
          <MDBCard narrow className="pb-3">
            <MDBView
              cascade
              className="gradient-card-header blue-gradient py-2 mx-4 d-flex justify-content-between align-items-center"
            >
              <span className="ml-3">
                <i>Entrance Exam </i>
              </span>
              <Search
                didSearch={didSearch}
                handleSearch={handleSearch}
                setShow={handleADD}
                array={collections}
                setArray={setEntranceExam}
                setDidSearch={setDidSearch}
                handleUpdate={handleUpdate}
                handleDelete={handleDelete}
              />
            </MDBView>
            <MDBCardBody>
              {!isLoading && (
                <SwitchView
                  array={collections}
                  active={activeProgress}
                  setActive={setActiveProgress}
                  _key="progress"
                  titles={[
                    { text: "Junior High School", value: "jhs" },
                    { text: "Senior High School", value: "shs" },
                  ]}
                />
              )}
              <Table
                entranceExam={entranceExam}
                isLoading={isLoading}
                container={container}
                setContainer={setContainer}
                setQuestionView={(exam) => {
                  setViewQuestions(true);
                  setSelected(exam);
                }}
              />
            </MDBCardBody>
          </MDBCard>

          <ViewQuestions
            show={viewQuestions}
            toggle={() => setViewQuestions(false)}
            questions={selected.questions}
            isView={true}
            title={`${PROGRESS[selected?.progress?.toLowerCase()]}  ${
              selected?.batch?.sy
            }`}
          />
        </>
      ) : (
        <SelecQuestions
          toggle={() => {
            if (!willCreate) {
              setWillCreate(true);
              setSelected({});
            }
            setShow(false);
          }}
          show={show}
          selected={selected}
          selectedDepartment={selectedDepartment}
          willCreate={willCreate}
        />
      )}
    </>
  );
};

export default EntranceExamV2;
