import React, { useEffect, useMemo, useState } from "react";
import { MDBContainer } from "mdbreact";
import { useDispatch, useSelector } from "react-redux";
import { BROWSE } from "../../../../services/redux/slices/resources/batches";
import EnrollmentForm from "../../student/dashboard/enrollment form";
import { useToasts } from "react-toast-notifications";

const WalkIn = () => {
  const { auth, token } = useSelector(({ auth }) => auth);
  const { collections } = useSelector(({ batches }) => batches);
  const { isSuccess, message } = useSelector(({ credentials }) => credentials);
  const { addToast } = useToasts();
  const [remarks, setRemarks] = useState(0);

  const [state, setState] = useState({
    openBatch: [],
    student: [],
    batchStatus: "",
    batches: [],
    resetForm: false,
    isNewStudent: false,
  });

  const dispatch = useDispatch();

  useEffect(() => {
    if (message) {
      addToast(message, {
        appearance: isSuccess ? "success" : "error",
      });
      if (isSuccess) {
        setTimeout(() => {
          setState((prev) => ({
            ...prev,
            resetForm: true,
          }));
        }, 3000);

        setState((prev) => ({
          ...prev,
          resetForm: false,
        }));
        localStorage.removeItem("data")
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [message, token, isSuccess]);

  useEffect(() => {
    let isMounted = true;

    if (token && isMounted) {
      dispatch(BROWSE({ token }));
    }

    return () => {
      isMounted = false;
    };
  }, [dispatch, token]);

  useEffect(() => {
    const batchOpen =
      collections.filter((item) => item.status === "ACTIVE") || [];
    if (batchOpen.length > 0) {
      setState((prev) => ({
        ...prev,
        openBatch: batchOpen,
        batches: collections,
      }));

      batchOpen.forEach((active) => {
        setState((prev) => ({
          ...prev,
          batchStatus: active.status,
        }));
      });
    }
  }, [collections]);

  const getRemarks = useMemo(() => {
    const { lvl, strand, transcript } = state.student;
    console.log(state.student);
    let _transcript = transcript || [];

    if (_transcript.length === 0) return 0;
    const { grades, semester } = _transcript;

    if (grades.length === 0) return 0;

    const calculateAverage = (grades) => {
      const total = grades.reduce((acc, grade) => acc + grade, 0);
      return total / grades.length;
    };

    const getGrades = (data) => {
      return data.map(
        (grade) =>
          (grade.firstQuarter +
            grade.secondQuarter +
            (grade.thirdQuarter || 0) +
            (grade.fourthQuarter || 0)) /
          (grade.thirdQuarter !== undefined && grade.fourthQuarter !== undefined
            ? 4
            : 2)
      );
    };

    if (semester === "2nd") {
      let secondSemGrades = getGrades(grades);
      if (secondSemGrades.length === 0) return 0;

      let gradesFirstSem = _transcript.find(
        (data) =>
          data.semester === "1st" &&
          parseInt(data.lvl) === parseInt(lvl) &&
          data.strand === strand
      );

      let { grades: gradesFsem } = gradesFirstSem;
      let firstSemGrades = getGrades(gradesFsem);
      if (firstSemGrades.length === 0) return 0;

      let total2nd = calculateAverage(secondSemGrades);
      let total1st = calculateAverage(firstSemGrades);

      return (total1st + total2nd) / 2;
    }

    let gradesArr = getGrades(grades);
    let total = calculateAverage(gradesArr);
    return total;
  }, [state.student]);

  useEffect(() => {
    if (state.student) {
      const _remarks = getRemarks;
      console.log(_remarks);
      setRemarks(_remarks);
    }
  }, [state.student, setRemarks, getRemarks]);
  
  return (
    <MDBContainer>
      <EnrollmentForm
        resetForm={state.resetForm}
        auth={auth}
        token={token}
        batches={state.batches}
        status={state.batchStatus}
        batch={state.openBatch}
        studentData={state.student}
        enrolleeID={{}}
        remarks={remarks}
        isRegistrar={true}
        setState={(data) => {
          console.log("data", data);
          if(Object.keys(data).length === 0) {
            setState((prev) => ({
              ...prev,
              isNewStudent: true
            }))
            return
          }
          setState((prev) => ({
            ...prev,
            student: data,
            isNewStudent: false
          }));
        }}
        isNewStudent={state.isNewStudent}
      />
    </MDBContainer>
  );
};

export default WalkIn;
