import React, { useCallback, useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { MDBCard, MDBCardBody, MDBCol, MDBIcon, MDBView } from "mdbreact";
import { BROWSE } from "../../../../../services/redux/slices/registrar/examParticipants";
import Search from "../../../../../widgets/search";
import SwitchView from "../../../../../widgets/view";
import TableLoading from "../../../../../widgets/tableLoading";
import Table from "./table";
import ViewQuestions from "../exam/viewQuestions";

const Participants = ({ isView = false, toggle = () => {} }) => {
  //this props is passed by principal dashboard
  const { token } = useSelector(({ auth }) => auth),
    { collections, isLoading } = useSelector(
      ({ examParticipants }) => examParticipants
    ),
    [participants, setParticipants] = useState([]),
    [participantsByStatus, setParticipantsByStatus] = useState([]),
    [batches, setBatches] = useState([]),
    [progress, setProgress] = useState([]),
    [selected, setSelected] = useState({}),
    [isViewAnswer, setIsViewAnswer] = useState(false),
    [form, setForm] = useState({}),
    [active, setActive] = useState("passed"),
    [didSearch, setDidSearch] = useState(false),
    dispatch = useDispatch();

  useEffect(() => {
    dispatch(BROWSE({ token }));
  }, [token, dispatch]);

  const participantsFilterByProgress = useCallback((_progress, students) => {
    const participantsWithStatus = [...students].map((c) => ({
      ...c,
      status: c.score >= c.exam.passingScore ? "passed" : "failed",
    }));
    return participantsWithStatus.filter(
      ({ progress }) => progress === _progress
    );
  }, []);

  const getProgress = useCallback((students) => {
    return [...students].reduce((acc, curr) => {
      const { progress } = curr;

      if (!acc.includes(progress)) {
        acc.push(progress);
      }

      return acc;
    }, []);
  }, []);

  useEffect(() => {
    if (!!collections) {
      const { students = [], batch = {} } = collections[0] || {};
      const _participants = [...students];
      const _progress = getProgress(_participants);

      const _batches = [...collections].map(({ batch }) => batch);

      const defaultProgress = _progress[0];
      const _participantsFilterByProgress = participantsFilterByProgress(
        defaultProgress,
        _participants
      );
      setForm({ batch: batch._id, progress: defaultProgress });
      setBatches(_batches);
      setProgress(_progress);
      setParticipants(_participantsFilterByProgress);
    }
  }, [collections, participantsFilterByProgress, getProgress]);

  useEffect(() => {
    if (active) {
      const _participants = [...participants];
      const filteredByStatus = _participants.filter(
        ({ status }) => active === status
      );
      setParticipantsByStatus(filteredByStatus);
    }
  }, [participants, active]);

  const handleChangeBatch = (batchID) => {
    const exam = [...collections].find(({ batch }) => batch._id === batchID);

    const { students = [] } = exam || {};

    const _progress = getProgress(students);
    const defaultProgress = _progress[0];
    const _participants = participantsFilterByProgress(
      defaultProgress,
      students
    );

    setProgress(_progress);
    setParticipants(_participants);
    setForm({ batch: batchID, progress: defaultProgress });
  };

  const handleChangeProgress = (_progress) => {
    const exam = [...collections].find(({ batch }) => batch._id === form.batch);

    const _participants = participantsFilterByProgress(
      _progress,
      exam.students
    );
    setParticipants(_participants);
    setForm({ ...form, progress: _progress });
  };

  const handleViewAnswer = (exam) => {
    setIsViewAnswer(true);
    setSelected(exam);
  };
  const handleSearch = () => {};

  return (
    <MDBCard narrow className={isView ? "pb-3 flip-dashboard" : "pb-3"}>
      <MDBView
        cascade
        className="gradient-card-header blue-gradient py-2 mx-4 d-flex justify-content-between align-items-center"
      >
        <span className={isView ? "ml-3 my-2" : "ml-3"}>
          <i>{isView ? "Qualified Applicants for ICT" : "Participants"} </i>
        </span>
        {!isView && (
          <>
            {!isLoading && (
              <div className="w-50 d-flex align-items-center justify-content-center">
                <MDBCol size="6">
                  <select
                    className="form-control w-100 bg-light"
                    value={form.batch}
                    onChange={({ target }) => handleChangeBatch(target.value)}
                  >
                    {batches.map((batch, index) => (
                      <option key={index} value={batch._id}>
                        SY - {batch.sy}
                      </option>
                    ))}
                  </select>
                </MDBCol>
              </div>
            )}
            <Search
              didSearch={didSearch}
              handleSearch={handleSearch}
              array={collections}
              isRegistrar={true}
              setArray={setParticipants}
              setDidSearch={setDidSearch}
            />
          </>
        )}

        {isView && (
          <>
            <MDBCol size="4">
              <select
                className="form-control w-50 bg-light"
                value={form?.progress}
                onChange={({ target }) => handleChangeProgress(target.value)}
              >
                {progress.map((p, index) => (
                  <option key={index} value={p}>
                    {p.toUpperCase()}
                  </option>
                ))}
              </select>
            </MDBCol>
            <MDBIcon icon="times" onClick={toggle} className="cursor-pointer" />
          </>
        )}
      </MDBView>
      <MDBCardBody>
        {!isLoading ? (
          <>
            {!isView && (
              <SwitchView
                active={active}
                setActive={setActive}
                array={participants}
                _key="status"
                titles={[
                  { text: "PASSED", value: "passed" },
                  { text: "FAILED", value: "failed" },
                ]}
              />
            )}
            <Table
              participants={participantsByStatus}
              handleViewAnswer={handleViewAnswer}
            />
          </>
        ) : (
          <TableLoading />
        )}
      </MDBCardBody>

      <ViewQuestions
        show={isViewAnswer}
        isView={true}
        toggle={() => setIsViewAnswer(false)}
        participant={selected}
        isChecking={true}
        questions={selected?.answers}
      />
    </MDBCard>
  );
};

export default Participants;
