import React, { useEffect, useState } from "react";

import Login from "../login";
import Banner from "../banner";
import Features from "../features";
import Mission from "../mission";
import NewLogin from "../newLogin";
import Register from "../register";
import TermsAndConditions from "../termsAndConditions";
import "./index.css";
// import Copyrights from "../../../components/footer";

export default function Home({ login, show, toggleLogin, toggleregister }) {
  const [accept, setAccept] = useState(false),
    [openTerms, setOpenTerms] = useState(false),
    [lastStep, setLastStep] = useState(1);

  useEffect(() => {
    window.scrollTo({ top: 0, behavior: "smooth" });
  }, []);

  return (
    <>
      {openTerms ? (
        <TermsAndConditions
          handleAcctions={(acc, open, step) => {
            setAccept(acc);
            setOpenTerms(open);
            setLastStep(step);
          }}
        />
      ) : (
        <>
          <Login show={login} toggleLogin={toggleLogin} />
          <Register
            show={show}
            toggleregister={toggleregister}
            setOpenTerms={setOpenTerms}
            accept={accept}
            lastStep={lastStep}
          />

          <Banner show={show || login} />
          <Features />
          <NewLogin />
          <Mission />
          {/* <Copyrights /> */}
        </>
      )}
    </>
  );
}
