import React from "react";
import { MDBCol, MDBRow } from "mdbreact";
import logo from "../../assets/logo/logo.png";
import matatag from "../../assets/logo/matatag.png";
import deped from "../../assets/logo/deped.png";
import "./header.css";
export const Header = () => {
  return (
    <>
      <MDBRow className="mb-4 d-flex align-items-center position-relative">
        <div className="container-logo ">
          <img
            src={logo}
            className="logo"
            alt="Logo"
            style={{ height: "80px", width: "80px" }}
          />
        </div>

        <MDBCol className="text-center">
          <h1
            className="font-weight-bold school-name"
            style={{ color: " #0000FF", marginRight: "5rem" }}
          >
            Leonor M. Bautista National High School
          </h1>
          <h6 className="font-weight-bold address">
            Brgy.Pias, General Tinio, Nueva Ecija Region III
          </h6>
        </MDBCol>

        <div className="container-logo-left ">
          <img
            src={deped}
            className="logo"
            alt="Logo"
            style={{ height: "80px", width: "80px" }}
          />
          <img
            src={matatag}
            className="logo"
            alt="Logo"
            style={{ height: "80px", width: "80px" }}
          />
        </div>
      </MDBRow>

      <MDBRow className="mt-5 container-enrollment">
        <MDBCol className="d-flex align-items-center justify-content-center">
          <h2 className="font-weight-bold text-white mt-2 enrollment">
            BASIC EDUCATION ENROLLMENT FORM
          </h2>
        </MDBCol>
      </MDBRow>
    </>
  );
};
