import React from "react";
import { MDBRow, MDBCol, MDBBtn } from "mdbreact";
import CustomSelect from "../../../../../components/customSelect";
import { fullName } from "../../../../../services/utilities";
import Days from "../days";
import Time from "../time";
// import TimeMessage from "../timeMessage";

function Header({ props }) {
  const { form = {} } = props || {};
  const key = JSON.stringify(form);
  return (
    <>
      <MDBRow className="mt-2">
        {props?.willCreate ? (
          <>
            <MDBCol>
              {!form.isBreakTime && (
                <CustomSelect
                  choices={props.instructors.map(({ fullName: name, _id }) => {
                    return { fullName: fullName(name), _id };
                  })}
                  values="_id"
                  label={"Teacher"}
                  texts="fullName"
                  key={`${key}-instructor`}
                  preValue={props?.form?.instructor}
                  onChange={(res) =>
                    props.setForm((form) => ({ ...form, instructor: res }))
                  }
                />
              )}
            </MDBCol>
            <MDBCol md={form.isBreakTime ? "12" : ""}>
              <CustomSelect
                choices={props?.sections}
                values="_id"
                label={"Section"}
                key={`${key}-section`}
                texts="name"
                preValue={props?.form?.section || ""}
                onChange={(res) =>
                  props?.setForm((form) => ({ ...form, section: res }))
                }
              />
            </MDBCol>
            {props?.form?.lvl > 10 && (
              <MDBCol md="2">
                <CustomSelect
                  choices={["1st", "2nd"]}
                  label={"Semester"}
                  key={`${key}-semester`}
                  preValue={props?.form?.semester}
                  onChange={(res) =>
                    props?.setForm((form) => ({ ...form, semester: res }))
                  }
                />
              </MDBCol>
            )}
            {!form.isBreakTime && (
              <MDBCol>
                <CustomSelect
                  choices={props?.subjects}
                  values="_id"
                  label={"Subject"}
                  texts="name"
                  key={`${key}-subject`}
                  preValue={props?.form?.subject}
                  onChange={(res) =>
                    props.setForm((form) => ({ ...form, subject: res }))
                  }
                />
              </MDBCol>
            )}
          </>
        ) : (
          <>
            {props?.form?._id && (
              <>
                {!form.isBreakTime && (
                  <MDBCol className="d-flex align-items-center" md="6">
                    <CustomSelect
                      choices={props.instructors.map(
                        ({ fullName: name, _id }) => {
                          return { fullName: fullName(name), _id };
                        }
                      )}
                      values="_id"
                      label={"Instructor"}
                      className="w-100 m-0 p-0 mt-2"
                      texts="fullName"
                      key={`${key}-instructor`}
                      preValue={props?.form?.instructor}
                      onChange={(res) =>
                        props.setForm((form) => ({ ...form, instructor: res }))
                      }
                    />
                  </MDBCol>
                )}

                {!form.isBreakTime && (
                  <MDBCol className="d-flex align-items-center" md="6">
                    <CustomSelect
                      choices={props?.subjects}
                      values="_id"
                      label={"Subject"}
                      texts="name"
                      className="w-100 m-0 p-0  mt-2"
                      key={`${key}-subject`}
                      preValue={props?.form?.subject}
                      onChange={(res) =>
                        props.setForm((form) => ({ ...form, subject: res }))
                      }
                    />
                  </MDBCol>
                )}
              </>
            )}
          </>
        )}
      </MDBRow>

      {props?.willCreate || props?.form?._id ? (
        <>
          <MDBRow className="mt-3 d-flex align-items-center">
            <Days pickDays={props?.pickDays} handlePick={props?.handlePick} />
          </MDBRow>

          <MDBRow className=" mt-3 d-flex align-items-center">
            <Time
              setHour={props.setHourStart}
              hour={Number(props.hourStart)}
              setMin={props.setMinStart}
              min={Number(props.minStart)}
              period={props.periodStart}
              setPeriod={props.setPeriodStart}
              title={"Start"}
            />
            <Time
              setHour={props.setHourEnd}
              hour={props.hourEnd}
              setMin={props.setMinEnd}
              min={props.minEnd}
              period={props.periodEnd}
              setPeriod={props.setPeriodEnd}
              title={"End"}
            />
          </MDBRow>
          <MDBRow className="mb-5">
            <MDBCol className="d-flex align-items-center">
              <h6 className="mr-3 mt-2 font-weight-bolder">
                This is for break time?{" "}
              </h6>
              <input
                className="form-check-input"
                type="checkbox"
                checked={props.form.isBreakTime}
                disabled={!props.willCreate && !form.isBreakTime}
                onChange={() => {
                  if (!props.willCreate && form.isBreakTime) return;
                  props.setForm((prev) => ({
                    ...prev,
                    isBreakTime: !props?.form?.isBreakTime,
                  }));
                }}
                id="Yes"
              />
              <label
                htmlFor="Yes"
                className="form-check-label mr-4 label-table"
              >
                Yes
              </label>

              <input
                className="form-check-input"
                type="checkbox"
                checked={!props.form.isBreakTime}
                disabled={!props.willCreate && form.isBreakTime}
                onChange={() =>
                  props.setForm((prev) => ({
                    ...prev,
                    isBreakTime: false,
                  }))
                }
                id="No"
              />
              <label htmlFor="No" className="form-check-label mr-2 label-table">
                No
              </label>

              {/* <TimeMessage
                hourInterval={props.hourInterval}
                minInterVal={props.minInterVal}
              /> */}
            </MDBCol>
            <MDBCol className="d-flex justify-content-end">
              <MDBBtn
                size="sm"
                color="success"
                onClick={props.handleCreate}
                disabled={!props.isFillUp}
              >
                {props.willCreate ? "ADD" : "UPDATE"}
              </MDBBtn>
            </MDBCol>
          </MDBRow>
        </>
      ) : (
        ""
      )}
    </>
  );
}

export default Header;
