import React from "react";
import { MDBBtn, MDBCard, MDBCardBody, MDBIcon } from "mdbreact";
import converter from "../../../../services/utilities/converter";

const Questions = ({
  questionIndex = -1,
  collections = [],
  colors = [],
  refs = [],
  handleClick = () => {},
  isChoices = false,
  isChecking = false,
  disableAction = false,
  isView = false,
}) => {
  const handleChecking = (collection) => {
    if (!collection.hasOwnProperty("isCorrect"))
      return <h5 className="ml-5"> &nbsp;</h5>;
    const { isCorrect = false } = collection;
    return (
      <MDBBtn
        floating
        size="sm"
        color="white"
        className="m-0 p-0 ml-3"
        disabled
      >
        <MDBIcon
          icon={isCorrect ? "check" : "times"}
          style={{ color: isCorrect ? "#30D272" : "red" }}
          className={isCorrect ? "mr-3" : "mr-4"}
        />
      </MDBBtn>
    );
  };
  const handleButton = ({ index, color = "", isChoose, letter }) => {
    if (!isChoices) {
      return (
        <div
          className="circle-question"
          ref={(el) => (refs.current[index] = el)}
          style={{ backgroundColor: colors[index] }}
        >
          {converter.indexToLetter(index)}
        </div>
      );
    } else {
      return (
        <div
          className="circle-answer"
          ref={(el) => (refs.current[index] = el)} // Store question refs
          style={{
            backgroundColor: !isChoose ? "whitesmoke" : color,
            border: !isChoose && "1px dashed #9999a1",
          }}
        >
          {letter}
        </div>
      );
    }
  };
  return (
    <div className={"answers"}>
      {collections.map((collection, index) => {
        const {
          text = "",
          textA = "",
          letter = "",
          color,
          isConfusing,
        } = collection || {};
        const isChoose = letter ? true : false;
        const baseText = textA || text;
        return !isConfusing ? (
          <div
            onClick={() => handleClick(disableAction ? -1 : index)}
            key={`$question-${index}`}
            className="mb-2 cursor-pointer"
          >
            <MDBCard
              className={`matching-card ${
                questionIndex === index && !isChoices ? "matching-active" : ""
              }`}
            >
              <MDBCardBody className="m-0 p-3 d-flex align-items-center ">
                {isChecking && isChoices && handleChecking(collection)}
                <span className={isChoices ? "ml-4" : ""}> {baseText}</span>
                {handleButton({ index, isChoose, letter, color })}
              </MDBCardBody>
            </MDBCard>
          </div>
        ) : (
          ""
        );
      })}
    </div>
  );
};

export default Questions;
