import React from "react";
// import deped from "../../../assets/logo/deped.png";
import "./images.css";
import { MDBIcon } from "mdbreact";
// const images = [deped, deped, deped, deped];
const Images = ({ images, setImages, handleUploadImg }) => {
  const handleRemoveImg = (index) => {
    const _images = [...images];
    _images.splice(index, 1);
    setImages(_images);
  };
  return (
    <div className="images">
      <div
        className="add-img"
        onClick={() => document.getElementById("add-img").click()}
      >
        <div className="card-1">
          <MDBIcon icon="plus" />
        </div>
        <div className="card-2"></div>
      </div>
      <input
        type="file"
        accept="image/*"
        className="form-control"
        style={{ display: "none" }}
        onChange={handleUploadImg}
        id="add-img"
      />
      {images.map((img, index) => (
        <div className="img-wrapper" key={index}>
          <img
            src={img}
            alt={`img for -${index}`}
            height={65}
            style={{ objectFit: "contain" }}
            width={70}
            className="mr-2 ml-1"
          />
          <div className="remove-icon" onClick={() => handleRemoveImg(index)}>
            <MDBIcon icon="times" />
          </div>
        </div>
      ))}
    </div>
  );
};

export default Images;
