import React from "react";
import { useHistory } from "react-router";
import { RESET, SETROUTE } from "../../../../../../services/redux/slices/auth";
import { MDBBtn } from "mdbreact";
import { useDispatch } from "react-redux";

const FAILED = ({ proceedToEnrollment }) => (
  <div className="text-center my-5 py-4">
    <h1 className="text-danger display-3 font-weight-bold">
      <span role="img" aria-label="Cross mark">
        ❌
      </span>{" "}
      You Did Not Qualify for ICT
    </h1>
    <h4 className="my-3 text-secondary">
      Unfortunately, you did not pass the entrance exam for the ICT program.
    </h4>
    <h2 className="my-4">
      <strong>But you can still enroll!</strong>
      <br />
      You can join as a regular student, even if you’re not part of the ICT
      track.
    </h2>
    <MDBBtn
      color="primary"
      size="lg"
      className="mt-4 px-5 py-3"
      style={{ fontSize: "1.2rem" }}
      onClick={proceedToEnrollment}
    >
      Click here to proceed to Enrollment Form
    </MDBBtn>
  </div>
);

const PASSED = ({ proceedToEnrollment }) => (
  <div className="text-center my-5 py-4">
    <h1 className="text-success display-3 font-weight-bold">
      <span role="img" aria-label="Party popper">
        🎉
      </span>{" "}
      Congratulations!{" "}
      <span role="img" aria-label="Party popper">
        🎉
      </span>
    </h1>
    <h4 className="my-3 text-secondary">
      You’ve successfully passed the entrance exam!
    </h4>
    <h2 className="my-4">
      <strong>Welcome to the ICT program!</strong>
      <br />
      You're now ready to take the next step in your journey.
    </h2>
    <MDBBtn
      color="primary"
      size="lg"
      onClick={proceedToEnrollment}
      className="mt-4 px-5 py-3"
      style={{ fontSize: "1.2rem" }}
    >
      Click here to proceed to Enrollment Form
    </MDBBtn>
  </div>
);

const CompletedExam = ({ totalScore, passingScore }) => {
  const history = useHistory(),
    dispatch = useDispatch();
  const hasPassed = totalScore >= passingScore;

  const proceedToEnrollment = () => {
    history.push("/dashboard");
    dispatch(SETROUTE("Dashboard"));
    dispatch(RESET());
  };

  return (
    <>
      {hasPassed ? (
        <PASSED proceedToEnrollment={proceedToEnrollment} />
      ) : (
        <FAILED proceedToEnrollment={proceedToEnrollment} />
      )}
    </>
  );
};

export default CompletedExam;
