import { MDBCard, MDBCardBody, MDBCol, MDBRow } from "mdbreact";
import React, { useEffect } from "react";
import "./terms.css";

export default function TermsAndConditions({
  hasAccept = true,
  handleAcctions = () => {},
}) {
  const handleAccept = (e) => {
    e.preventDefault();
    handleAcctions(true, false, 3);
  };

  useEffect(() => {
    window.scrollTo({ top: 0, behavior: "smooth" });
  }, []);

  return (
    <MDBCard style={{ backgroundColor: "#eee" }}>
      {/* <MDBCardHeader className=" border-none"> */}

      {/* </MDBCardHeader> */}
      <MDBCardBody className="p-5">
        <MDBRow className="d-flex flex-column align-items-center justify-center mb-4">
          {/* <div>
                        <img src={logo} alt="" className='img'/>
                    </div> */}
          <div className="pt-4">
            <h3 className="font-bold head-title">
              <b>LEONOR M. BAUTISTA NATIONAL HIGH SCHOOL</b>
            </h3>
          </div>
          <div>
            <h4 className="text-decoration-underline font-bold terms">
              <b>TERMS AND CONDITIONS</b>
            </h4>
          </div>
          <div>
            <h6>For new students, transferees, and cross-enrollees</h6>
          </div>
        </MDBRow>
        <MDBRow>
          <p>
            Welcome to the Leonor M Bautista National High School Online
            Enrollment System. By accessing or using our website, you agree to
            comply with and be bound by these Terms and Conditions.
          </p>
        </MDBRow>
        <MDBRow>
          <p>
            These Terms and Conditions represent a binding agreement between the
            school and the online enrolment applicants. Please read them
            carefully, as it is your responsibility to fully read, understand,
            and agree to all the Terms and Conditions of the School’s online
            enrollment system, before proceeding to the actual online enrollment
            process. These Terms and Conditions, however, may be subject to
            change without further notice.
          </p>
        </MDBRow>
        <MDBRow>
          <MDBCol md="12">
            <h5>
              <b>I. General Policy</b>
            </h5>
          </MDBCol>
        </MDBRow>
        <MDBRow className="ml-4 mr-4">
          <MDBCol md="12">
            <p>
              Your online enrollment is for official reference use only. It is
              still subject to the following terms and conditions:
            </p>
            <ul className="ul">
              <li className="li">Approval by the principal/registrar;</li>
              <li className="li">
                Submission and verification of actual academic credentials;
              </li>
              <li className="li">
                Satisfactory compliance of additional admission requirements;
              </li>
              <li className="li">
                Availability of technical requirements, if you enrolled in
                online subjects or sections;
              </li>
              <li className="li">
                Adherence to school rules and regulations; and
              </li>
              <li className="li">
                Confirmation of the Data Privacy Policy of the School.
              </li>
            </ul>
          </MDBCol>
          <MDBCol md="12">
            <h5>
              <b>1.1 Registrar’s Approval</b>
            </h5>
            <p>
              Your online enrollment is still subject to approval by the
              registrar.
            </p>
          </MDBCol>
          <MDBCol md="12">
            <h5>
              <b>1.2 Academic Credentials</b>
            </h5>
            <p>
              Your online enrollment is still subject to the submission,
              presentation, and verification of the following credentials, which
              may be accomplished not later than 30 days from start of classes:
            </p>
          </MDBCol>
          <MDBCol md="12" className="ml-4 mr-4">
            <ol className="ol">
              <li className="li">
                1.2.1 Competent school identification (ID) card from the school
                last attended;
              </li>
              <li className="li">1.2.2 NSA / PSA Birth Certificate;</li>
              <li className="li">
                1.2.3 Form 138 (for new students) or transfer credentials (for
                transferees);
              </li>
              <li className="li">1.2.4 Certificate of Good Moral Character;</li>
            </ol>
          </MDBCol>
          <MDBCol md="12">
            <p>
              Should you fail to submit any of the above documents within the
              prescribed period or should you submit fraudulent documents, the
              School reserves the right to cancel your enrollment, without
              prejudice to other criminal, civil, or administrative sanctions.
              For qualified DepEd PEAC JHS-ESC/SHS-Voucher recipients, please
              present your certificate by uploading the same on the enrolment
              portal or emailing to the principal/registrar or submitting in
              person but not later than 30 days from start of classes.
            </p>
          </MDBCol>
          <MDBCol md="12">
            <h5>
              <b>1.3 Additional Admission Requirements</b>
            </h5>
            <p>
              As a rule, the School’s policy is open enrollment to all qualified
              applicants. However, there are departments/courses that require
              the conduct of entrance exam, physical/medical exam, and/or
              preliminary interview as prerequisites to the final approval of
              enrollment. Please contact your principal or dean for any
              additional admission requirements, if any, and for the schedule of
              taking or submitting the same once community quarantine protocols
              allow but not later than the end of the semester/academic term.
              This is without prejudice to the option of conducting the same
              through other flexible means, if feasible, while community
              quarantine protocols are in effect.
            </p>
          </MDBCol>
          <MDBCol md="12">
            <p>
              Should you fail to take or to pass the entrance exam,
              physical/medical exam, preliminary interview, and/or other
              additional prerequisite admission requirements as prescribed by
              your department, the School reserves the right to cancel your
              enrollment, without prejudice to other acceptable curricular
              options.
            </p>
          </MDBCol>
        </MDBRow>

        <MDBRow>
          <MDBCol md="12">
            <h5>
              <b>II. Technical Requirements</b>
            </h5>
            <p>
              In case you have taken up online subjects or sections, you will
              need the following technical requirements to succeed:
            </p>
          </MDBCol>
        </MDBRow>
        <MDBRow className="ml-4 mr-4">
          <MDBCol md="12">
            <h5>
              2.1
              <b>Access to Digital Devices</b>
            </h5>
            <p>
              You need access to a laptop, desktop computer, or digital phones
              with reliable internet connection to complete the work assigned in
              the online subjects or sections.
            </p>
          </MDBCol>

          <MDBCol md="12">
            <h5>
              2.2
              <b>Access to Internet Connection</b>
            </h5>
            <p>
              This will be necessary to access email, Google Classroom, and
              other related online tools and applications, as well as
              to download resources, upload assignment files, watch videos, and
              more within your electronic learning courses. 
            </p>
          </MDBCol>
          <MDBCol md="12">
            <h5>
              2.3
              <b>Access to Productivity Softwares and Basic Online Tools</b>
            </h5>
            <p>
              You will need access to productivity softwares like Microsoft
              Office or Open Office applications for accomplishing certain
              assignments and exams. You can also compose assignments using the
              Google Docs available through Google Drive, which is a free
              cloud-based alternative that allows you to access and compose your
              documents from any device with an internet connection. Google
              Classroom and other applications including Zoom, Facebook
              Messenger, Quizlet, Mentimeter applications, and among others
              shall be used in the delivery of important announcements, email
              communication, discussion board postings, homework submissions,
              taking exams and quizzes, and other enhanced course activities.
              You are advised to explore and be familiar with the features of
              these productivity tools and online applications before the first
              day of class.
            </p>
          </MDBCol>
        </MDBRow>

        <MDBRow>
          <MDBCol md="12">
            <h5>
              <b>III. School Rules and Regulations</b>
            </h5>
            <p>
              By accepting these Online Enrolment Terms and Conditions, you also
              agree to fully abide by and comply with the School’s Student
              Manual, guiding principles, policies, rules, and regulations,
              which may be subject to change from time to time.
            </p>
          </MDBCol>
          <MDBCol md="12">
            <p>
              Furthermore, your online enrollment is also subject to the
              condition that you have not been previously penalized for
              expulsion, exclusion, or non-readmission by the School, Commission
              on Higher Education, or Department of Education, as the case may
              be.
            </p>
          </MDBCol>
        </MDBRow>

        <MDBRow>
          <MDBCol md="12">
            <h5>
              <b>IV. Data Privacy Policy</b>
            </h5>
            <p>
              By accepting this Online Enrolment Terms and Conditions, you are
              also giving your consent and approval to the Data Privacy Policy
              of the School. You are hereby authorizing the School to collect,
              record, organize, update, use, consolidate, or destruct your
              personal information for the following purposes:
            </p>
          </MDBCol>
          <MDBCol md="12" className="ml-4 mr-4">
            <ul className="ul">
              <li className="li">
                evaluating applications for admission to the School;
              </li>
              <li className="li">
                establishing and maintaining student information systems;
              </li>
              <li className="li">
                recording, generating, and maintaining student records for
                academic, co-curricular, and extra-curricular monitoring;
              </li>
              <li className="li">
                sharing of grades between and among faculty members and others
                with legitimate official need for academic deliberations and
                evaluation of student performance;
              </li>
              <li className="li">
                processing scholarship applications, grants and other forms of
                financial assistance;
              </li>
              <li className="li">
                investigating incidents that relate to student discipline;
              </li>
              <li className="li">
                compiling and generating reports for statistical and research
                purposes;
              </li>
              <li className="li">providing student services;</li>
              <li className="li">
                communicating official School announcements; and
              </li>
              <li className="li">
                sharing marketing and promotional materials regarding
                School-related functions, events, projects, and activities.
              </li>
            </ul>
          </MDBCol>
          <MDBCol>
            <p>
              You also agree that any personal information may be entered and
              stored within the School’s authorized information and
              communications system equipped with security measures to protect
              your personal information. Your personal information will only be
              accessed and shared by the School, its authorized personnel, and
              other persons or institutions as may be required by law. You agree
              that there must be a free flow of personal information to and from
              the School to ensure the efficient delivery of student services
              and implementation of institutional mechanisms. You affirm your
              rights to be informed, to object to processing, to access and
              rectify, to suspend or withdraw your personal information, and to
              be indemnified for damages pursuant to <b>Republic Act No. 10173 or
              the Data Privacy Act of 2012</b> and its Implementing Rules and
              Regulations.
            </p>
          </MDBCol>
        </MDBRow>

        <MDBRow>
          <MDBCol md="12">
            <h5>
              <b>IV. Acceptance</b>
            </h5>
            <p>
              Your online enrolment requires a confirmation that you have first
              read and understood these Terms and Conditions before proceeding
              to the actual online enrolment process. By clicking on the “I
              ACCEPT” button below, you hereby agree to, consent to, and accept
              in full the School’s Terms and Conditions, in lieu of your
              physical or actual signature.
            </p>
          </MDBCol>
        </MDBRow>
        <MDBRow>
          <MDBCol
            md="12"
            className="d-flex align-items-center justify-content-center"
          >
            {hasAccept && (
              <button
                className="btn bg-primary text-light rounded-sm font-bold"
                type="button"
                onClick={(e) => handleAccept(e)}
              >
                I Accept
              </button>
            )}
          </MDBCol>
        </MDBRow>
      </MDBCardBody>
    </MDBCard>
  );
}
