import React, { useEffect, useState } from "react";
import {
  MDBModal,
  MDBModalBody,
  MDBIcon,
  MDBModalHeader,
  MDBTable,
  MDBBtn,
  MDBModalFooter,
} from "mdbreact";
import { fullName } from "../../../../services/utilities";
import Swal from "sweetalert2";

export default function ViewEnrollees({
  show,
  toggle,
  enrollees,
  isPending = true,
  section = {},
  container = [],
  setContainer = () => {},
}) {
  const [baseEnrollees, setBaseEnrollees] = useState([]);

  useEffect(() => {
    setBaseEnrollees(enrollees);
  }, [enrollees]);

  console.log(enrollees);
  const handleClose = () => {
    toggle();
  };

  const handleRemove = (student, _id) => {
    Swal.fire({
      title: "Are you sure?",
      text: `Do you want to remove ${fullName(
        student?.fullName
      )} from your selected enrollees?`,
      icon: "warning",
      showCancelButton: true,
      confirmButtonText: "Yes",
      cancelButtonText: "No",
      confirmButtonColor: "#d33",
      cancelButtonColor: "#3085d6",
    }).then((result) => {
      if (result.isConfirmed) {
        const _container = [...container];
        const index = _container.findIndex(
          ({ enrolleeId }) => enrolleeId === _id
        );
        _container.splice(index, 1);

        setContainer(_container);
        setBaseEnrollees(_container);

        if (_container.length === 0) {
          toggle();
        }
      }
    });
  };

  return (
    <MDBModal isOpen={show} toggle={toggle} backdrop size="lg">
      <MDBModalHeader
        toggle={handleClose}
        className="light-blue darken-3 white-text"
      >
        <MDBIcon icon="users" className="mr-2" />
        {isPending
          ? "Selected Enrollees"
          : `Enrolled Students in ${section?.name}`}
      </MDBModalHeader>
      <MDBModalBody className="mb-0">
        <MDBTable>
          <thead>
            <tr>
              <th>#</th>
              <th>Student</th>
              {isPending && <th className="text-center">Action</th>}
            </tr>
          </thead>
          <tbody>
            {baseEnrollees.map(({ student, enrolleeId = "" }, index) => (
              <tr key={index}>
                <td> {index + 1} </td>
                <td style={{ fontWeight: "600" }}>
                  {fullName(student.fullName)}
                </td>
                {isPending && (
                  <td className="text-center">
                    <MDBBtn
                      size="sm"
                      rounded
                      color="danger"
                      onClick={() => handleRemove(student, enrolleeId)}
                    >
                      <MDBIcon icon="trash" />
                    </MDBBtn>
                  </td>
                )}
              </tr>
            ))}
          </tbody>
        </MDBTable>
      </MDBModalBody>
      <MDBModalFooter>
        <MDBBtn color="info" className="float-right" onClick={handleClose}>
          close
        </MDBBtn>
      </MDBModalFooter>
    </MDBModal>
  );
}
