import React from "react";
import { MDBCol, MDBInput, MDBRow } from "mdbreact";

import "./learner.css";

const Enrollment = ({ selected }) => {
  return (
    <>
      <MDBRow style={{ backgroundColor: "#0000FF" }}>
        <MDBCol>
          <h5 className="font-weight-bold text-white label mt-2 mb-2 ml-5 section-title">
            V. Enrollment
          </h5>
        </MDBCol>
      </MDBRow>

        {selected.transferee && (
            <>
                <MDBRow className="mr-2 ml-2 mt-2">
                    <MDBCol>
                        <MDBInput
                        label="Transferee"
                        type="checkbox"
                        name="transferee"
                        value="transferee"
                        checked={selected.transferee}
                        id="transferee"
                        readOnly={true}
                        />
                    </MDBCol>
                </MDBRow>
                <MDBRow className="mt-4 mr-4 ml-4">
                    <MDBCol>
                    <h6>Last School Attended</h6>

                    <input
                        placeholder="Last School Attended"
                        className="form-control"
                        value={selected?.lastSchool?.name}
                        name="name"
                        readOnly={true}
                    />
                    </MDBCol>

                    <MDBCol>
                    <h6>Last School Address</h6>

                    <input
                        placeholder="Last School Address"
                        className="form-control"
                        name="address"
                        value={selected?.lastSchool?.address}
                        readOnly={true}
                    />
                    </MDBCol>
                </MDBRow>
            </>
        )}

        <MDBRow className="mt-4 mr-4 ml-4">
        <MDBCol>
            <h6>
            <strong>Level</strong>
            </h6>
            <input
            name="progress"
            value={selected.progress}
            className="form-control"
            readOnly={true}
            />
        </MDBCol>

        <MDBCol>
            <h6>
            <strong>Grade Level</strong>
            </h6>
            <input
            name="lvl"
            value={selected.lvl ? selected.lvl.toString() : "7"}
            className="form-control"
            readOnly={true}
            />
        </MDBCol>
        </MDBRow>

        {selected.progress === "shs" && (
            <MDBRow className="mt-4 mr-4 ml-4">
                <MDBCol>
                <h6>
                    <strong>Specialization</strong>
                </h6>
                <input
                    name="specialization"
                    value={selected.specialization}
                    className="form-control"
                    readOnly={true}
                />
                </MDBCol>

                <MDBCol>
                <h6>
                    <strong>Strand</strong>
                </h6>
                <input
                    name="strand"
                    value={selected.strand}
                    className="form-control"
                    readOnly={true}
                />
                </MDBCol>
            </MDBRow>
        )}
    </>
  );
}

export default Enrollment;
