import React, { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import {
  MDBCard,
  MDBCardBody,
  MDBRow,
  MDBCol,
  MDBCardImage,
  MDBBtn,
  MDBTypography,
} from "mdbreact";
import { BROWSE } from "../../../../services/redux/slices/teacher/schedule";
import Scheduler from "../../../../widgets/schedule";
import logo from "../../../../assets/logo/lmbnhs logo.png";
import deped from "../../../../assets/logo/deped.png";
import matatag from "../../../../assets/logo/matatag.png";
import jsPDF from "jspdf";
import html2canvas from "html2canvas";

export default function Dashboard() {
  const { token, auth, information } = useSelector(({ auth }) => auth),
    { collections } = useSelector(({ schedule }) => schedule),
    [schedules, setSchedules] = useState([]),
    dispatch = useDispatch();

  useEffect(() => {
    dispatch(BROWSE({ token, data: { id: auth._id } }));
  }, [token, auth, dispatch]);

  useEffect(() => {
    const isShsSchedule = collections.some(({ lvl }) => lvl > 10);
    if (isShsSchedule) {
      const batchesActive = information.previousBatches.find(
        ({ status, progress }) =>
          (status === "ACTIVE" || status === "INACTIVE") && progress === "shs"
      );

      if (batchesActive) {
        const activeSem = batchesActive.semester;
        const isShedule2ndSem = collections.some(
          ({ semester }) => semester === "2nd"
        );
        const isShedule1stSem = collections.some(
          ({ semester }) => semester === "1st"
        );
        var _schedules = [];
        if (isShedule1stSem && isShedule2ndSem) {
          _schedules = collections.filter(
            ({ semester }) => semester === "" || semester === activeSem
          );
        }
        if (!isShedule2ndSem && isShedule1stSem) {
          _schedules = collections.filter(
            ({ semester }) => semester === "" || semester === "1st"
          );
        }
        if (isShedule2ndSem && !isShedule1stSem) {
          _schedules = collections.filter(
            ({ semester }) => semester === "" || semester === "2nd"
          );
        }
        setSchedules(_schedules);
      } else {
        _schedules = collections.filter(({ lvl }) => lvl <= 10);
        setSchedules(_schedules);
      }
    } else {
      setSchedules(collections);
    }
  }, [collections, information.previousBatches]);

  const generatePDF = () => {
    const input = document.getElementById("pdf-content");

    html2canvas(input, {
      scale: 2, // Optional: Adjust scale for better resolution
    }).then((canvas) => {
      const imgData = canvas.toDataURL("image/png");
      const pdf = new jsPDF();

      // Define the PDF width and height (A4 size dimensions in mm)
      const pdfWidth = 210;
      const pdfHeight = (canvas.height * pdfWidth) / canvas.width; // Keep the aspect ratio

      const margin = 10; // Margin in mm

      pdf.addImage(
        imgData,
        "JPG",
        margin, // X-coordinate for left margin
        margin, // Y-coordinate for top margin
        pdfWidth - 2 * margin, // Adjusted width to account for margins
        pdfHeight - 2 * margin // Adjusted height to account for margins
      );
      pdf.save("schedule.pdf");
    });
  };

  return (
    <MDBCard>
      {schedules.length > 0 ? (
        <MDBCardBody>
          <div id="pdf-content">
            <MDBRow>
              <MDBCol className="d-flex justify-content-end">
                <MDBCardImage src={logo} style={{ height: "100px" }} />
              </MDBCol>
              <MDBCol className="text-center" md="4">
                <h5 className="m-0" style={{ fontFamily: "Times New Roman" }}>
                  Republic of the Philippines
                </h5>
                <h4 className="m-0" style={{ fontFamily: "Sans" }}>
                  Department of Education
                </h4>
                <h4
                  className="font-weight-bold mt-0 m-0"
                  style={{ fontFamily: "Open Sans" }}
                >
                  Leonor M. Bautista National High School
                </h4>
              </MDBCol>
              <MDBCol className="d-flex flex-row">
                <MDBCardImage src={deped} style={{ height: "100px" }} />
                <MDBCardImage src={matatag} style={{ height: "110px" }} />
              </MDBCol>
            </MDBRow>
            <MDBRow>
              <MDBCol>
                <h5 className="text-center mt-0 ">Teacher Schedule</h5>
                <h6 className="text-center">
                  <i>
                    <strong>Academic Year 2024-2025</strong>
                  </i>
                </h6>
              </MDBCol>
            </MDBRow>
            <Scheduler array={schedules} isTeacher={true} />
          </div>
          <MDBRow>
            <MDBCol className="text-center mt-3">
              <MDBBtn color="primary" onClick={generatePDF}>
                Download as PDF
              </MDBBtn>
            </MDBCol>
          </MDBRow>
        </MDBCardBody>
      ) : (
        <MDBTypography
          className="mb-0 text-black-100"
          noteColor="warning"
          note
          noteTitle="No Schedule Assigned: "
        >
          Your schedule has not been created by the registrar yet. Please wait
          while it is being processed. Thank you for your patience.
        </MDBTypography>
      )}
    </MDBCard>
  );
}
