import React, { useEffect, useState } from "react";
import Convo from "../../../../widgets/convo";
import {
  BROWSE,
  UPDATE,
  UPDATE_SHOWPROFILE,
} from "../../../../services/redux/slices/messages";
import { useDispatch, useSelector } from "react-redux";
import { acMessages, socket } from "../../../../services/utilities";
const Chat = () => {
  const { auth, token, role } = useSelector(({ auth }) => auth),
    { collections } = useSelector(({ messages }) => messages),
    [messages, setMessages] = useState([]),
    [height, setHeight] = useState(window.innerHeight),
    [isVisible, setIsVisible] = useState(true),
    [isTyping, setIsTyping] = useState(false),
    [width, setWidth] = useState(window.innerWidth),
    dispatch = useDispatch();

  const requirmentsForSeen = {
    token,
    dispatch,
    UPDATE,
    student: auth,
    messages: [],
  };

  useEffect(() => {
    acMessages.visibleChecker(setIsVisible);
  }, []);

  useEffect(() => {
    acMessages.resizeHeight(setHeight, setWidth);
  }, []);

  useEffect(() => {
    setHeight(window.innerHeight - 120);
    setWidth(acMessages.calculateWidth(window.innerWidth));
  }, []);

  useEffect(() => {
    if (auth._id) {
      dispatch(BROWSE({ token, key: { _id: auth._id, role: role.name } }));
    }
  }, [dispatch, token, auth, role]);

  useEffect(() => {
    if (isVisible) {
      const notSeenMessages = acMessages.notSeen(messages, auth);

      if (notSeenMessages.length > 0) {
        acMessages.seen({ ...requirmentsForSeen, messages: notSeenMessages });
      }
    }
  }, [isVisible, requirmentsForSeen, messages, auth]);

  useEffect(() => {
    const _collections = [...collections];
    const notSeenMessages = acMessages.notSeen(_collections, auth);
    if (notSeenMessages.length > 0) {
      for (const msg of notSeenMessages) {
        const index = _collections.findIndex(({ _id }) => _id === msg._id);
        _collections[index] = { ..._collections[index], isSeen: true };
      }
      dispatch(
        UPDATE({
          token,
          data: { student: auth, messages: notSeenMessages },
        })
      );
    }
    setMessages(_collections);
  }, [collections, dispatch, token, auth]);

  useEffect(() => {
    socket.on("receive_seenMessages", (data) => {
      if (data?.student?._id === auth._id) {
        const { messages: seenMessages } = data;
        const _messages = [...messages];

        for (const msg of seenMessages) {
          const index = _messages.findIndex(({ _id }) => _id === msg._id);
          _messages[index] = { ..._messages[index], isSeen: true };
        }
        setMessages(_messages);
      }
    });

    return () => {
      socket.off("receive_seenMessages");
    };
  }, [messages, auth]);

  useEffect(() => {
    socket.on("receive_message", (data) => {
      const { receiver, sender } = data;
      if (receiver._id === auth._id || sender._id === auth._id) {
        const isSeen = receiver._id === auth._id && isVisible;
        const _messages = [...messages];

        if (sender._id === auth._id) {
          //receiver dati
          acMessages.profileChecker({
            ...requirmentsForSeen,
            UPDATE: UPDATE_SHOWPROFILE,
            messages: _messages,
          });
        }
        _messages.push({ ...data, isSeen });

        setMessages(_messages);
        if (isSeen && isVisible) {
          acMessages.seen({
            ...requirmentsForSeen,
            messages: data,
          });
        }
      }
    });

    return () => {
      socket.off("receive_message");
    };
  }, [messages, auth, isVisible, dispatch, requirmentsForSeen]);

  useEffect(() => {
    socket.on("receive_updateOldMsg", (data) => {
      if (!data.student) return false;
      const { message } = data;
      if (message.receiver._id === auth._id) {
        const _messages = [...messages];
        const index = _messages.findIndex(({ _id }) => _id === message._id);
        _messages[index] = message;
        setMessages(_messages);
      }
    });
    return () => {
      socket.off("receive_updateOldMsg");
    };
  }, [messages, auth]);

  useEffect(() => {
    socket.on("receive_isTyping", (data) => {
      const { typingID = "", isTyping: _isTyping } = data;
      if (typingID === auth._id) {
        setIsTyping(_isTyping);
      } else {
        setIsTyping(false);
      }
    });
    return () => {
      socket.off("receive_isTyping");
    };
  }, [auth]);

  return (
    <Convo
      height={height}
      receiver={"66aa902a495963b36ff59e7e"}
      baseMessages={messages}
      isTyping={isTyping}
      setIsTyping={setIsTyping}
      typingID={auth._id}
      width={width + 350}
      activeStudent={"Cheyenne Dela cruz"}
    />
  );
};

export default Chat;
