import React from "react";

import { MDBAnimation, MDBIcon } from "mdbreact";
import dateConverter from "../dateConverter";

const Message = ({
  messageByYou,
  message,
  bounceMessage,
  setSelectedMsg,
  setIsReplied,
  messageRef,
  index,
  timeIndex,
  setTimeIndex,
  setToggleImgView,
  setImgView
}) => {
  const hasBounce = bounceMessage === message?._id;
  const isImage = message.isImage ? true : false;
  const handleReplied = () => {
    messageRef.current.focus();
    setSelectedMsg(message);
    setIsReplied(true);
  };

  return (
    <div className="d-flex align-items-center position-relative">
      {(timeIndex !== index && messageByYou) && (
        <MDBIcon
          icon="reply"
          className="reply-chat-icon mr-2"
          onClick={handleReplied}
        />
      )}
      <MDBAnimation
        type={hasBounce ? "pulse" : ""}
        className={`animation `}
        key={hasBounce ? bounceMessage : ""}
      >
        <div className={`d-flex  ${messageByYou ? "yourMsg flex-row-reverse " : "receiverMsg flex-row"} align-items-center`}>

          {!isImage ? (
            <p
              className={`${
                messageByYou
                  ? "primary-color  text-white"
                  : "grey lighten-3  text-dark"
              } rounded chat-row message-highlight ${
                hasBounce ? `highlight` : ""
              }  baseMsg  `}
              style={{ textAlign: "start" }}
              onMouseEnter={() => setTimeIndex(index)}
              onMouseLeave={() => setTimeIndex(-1)}
            >
              {message.text}
            </p>
          ) : (
            <div
              className={`d-flex flex-wrap message-highlight ${
                hasBounce ? `highlight` : ""
              }`}
              onMouseEnter={() => setTimeIndex(index)}
              onMouseLeave={() => setTimeIndex(-1)}
              style={{ maxWidth: "310px", borderRadius: "10px" }}
            >
              {message.images.map((img, i) => (
                <img
                  key={i}
                  src={img}
                  alt={message._id}
                  height={80}
                  width={100}
                  style={{ borderRadius: "10px", objectFit: "contain" }}
                  onClick={() => {
                    setToggleImgView(true)
                    setImgView(img)
                  }}
                />
              ))}
            </div>
          )}

          {timeIndex === index && (
            <div className={messageByYou ? "time-right" : "time-left"}>
              {dateConverter(message.createdAt)}
            </div>
          )}
          
        </div>
      </MDBAnimation>
      
      {(timeIndex !== index && !messageByYou) && (
        <MDBIcon
          icon="reply"
          className="reply-chat-icon ml-2"
          onClick={handleReplied}
        />
      )}
    </div>
  );
};

export default Message;
