import React, { useState, useEffect } from "react";
import {
  MDBSideNavLink,
  MDBSideNavCat,
  MDBSideNavNav,
  MDBSideNav,
  MDBIcon,
} from "mdbreact";

import ACCESS from "../../pages/platforms/access";
import logo from "../../assets/logo/lmbnhs logo.png";

import { useDispatch, useSelector } from "react-redux";
import { SETROUTE } from "../../services/redux/slices/auth";

import "./styles.css";
import Advisory from "../../pages/platforms/teacher/advisory";
import Enrollees from "../../pages/platforms/registrar/enrollees";
import EntranceExam from "../../pages/platforms/student/entranceExam";
import Participants from "../../pages/platforms/registrar/entranceExam/participants";
import EntranceExamV2 from "../../pages/platforms/registrar/entranceExam/exam";
import QuestionBank from "../../pages/platforms/registrar/questionBank";

export default function SideNavigation({
  triggerOpening,
  breakWidth,
  onLinkClick,
}) {
  const [links, setLinks] = useState([]),
    { role, information = {} } = useSelector(({ auth }) => auth),
    dispatch = useDispatch();

  useEffect(() => {
    if (role.name) {
      var _links = ACCESS[role.name];

      if (role.name === "STUDENT") {
        if (information.isFreshman === true) {
          _links.push({
            name: "Entrance Exam",
            path: "/entranceExam",
            icon: "dungeon",
            component: EntranceExam,
          });
        } else {
          const _copyOfLinks = [..._links];
          const index = _copyOfLinks.findIndex(
            ({ name }) => name === "Entrance Exam"
          );
          if (index > -1) {
            _copyOfLinks.splice(index, 1);
            _links = _copyOfLinks;
          }
        }
      }
      if (information.isAdvisory) {
        _links.push({
          name: "Advisory",
          path: "/advisory",
          icon: "users",
          component: Advisory,
        });
      }

      if (information.haveEnrollmentAccess) {
        _links.push(
          {
            name: "Enrollees",
            path: "/enrollees",
            icon: "users-cog",
            children: [
              {
                name: "Pending",
                path: "/pending",
                component: Enrollees,
                props: "PENDING",
              },
              {
                name: "Approved",
                path: "/approved",
                props: "APPROVED",
                component: Enrollees,
              },

              {
                name: "Rejected",
                path: "/rejected",
                props: "REJECT",
                component: Enrollees,
              },
            ],
          },
          {
            name: "Entrance Exam",
            path: "/entranceExam",
            icon: "dungeon",
            children: [
              {
                name: "Participants",
                path: "/participants",
                component: Participants,
              },
              {
                name: "Exam",
                path: "/exam",
                component: EntranceExamV2,
              },
            ],
          },
          {
            name: "Question Bank",
            path: "/questions",
            icon: "university",
            component: QuestionBank,
          }
        );
      }
      setLinks(_links);
    }
  }, [role, information]);

  const handleLinks = () => {
    if (links.length === 0)
      return (
        <MDBSideNavLink to="/" topLevel onClick={onLinkClick}>
          <MDBIcon icon="home mr-2" />
          Home
        </MDBSideNavLink>
      );

    return links.map(({ path, name, icon, children }, index) => {
      if (children)
        return (
          <MDBSideNavCat
            id={`${name}-cat`}
            name={name}
            key={`sidebar-${index}`}
            icon={icon}
          >
            {children.map((child, cIndex) => (
              <div key={`sidebar-${index}-${cIndex}`}>
                <MDBSideNavLink
                  to={`${path}${child.path}`}
                  onClick={() => {
                    onLinkClick();
                    dispatch(SETROUTE(child.name));
                  }}
                >
                  {child.name}
                </MDBSideNavLink>
              </div>
            ))}
          </MDBSideNavCat>
        );

      return (
        <MDBSideNavLink
          key={`sidebar-${index}`}
          to={path}
          topLevel
          onClick={() => {
            onLinkClick();
            dispatch(SETROUTE(name));
          }}
        >
          <MDBIcon icon={`${icon} mr-2`} />
          {name}
        </MDBSideNavLink>
      );
    });
  };

  return (
    <div>
      <MDBSideNav
        logo={logo}
        className="blue-gradient"
        // bg="https://mdbootstrap.com/img/Photos/Others/sidenav2.jpg"
        href="/dashboard"
        fixed
        breakWidth={breakWidth}
        triggerOpening={triggerOpening}
        style={{ transition: "padding-left .3s", backgroundColor: "red" }}
      >
        <MDBSideNavNav>{handleLinks()}</MDBSideNavNav>
      </MDBSideNav>
    </div>
  );
}
