import React, { useCallback, useEffect, useState } from "react";
import {
  MDBAvatar,
  MDBCard,
  MDBCardBody,
  MDBCardFooter,
  MDBCol,
  MDBRow,
} from "mdbreact";
import "./agent.css";
import {
  acMessages,
  fullName,
  socket,
  truncateString,
} from "../../../services/utilities";
import Convo from "../../../widgets/convo";
import { useDispatch, useSelector } from "react-redux";
import {
  BROWSE,
  UPDATE,
  UPDATE_SHOWPROFILE,
} from "../../../services/redux/slices/messages";
import ElapsedTime from "../../../widgets/ellapsedTime";
import SidebarLoading from "../../../widgets/sidebarLoading";

const Messages = () => {
  const { token, auth, role } = useSelector(({ auth }) => auth),
    { collections, isLoading = false } = useSelector(
      ({ messages }) => messages
    ),
    [students, setStudents] = useState([]),
    [messages, setMessages] = useState([]),
    [activeMsg, setActiveMsg] = useState({}),
    [isVisible, setIsVisible] = useState(true),
    [isTyping, setIsTyping] = useState(false),
    [height, setHeight] = useState(window.innerHeight),
    [width, setWidth] = useState(window.innerWidth),
    dispatch = useDispatch();

  const requirmentsForSeen = {
    token,
    dispatch,
    UPDATE,
    student: auth,
    messages: [],
  };

  useEffect(() => {
    acMessages.visibleChecker(setIsVisible);
  }, []);

  useEffect(() => {
    acMessages.removeParentScrollY();
  }, []);

  useEffect(() => {
    acMessages.resizeHeight(setHeight, setWidth);
  }, []);

  useEffect(() => {
    setHeight(window.innerHeight - 120);
    setWidth(acMessages.calculateWidth(window.innerWidth));
  }, []);

  useEffect(() => {
    if (isVisible && activeMsg?.student?._id) {
      const notSeenMessages = acMessages.notSeen(messages, auth);
      if (notSeenMessages.length > 0) {
        const { student } = activeMsg;
        acMessages.seen({
          ...requirmentsForSeen,
          student,
          messages: notSeenMessages,
        });
      }
    }
  }, [isVisible, activeMsg, messages, auth, requirmentsForSeen]);

  useEffect(() => {
    if (auth._id) {
      dispatch(BROWSE({ token, key: { _id: auth._id, role: role.name } }));
    }
  }, [dispatch, token, auth, role]);

  useEffect(() => {
    setStudents(collections);
  }, [collections]);

  useEffect(() => {
    if (activeMsg?.student?._id) {
      const _messages = [...activeMsg.messages];
      const notSeenMessages = acMessages.notSeen(_messages, auth);

      if (notSeenMessages.length > 0) {
        dispatch(
          UPDATE({
            token,
            data: { student: activeMsg.student, messages: notSeenMessages },
          })
        );
      }
      const messagesChecker = _messages.map((msg) => {
        const { receiver } = msg;
        if (receiver._id === auth._id) {
          return { ...msg, isSeen: true };
        } else {
          return msg;
        }
      });

      setMessages(messagesChecker);
      setIsTyping(false);
    }
    return () => false;
  }, [activeMsg, dispatch, token, auth]);

  useEffect(() => {
    socket.on("receive_seenMessages", (data) => {
      if (data?.student?._id) {
        const { student, messages: seenMessages } = data;
        const _students = [...students];
        const indexOfStudent = _students.findIndex(
          ({ student: stud }) => stud._id === student._id
        );
        if (indexOfStudent > -1) {
          const _messages = [..._students[indexOfStudent]?.messages];

          for (const msg of seenMessages) {
            const index = _messages.findIndex(({ _id }) => _id === msg._id);
            _messages[index] = { ..._messages[index], isSeen: true };
          }

          _students[indexOfStudent] = {
            ..._students[indexOfStudent],
            messages: _messages,
          };
          if (activeMsg?.student?._id === data?.student?._id) {
            setMessages(_messages);
          }
          setStudents(_students);
        } else {
          console.log("Student Not found for this ID:", student._id);
        }
      }
    });

    return () => {
      socket.off("receive_seenMessages");
    };
  }, [students, activeMsg]);

  const unshiftNewStdMsg = useCallback((_students = []) => {
    const copyOfStudents = [..._students];

    const sortedStudents = copyOfStudents.sort(
      (a, b) => new Date(b.createdAt) - new Date(a.createdAt)
    );
    setStudents(sortedStudents);
  }, []);

  useEffect(() => {
    socket.on("receive_message", (data) => {
      const { receiver, sender } = data;
      if (receiver._id === auth._id || sender._id === auth._id) {
        const _students = [...students];
        const handleUpdateStudents = (newStudent, isReceiver) => {
          const indexOfStudent = _students.findIndex(
            ({ student }) => student._id === newStudent._id
          );

          if (indexOfStudent > -1) {
            const selectedStudent = { ..._students[indexOfStudent].student };

            const hasActive = activeMsg?.student?._id === newStudent?._id;
            const _messages = [..._students[indexOfStudent].messages];

            if (!isReceiver) {
              // isReceiver dati
              acMessages.profileChecker({
                ...requirmentsForSeen,
                UPDATE: UPDATE_SHOWPROFILE,
                messages: _messages,
                student: { ...selectedStudent },
                isAgent: true,
              });
            }
            _messages.push({
              ...data,
              isSeen: hasActive && isReceiver && isVisible,
            });

            _students[indexOfStudent] = {
              ..._students[indexOfStudent],
              messages: _messages,
              createdAt: data.createdAt,
            };
            if (hasActive) {
              if (isReceiver && isVisible) {
                acMessages.seen({
                  ...requirmentsForSeen,
                  student: activeMsg.student,
                  messages: data,
                });
              }
              setMessages(_messages);
            }
          } else {
            _students.push({
              student: sender,
              messages: [data],
              createdAt: data.createdAt,
            });
          }
          unshiftNewStdMsg(_students);
        };
        if (receiver._id === auth._id) {
          handleUpdateStudents(sender, true);
        }
        if (sender._id === auth._id) {
          handleUpdateStudents(receiver, false);
        }
      }
    });

    return () => {
      socket.off("receive_message");
    };
  }, [
    students,
    auth,
    activeMsg,
    isVisible,
    requirmentsForSeen,
    unshiftNewStdMsg,
  ]);

  const handleGetLatestMessage = (messages) => {
    const _messages = [...messages];
    const sortedMessages = _messages.sort(
      (a, b) => new Date(b.createdAt) - new Date(a.createdAt)
    );
    return sortedMessages[0] || {};
  };

  useEffect(() => {
    socket.on("receive_updateOldMsg", (data) => {
      if (!data.student) return false;
      const { student, message } = data;
      const _students = [...students];
      const indexOfStudent = _students.findIndex(
        ({ student: stud }) => stud._id === student._id
      );
      if (indexOfStudent <= -1) return false;
      if (message.receiver._id !== auth._id) return false;
      const studentMessages = [..._students[indexOfStudent].messages];
      const indexOfMessage = studentMessages.findIndex(
        ({ _id }) => _id === message._id
      );
      studentMessages[indexOfMessage] = { ...message };

      _students[indexOfStudent] = {
        ..._students[indexOfStudent],
        messages: studentMessages,
      };

      if (student._id === activeMsg?.student?._id) {
        setMessages(studentMessages);
      }
      setStudents(_students);
    });
    return () => {
      socket.off("receive_updateOldMsg");
    };
  }, [messages, auth, activeMsg, students]);

  useEffect(() => {
    socket.on("receive_isTyping", (receiver) => {
      const { typingID, isTyping: _isTyping } = receiver;
      if (typingID === activeMsg.student?._id) {
        setIsTyping(_isTyping);
      } else {
        setIsTyping(false);
      }
    });
    return () => {
      socket.off("receive_isTyping");
    };
  }, [activeMsg]);

  return (
    <MDBRow>
      <MDBCol md="4" className="m-0 p-0">
        <MDBCard
          className="sidebar-message agent-card"
          style={{ height: height }}
        >
          <MDBCardBody className="m-1 p-1">
            <h5 className="font-weight-bold">Chats</h5>
            <input
              className="form-control agent-search"
              placeholder="Search Student"
            />
            {!isLoading ? (
              students.map((message, index) => {
                const latestMessage = handleGetLatestMessage(message?.messages);
                const { isSeen = false, receiver = {} } = latestMessage;
                const isSender = latestMessage?.sender?._id === auth._id;
                const isReceiver = receiver._id === auth._id;
                const { sender, isImage = false, text } = latestMessage;

                return (
                  <div
                    key={index}
                    onClick={() => setActiveMsg(message)}
                    className={`d-flex align-items-center ${
                      index === 0 ? "mt-2 " : ""
                    } ${
                      message?.student?._id === activeMsg?.student?._id
                        ? "student-active-row"
                        : ""
                    }  student-row`}
                  >
                    <div>
                      <MDBAvatar
                        src="https://mdbootstrap.com/img/Photos/Avatars/adach.jpg"
                        alt="User mugshot"
                        tag="img"
                        style={{ height: "35px", width: "35px" }}
                        circle
                        className="float-left mr-2 avatar "
                      />
                    </div>
                    <div key={index}>
                      <div className="d-flex flex-column">
                        <span className="student-name">
                          {fullName(message?.student.fullName)}
                        </span>
                        <div className="d-flex align-items-center">
                          <span className={`student-message `}>
                            {isSender ? "You: " : ""}
                            {!isSeen && isReceiver ? (
                              <b>
                                {truncateString(
                                  isImage
                                    ? `${sender?.fullName?.fname} sent a photo.`
                                    : text,
                                  40
                                )}
                              </b>
                            ) : (
                              truncateString(
                                isImage
                                  ? `${
                                      isSender ? "" : sender?.fullName.fname
                                    } sent a photo.`
                                  : text,
                                40
                              )
                            )}
                            &nbsp;&#8226;
                            <ElapsedTime
                              createdAt={latestMessage.createdAt}
                              isConvo={false}
                            />
                          </span>
                          {/* <span className="sidebar-time"></span> */}
                        </div>
                      </div>
                    </div>
                  </div>
                );
              })
            ) : (
              <SidebarLoading />
            )}
          </MDBCardBody>
          <MDBCardFooter transparent></MDBCardFooter>
        </MDBCard>
      </MDBCol>
      <MDBCol>
        <Convo
          activeStudent={fullName(activeMsg.student?.fullName)}
          height={height}
          baseMessages={messages}
          receiver={activeMsg?.student?._id}
          isTyping={isTyping}
          setIsTyping={setIsTyping}
          typingID={activeMsg?.student?._id || ""}
          width={width}
        />
      </MDBCol>
    </MDBRow>
  );
};

export default Messages;
