import React, { useEffect, useState } from "react";
import {
  MDBBtn,
  MDBCol,
  MDBIcon,
  MDBInput,
  MDBRow,
  MDBTypography,
} from "mdbreact";
import "./type.css";

const MatchingType = ({
  choices,
  setChoices,
  confusingChoices,
  setConfusingChoices,
  form,
  setForm = () => {},
}) => {
  const [maxConfusing, setMaxConfusing] = useState(1),
    maxItem = 8;

  useEffect(() => {
    const max = Math.floor(choices.length / 2);
    if (confusingChoices.length > max) {
      const _confusing = [...confusingChoices];
      _confusing.splice(_confusing.length - 1, 1);
      setConfusingChoices(_confusing);
    }
    setMaxConfusing(max);
  }, [choices, confusingChoices, setConfusingChoices]);

  const handleGetChoicesOrConfusing = (isConfusing) => {
    return {
      array: isConfusing ? [...confusingChoices] : [...choices],
      setArray: isConfusing ? setConfusingChoices : setChoices,
    };
  };

  const handleAdd = (isConfusing) => {
    const { array, setArray } = handleGetChoicesOrConfusing(isConfusing);
    array.push({ textA: "", textB: "", isConfusing });
    setArray(array);
  };

  const handleChange = ({ index, column, value, isConfusing = false }) => {
    const { array, setArray } = handleGetChoicesOrConfusing(isConfusing);
    array[index] = { ...array[index], [`text${column}`]: value };
    setArray(array);
  };

  const handleRemove = (index, isConfusing = false) => {
    const { array, setArray } = handleGetChoicesOrConfusing(isConfusing);
    array.splice(index, 1);
    setArray(array);
  };

  return (
    <>
      <MDBTypography
        noteTitle="Instruction: "
        variant="h2"
        className="mb-0 text-black-100"
        noteColor="warning"
        note
      >
        For each number in Column A, the correct answer must be placed in the
        corresponding row of Column B.
      </MDBTypography>
      <MDBRow style={{ marginBottom: "-20px" }}>
        <MDBCol className="d-flex justify-content-center">
          <MDBInput
            label="Title for Column A"
            labelClass="custom-label"
            className="w-100 text-center font-weight-bold "
            value={form.titleA || "Column A"}
            onChange={({ target }) =>
              setForm({ ...form, titleA: target.value })
            }
          />
        </MDBCol>
        <MDBCol className="d-flex justify-content-center">
          <MDBInput
            label="Title for Column B"
            labelClass="custom-label"
            className="w-100 text-center font-weight-bold"
            value={form.titleB || "Column B"}
            onChange={({ target }) =>
              setForm({ ...form, titleB: target.value })
            }
          />
        </MDBCol>
      </MDBRow>

      {choices
        .filter(({ isConfusing }) => !isConfusing)
        .map((choice, index) => {
          const showDeleteBtn =
            [...choices.filter(({ isConfusing = false }) => !isConfusing)]
              .length > 4;
          return (
            <MDBRow key={`item-${index}`} className="mt-2">
              <MDBCol className="d-flex align-items-center">
                <span className="font-weight-bold mr-2">{index + 1}.</span>
                <input
                  className="form-control"
                  value={choice.textA}
                  required
                  placeholder="Type Here..."
                  onChange={({ target }) =>
                    handleChange({ index, column: "A", value: target.value })
                  }
                />
              </MDBCol>
              <MDBCol className="d-flex align-items-center">
                <input
                  className="form-control"
                  value={choice.textB}
                  placeholder="Type Here..."
                  required
                  onChange={({ target }) =>
                    handleChange({ index, column: "B", value: target.value })
                  }
                />
                {showDeleteBtn && (
                  <MDBBtn
                    color="danger"
                    rounded
                    type="button"
                    size="sm"
                    onClick={() => handleRemove(index)}
                  >
                    <MDBIcon icon="trash" />
                  </MDBBtn>
                )}
              </MDBCol>
            </MDBRow>
          );
        })}
      <MDBBtn
        size="sm"
        className="ml-4 mt-3"
        type="button"
        color="success"
        disabled={choices.length === maxItem}
        onClick={() => handleAdd(false)}
      >
        <MDBIcon icon="plus" className="mr-2" />
        {choices.length === maxItem ? "Item Limit Reached" : "ADD ITEM"}
      </MDBBtn>
      {confusingChoices.length > 0 && (
        <MDBRow className="d-flex justify-content-end mt-2">
          <MDBCol md="6" className="text-center">
            <span className="font-weight-bold ">Confusing choices</span>
          </MDBCol>
        </MDBRow>
      )}

      {confusingChoices.length > 0 &&
        confusingChoices.map((confusing, index) => {
          return (
            <MDBRow
              className="d-flex justify-content-end mt-2"
              key={`confusing-${index}`}
            >
              <MDBCol md="6" className="text-center d-flex align-items-center">
                <span className="font-weight-bold mr-2">{index + 1}.</span>
                <input
                  required
                  className="form-control"
                  value={confusing.textB}
                  placeholder="Type Here..."
                  onChange={({ target }) =>
                    handleChange({
                      index,
                      column: "B",
                      value: target.value,
                      isConfusing: true,
                    })
                  }
                />
                <MDBBtn
                  color="danger"
                  rounded
                  type="button"
                  size="sm"
                  onClick={() => handleRemove(index, true)}
                >
                  <MDBIcon icon="trash" />
                </MDBBtn>
              </MDBCol>
            </MDBRow>
          );
        })}
      <div className="d-flex justify-content-end mt-1 mb-2">
        <MDBBtn
          size="sm"
          type="button"
          color="info"
          onClick={() => handleAdd(true)}
          disabled={confusingChoices.length === maxConfusing}
        >
          <MDBIcon icon="plus" className="mr-2" />{" "}
          {confusingChoices.length === maxConfusing
            ? "Confusing Limit reached"
            : "ADD CONFUSING CHOICE"}
        </MDBBtn>
      </div>
    </>
  );
};

export default MatchingType;
