import React, { useState } from "react";
import { MDBRow, MDBCol, MDBInput, MDBIcon } from "mdbreact";
import PasswordInput from "../../../../../components/passwordInput";

const AccountInformation = ({
  form,
  handleChange,
  defaultDisplayInWarning,
}) => {
  const [isLockedPassword, setIsLockedPassword] = useState(true),
    [isLockedCpassword, setIsLockedCpassword] = useState(true),
    [passwordStatus, setPasswordStatus] = useState("");

  return (
    <>
      <h6 className="font-weight-bold ml-1">Account Information:</h6>
      <MDBRow>
        <MDBCol className="border border-black p-3 m-2">
          <MDBInput
            type="email"
            label="Email"
            icon="envelope"
            value={form.email}
            required
            onChange={({ target }) => handleChange("email", target.value)}
          />

          <PasswordInput
            password={form.password}
            setPassword={(value) => handleChange("password", value)}
            hasIcon={true}
            label={"Password"}
            isLocked={isLockedPassword}
            passwordStatus={passwordStatus}
            setPasswordStatus={setPasswordStatus}
            setIsLocked={setIsLockedPassword}
          />

          <MDBInput
            type={isLockedCpassword ? "password" : "text"}
            icon={isLockedCpassword ? "lock" : "unlock"}
            value={form.confirmPassword}
            onChange={({ target }) =>
              handleChange("confirmPassword", target.value)
            }
            label="Confirm password"
            style={{ position: "relative" }}
          >
            <button
              className="isLock-eye"
              type="button"
              onClick={() => setIsLockedCpassword(!isLockedCpassword)}
            >
              <MDBIcon icon={isLockedCpassword ? "eye-slash" : "eye"} />
            </button>
          </MDBInput>

          <h6 className="text-danger m-0 p-0" id="warningMessage">
            {defaultDisplayInWarning}
          </h6>
        </MDBCol>
      </MDBRow>
    </>
  );
};

export default AccountInformation;
