import React from "react";

const Lines = ({ lines = [], containerPos = {} }) => {
  return (
    <svg
      className="line-svg"
      viewBox={`0 0 ${containerPos?.width || 0} ${containerPos?.height || 0}`}
      style={{ position: "absolute", left: "0", top: "0" }}
    >
      {!!lines &&
        lines.map(({ x1 = 0, y1 = 0, x2 = 0, y2 = 0 }, index) => (
          <line
            key={index}
            x1={x1}
            y1={y1}
            x2={x2}
            y2={y2}
            strokeWidth="2"
            stroke="black"
          />
        ))}
      <line></line>
    </svg>
  );
};

export default Lines;
