import React, { useCallback, useEffect, useState } from "react";
import {
  MDBBtn,
  MDBModal,
  MDBModalBody,
  MDBIcon,
  MDBModalHeader,
  MDBRow,
  MDBCol,
  MDBModalFooter,
  MDBSwitch,
} from "mdbreact";
import { v4 as uuidv4 } from "uuid";
import { useToasts } from "react-toast-notifications";
import { useDispatch, useSelector } from "react-redux";
import {
  SAVE,
  UPDATE,
  SECTIONSANDSUBJECTS,
  INSTRUCTORS,
} from "../../../../services/redux/slices/registrar/schedulers";
import { isEqual } from "lodash";
import { colors } from "../../../../services/fakeDb";
import { fullName } from "../../../../services/utilities";
import SelectLevel from "../../.././../components/SelectLevel";
import Scheduler from "../../../../widgets/schedule";
import SchedTable from "./schedTable";
import conflictMessage from "../../../../widgets/conflictMessage";
import setHoursAndMinutes from "./js/hours";
import validate from "./js/scheduleValidation";
import Header from "./header";
import scheduleAction from "./js/scheduleAction";
import Swal from "sweetalert2";

const _form = {
  section: "",
  subject: "",
  instructor: "",
  lvl: 7,
  strand: "ABM",
  specialization: "Academics track",
  semester: "1st",
  isBreakTime: false,
};

export default function Modal({
  show = false,
  toggle = () => {},
  selected = {},
  schedulesUpdate = [],
  willCreate = false,
  collections = [],
  isPerInstructor,
  instructor: selectedInstructor,
}) {
  const { token } = useSelector(({ auth }) => auth),
    { isLoading, sectionsAndsubjects, instructors } = useSelector(
      ({ schedulers }) => schedulers
    ),
    [form, setForm] = useState(_form),
    [sections, setSections] = useState([]),
    [subjects, setSubjects] = useState([]),
    [pickDays, setPickDays] = useState([]),
    [scheduleStorage, setScheduleStorage] = useState([]),
    [schedulesUpdateStorage, setSchedulesUpdateStorage] = useState([]),
    [schedulesDeleted, setschedulesDeleted] = useState([]),
    [allSchedules, setAllSchedules] = useState([]),
    [schedulePick, setSchedulePick] = useState([]),
    [originalCopyOfSchedules, setOriginalCopyOfSchedules] = useState([]),
    [schedulesView, setSchedulesView] = useState([]),
    [hourStart, setHourStart] = useState(7),
    [minStart, setMinStart] = useState(0),
    [hourEnd, setHourEnd] = useState(8),
    [minEnd, setMinEnd] = useState(0),
    [periodStart, setPeriodStart] = useState("AM"),
    [periodEnd, setPeriodEnd] = useState("AM"),
    [hourInterval, setHourInterval] = useState(1),
    [minInterVal, setMinInterval] = useState(0),
    [isFillUp, setIsFillUp] = useState(false),
    [isInstructorView, setIsInstructorView] = useState(false),
    dispatch = useDispatch(),
    { addToast } = useToasts();

  useEffect(() => {
    if (!willCreate && show) {
      setAllSchedules(schedulesUpdate);
      setSchedulePick(schedulesUpdate);
      setOriginalCopyOfSchedules(schedulesUpdate);
      setForm((prev) => ({ ...prev, ...selected, lvl: selected.level }));
      setSchedulesView(schedulesUpdate);
    } else {
      setAllSchedules([]);
      setSchedulePick([]);
      setSchedulesView([]);
    }
    setIsInstructorView(false);
    setSchedulesUpdateStorage([]);
    setschedulesDeleted([]);
    setPickDays([]);
    setScheduleStorage(collections);
  }, [willCreate, schedulesUpdate, show, selected, collections]);

  useEffect(() => {
    if (show) {
      if (form.lvl <= 10) {
        dispatch(
          SECTIONSANDSUBJECTS({
            token,
            data: { lvl: form.lvl, semester: form.semester },
          })
        );
      } else if (form.strand && form.specialization) {
        dispatch(
          SECTIONSANDSUBJECTS({
            token,
            data: {
              lvl: form.lvl,
              strand: form.strand,
              specialization: form.specialization,
            },
          })
        );
      }
    }
  }, [
    form.lvl,
    form.strand,
    form.semester,
    form.specialization,
    token,
    show,
    dispatch,
  ]);

  useEffect(() => {
    if (show) {
      dispatch(INSTRUCTORS({ token }));
    }
  }, [show, dispatch, token]);

  const handleSortICTsections = useCallback((array) => {
    return (
      !!array &&
      [...array]
        .sort((a, b) => a.isICT - b.isICT)
        .map((section) => ({
          ...section,
          name: section.isICT ? `${section.name} - ICT` : section.name,
        }))
    );
  }, []);

  const handleFilterSubjects = useCallback((array) => {
    const handleFilter = (decision) =>
      [...array].filter(({ isICT = false }) => isICT === decision);
    const _ictSubjects = handleFilter(true);
    const _subjects = handleFilter(false);

    return { subjects: _subjects, ictSubjects: _ictSubjects };
  }, []);

  useEffect(() => {
    if (show) {
      const { sections: secs = [], subjects: subs = [] } =
        sectionsAndsubjects || {};
      var baseSubjects = subs || [];
      if (form.lvl > 10) {
        baseSubjects = subs?.filter(
          ({ semester }) => semester === form.semester
        );
      }
      const sorterSections = handleSortICTsections(secs);
      const { ictSubjects: _ictSubjects = [], subjects: _subjects = [] } =
        handleFilterSubjects(baseSubjects);

      if (form.section) {
        const isICT =
          [...secs].find(({ _id }) => _id === form.section)?.isICT || false;
        const mergeSubjects = isICT
          ? [..._subjects, ..._ictSubjects].filter(Boolean)
          : _subjects;

        setSubjects(mergeSubjects);
      } else {
        setSubjects(_subjects);
      }
      setSections(sorterSections || []);
    }
  }, [
    sectionsAndsubjects,
    form.section,
    form.lvl,
    form.semester,
    show,
    handleSortICTsections,
    handleFilterSubjects,
  ]);

  useEffect(() => {
    if (hourStart === 12) {
      setHourEnd(1);
    } else if (hourStart === 5) {
      setHourEnd(5);
    } else {
      if (willCreate) setHourEnd(hourStart + 1);
    }

    if (willCreate) return setMinEnd(minStart);
  }, [hourStart, minStart, willCreate]);

  useEffect(() => {
    const getPeriod = (hour) =>
      (hour >= 1 && hour <= 5) || hour === 12 ? "PM" : "AM";
    setPeriodStart(getPeriod(hourStart));
    setPeriodEnd(getPeriod(hourEnd));
  }, [hourStart, hourEnd]);

  useEffect(() => {
    setHoursAndMinutes({
      hourEnd,
      hourStart,
      setHourInterval,
      setMinInterval,
      minStart,
      minEnd,
    });
  }, [hourEnd, hourStart, minEnd, minStart]);

  useEffect(() => {
    if (form.lvl && pickDays.length > 0) {
      if (form.isBreakTime) return setIsFillUp(true);
      if (!form.isBreakTime && form.instructor && form.subject) {
        return setIsFillUp(true);
      } else {
        setIsFillUp(false);
      }
    } else {
      setIsFillUp(false);
    }
  }, [form.lvl, form.instructor, form.subject, pickDays, form.isBreakTime]);

  useEffect(() => {
    if (form.section && form.lvl && willCreate) {
      const filterSchedules = (array) =>
        array?.filter(({ section, semester = "" }) => {
          const sectionID = section._id || section;
          return form.lvl > 10
            ? sectionID === form.section && semester === form.semester
            : sectionID === form.section;
        });

      const isEmpty = (array) => array?.length === 0;

      const _scheduleInSection = filterSchedules(schedulePick);
      const firstSchedule = schedulePick?.length > 0 ? schedulePick[0] : null;
      const schedLvl = firstSchedule?.lvl || form.lvl;
      const specialization = firstSchedule?.specialization || form.lvl;
      const strand = firstSchedule?.strand || form.lvl;
      const section = firstSchedule?.section || form.section;

      const hasNoSchedules =
        isEmpty(schedulePick) && isEmpty(_scheduleInSection);

      const hasSameSectionAndLevel =
        _scheduleInSection?.length === schedulePick?.length &&
        schedLvl === form.lvl;

      if (hasNoSchedules || hasSameSectionAndLevel) {
        const schedules = filterSchedules(collections);
        const mergeSchedules = [
          ...(schedules?.length > 0 ? schedules : []),
          ...(_scheduleInSection?.length > 0 ? _scheduleInSection : []),
        ].filter(Boolean);
        setAllSchedules(mergeSchedules || []);
      } else {
        const isChangeSection = section !== form.section;
        const isChangeLevel = schedLvl !== form.lvl;

        Swal.fire({
          title: "Are you sure?",
          text: `You want to change the ${
            isChangeSection ? "section" : isChangeLevel ? "Grade Level" : ""
          }? If you change the section, your set schedules will be erased!`,
          icon: "warning",
          showCancelButton: true,
          confirmButtonColor: "#3085d6",
          cancelButtonColor: "#d33",
          confirmButtonText: "Yes, Change it!",
        }).then((result) => {
          if (result.isConfirmed) {
            setSchedulePick([]);
          } else {
            const _section = schedulePick[0]?.section;
            const newObj =
              schedLvl > 10
                ? { section: _section, lvl: schedLvl, strand, specialization }
                : { section: _section, lvl: schedLvl };

            setForm((prev) => ({ ...prev, ...newObj }));
          }
        });
      }
    }
  }, [
    form.lvl,
    form.section,
    form.semester,
    collections,
    schedulePick,
    willCreate,
  ]);

  const filterSchedsByInstructor = useCallback((_instructor, baseScheds) => {
    const scheds = baseScheds;
    const _schedules = [...scheds].filter(
      ({ isBreakTime = false, instructor }) =>
        !isBreakTime && instructor._id === _instructor
    );

    setSchedulesView(_schedules);
  }, []);

  useEffect(() => {
    if (isInstructorView && form.instructor) {
      filterSchedsByInstructor(form.instructor, scheduleStorage);
    }
  }, [isInstructorView, form.instructor, scheduleStorage]);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!willCreate) {
      if (isEqual(allSchedules, originalCopyOfSchedules)) {
        addToast("No changes found, skipping update.", {
          appearance: "info",
        });
      } else {
        dispatch(
          UPDATE({
            data: {
              updatedSchedules: schedulesUpdateStorage,
              deletedSchedules: schedulesDeleted,
            },
            token,
          })
        );
      }
    } else {
      dispatch(SAVE({ data: schedulePick, token }));
    }
    setForm(_form);
    toggle();
  };

  const handleClose = () => {
    setForm(_form);
    toggle();
  };

  const handlePick = (day) => {
    const _days = [...pickDays];
    const index = _days.findIndex((d) => d === day);
    if (index > -1) {
      _days.splice(index, 1);
    } else {
      _days.push(day);
    }
    setPickDays(_days);
  };

  const removedUpdatedSchedule = () => {
    return scheduleAction({ form, action: "REMOVE", array: scheduleStorage });
  };

  const conflicts = ({ scheduleForm, willCreate }) => {
    const breaktime = validate.breakTime({
      ...scheduleForm,
      schedulePick,
      willCreate,
      form,
      pickDays,
    });

    return [
      breaktime.isConflict && {
        ...breaktime,
        isBreakTime: true,
      },
      willCreate &&
        validate.subjectPick({ schedules: schedulePick, pickDays, form })
          .isDuplicate && {
          conflict: "subjectDuplicate",
        },
      willCreate &&
        validate.schedulePick(scheduleForm) && {
          conflict: "schedule",
        },
      validate.instructor(scheduleForm).isConflict && {
        conflict: "teacher",
        message: validate.instructor(scheduleForm),
      },
      validate.section(scheduleForm).isConflict && {
        conflict: "section",
        message: validate.section(scheduleForm),
      },
      validate.subject(scheduleForm).isDuplicate && {
        conflict: "subject",
        message: validate.subject(scheduleForm),
      },
    ];
  };

  const handleCreate = async () => {
    const startTime = hourStart * 60 + minStart;
    const endTime = hourEnd * 60 + minEnd;
    const totalDifference = endTime - startTime;

    if (form.isBreakTime) {
      if (totalDifference < 30 || totalDifference > 45) {
        return Swal.fire({
          icon: "warning",
          title: "Invalid Time Difference",
          text: "For break time, the difference must be between 30 to 45 minutes.",
        });
      }
    } else {
      if (totalDifference < 60) {
        return Swal.fire({
          icon: "warning",
          title: "Invalid Time Difference",
          text: "For non-break time, the difference must be at least 1 hour.",
        });
      }
    }

    const schedules = willCreate ? scheduleStorage : removedUpdatedSchedule();
    const scheduleForm = {
      schedules,
      form,
      pickDays,
      hourStart,
      hourEnd,
      minStart,
      minEnd,
      schedulePick,
      periodStart,
      periodEnd,
    };

    const conflictFound = conflicts({ scheduleForm, willCreate }).find(Boolean);
    if (conflictFound) {
      setIsInstructorView(conflictFound.conflict === "teacher" ? true : false);
      await conflictMessage({
        conflict: conflictFound.conflict,
        time: conflictFound.message,
        isBreakTime: conflictFound.isBreakTime,
        message: conflictFound.message,
      });
      return;
    }

    // if willCreate
    const indexColor = Math.floor(Math.random() * 21); //
    const subject = subjects.find(({ _id }) => _id === form.subject);
    const instructor = instructors.find(({ _id }) => _id === form.instructor);
    const _id = allSchedules?.length;
    const newSchedule = {
      _id,
      isBreakTime: form.isBreakTime,
      section: form.section,
      ...(!form.isBreakTime && { subject, instructor }),
      semester: form.lvl > 10 ? form.semester : "",
      lvl: form.lvl,
      specialization: form.specialization,
      strand: form.strand,
      schedules: [
        {
          days: pickDays,
          time: {
            start: { hours: hourStart, min: minStart, period: periodStart },
            end: { hours: hourEnd, min: minEnd, period: periodEnd },
          },
          color: colors[indexColor] || "#B5D9F9",
          scheduleID: uuidv4(),
        },
      ],
    };

    setSchedulePick((prev = []) => [...prev, newSchedule]);
    setAllSchedules((prev = []) => [
      ...prev,
      {
        ...newSchedule,
        id: prev.length,
        _id,
        section: { ...form.section, lvl: 7 },
      },
    ]);

    const newSchedulesStorage = [
      ...scheduleStorage,
      {
        ...newSchedule,
        id: scheduleStorage.length,
        _id,
        section: { ...sections.find(({ _id }) => _id === form.section) },
      },
    ];

    setScheduleStorage(newSchedulesStorage);

    setPickDays([]);
    //end willCreate
    if (!willCreate) {
      const updatedSchedules = scheduleAction({
        array: allSchedules,
        form: { ...scheduleForm, ...form },
        subjects,
        instructors,
      });

      const updatedParentSchedules = scheduleAction({
        array: scheduleStorage,
        form: { ...scheduleForm, ...form },
        subjects,
        instructors,
      });

      const _schedulesToUpdate = [...schedulesUpdateStorage];
      const index = _schedulesToUpdate.findIndex(
        ({ _id }) => _id === updatedSchedules.obj._id
      );

      if (index > -1) {
        _schedulesToUpdate[index] = updatedSchedules.obj;
      } else {
        _schedulesToUpdate.push(updatedSchedules.obj);
      }

      setSchedulePick(updatedSchedules.collections);
      setAllSchedules(updatedSchedules.collections);
      setScheduleStorage(updatedParentSchedules.collections);
      setSchedulesUpdateStorage(_schedulesToUpdate);
      setIsInstructorView(false);
    }
    setForm({ ...form, _id: "" });
  };
  const handleRemoveSchedule = (allScheduleObj) => {
    Swal.fire({
      title: "Are you sure?",
      text: "You want to delete",
      icon: "warning",
      showCancelButton: true,
      confirmButtonColor: "#d33",
      cancelButtonColor: "#3085d6",
      confirmButtonText: "Yes, delete it!",
      cancelButtonText: "Cancel",
      reverseButtons: true,
    }).then((result) => {
      if (result.isConfirmed) {
        const scheduleForm = {
          array: allSchedules,
          instructors,
          subjects,
          form: {
            ...allScheduleObj,
            oldDays: allScheduleObj.days,
          },
          action: "DELETE",
        };

        const _allSchedules = scheduleAction({
          ...scheduleForm,
        });

        const _scheduleStorage = scheduleAction({
          ...scheduleForm,
          array: scheduleStorage,
        });

        const _schedulesPick = scheduleAction({
          ...scheduleForm,
          array: schedulePick,
        });

        const _schedulesDeleted = [...schedulesDeleted];
        const _schedulesToUpdate = [...schedulesUpdateStorage];

        if (_allSchedules?.objDeleted?._id) {
          _schedulesDeleted.push(_allSchedules.objDeleted);
        } else {
          _schedulesToUpdate.push(_allSchedules.obj);
        }

        setschedulesDeleted(_schedulesDeleted);
        setSchedulesUpdateStorage(_schedulesToUpdate);
        setAllSchedules(_allSchedules.collections);
        setSchedulePick(_schedulesPick.collections);
        setScheduleStorage(_scheduleStorage.collections);
        if (!willCreate) {
          setForm({ ...form, instructor: "", _id: "" });
          setIsInstructorView(false);
        }
      }
    });
  };

  const handleChangeView = (isInstructor) => {
    let teacher = form.instructor;
    if (!teacher || form.isBreakTime)
      return Swal.fire({
        icon: "warning",
        title: "Instructor Required",
        text: "Please select an instructor to view their schedule.",
      });

    filterSchedsByInstructor(teacher, scheduleStorage);
    setIsInstructorView(isInstructor);
  };

  const props = {
    handleRemoveSchedule,
    setPickDays,
    setForm,
    setHourStart,
    setHourEnd,
    setMinStart,
    setMinEnd,
    setPeriodStart,
    handleCreate,
    setPeriodEnd,
    handlePick,
    willCreate,
    form,
    instructors,
    sections,
    subjects,
    pickDays,
    hourStart,
    minStart,
    hourEnd,
    minEnd,
    periodStart,
    periodEnd,
    hourInterval,
    minInterVal,
    isFillUp,
  };
  const title = !isPerInstructor
    ? !willCreate
      ? `in Grade - ${form.lvl} ${form.lvl > 10 ? form.strand : ""} , ${
          sections.find(({ _id }) => _id === form?.section)?.name
        } ${form.lvl > 10 ? `${form.semester} semester ` : ""}`
      : ""
    : `for ${fullName(selectedInstructor?.fullName)}`;

  const scheduleLabel = !isInstructorView
    ? `Grade-${form.lvl} ${form.lvl > 10 ? form?.strand || "" : ""}, ${
        sections?.find(({ _id }) => _id === form?.section)?.name || ""
      }`
    : fullName(
        instructors.find(({ _id }) => _id === form.instructor)?.fullName
      ) || "";

  const baseSchedulesView = isInstructorView ? schedulesView : allSchedules;

  return (
    <MDBModal isOpen={show} toggle={toggle} backdrop size="fluid">
      <MDBModalHeader
        toggle={handleClose}
        className="light-blue darken-3 white-text"
      >
        <MDBIcon icon="calendar-alt" className="mr-2" />
        {!willCreate ? "Update" : "Create"} a Schedule {title}
      </MDBModalHeader>

      <MDBModalBody className="mb-0 m-0 p-0">
        <form onSubmit={handleSubmit}>
          <MDBRow>
            <MDBCol md="5">
              {willCreate && <SelectLevel form={form} setForm={setForm} />}
              <div className="ml-2">
                <Header props={props} />
              </div>

              {schedulePick?.length > 0 && (
                <SchedTable
                  array={schedulePick}
                  props={props}
                  willCreate={willCreate}
                  form={form}
                />
              )}
            </MDBCol>
            <MDBCol size="7">
              {form.section || !willCreate ? (
                <div className="mt-2">
                  <div className="d-flex justify-content-between align-items-center">
                    <h6 className="mt-1">
                      <strong>
                        Schedule For &nbsp;
                        {scheduleLabel}
                      </strong>
                    </h6>
                    <MDBSwitch
                      className="float-right mr-5"
                      checked={isInstructorView}
                      id="flexSwitchCheckChecked"
                      getValue={(value) => {
                        handleChangeView(value);
                      }}
                      labelLeft="Section"
                      labelRight="Teacher"
                    />
                  </div>
                  <Scheduler
                    array={baseSchedulesView || []}
                    props={props}
                    isTeacher={isInstructorView}
                  />
                </div>
              ) : (
                <div className="h-100 d-flex align-items-center justify-content-center">
                  <h5>Select a section to view the schedule.</h5>
                </div>
              )}
            </MDBCol>
          </MDBRow>
        </form>
      </MDBModalBody>
      <MDBModalFooter className="mt-2">
        <div className="mt-0 text-center mb-1-half">
          <MDBBtn
            type="submit"
            disabled={isLoading || schedulePick?.length <= 0}
            color="primary"
            className="mb-2 float-right"
            onClick={handleSubmit}
          >
            {!willCreate ? "Update" : "Submit"}
          </MDBBtn>
        </div>
      </MDBModalFooter>
    </MDBModal>
  );
}
