import { configureStore } from "@reduxjs/toolkit";
import auth from "./slices/auth";
import users from "./slices/users";
import roles from "./slices/roles";
import projects from "./slices/projects";
import tasks from "./slices/tasks";
import events from "./slices/events";
import subjects from "./slices/pricipal/subjects";
import rooms from "./slices/pricipal/rooms";
import sections from "./slices/pricipal/sections";
import batches from "./slices/resources/batches";
import credentials from "./slices/student/credentials";
import enrollees from "./slices/admission/enrollees";
import students from "./slices/registrar/students";
import schedulers from "./slices/registrar/schedulers";
import schedule from "./slices/teacher/schedule";
import classes from "./slices/teacher/classes";
import advisory from "./slices/teacher/advisory";
import employees from "./slices/admission/employees";
import applicants from "./slices/registrar/applicants";
import studentsDrop from "./slices/registrar/studentsDrop";
import messages from "./slices/messages";
import dashboard from "./slices/dashboard";
import questionBank from "./slices/registrar/questionBank";
import entranceExam from "./slices/registrar/entranceExam";
import exam from "./slices/student/exam";
import examParticipants from "./slices/registrar/examParticipants";
import organization from "./slices/organization";
const store = configureStore({
  reducer: {
    auth,
    users,
    roles,
    projects,
    tasks,
    subjects,
    events,
    rooms,
    sections,
    batches,
    credentials,
    enrollees,
    students,
    schedulers,
    schedule,
    classes,
    advisory,
    employees,
    applicants,
    studentsDrop,
    messages,
    dashboard,
    questionBank,
    entranceExam,
    exam,
    examParticipants,
    organization,
  },
});

export default store;
