import React, { useEffect, useState } from "react";
import { MDBTable } from "mdbreact";
import { useDispatch, useSelector } from "react-redux";
import { BROWSE } from "../../../../../services/redux/slices/pricipal/sections";
import { fullName } from "../../../../../services/utilities";
import SORTING from "../../../../../widgets/sorting";
import PaginationButtons from "../../../../../widgets/pagination/buttons";
import Rows from "../../../../../widgets/pagination/rows";
import handlePagination from "../../../../../widgets/pagination";

const Table = () => {
  const { token } = useSelector(({ auth }) => auth),
    { collections } = useSelector(({ sections }) => sections),
    dispatch = useDispatch();

  const [max, setMax] = useState(5),
    [storageSections, setStorageSections] = useState([]),
    [page, setPage] = useState(1);

  useEffect(() => {
    if (token) {
      dispatch(BROWSE({ token }));
    }
  }, [dispatch, token]);

  useEffect(() => {
    if (collections) {
      setStorageSections(SORTING(collections));
    }
  }, [collections]);

  return (
    <>
      <MDBTable responsive hover key={`collapse`}>
        <thead>
          <tr>
            <th>#</th>
            <th>Name</th>
            <th>Grade level</th>
            <th>Capacity</th>
            <th>Adviser</th>
          </tr>
        </thead>

        <tbody>
          {storageSections.length > 0 ? (
            handlePagination(storageSections, page, max)?.map(
              (section, index) => {
                const {
                  _id,
                  name,
                  lvl,
                  strand,
                  capacity,
                  adviser,
                  isICT = false,
                } = section;
                console.log(section);
                return (
                  <tr key={`${_id}`}>
                    <td>{index + 1}</td>
                    <td style={{ fontWeight: 400 }}>{name}</td>
                    <td style={{ fontWeight: 400 }}>{`Grade - ${lvl} ${
                      isICT ? ", ICT" : ""
                    } ${lvl > 10 ? `, ${strand}` : ""}`}</td>

                    <td style={{ fontWeight: 400 }}>{capacity}</td>
                    <td style={{ fontWeight: 400 }}>
                      {fullName(adviser.fullName)}
                    </td>
                  </tr>
                );
              }
            )
          ) : (
            <tr>
              <td>No Records</td>
            </tr>
          )}
        </tbody>
      </MDBTable>
      {storageSections.length > 0 && (
        <>
          <Rows max={max} setMax={setMax} />
          <PaginationButtons
            max={max}
            page={page}
            setPage={setPage}
            array={storageSections}
          />
        </>
      )}
    </>
  );
};

export default Table;
