const handleRemarks = (grade) =>
  grade ? (grade >= 75 ? "PASSED" : "FAILED") : "--";

const grades = {
  remarks: (advisory) => {
    const { grades: _grades, lvl = 7, semester } = advisory;
    const level = Number(lvl);

    const gradesWithRemarks = _grades.map((grade) => {
      const {
        firstQuarter = 0,
        secondQuarter = 0,
        thirdQuarter = 0,
        fourthQuarter = 0,
      } = grade;

      let remarks = "";
      var finals = 0;

      if (level <= 10) {
        if (firstQuarter && !secondQuarter && !thirdQuarter && !fourthQuarter) {
          remarks = handleRemarks(firstQuarter);
        } else if (
          firstQuarter &&
          secondQuarter &&
          !thirdQuarter &&
          !fourthQuarter
        ) {
          remarks = handleRemarks(secondQuarter);
        } else if (
          firstQuarter &&
          secondQuarter &&
          thirdQuarter &&
          !fourthQuarter
        ) {
          remarks = handleRemarks(thirdQuarter);
        } else if (
          firstQuarter &&
          secondQuarter &&
          thirdQuarter &&
          fourthQuarter
        ) {
          const _finals =
            (firstQuarter + secondQuarter + thirdQuarter + fourthQuarter) / 4;

          remarks = handleRemarks(_finals);
          finals = _finals;
        } else {
          remarks = handleRemarks(0);
        }
      } else {
        if (semester === "1st") {
          if (firstQuarter && !secondQuarter) {
            remarks = handleRemarks(firstQuarter);
          } else if (firstQuarter && secondQuarter) {
            const _finals = (firstQuarter + secondQuarter) / 2;
            remarks = handleRemarks(_finals);
            finals = _finals;
          }
        } else {
          if (thirdQuarter && !fourthQuarter) {
            remarks = handleRemarks(thirdQuarter);
          } else if (thirdQuarter && fourthQuarter) {
            const _finals = (thirdQuarter + fourthQuarter) / 2;
            remarks = handleRemarks(_finals);
            finals = _finals;
          }
        }
      }

      return {
        subject: grade.subject,
        grade: {
          firstQuarter,
          secondQuarter,
          thirdQuarter,
          fourthQuarter,
        },
        finals: finals > 0 ? Math.ceil(finals) : 0,

        remarks: remarks || "--",
      };
    });

    return { ...advisory, grades: gradesWithRemarks };
  },

  average: (advisory) => {
    const { grades = [] } = advisory;
    const _grades = [...grades];
    const haveFinalsAllGrades = _grades.every(({ finals = 0 }) => finals);
    if (haveFinalsAllGrades) {
      const totalFinals = _grades.reduce(
        (acc, curr) => (acc += curr.finals),
        0
      );
      const result = totalFinals / _grades.length;
      return result;
    } else {
      return "--";
    }
  },
};

export default grades;
