import Applicants from "./applicants";
import Enrollees from "./enrollees";
import Schedules from "./schedule";
import Students from "./students";
import StudentDrops from "./studentsDrop";
import WalkIn from "./walkin";
import QuestionBank from "./questionBank";
import Participants from "./entranceExam/participants";
import EntranceExamV2 from "./entranceExam/exam";
import Dashboard from "../principal/dashboard";

const access = [
  {
    name: "Dashboard",
    path: "/dashboard",
    icon: "tachometer-alt",
    component: Dashboard,
  },
  {
    name: "Enrollees",
    path: "/enrollees",
    icon: "users",
    children: [
      {
        name: "Pending",
        path: "/pending",
        component: Enrollees,
        props: "PENDING",
      },
      {
        name: "Approved",
        path: "/approved",
        props: "APPROVED",
        component: Enrollees,
      },

      {
        name: "Rejected",
        path: "/rejected",
        props: "REJECT",
        component: Enrollees,
      },
    ],
  },

  {
    name: "Walkin",
    path: "/walkin",
    icon: "walking",
    component: WalkIn,
  },

  {
    name: "Students",
    path: "/students",
    icon: "user-graduate",
    component: Students,
  },

  {
    name: "Students Drop",
    path: "/drop",
    icon: "user-times",
    component: StudentDrops,
  },

  {
    name: "Schedules",
    path: "/schedules",
    icon: "chalkboard-teacher",
    component: Schedules,
  },
  {
    name: "Entrance Exam",
    path: "/entranceExam",
    icon: "dungeon",
    children: [
      {
        name: "Participants",
        path: "/participants",
        component: Participants,
      },
      {
        name: "Exam",
        path: "/exam",
        component: EntranceExamV2,
      },
    ],
  },
  {
    name: "Question Bank",
    path: "/questions",
    icon: "university",
    component: QuestionBank,
  },

  {
    name: "Activation Accounts",
    path: "/applicants",
    icon: "user-nurse",
    component: Applicants,
  },
];

export default access;
