import Swal from "sweetalert2";

const MESSAGES = {
  teacher: "This instructor is already scheduled for a class on",
  subject: "This Subject is already scheduled for a class on",
  subjectDuplicate: "This Subject is already exist on this day",
  schedule:
    "Double check your Schedule Selected List because there is a conflict.",
  section: "This section is already scheduled for",
  breakTimeMaximum: "Only 2 schedules are allowed, and there's a conflict on",
  breakTime: "That time is already set as breaktime.",
};

async function conflictMessage({
  conflict,
  time,
  isBreakTime = false,
  message: messageForBreakTime = "",
}) {
  const { element = {}, timeConflict = {}, day = "" } = time || {};
  const { start = {}, end = {} } = timeConflict;
  const { subject = {} } = element;

  const formatTime = () => {
    return `${day},
    teaching ${subject?.name} from ${start?.hours}:${
      start?.min === 0 ? "00" : start.min
    } ${start?.period} to
    ${end?.hours}:${end?.min === 0 ? "00" : end.min} ${" " + end?.period}`;
  };

  console.log(time);

  return await Swal.fire({
    title: "Conflict!",
    text: isBreakTime
      ? messageForBreakTime
      : `${MESSAGES[conflict]} ${time ? formatTime() : ""}`,
    icon: "warning",
    confirmButtonColor: "#d33",
    confirmButtonText: "OK",
  });
}

export default conflictMessage;
