import React from "react";
import MultipleChoice from "./multipleChoice";
import Matching from "../../../../../matchingType";
import Identification from "./identification";
const QuestionType = ({ question, setStudentAnswer }) => {
  const type = question?.type;

  switch (type) {
    case "mc":
      return (
        <MultipleChoice
          question={question}
          setStudentAnswer={setStudentAnswer}
        />
      );

    case "matching":
      return (
        <Matching question={question} setStudentAnswer={setStudentAnswer} />
      );

    case "identification":
      return (
        <Identification
          setStudentAnswer={setStudentAnswer}
          question={question}
        />
      );

    default:
      return <div>Unknown question type</div>;
  }
};

export default QuestionType;
