import React, { useState, useEffect } from "react";
import { MDBContainer, MDBMask, MDBView } from "mdbreact";
import BG2 from "../../../assets/landing/bg7.png";
import BG4 from "../../../assets/landing/bg9.png";
import BG5 from "../../../assets/landing/bg12.png";
import BG3 from "../../../assets/landing/bg11.png";

const backgrounds = [BG2, BG4, BG3, BG5].sort(() => Math.random() - 0.4);

export default function Banner({ show }) {
  const [imageIndex, setImageIndex] = useState(0);
  useEffect(() => {
    if (show) return setImageIndex(2);

    const timeInterval = setInterval(() => {
      setImageIndex((prev) => {
        if (prev > 2) return 0;

        return prev + 1;
      });
    }, 5000);

    return () => clearInterval(timeInterval);
  }, [show]);

  return (
    <section id="banner" style={{ paddingTop: "5rem" }}>
      <MDBView src={backgrounds[imageIndex]} fixed>
        <MDBMask
          overlay="stylish-light"
          className="rgba-white-light d-flex justify-content-center align-items-center"
        >
          <MDBContainer className="h-100 d-flex align-items-center" style={{position: "relative"}}>
            <div className="pt-5 banner-text">
              <h1 className="display-5 white-text font-weight-bold mb-0">
                Small School
              </h1>
              <h1 className="display-5 white-text font-weight-bold mb-0">
                Big Opportunities
              </h1>
              <h1 className="display-5 white-text font-weight-bold mb-0">
                Endless Possibilities
              </h1>
              {/* <p className="text-uppercase white-text">- Liza Fisher Norman</p> */}
              <h5 className="text-uppercase white-text mt-3">
                Give your future a boost at&nbsp;
                <strong>L.M.B.N.H.S!</strong>
              </h5>
            </div>
          </MDBContainer>
        </MDBMask>
      </MDBView>
    </section>
  );
}
