import React, { useEffect, useState } from "react";
import {
  SectionsWithStudents,
  UPDATE,
} from "../../../../services/redux/slices/admission/enrollees";

import { useDispatch, useSelector } from "react-redux";
import {
  MDBAnimation,
  MDBBadge,
  MDBIcon,
  MDBInput,
  MDBListGroup,
  MDBListGroupItem,
  MDBProgress,
  MDBTypography,
} from "mdbreact";

import "./sections.css";
import Swal from "sweetalert2";
import { fullName } from "../../../../services/utilities";
import ViewEnrollees from "./viewEnrollees";

const Sections = ({
  params = {},
  sections = [],
  collections = [],
  setContainer = () => {},
  setSections = () => {},
  setIsSelectAll = () => {},
}) => {
  const { information, token, auth } = useSelector(({ auth }) => auth),
    { sectionsWithStudents, isLoadingSectionAndSubjects: isLoading } =
      useSelector(({ enrollees }) => enrollees),
    // [sections, setSections] = useState([]),
    [show, setShow] = useState(false),
    [isPending, setIsPending] = useState(false),
    [section, setSection] = useState({}),
    [enrollees, setEnrollees] = useState([]),
    dispatch = useDispatch();

  // useEffect(() => {
  //   dispatch(
  //     SectionsWithStudents({
  //       token,
  //       data: {
  //         batches: information.batches,
  //         lvl: params.lvl || 7,
  //         strand: params.strand || "",
  //         isICT: params?.isICT || false,
  //       },
  //     })
  //   );
  //   // return () => dispatch(RESET_SECTIONS());
  // }, [information, token, dispatch, params.lvl, params.strand, params.isICT]);

  // useEffect(() => {
  //   setSections(sectionsWithStudents);
  // }, [sectionsWithStudents]);

  const toggle = () => setShow(!show);

  const handleLoading = (width = 100) => {
    return (
      <div
        style={{
          width: `${width}px`,
        }}
      >
        <MDBAnimation
          type="flash"
          infinite
          delay={`${1}00ms`}
          duration="3000ms"
        >
          <MDBProgress
            color="light"
            value={200}
            id="section-loading"
          ></MDBProgress>
        </MDBAnimation>
      </div>
    );
  };

  const handleDragOver = (e) => {
    e.preventDefault(); // Required to allow drop
  };

  const handleDrop = (e, section) => {
    e.preventDefault();

    // Get the dragged enrollee data
    const enrolleeData = e.dataTransfer.getData("application/json");
    const data = JSON.parse(enrolleeData);
    const { slots } = section;
    const { isMultiple = false, enrollees, enrollee = {} } = data;
    const baseEnrollees = isMultiple ? enrollees : [enrollee];
    const remainingSlots = slots - baseEnrollees.length;

    if (baseEnrollees.length === 0) {
      Swal.fire({
        icon: "warning",
        title: "No Enrollees Selected",
        text: "Please select at least one enrollee before proceeding.",
        confirmButtonText: "Got it",
      });
      return;
    }

    if (remainingSlots < 0) {
      Swal.fire({
        icon: "warning",
        title: "No Available Slots",
        text: `Only ${slots} slot(s) remaining in the section "${section.name}".`,
        confirmButtonText: "Got it",
      });
      return;
    }

    const _html = `Do you want to assign <br/> <b>${
      isMultiple
        ? `${enrollees.length} enrollees`
        : fullName(enrollee.student.fullName)
    }</b> to <br/> Grade <b>${section.lvl} ${
      section.lvl > 10 && section.strand ? section.strand : ""
    } - ${section.name}</b>?`;

    Swal.fire({
      focusDeny: true,
      icon: "question",
      title: "Are you sure?",
      html: _html,
      confirmButtonText: `<span class="text-dark">Cancel</span>`,
      confirmButtonColor: "#fff",
      showDenyButton: true,
      denyButtonText: `Proceed`,
      denyButtonColor: "#3B71CA",
    }).then((res) => {
      if (res.isDenied) {
        const _enrollees = baseEnrollees.map((e) => ({
          _id: e.enrolleeId,
          section,
          status: "APPROVED",
          registrar: { approvedBy: auth._id },
        }));
        dispatch(
          UPDATE({
            token,
            data: { enrollees: _enrollees, section },
          })
        );

        Swal.fire({
          title: "Successfully Enrolled!",
          text: `${
            isMultiple ? `${baseEnrollees.length} enrollees` : "The student"
          } has been assigned to Grade ${section.lvl} ${
            section.strand && section.lvl > 10 ? section.strand : ""
          } - ${section.name}.`,
          icon: "success",
          confirmButtonText: "Okay",
        });
      } else {
        setContainer([]);
        setIsSelectAll(false);
        Swal.fire({
          title: "Changes are not Saved!",
          icon: "warning",
          showConfirmButton: false,
          timer: 2500,
          timerProgressBar: true,
        });
      }
    });
  };
  console.log(collections);
  const handleDragStartForEnrollees = (e, container) => {
    e.dataTransfer.setData(
      "application/json",
      JSON.stringify({ isMultiple: true, enrollees: container })
    );
  };

  const handleView = (_enrollees, _isPending = false, _section) => {
    if (_enrollees.length === 0) {
      Swal.fire({
        icon: "warning",
        title: _isPending ? "No Selected Enrollees" : "No Enrolled Students",
        text: _isPending
          ? "You haven't selected any enrollees yet."
          : `No students enrolled in ${_section.name}.`,
        confirmButtonText: "Got it",
      });
      return;
    }
    setEnrollees(_enrollees);
    setSection(_section);
    setIsPending(_isPending);
    toggle();
  };

  const handleSearch = (search) => {
    const _sections = [...sections];

    const results = _sections.filter(({ section: sec }) =>
      sec.name.toLowerCase().includes(search.toLowerCase())
    );
    setSections(search ? results : collections);
  };

  return (
    <>
      <div style={{ position: "fixed", width: "21%" }}>
        <div className="mt-3 mb-3">
          <span>
            <strong> Selected Enrollees:</strong>
            <MDBBadge
              className="px-2 py-2 ml-2 cursor-pointer"
              color="primary"
              draggable
              onDragStart={(e) =>
                handleDragStartForEnrollees(e, params.container)
              }
              onClick={() => handleView(params.container, true)}
            >
              {params.container?.length} <MDBIcon icon="user-graduate ml-2" />
            </MDBBadge>
          </span>
        </div>
        <hr />
        <div className="mb-1 d-flex justify-content-between align-items-center">
          <span>Sections:</span>
          <input
            type="search"
            placeholder="Search..."
            onChange={({ target }) => handleSearch(target.value)}
            className="form-control w-75"
          />
        </div>

        {!isLoading ? (
          <div
            style={{ maxHeight: "33rem", overflowY: "auto" }}
            className="mt-2"
          >
            {sections.length > 0 ? (
              sections.map((data, index) => {
                const { section: sec, students: studs } = data;
                const slots = sec.capacity - studs.length;
                return (
                  <MDBListGroup
                    key={index}
                    className={index !== 0 ? "mt-1" : ""}
                    onDragOver={(e) => handleDragOver(e)} // Allow the drop
                    onDrop={(e) => handleDrop(e, { ...sec, slots })} //
                    onClick={() => handleView(studs, false, sec)}
                  >
                    <MDBListGroupItem className="d-flex justify-content-between align-items-start cursor-pointer">
                      <div>
                        <div className="font-weight-bold">
                          {sec.name.toUpperCase()}
                        </div>
                        {fullName(sec.adviser.fullName)}
                      </div>
                      <MDBBadge pill color="primary">
                        Slots {slots}
                      </MDBBadge>
                    </MDBListGroupItem>
                  </MDBListGroup>
                );
              })
            ) : (
              <MDBTypography
                variant="h2"
                className="mb-0 text-black mt-4"
                noteColor="danger"
                note
                noteTitle="No section: "
              >
                available for this grade level. Please inform the principal to
                create one before approving the student's enrollment.
              </MDBTypography>
            )}
          </div>
        ) : (
          <>
            {new Array(5).fill("").map((_, index) => {
              return (
                <MDBListGroup key={index} className={index !== 0 ? "mt-1" : ""}>
                  <MDBListGroupItem className="d-flex justify-content-between align-items-start cursor-pointer">
                    <div>
                      <div className="font-weight-bold mb-3">
                        {handleLoading()}
                      </div>
                      {handleLoading(180)}
                    </div>
                    {handleLoading(70)}
                  </MDBListGroupItem>
                </MDBListGroup>
              );
            })}
          </>
        )}
      </div>

      <ViewEnrollees
        toggle={toggle}
        show={show}
        enrollees={enrollees}
        isPending={isPending}
        section={section}
        setContainer={setContainer}
        container={params.container}
      />
    </>
  );
};

export default Sections;
