import React, { useEffect, useState } from "react";
import { MDBCard, MDBCardBody, MDBView } from "mdbreact";
import { useDispatch, useSelector } from "react-redux";
import {
  BROWSE,
  RESET,
} from "../../../../services/redux/slices/registrar/schedulers";
import { useToasts } from "react-toast-notifications";

import Search from "../../../../widgets/search";
import Modal from "./modal";
import Scheduler from "../../../../widgets/schedule";
import handleForm from "../../../../widgets/form";
import Level from "../../../../widgets/form/level";
import CustomSelect from "../../../../components/customSelect";
import { fullName } from "../../../../services/utilities";
import TableLoading from "../../../../widgets/tableLoading";
const { StoreDefualtValueForForm } = handleForm;
const _form = {
  levels: [],
  level: 0,
  specializations: [],
  specialization: "",
  strands: [],
  strand: "",
  semesters: [],
  semester: "",
  sections: [],
  section: "",
};

export default function Schedules() {
  const { token } = useSelector(({ auth }) => auth),
    {
      collections,
      message,
      isSuccess,
      scheduleIsLoading = false,
    } = useSelector(({ schedulers }) => schedulers),
    [schedulers, setSchedulers] = useState([]),
    [instructors, setInstructors] = useState([]),
    [instructor, setInstructor] = useState(""),
    [willCreate, setWillCreate] = useState(true),
    [show, setShow] = useState(false),
    [form, setForm] = useState(_form),
    [isPerInstructor, setIsPerInstructor] = useState(false),
    [didSearch, setDidSearch] = useState(false),
    dispatch = useDispatch(),
    { addToast } = useToasts();

  useEffect(() => {
    if (message) {
      addToast(message, {
        appearance: isSuccess ? "success" : "error",
      });
    }
  }, [isSuccess, message, addToast]);

  useEffect(() => {
    if (token) {
      dispatch(
        BROWSE({
          token,
        })
      );
    }
    return () => dispatch(RESET());
  }, [dispatch, token]);

  useEffect(() => {
    if (!isPerInstructor) {
      StoreDefualtValueForForm({
        form: {
          level: form.level,
          strand: form.strand,
          specialization: form.specialization,
          section: form.section,
          semester: form.semester,
        },
        setForm,
        collections,
        setArray: setSchedulers,
        isShowAll: false,
        isRegistrar: true,
      });
    }
  }, [
    collections,
    form.level,
    form.strand,
    form.specialization,
    form.section,
    form.semester,
    isPerInstructor,
  ]);

  useEffect(() => {
    if (collections.length > 0) {
      const _instructors = collections
        .filter(({ isBreakTime = false }) => !isBreakTime)
        .reduce((acc, curr) => {
          const { instructor } = curr;
          const key = instructor?._id;
          const index = acc.findIndex(({ key: _key }) => _key === key);
          if (index > -1) {
            acc[index].allSchedules.push(curr);
          } else {
            acc.push({ key, allSchedules: [curr], instructor });
          }

          return acc;
        }, []);

      setInstructors(_instructors);
    }
  }, [collections]);

  useEffect(() => {
    if (instructor && isPerInstructor) {
      const _instructors = [...instructors];
      const instructorScheds =
        _instructors.find(({ instructor: ins }) => ins._id === instructor)
          ?.allSchedules || [];
      setSchedulers(instructorScheds);
    }
  }, [instructor, isPerInstructor, instructors]);

  useEffect(() => {
    if (!isPerInstructor) {
      setIsPerInstructor("");
    } else {
      const _instructor = instructors[0]?.instructor;
      setInstructor(_instructor?._id);
    }
  }, [isPerInstructor, instructors]);

  const handleSearch = (e) => {
    e.preventDefault();

    const key = e.target.searchKey.value.toUpperCase();

    const result = collections.filter(({ student }) =>
      Object.values(student.fullName).some((value) =>
        value.toUpperCase().includes(key)
      )
    );
    setSchedulers(result);

    setDidSearch(true);
  };

  const handleUpdate = () => {
    setWillCreate(false);
    setShow(true);
  };

  return (
    <>
      <MDBCard narrow className="pb-3">
        <MDBView
          cascade
          className="gradient-card-header blue-gradient py-2 mx-4 d-flex justify-content-between align-items-center"
        >
          <span className="ml-3 ">
            <i>Schedule List</i>
          </span>
          <div>
            <input
              className="form-check-input"
              type="checkbox"
              checked={!isPerInstructor}
              onChange={() => setIsPerInstructor(!isPerInstructor)}
              id="gradeLevel"
            />
            <label htmlFor="gradeLevel" className="form-check-label mr-2 ">
              Grade Level
            </label>
            <input
              className="form-check-input"
              type="checkbox"
              checked={isPerInstructor}
              onChange={() => setIsPerInstructor(!isPerInstructor)}
              id="Instructor"
            />
            <label htmlFor="Instructor" className="form-check-label mr-2 ">
              Teacher
            </label>
          </div>

          <Search
            handleSearch={handleSearch}
            didSearch={didSearch}
            setDidSearch={setDidSearch}
            array={schedulers}
            setArray={setSchedulers}
            handleUpdate={handleUpdate}
            setShow={setShow}
          />
        </MDBView>
        <MDBCardBody className="m-0 p-0">
          {scheduleIsLoading ? (
            <div className="mt-4">
              <TableLoading />
            </div>
          ) : (
            <>
              {schedulers.length > 0 ? (
                <>
                  <div className="mb-0  mt-3 mx-3 mt-4">
                    {!isPerInstructor ? (
                      <Level
                        form={form}
                        setForm={setForm}
                        isRegistrar={true}
                        disabedICT={true}
                        disableSemester={true}
                        disableShowAll={true}
                      />
                    ) : (
                      <CustomSelect
                        className="m-0 p-0 text-center "
                        choices={instructors.map(({ instructor: ins }) => ({
                          _id: ins._id,
                          fullName: fullName(ins.fullName),
                        }))}
                        label={"Instructor"}
                        key={instructor}
                        values={"_id"}
                        preValue={instructor}
                        inputClassName="text-center"
                        optionClassName="text-center"
                        onChange={(value) => setInstructor(value)}
                        texts="fullName"
                      />
                    )}
                  </div>
                  <div className="mr-3 ml-3">
                    <Scheduler array={schedulers} isTeacher={isPerInstructor} />
                  </div>
                </>
              ) : (
                <h4 className="text-center">No Schedules.</h4>
              )}
            </>
          )}
        </MDBCardBody>
      </MDBCard>
      <Modal
        show={show}
        toggle={() => {
          if (!willCreate) {
            setWillCreate(true);
          }
          setShow(false);
        }}
        selected={form}
        schedulesUpdate={schedulers}
        willCreate={willCreate}
        setWillCreate={setWillCreate}
        collections={collections}
        previewForm={{
          lvl: form.level,
          strand: form.strand,
          specialization: form.specialization,
          semester: form.semester,
          section: form.section,
        }}
        isPerInstructor={isPerInstructor}
        instructor={
          isPerInstructor
            ? instructors.find(({ instructor: ins }) => ins._id === instructor)
                ?.instructor
            : {}
        }
      />
    </>
  );
}
