import React, { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import {
  MDBCard,
  MDBCardBody,
  MDBCol,
  MDBCardImage,
  MDBRow,
  MDBTypography,
} from "mdbreact";
import { BROWSE } from "../../../../services/redux/slices/student/credentials";
import Scheduler from "../../../../widgets/schedule";
import logo from "../../../../assets/logo/lmbnhs logo.png";
import deped from "../../../../assets/logo/deped.png";
import matatag from "../../../../assets/logo/matatag.png";
// import StudentChat from "../../../../widgets/studentChat";
const Schedule = () => {
  const { information, token } = useSelector(({ auth }) => auth),
    { collections } = useSelector(({ credentials }) => credentials),
    { enrolleeData } = information,
    { lvl = 7, section = {}, strand = "", batch = {} } = enrolleeData || {},
    { semester = "", sy = "" } = batch,
    [schedules, setSchedules] = useState([]),
    // [show, setShow] = useState(false),
    dispatch = useDispatch();

  // const toggle = () => setShow(!show);

  useEffect(() => {
    if (enrolleeData?.status === "APPROVED") {
      dispatch(
        BROWSE({
          token,
          data: {
            section: enrolleeData.section,
            semester: semester || "",
          },
        })
      );
    }
  }, [enrolleeData, token, dispatch, semester]);

  useEffect(() => {
    setSchedules(collections);
  }, [collections]);

  // useEffect(() => {
  //   const removeClass = "overflow-y-scroll";
  //   if (show) {
  //     document.body.classList.remove(removeClass);
  //   }

  //   return () => {
  //     document.body.classList.remove(removeClass);
  //   };
  // }, [show]);
  return (
    <div style={{ overflowY: "hidden !important" }}>
      <div className="vh-100">
        {enrolleeData?.status === "APPROVED" ? (
          <MDBCard>
            <MDBCardBody>
              <MDBRow className="m-0 p-0">
                <MDBCol className="d-flex justify-content-end">
                  <MDBCardImage src={logo} style={{ height: "100px" }} />
                </MDBCol>
                <MDBCol className="text-center" md="4">
                  <h5 className="m-0" style={{ fontFamily: "Times New Roman" }}>
                    Republic of the Philippines
                  </h5>
                  <h4 className="m-0" style={{ fontFamily: "Sans" }}>
                    Department of Education
                  </h4>
                  <h5 className="m-0">Region III</h5>
                  <h5>Division of Nueva Ecija</h5>
                  <h4
                    className="font-weight-bold mt-0 m-0 "
                    style={{ fontFamily: "Open Sans" }}
                  >
                    Leonor M. Bautista National High School
                  </h4>
                  <h5>General Tinio Nueva Ecija</h5>
                </MDBCol>
                <MDBCol className="d-flex flex-row">
                  <MDBCardImage src={deped} style={{ height: "100px" }} />
                  <MDBCardImage src={matatag} style={{ height: "110px" }} />
                </MDBCol>
              </MDBRow>
              <MDBRow className="mt-0">
                <MDBCol>
                  <h5 className="text-center mt-0 font-weight-bold">
                    Student Schedule
                  </h5>

                  <h6 className="text-center">
                    <strong>
                      Academic Year {sy}{" "}
                      {semester
                        ? semester === "1st"
                          ? "First Semester"
                          : "Second Semester"
                        : ""}
                    </strong>
                  </h6>
                </MDBCol>
              </MDBRow>
              <MDBRow>
                <MDBCol md="5" className="mr-5">
                  <h6>
                    <i>
                      Grade and Section:{" "}
                      <strong>
                        {strand ? strand : ""} {lvl}- {section.name}
                      </strong>{" "}
                    </i>
                  </h6>
                </MDBCol>
              </MDBRow>

              <Scheduler array={schedules} />
            </MDBCardBody>
          </MDBCard>
        ) : (
          <MDBCard className="text-center ">
            <MDBTypography
              className="mb-0 text-black-100"
              noteColor="warning"
              note
              noteTitle="Reminder: "
            >
              No schedule. Please wait until your request enrollment form is
              approved
            </MDBTypography>
          </MDBCard>
        )}
      </div>
      {/* <div
        style={{
          position: "sticky",
          marginRight: "-100px",
          float: "right",
          bottom: "-4px",
        }}
      >
        <MDBBtn
          className="d-flex align-items-center"
          color="white"
          onClick={toggle}
        >
          <MDBIcon
            icon="comments"
            style={{ color: "#007BFF" }}
            size="2x"
            className="mr-2"
          />{" "}
          <span className="font-weight-bold text-primary">Chat</span>
        </MDBBtn>
      </div> */}
      {/* <StudentChat show={show} toggle={toggle} /> */}
    </div>
  );
};

export default Schedule;
