import React, { useState } from "react";
import {
  MDBModal,
  MDBModalBody,
  MDBIcon,
  MDBModalHeader,
  MDBRow,
  MDBCol,
  MDBBtn,
  MDBTypography,
} from "mdbreact";
import MatchingType from "../../../../student/matchingType";
import Identification from "../viewQuestions/type/identification";
import MultiplceChoice from "../viewQuestions/type/multipleChoice";
import shuffle from "../../../../../../services/utilities/shuffle";
import { globalSearch } from "../../../../../../services/utilities";
const TYPES = [
  { text: "Multiple Choice", value: "mc" },
  { text: "Matching Type", value: "matching" },
  { text: "Identification", value: "identification" },
];
export default function AvailableQuestions({
  show = false,
  questions = [],
  collections = [],
  selectedQuestions = [],
  setSelectedQuestions = () => {},
  toggle = () => {},
  setQuestions = () => {},
  handleSelectQuestion = () => {},
}) {
  const [getQuestion, setGetQuestion] = useState(0);
  const [activeType, setActiveType] = useState("all");
  const [search, setSearch] = useState("");
  const [didSearch, setDidSearch] = useState(false);
  const handleFilter = (type) => {
    if (!type) {
      return setQuestions(collections);
    }

    const questionsFilterByType = collections.filter(
      ({ type: t }) => type === t
    );
    setQuestions(questionsFilterByType);
  };

  const handleGet = () => {
    if (!getQuestion) return false;
    const _questions = [...questions].filter(
      ({ _id }) =>
        !selectedQuestions.some(({ _id: existID }) => _id === existID)
    );
    const questionsFiltered = _questions.filter(
      ({ type }) => type === activeType
    );
    const questionsToShuffle =
      activeType === "all" ? _questions : questionsFiltered;

    const shuffleQuestions = shuffle(questionsToShuffle, getQuestion);

    setSelectedQuestions([...shuffleQuestions, ...selectedQuestions]);
    setGetQuestion(0);
  };

  const handleSearch = () => {
    if (!search) return false;
    if (!didSearch) {
      const key = search.toUpperCase();
      setQuestions(globalSearch(collections, key));
      setDidSearch(true);
    } else {
      setQuestions(collections);
      setSearch("");
      setDidSearch(false);
    }
  };
  return (
    <MDBModal
      isOpen={show}
      toggle={toggle}
      position="right"
      size="lg"
      fullHeight
    >
      <MDBModalHeader
        toggle={() => toggle()}
        className="light-blue darken-3 white-text"
      >
        <MDBIcon icon="clipboard-list" className="mr-2" />
        Questions
      </MDBModalHeader>
      <MDBModalBody className="mb-0">
        <MDBRow className="mb-4">
          <MDBCol>
            <div className="d-flex align-items-center">
              <input
                className="form-control"
                placeholder="Search Question"
                value={search}
                onChange={({ target }) => setSearch(target.value)}
              />
              <MDBBtn
                size="md"
                color="info"
                onClick={handleSearch}
                className="btn-search-question"
              >
                <MDBIcon icon={!didSearch ? "search" : "times"} />
              </MDBBtn>
            </div>
            <div className="mt-3 d-flex align-items-center justify-content-between">
              <div className="w-100 d-flex align-items-center">
                <div className="search-container">
                  <input
                    className="form-control"
                    value={String(getQuestion || "")}
                    onChange={({ target }) =>
                      setGetQuestion(Number(target.value))
                    }
                    placeholder="How many questions do you want to get?"
                  />
                  <div className="custom-select-wrapper">
                    <select
                      className="form-control"
                      value={activeType}
                      onChange={({ target }) => setActiveType(target.value)}
                    >
                      <option value={"all"}>Type</option>
                      <option value={"mc"}>Multiple Choice</option>
                      <option value={"matching"}>Matching Type</option>
                      <option value={"identification"}>Identification</option>
                    </select>
                  </div>
                </div>
                <MDBBtn
                  color="info"
                  size="md"
                  className="text-nowrap"
                  onClick={handleGet}
                >
                  GET
                </MDBBtn>
              </div>
              <div className="w-100 d-flex align-items-center justify-content-end ml-4">
                <span className="mr-2" style={{ fontWeight: 500 }}>
                  Filter By:
                </span>
                <select
                  className="form-control  w-50"
                  onChange={({ target }) => handleFilter(target.value)}
                >
                  <option value={""}>Type</option>
                  {TYPES.map((type, index) => (
                    <option key={index} value={type.value}>
                      {type.text}
                    </option>
                  ))}
                </select>
              </div>
            </div>
          </MDBCol>
        </MDBRow>
        <hr />
        <div style={{ scrollY: "auto", maxHeight: "auto" }}>
          {questions.length > 0 ? (
            questions.map((question, index) => (
              <React.Fragment key={index}>
                {question.type === "mc" ? (
                  <MultiplceChoice
                    question={question}
                    index={index}
                    isAdd={true}
                    selectedQuestions={selectedQuestions}
                    handleSelectQuestion={handleSelectQuestion}
                  />
                ) : question.type === "matching" ? (
                  <MatchingType
                    question={question}
                    index={index}
                    haveIndexOfQuestion={true}
                    isView={true}
                    isAdd={true}
                    selectedQuestions={selectedQuestions}
                    handleSelectQuestion={handleSelectQuestion}
                  />
                ) : (
                  <Identification
                    question={question}
                    isAdd={true}
                    selectedQuestions={selectedQuestions}
                    index={index}
                    handleSelectQuestion={handleSelectQuestion}
                  />
                )}
              </React.Fragment>
            ))
          ) : (
            <MDBTypography
              variant="h2"
              className="mb-0 text-black-100 text-center"
              noteColor="danger"
              note
            >
              {didSearch
                ? "No results found, try other keywords."
                : "No Available Questions"}
            </MDBTypography>
          )}
        </div>
      </MDBModalBody>
    </MDBModal>
  );
}
