import { MDBBtn, MDBIcon } from "mdbreact";
import React from "react";

const Footer = ({
  setPage = () => {},
  numberOfQuestions,
  page,
  handleSubmit,
}) => {
  const isLastQuestion = numberOfQuestions === page;
  return (
    <div className="d-flex justify-content-end">
      <MDBBtn
        color="primary"
        size="md"
        rounded
        onClick={() => {
          if (!isLastQuestion) {
            return setPage((prev) => prev + 1);
          }
          handleSubmit();
        }}
      >
        {!isLastQuestion ? "NEXT" : "FINISH"}
        <MDBIcon
          icon={isLastQuestion ? "flag" : "arrow-right"}
          className="ml-2"
        />
      </MDBBtn>
    </div>
  );
};

export default Footer;
