import React, { useCallback, useEffect, useRef, useState } from "react";
import { MDBAvatar, MDBCard, MDBCardHeader } from "mdbreact";
import "./modal.css";
import { useDispatch, useSelector } from "react-redux";
import { SAVE } from "../../services/redux/slices/messages";
import { socket } from "../../services/utilities";
import MessageInput from "./footer/messageInput";
import Replied from "./footer/replied";
import Content from "./content";

const Convo = ({
  receiver,
  height,
  baseMessages = [],
  isTyping,
  typingID = "",
  activeStudent,
  width = "900px",
}) => {
  const { auth, token } = useSelector(({ auth }) => auth);
  const [messages, setMessages] = useState([]);
  const [message, setMessage] = useState("");
  const [isReplied, setIsReplied] = useState(false);
  const [selectedMsg, setSelectedMsg] = useState({});
  const [images, setImages] = useState([]);
  const [haveMessages, setHaveMessages] = useState(true);
  const [chatNow, setChatNow] = useState(false);
  const [bounceMessage, setBounceMessage] = useState("");
  const [isScrolling, setIsScrolling] = useState(false);
  const [baseScrollTop, setBaseScrollTop] = useState(0);
  const chatContainerRef = useRef(null);
  const messageRef = useRef(null);
  const disptach = useDispatch();

  const handleFilter = useCallback((datas, latestIsSeen) => {
    const _messages = datas.filter(({ isSeen }) =>
      latestIsSeen ? isSeen : !isSeen
    );
    return _messages.length > 0
      ? _messages?.sort(
          (a, b) => new Date(b.createdAt) - new Date(a.createdAt)
        )[0] || {}
      : "";
  }, []);

  const handleUpdateMessagaes = useCallback((key, _id, _datas) => {
    const _messages = [..._datas];
    const index = _messages.findIndex(
      ({ _id: messageID }) => messageID === _id
    );
    _messages[index] = {
      ..._messages[index],
      [key]: true,
    };

    return _messages;
  }, []);

  const handlePutShowProfileSeen = useCallback(
    (datas = []) => {
      var _datas = [...datas];

      const latestMessageIsSeen = handleFilter(_datas, true);
      const latestMessageSent = handleFilter(_datas, false);
      if (latestMessageIsSeen) {
        _datas = handleUpdateMessagaes(
          "showProfileSeen",
          latestMessageIsSeen._id,
          _datas
        );
      }

      if (latestMessageSent) {
        _datas = handleUpdateMessagaes(
          "showSent",
          latestMessageSent._id,
          _datas
        );
      }
      setMessages(_datas);
    },
    [handleFilter, handleUpdateMessagaes]
  );

  useEffect(() => {
    const _chatContainer = chatContainerRef.current;

    const handleScroll = () => {
      const scroll = baseScrollTop - _chatContainer.scrollTop;
      if (scroll > 350) {
        setIsScrolling(true);
      } else {
        setIsScrolling(false);
      }
    };

    if (_chatContainer) {
      _chatContainer.addEventListener("scroll", handleScroll);
      handleScroll();
      return () => {
        _chatContainer.removeEventListener("scroll", handleScroll);
      };
    }
  }, [chatContainerRef, baseScrollTop]);

  useEffect(() => {
    if (auth._id && baseMessages.length > 0) {
      handlePutShowProfileSeen(baseMessages);
      setHaveMessages(true);
      setChatNow(true);
    } else {
      setHaveMessages(false);
      setChatNow(false);
    }
  }, [auth, handlePutShowProfileSeen, baseMessages]);

  useEffect(() => {
    setSelectedMsg({});
    setBounceMessage("");
    const timer = setTimeout(() => {
      if (chatContainerRef.current) {
        chatContainerRef.current.scrollTop =
          chatContainerRef.current.scrollHeight;
        setBaseScrollTop(chatContainerRef.current.scrollTop);
        setIsScrolling(false);
      }
    }, 0);

    return () => clearTimeout(timer);
  }, [baseMessages]);

  const scrollToReplyMessage = (message) => {
    const { _id } = message;
    if (chatContainerRef.current) {
      const allMessages =
        chatContainerRef.current.querySelectorAll(".highlight");
      allMessages.forEach((msg) => msg.classList.remove("highlight"));

      const messageElement = chatContainerRef.current.querySelector(
        `[data-message-id="${_id}"]`
      );
      if (messageElement) {
        const messageParagraph = messageElement.querySelector(
          `${message.isImage ? "div" : "p"}.message-highlight`
        );

        chatContainerRef.current.scrollTop =
          messageElement.offsetTop - chatContainerRef.current.offsetTop;

        setBounceMessage(_id);
        if (messageParagraph) {
          messageParagraph.classList.add("highlight");
        }
      } else {
        console.log("no have message for this messageID:", _id);
      }
    }
  };
  const handleResetReplied = () => {
    setIsReplied(false);
    setSelectedMsg({});
  };

  const handleScrollToBottom = () => {
    chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
  };

  const handleSendMessage = () => {
    disptach(
      SAVE({
        token,
        data: {
          sender: auth._id,
          receiver: receiver,
          text: message || "",
          ...(images.length > 0 && { isImage: true, images }),
          ...(isReplied && { replied: selectedMsg._id }),
        },
      })
    );
    setMessage("");
    setImages([]);
    handleResetReplied();
  };

  useEffect(() => {
    const trimmedMessage = message.trim();
    if (trimmedMessage && typingID) {
      socket.emit("send_isTyping", { typingID, isTyping: true });
    } else {
      socket.emit("send_isTyping", { typingID, isTyping: false });
    }
  }, [receiver, message, typingID]);

  useEffect(() => {
    setMessage("");
  }, [typingID]);

  const handleUploadImg = (event) => {
    const file = event.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const _images = [...images];
        _images.push(reader.result);
        setImages(_images);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSendDefaultMessage = () => {
    disptach(
      SAVE({
        token,
        data: {
          sender: "66aa902a495963b36ff59e7e",
          receiver: auth._id,
          text: "Hello, how can i help you",
        },
      })
    );
  };

  return (
    <MDBCard
      style={{
        height: height,
        display: "flex",
        borderRadius: "10px",
        justifyContent: "space-between",
      }}
    >
      {chatNow && (
        <MDBCardHeader className="bg-white text-dark font-weight-bold agent-card mt-2 m-1 p-0">
          <div className="active-student">
            <MDBAvatar
              src="https://mdbootstrap.com/img/Photos/Avatars/adach.jpg"
              alt="User mugshot"
              tag="img"
              style={{ height: "28px", width: "28px" }}
              circle
              className="float-left mr-2 avatar "
            />
            <p> {activeStudent}</p>
          </div>
        </MDBCardHeader>
      )}
      <Content
        chatContainerRef={chatContainerRef}
        handleScrollToBottom={handleScrollToBottom}
        haveMessages={haveMessages}
        isScrolling={isScrolling}
        scrollToReplyMessage={scrollToReplyMessage}
        messageRef={messageRef}
        bounceMessage={bounceMessage}
        height={height}
        setIsReplied={setIsReplied}
        setSelectedMsg={setSelectedMsg}
        auth={auth}
        isTyping={isTyping}
        messages={messages}
        chatNow={chatNow}
        setChatNow={setChatNow}
        handleSendDefaultMessage={handleSendDefaultMessage}
      />
      <Replied
        selectedMsg={selectedMsg}
        handleResetReplied={handleResetReplied}
      />
      {chatNow && (
        <MessageInput
          message={message}
          handleSendMessage={handleSendMessage}
          setMessage={setMessage}
          messageRef={messageRef}
          setImages={setImages}
          images={images}
          width={width}
          handleUploadImg={handleUploadImg}
        />
      )}
    </MDBCard>
  );
};

export default Convo;
