import React, { useEffect, useRef, useState } from "react";
import { MDBRow, MDBCol, MDBIcon, MDBStepper, MDBStep } from "mdbreact";
import "./steps.css";

/**
 * Steps component for displaying a step-by-step progress indicator.
 *
 * @param {number} activeStep - the currently active step
 * @param {Array} _steps - an array of steps with their details also dont forget to add a done key with a empty string value
 *   example of _steps array:
 *  const allSteps = [
 *     { "icon": "user", "step": 1, "done": "" },
 *     { "icon": "home", "step": 2, "done": "" },
 *     { "icon": "users", "step": 3, "done": "" },
 *     { "icon": "image", "step": 4, "done": "" },
 *     { "icon": "keyboard", "step": 5, "done": "" }
 *   ]
 * @param {number} numStep - number of steps to display at a time
 * @returns JSX element
 */

const Steps = ({ activeStep, _steps, numStep = 3, _onClick }) => {
  const [lastStep, setLastStep] = useState(1);
  const stepperRef = useRef(null);

  const getStepClassName = (stepNumber) => {
    if (activeStep === stepNumber) return "active";
    if (activeStep > stepNumber) return "completed";
    if (lastStep >= activeStep) return "current";
    return "";
  };

  useEffect(() => {
    if (activeStep > lastStep) {
      setLastStep(activeStep);
    }
  }, [activeStep, lastStep]);

  useEffect(() => {
    const scrollToStep = (stepIndex) => {
      const stepper = stepperRef.current;
      const stepWidth = stepper.scrollWidth / _steps.length;
      const scrollPosition = Math.max(0, stepWidth * (stepIndex - Math.ceil(numStep / 2)));
  
      stepper.scrollTo({
        left: scrollPosition,
        behavior: "smooth",
      });
    };

    if(activeStep) {
      scrollToStep(activeStep);
    }
   
  }, [activeStep, _steps.length, numStep]);

  const renderDots = () => {
    return Array.from({ length: _steps.length }, (_, i) => (
      <span
        key={i}
        className={`dot ${i === (activeStep -1) ? "active" : ""}`}
        onClick={() => { _onClick(_steps[i].step) }}
      />
    ));
  };

  return (
    <>
      <MDBRow className="p-0">
        <MDBCol md="12" className="d-flex justify-content-center p-0">
            <MDBStepper className="m-0 p-0">
              <div
                className="scroll-container"
                ref={stepperRef}
                style={{ overflowX: "scroll", whiteSpace: "nowrap" }}
              >
                {_steps.map((step, index, stepsArr) => (
                  <React.Fragment key={index}>
                    <MDBStep className={getStepClassName(step.step)}>
                      <a
                        href="#!"
                        onClick={(e) => {
                          e.preventDefault()
                          _onClick(step.step)
                        }}
                        className="icon-cont p-0 pt-2"
                        style={{ lineHeight: "1", overflow: "hidden" }}
                      >
                        {_steps[step.step - 1].done && (
                          <span className="small-circle">
                            <MDBIcon
                              icon="check"
                              style={{ fontSize: "7px" }}
                            ></MDBIcon>
                          </span>
                        )}

                        {_steps[step.step - 1].done === false &&
                        lastStep >= step.step ? (
                          <span className="circle" style={{ color: "red" }}>
                            <MDBIcon
                              icon="exclamation-triangle"
                              style={{ fontSize: "12px" }}
                            ></MDBIcon>
                          </span>
                        ) : (
                          <span className="circle">
                            <MDBIcon
                              icon={step.icon}
                              style={{ fontSize: "15px" }}
                            ></MDBIcon>
                          </span>
                        )}

                        <br />
                        <span className="step-label">Step {step.step}</span>
                      </a>
                    </MDBStep>

                    {index + 1 < stepsArr.length && (
                      <div
                        className={`step-line ${
                          lastStep > step.step ? "glow-line" : ""
                        }`}
                      ></div>
                    )}
                  </React.Fragment>
                ))}
              </div>
            </MDBStepper>
        </MDBCol>
      </MDBRow>
      <MDBRow className="d-flex w-100 m-0">
        <MDBCol className="d-flex flex-row justify-content-end align-items-center dots-main-container" style={{height: "1rem"}}>
          {_steps.length > 4 && (
          <div className="dots-container d-flex flex-row">{renderDots()}</div>
          )}
        </MDBCol>
      </MDBRow>
    </>
  );
};

export default Steps;