import React, { useEffect, useState } from "react";
import { MDBBtn, MDBBtnGroup, MDBIcon, MDBTable } from "mdbreact";
import { useDispatch, useSelector } from "react-redux";
import {
  formattedDate,
  fullName,
  handlePagination,
} from "../../../../services/utilities";
import {
  UPDATE,
  RESET,
  CHANGESECTION,
  DROP,
} from "../../../../services/redux/slices/admission/enrollees";
import Swal from "sweetalert2";
import "./sections.css";

import handleMultiSeclect from "../../../../widgets/multipleSelect";
import Rows from "../../../../widgets/pagination/rows";
import PaginationButtons from "../../../../widgets/pagination/buttons";
import SORTING from "../../../../widgets/sorting";
// import APPROVED from "../../../../widgets/desicionForEnrollees/approved";
import Modal from "./modal";
// import CEO from "../coe/download";

const Table = ({
  lvlKey,
  enrollees = [],
  setContainer,
  container,
  isSelectAll,
  setIsSelectAll,
  activeId,
  didSearch,
  isSection,
  setIsView,
  setSelected,
  // divisions,
  handleDragEnd,
  handleDragStart,
  isDragging = false,
  props,
  isShowAll,
  sections = [],
}) => {
  const { token, auth, information } = useSelector(({ auth }) => auth),
    [show, setShow] = useState(false),
    [selectedEnrollee, setSelectedEnrollee] = useState({}),
    [max, setMax] = useState(5),
    [page, setPage] = useState(1),
    [storageEnrollees, setStorageEnrollees] = useState([]),
    dispatch = useDispatch(),
    { previousBatches } = information,
    [openMenuRow, setOpenMenuRow] = useState(null),
    toggleMenu = (id) => {
      setOpenMenuRow((prev) => (prev === id ? null : id));
    };

  const batch = previousBatches.find(({ status }) => status !== "DONE");
  useEffect(() => {
    if (isSelectAll) {
      if (didSearch) {
        setContainer(enrollees);
      } else {
        setContainer(enrollees);
      }
    } else {
      setContainer((prev) => (prev.length === enrollees.length ? [] : prev));
    }
    setStorageEnrollees(SORTING(enrollees));
  }, [isSelectAll, enrollees, setContainer, didSearch, activeId]);

  useEffect(() => {
    if (isShowAll) {
      dispatch(RESET());
    }
  }, [dispatch, isShowAll]);

  const toggle = () => setShow(!show);

  const handleReject = (selected) => {
    Swal.fire({
      title: "Are you sure?",
      text: "You want to reject this student?",
      icon: "warning",
      input: "textarea", // Adding textarea input
      inputPlaceholder: "Enter your reason here...",
      inputValidator: (value) => {
        if (!value) {
          return "You need to provide a reason!";
        }
      },
      showCancelButton: true,
      confirmButtonColor: "#3085d6",
      cancelButtonColor: "#d33",
      confirmButtonText: "Yes, Reject it!",
    }).then((res) => {
      if (res.isConfirmed) {
        const rejectionReason = res.value;
        dispatch(
          UPDATE({
            token,
            data: {
              enrollees: [
                {
                  _id: selected.enrolleeId,
                  status: "REJECT",
                  registrar: { approvedBy: auth._id, message: rejectionReason },
                },
              ],
            },
          })
        );
      }
    });
  };

  const handleDisableMultipleSelect = (isShowAll, props) => {
    const _isShowAll = !isShowAll;

    if (!_isShowAll || props !== "PENDING") return false;
  };
  const handleDrop = (student) => {
    Swal.fire({
      title: "Are you sure?",
      text: "Please provide a reason for dropping this student.",
      icon: "warning",
      input: "textarea", // Adding textarea input
      inputPlaceholder: "Enter your reason here...",
      inputValidator: (value) => {
        if (!value) {
          return "You need to provide a reason!";
        }
      },
      showCancelButton: true,
      confirmButtonColor: "#3085d6",
      cancelButtonColor: "#d33",
      confirmButtonText: "Yes, Drop it!",
    }).then((result) => {
      if (result.isConfirmed) {
        const reason = result.value; // Get the reason from the textarea
        dispatch(
          DROP({
            data: {
              student,
              registrar: auth._id,
              date: formattedDate(),
              reason, // Include the reason in the data
            },
            token,
          })
        );
        Swal.fire({
          title: "Success!",
          text: "Student dropped successfully.",
          icon: "success",
        });
      }
    });
  };

  const handleNewTab = (student, section, batch) => {
    if (typeof window !== "undefined" && window.screen) {
      localStorage.setItem(
        "printOut",
        JSON.stringify({ student, section, batch })
      );
      window.open(
        "/CEO",
        "Claim Stub",
        `top=0,left=0,width=${window.screen.width},height=${window.screen.height},fullscreen=yes`
      );
    } else {
      console.log("Screen size not available");
    }
  };

  const handleChangeSection = (enrollee) => {
    const sectionOptions = sections
      .map(({ section }) => section)
      .filter(({ _id }) => _id !== enrollee?.section?._id)
      .map(
        (section) => `<option value="${section._id}">${section.name}</option>`
      )
      .join("");

    Swal.fire({
      title: `<strong>Change Section</strong>`,
      html: `
        <div style="text-align: left; margin-bottom: 15px;">
          <p style="font-size: 16px; font-weight: 500; color: #333;">
            Student: <span style="font-weight: bold; color: #007bff;">${fullName(
              enrollee.student.fullName
            )}</span>
          </p>
            <p style="font-size: 16px; font-weight: 500; color: #333;">
            Current Section: <span style="font-weight: bold; color: #007bff;">${
              enrollee?.section?.name
            }</span>
          </p>
          <label for="sectionSelect" style="font-size: 14px; font-weight: bold; display: block; margin-bottom: 8px; color: #555;">
            Select a Section:
          </label>
          <select 
            class=" form-control float-left" 
            id="sectionSelect"
          >
            <option value="">-- Choose a section --</option>
            ${sectionOptions}
          </select>
        </div>
      `,
      showCancelButton: true,
      confirmButtonText: "Save",
      cancelButtonText: "Cancel",
      customClass: {
        confirmButton: "btn btn-primary",
        cancelButton: "btn btn-light",
      },
      buttonsStyling: false,
      preConfirm: () => {
        const selectedSection = document.getElementById("sectionSelect").value;
        if (!selectedSection) {
          Swal.showValidationMessage(
            `<span style="color: red;">Please select a section!</span>`
          );
          return null;
        }
        return selectedSection;
      },
    }).then((result) => {
      if (result.isConfirmed) {
        const selectedSection = result.value;
        const { enrolleeId } = enrollee;
        dispatch(
          CHANGESECTION({
            token,
            data: { enrolleeId, section: selectedSection },
          })
        );

        Swal.fire({
          icon: "success",
          title: "Successfully Changed Section",
          confirmButtonText: "Ok",
        });
      }
    });
  };

  console.log(enrollees);

  return (
    <>
      <MDBTable
        responsive
        hover
        key={`collapse-${lvlKey}`}
        className="overflow-hidden "
      >
        <thead>
          <tr>
            <th key={lvlKey}>
              <input
                className="form-check-input"
                type="checkbox"
                disabled={isShowAll || props !== "PENDING"}
                checked={isSelectAll}
                onChange={() => setIsSelectAll(!isSelectAll)}
                id={`collapse-${lvlKey}`}
              />
              <label
                htmlFor={`collapse-${lvlKey}`}
                className="form-check-label mr-2 label-table"
              />
            </th>
            <th className="th-lg cursor-pointer">
              Name&nbsp;
              <MDBIcon icon="sort" title="Sort by Name" />
            </th>
            <th className="th-lg">Grade Level</th>
            {isSection && <th>Section</th>}
            <th className="text-center">Action</th>
          </tr>
        </thead>
        <tbody>
          {storageEnrollees.length > 0 ? (
            handlePagination(storageEnrollees, page, max)
              ?.filter(({ wasDrop = false }) => wasDrop === false)
              .map((enrollee, index) => {
                const {
                  _id,
                  lvl,
                  strand,
                  student,
                  enrolleeId,
                  section = {},
                  isICT = false,
                } = enrollee;
                const isChecked =
                  isSelectAll ||
                  container.some(({ _id }) => _id === enrollee._id);

                return (
                  <tr
                    key={`${enrolleeId}-${lvlKey}`}
                    draggable={props === "PENDING"}
                    onDragStart={(e) => handleDragStart(e, enrollee)}
                    onDragEnd={handleDragEnd}
                    className={isDragging ? "cursor-grabbing" : "cursor-grab"}
                  >
                    <td>
                      <input
                        className="form-check-input"
                        type="checkbox"
                        id={_id}
                        checked={isChecked}
                        onChange={() => {
                          setContainer(
                            handleMultiSeclect(
                              container,
                              enrollee,
                              handleDisableMultipleSelect(isShowAll, props)
                            )
                          );
                          setIsSelectAll(false);
                        }}
                      />
                      <label
                        htmlFor={_id}
                        className="form-check-label mr-2 label-table"
                      />
                    </td>
                    <td style={{ fontWeight: 400 }}>
                      {fullName(student.fullName)}
                    </td>
                    <td style={{ fontWeight: 400 }}>{`Grade - ${lvl} ${
                      isICT ? ", ICT" : ""
                    } ${lvl > 10 ? `, ${strand}` : ""}`}</td>

                    {isSection && (
                      <td style={{ fontWeight: 400 }}>{section.name}</td>
                    )}
                    <td className="d-flex justify-content-center">
                      {props === "PENDING" ? (
                        <MDBBtnGroup>
                          <MDBBtn
                            size="sm"
                            rounded
                            color="yellow"
                            title="View"
                            onClick={() => {
                              setSelected(enrollee);
                              setIsView(true);
                            }}
                          >
                            <MDBIcon icon="eye" />
                          </MDBBtn>
                          {/* <MDBBtn
                            size="sm"
                            rounded
                            color="primary"
                            title="Approved"
                            onClick={() => {
                              setSelectedEnrollee(enrollee);
                              setShow(true);
                            }}
                          >
                            <MDBIcon icon="user-check" />
                          </MDBBtn> */}
                          <MDBBtn
                            size="sm"
                            title="Reject"
                            rounded
                            color="danger"
                            onClick={() => handleReject(enrollee)}
                          >
                            <MDBIcon icon="user-times" />
                          </MDBBtn>
                        </MDBBtnGroup>
                      ) : props === "APPROVED" ? (
                        <div style={{ position: "relative" }}>
                          <MDBBtn
                            size="sm"
                            rounded
                            color="light"
                            onClick={() => {
                              toggleMenu(enrolleeId);
                              console.log(
                                index === storageEnrollees.length - 1
                              );
                            }}
                            style={{ transition: "transform 0.3s ease-in-out" }}
                          >
                            <i
                              className={`fas ${
                                openMenuRow === enrolleeId
                                  ? "fa-times"
                                  : "fa-ellipsis-v"
                              }`}
                            ></i>
                          </MDBBtn>

                          {openMenuRow === enrolleeId && (
                            <div
                              className="_dropdown-menu show"
                              style={{
                                position: "absolute",
                                zIndex: 1050,
                                animation: "fadeIn 0.3s ease-in-out",
                              }}
                            >
                              <MDBBtnGroup vertical className="w-100">
                                <MDBBtn
                                  size="sm"
                                  title="View"
                                  color="primary"
                                  className="mx-0 text-left"
                                  onClick={() => {
                                    setSelected(enrollee);
                                    setIsView(true);
                                    setOpenMenuRow(null);
                                  }}
                                >
                                  <i className="fas fa-eye  mr-1"></i> View
                                </MDBBtn>
                                <MDBBtn
                                  size="sm"
                                  title="Change Section"
                                  color="primary"
                                  className="mx-0 text-left"
                                  onClick={() => {
                                    handleChangeSection(enrollee);
                                    // setShow(true);
                                    setOpenMenuRow(null);
                                  }}
                                >
                                  <i className="fas fa-window-restore  mr-1"></i>{" "}
                                  Change Section
                                </MDBBtn>
                                <MDBBtn
                                  size="sm"
                                  title="Certificate of Enrollment"
                                  color="primary"
                                  className="mx-0 text-left"
                                  onClick={() => {
                                    handleNewTab(student, section, batch.sy);
                                    setOpenMenuRow(null);
                                  }}
                                >
                                  <i className="fas fa-scroll  mr-1"></i>{" "}
                                  Certificate
                                </MDBBtn>
                                <MDBBtn
                                  size="sm"
                                  title="Drop"
                                  color="primary"
                                  className="mx-0 text-left"
                                  onClick={() => {
                                    handleDrop(enrollee);
                                    setOpenMenuRow(null);
                                  }}
                                >
                                  <i className="fas fa-user-times mr-1"></i>{" "}
                                  Drop
                                </MDBBtn>
                              </MDBBtnGroup>
                            </div>
                          )}
                        </div>
                      ) : (
                        <MDBBtnGroup>
                          <MDBBtn
                            size="sm"
                            rounded
                            color="yellow"
                            title="View"
                            onClick={() => {
                              setSelected(enrollee);
                              setIsView(true);
                            }}
                          >
                            <MDBIcon icon="eye" />
                          </MDBBtn>
                        </MDBBtnGroup>
                      )}
                    </td>
                  </tr>
                );
              })
          ) : (
            <tr>
              <td>No Records</td>
            </tr>
          )}
        </tbody>
      </MDBTable>
      <Rows max={max} setMax={setMax} />
      <Modal
        show={show}
        toggle={toggle}
        selected={selectedEnrollee}
        status={props}
      />
      <PaginationButtons
        page={page}
        setPage={setPage}
        max={max}
        array={storageEnrollees}
      />
    </>
  );
};

export default Table;
