import { MDBBadge, MDBProgress } from "mdbreact";
import React, { useEffect, useState } from "react";

const Header = ({
  page,
  exam,
  numberOfQuestions = 0,
  setPage = () => {},
  setIsFinish = () => {},
}) => {
  const [timeLeft, setTimeLeft] = useState(0),
    [duration, setDuration] = useState(0),
    [progressTimeLeft, setProgressTimeLeft] = useState(100),
    [hasSetTimeLeft, setHasSetTimeLeft] = useState(false);

  useEffect(() => {
    setDuration(exam.duration);
  }, [exam]);

  useEffect(() => {
    if (timeLeft <= 0 && hasSetTimeLeft) {
      const hasIncrease = numberOfQuestions !== page;

      setPage((prev) => (hasIncrease ? prev + 1 : prev));
    }

    if (duration) {
      const intervalId = setInterval(() => {
        if (timeLeft > 0) {
          setTimeLeft((prev) => prev - 1);
        } else {
          clearInterval(intervalId);
        }
      }, 1000);
      const decreaseInInterval = duration < 30 ? 3 : 49.000000000000000000999;
      const progressIntervalTime = 1000 / (100 / duration) - decreaseInInterval; //if lower than slow
      const progressIntervalId = setInterval(() => {
        setProgressTimeLeft((prev) => (prev > 0 ? prev - 1 : 0));
      }, progressIntervalTime);
      return () => {
        clearInterval(intervalId);
        clearInterval(progressIntervalId);
      };
    }
  }, [timeLeft, duration, numberOfQuestions, page, hasSetTimeLeft, setPage]);

  useEffect(() => {
    if (page === numberOfQuestions && timeLeft === 0) {
      setIsFinish(true);
    }
  }, [page, timeLeft, numberOfQuestions, setIsFinish]);

  useEffect(() => {
    if (duration) {
      setTimeLeft(duration);
      setProgressTimeLeft(100);
      setHasSetTimeLeft(true);
    }
  }, [page, duration]);

  return (
    <>
      <div className="d-flex justify-content-between">
        <h6 style={{ fontWeight: "500" }}>
          Duration:
          <span
            className="ml-1"
            // className={
            //   timeLeft <= 10 ? "text-danger ml-1" : "text-success ml-1"
            // }
          >
            {timeLeft} seconds
          </span>
        </h6>
        <MDBBadge pill color="info" className="d-flex align-items-center">
          <span>
            {page}/{numberOfQuestions}
          </span>
        </MDBBadge>
      </div>
      <div className="mt-2">
        <MDBProgress
          value={duration === timeLeft ? 100 : progressTimeLeft}
          color={progressTimeLeft <= 30 ? "danger" : "primary"}
          striped
          id="progress-exam"
        />
      </div>
    </>
  );
};

export default Header;
