import React from "react";
import { MDBModal, MDBModalBody, MDBIcon, MDBModalHeader } from "mdbreact";
import { fullName } from "../../../../services/utilities";

export default function Reason({ show, toggle, selected }) {
  return (
    <MDBModal isOpen={show} toggle={toggle} backdrop disableFocusTrap={false}>
      <MDBModalHeader
        toggle={toggle}
        className="light-blue darken-3 white-text"
      >
        <MDBIcon icon="user" className="mr-2" />
        {fullName(selected.student?.fullName)}
      </MDBModalHeader>
      <MDBModalBody className="mb-0">
        <h5>{selected.reasonForDrop}</h5>
      </MDBModalBody>
    </MDBModal>
  );
}
