import answerSanitizer from "../../../../../../../../services/utilities/answerSanitizer";

const answerIsCorrect = (question) => {
  const { answer = "", correctAnswer = "", type = "", answers = [] } = question;

  if (type !== "matching") {
    return answerSanitizer(answer) === answerSanitizer(correctAnswer);
  } else {
    const questionWithoutConfusing = [...answers].filter(
      ({ isConfusing = false }) => !isConfusing
    );

    return questionWithoutConfusing.every(
      ({ textB = "", answer = "" }) =>
        answerSanitizer(answer) === answerSanitizer(textB)
    );
  }
};

export default answerIsCorrect;
