import React, { useEffect, useState } from "react";
import {
  MDBBtn,
  MDBCard,
  MDBCardBody,
  MDBCol,
  MDBIcon,
  MDBRow,
  MDBView,
} from "mdbreact";
import { useDispatch, useSelector } from "react-redux";
import { GET_QUESTIONS } from "../../../../../../services/redux/slices/registrar/entranceExam";
import AvailableQuestions from "./availableQuestions";
import MatchingType from "../../../../student/matchingType";
import MultipleChoice from "../viewQuestions/type/multipleChoice";
import Identification from "../viewQuestions/type/identification";
import Details from "../details";
import TypesCount from "../typesCount";
import Swal from "sweetalert2";
const DEPARTMENT = {
  SHS: "Senior High School",
  JHS: "Junior High School",
};
const SelectQuestions = ({
  selectedDepartment = "jhs",
  willCreate = false,
  selected = {},
  toggle = () => {},
}) => {
  const { token, information } = useSelector(({ auth }) => auth),
    { questions: collections } = useSelector(
      ({ entranceExam }) => entranceExam
    ),
    [questions, setQuestions] = useState([]),
    [selectedQuestions, setSelectedQuestions] = useState([]),
    [activeBatch, setActiveBatch] = useState({}),
    [show, setShow] = useState(true),
    [showDetails, setShowDetails] = useState(false),
    dispatch = useDispatch();

  useEffect(() => {
    dispatch(GET_QUESTIONS({ token, key: { department: selectedDepartment } }));
  }, [dispatch, token, selectedDepartment]);

  useEffect(() => {
    setQuestions(collections);
  }, [collections]);

  useEffect(() => {
    if (!willCreate) {
      setSelectedQuestions(selected.questions);
      setShow(false);
    } else {
      setSelectedQuestions([]);
    }
  }, [willCreate, selected]);

  useEffect(() => {
    const _batches = [...information.previousBatches];
    const _activeBatch = _batches.find(
      ({ progress = "", status = "" }) =>
        progress === selectedDepartment.toLowerCase() &&
        status !== "DONE" &&
        status !== "PENDING"
    );

    setActiveBatch(_activeBatch);
  }, [information, selectedDepartment]);

  const handleSelectQuestion = (question) => {
    const _selectedQuestions = [...selectedQuestions];
    const index = _selectedQuestions.findIndex(
      ({ _id }) => _id === question._id
    );
    if (index > -1) {
      _selectedQuestions.splice(index, 1);
    } else {
      _selectedQuestions.unshift(question);
    }

    setSelectedQuestions(_selectedQuestions);
  };

  const handleDelete = (index) => {
    Swal.fire({
      title: "Are you sure?",
      text: "Do you want to delete this question?",
      icon: "warning",
      showCancelButton: true,
      confirmButtonColor: "#3085d6",
      cancelButtonColor: "#d33",
      confirmButtonText: "Yes, delete it!",
      cancelButtonText: "Cancel",
    }).then((result) => {
      if (result.isConfirmed) {
        const _selectedQuestions = [...selectedQuestions];
        _selectedQuestions.splice(index, 1);
        setSelectedQuestions(_selectedQuestions);
      }
    });
  };

  const handlePublish = () => {
    if (selectedQuestions.length <= 9) {
      return Swal.fire({
        icon: "warning",
        title: "Warning",
        text: "You need to select more than 10 questions before publishing the entrance exam.",
        confirmButtonColor: "#3085d6",
        confirmButtonText: "OK",
      });
    }

    setShowDetails(true);
  };

  return (
    <>
      <MDBCard narrow className="pb-3">
        <MDBView
          cascade
          className="gradient-card-header blue-gradient py-2 mx-4 d-flex justify-content-between align-items-center"
        >
          <MDBIcon
            icon="chevron-left "
            size="1x"
            className="cursor-pointer"
            onClick={() => toggle()}
          />
          <div>
            <h4 style={{ fontFamily: "Times New Roman" }}>
              <strong>
                Entrance Exam for {DEPARTMENT[selectedDepartment]}
              </strong>
            </h4>
            <h6 style={{ fontFamily: "Times New Roman" }}>
              SY {activeBatch?.sy}
            </h6>
          </div>

          <div className="cursor-pointer" onClick={handlePublish}>
            <MDBIcon
              icon={willCreate ? "save" : "pencil-alt"}
              className="mr-2"
            />
            <strong> {willCreate ? "Publish" : "Update"}</strong>
          </div>
        </MDBView>
        <MDBCardBody>
          {selectedQuestions.length > 0 && (
            <div className="ml-5 mr-5 mt-1">
              <MDBRow>
                <MDBCol md="12">
                  <TypesCount
                    questions={selectedQuestions}
                    toggle={() => setShow(true)}
                    isAdd={true}
                  />
                </MDBCol>
              </MDBRow>
            </div>
          )}
          <hr className="ml-5 mr-5" />

          {!!selectedQuestions && (
            <div className="ml-5 mr-5">
              {selectedQuestions.map((question, index) => (
                <MDBRow key={index}>
                  <MDBCol md="10">
                    {question.type === "mc" ? (
                      <MultipleChoice question={question} index={index} />
                    ) : question.type === "matching" ? (
                      <MatchingType
                        question={question}
                        index={index}
                        haveIndexOfQuestion={true}
                        isAdd={false}
                        isView={true}
                      />
                    ) : (
                      <Identification question={question} index={index} />
                    )}
                  </MDBCol>
                  <MDBCol md="2">
                    <MDBBtn
                      color="danger"
                      size="sm"
                      rounded
                      className="float-right"
                      onClick={() => handleDelete(index)}
                    >
                      <MDBIcon icon="trash" />
                    </MDBBtn>
                  </MDBCol>
                </MDBRow>
              ))}
            </div>
          )}
          {selectedQuestions.length === 0 && (
            <div className="text-center mt-3">
              <MDBBtn color="info" size="md" onClick={() => setShow(true)}>
                <MDBIcon icon="plus" className="mr-2" /> Add Question
              </MDBBtn>
            </div>
          )}
        </MDBCardBody>
      </MDBCard>

      <AvailableQuestions
        show={show}
        handleSelectQuestion={handleSelectQuestion}
        toggle={() => setShow(false)}
        questions={questions}
        selectedQuestions={selectedQuestions}
        setSelectedQuestions={setSelectedQuestions}
        setQuestions={setQuestions}
        collections={collections}
      />

      <Details
        toggle={() => setShowDetails(false)}
        show={showDetails}
        willCreate={willCreate}
        selected={selected}
        mainToggle={toggle}
        questions={selectedQuestions}
        activeBatch={activeBatch}
        selectedDepartment={selectedDepartment}
      />
    </>
  );
};

export default SelectQuestions;
