import React, { useEffect, useRef, useState } from "react";
import {
  MDBAvatar,
  MDBBtn,
  MDBCard,
  MDBCardBody,
  MDBCol,
  MDBIcon,
  MDBRow,
} from "mdbreact";
import logo from "../../assets/logo/logo.png";
import deped from "../../assets/logo/deped.png";
import matatag from "../../assets/logo/matatag.png";
import "./coe.css";
import PDF from "./PDF";
import currentDate from "./currentDate";
import { fullName } from "../../services/utilities";

const COE = () => {
  const [params, setParams] = useState({});
  const cardRef = useRef();
  const { student, section, batch } = params || {};

  const handlePrint = () => window.print();

  const handlePDF = () => {
    PDF(fullName(student.fullName), section, batch);
  };

  useEffect(() => {
    const printOutData = localStorage.getItem("printOut");
    if (printOutData) {
      const parseData = JSON.parse(printOutData);
      setParams(parseData);
    }
  }, []);

  return (
    <MDBRow
      className="d-flex justify-content-center"
      style={{ overFlowX: "hidden" }}
    >
      <MDBCol md="9" className="d-flex justify-content-center flex-column">
        <div
          className="d-flex justify-content-center mt-1 buttons"
          ref={cardRef}
        >
          <MDBBtn
            size="sm"
            color="primary"
            className="font-weight-bold"
            onClick={handlePDF}
          >
            <MDBIcon icon="file-pdf" className="mr-3" />
            Generate PDF
          </MDBBtn>
          <MDBBtn
            size="sm"
            color="info"
            className="font-weight-bold ml-5"
            onClick={handlePrint}
          >
            <MDBIcon icon="print" className="mr-3" />
            Print COE
          </MDBBtn>
        </div>
        <MDBCard className="ceo-card">
          <MDBCardBody>
            <MDBRow>
              <MDBCol md="3">
                <div className="logo-1">
                  <MDBAvatar
                    tag="img"
                    src={logo}
                    alt="Danny Collins"
                    className=" float-right mr-4 mt-3 leonors-logo"
                    style={{ width: "5rem" }}
                  />
                </div>
              </MDBCol>
              <MDBCol md="6" className="text-center">
                <div style={{ lineHeight: "4rem", margin: "0" }}>
                  <h5
                    className="m-0 republic-font "
                    style={{ fontFamily: "Old English Text MT" }}
                  >
                    Republic of the Philippines
                  </h5>
                  <h4
                    className="m-0 department-font"
                    style={{ fontFamily: "Old English Text MT" }}
                  >
                    Department of Education
                  </h4>
                  <h6
                    className="mt-0 font-weight-bold region-font"
                    style={{ fontFamily: "Times New Roman" }}
                  >
                    Region III
                  </h6>
                  <h6
                    className="mt-0 font-weight-bold division-font"
                    style={{ fontFamily: "Times New Roman" }}
                  >
                    Division of nueva ecija
                  </h6>
                  <h3
                    className="mt-0 font-weight-bold leonor-font"
                    style={{ fontFamily: "Times New Roman" }}
                  >
                    Leonor M. Bautista National High School
                  </h3>
                  <h6
                    className="mt-0 font-weight-bold ne-font"
                    style={{ fontFamily: "Times New Roman" }}
                  >
                    General Tinio Nueva Ecija
                  </h6>
                </div>
              </MDBCol>
              <MDBCol md="3">
                <div className="logo-2">
                  <MDBAvatar
                    tag="img"
                    src={deped}
                    alt="Danny Collins "
                    className="mt-3 deped-logo"
                    style={{ width: "5rem" }}
                  />
                  <img
                    tag="img"
                    src={matatag}
                    alt="Danny Collins"
                    className="mt-3 matatag-logo"
                    style={{ width: "5rem" }}
                  />
                </div>
              </MDBCol>
            </MDBRow>

            <h4
              className="text-center mt-4 font-weight-bold ceo-header-font"
              style={{ fontFamily: "Times New Roman" }}
            >
              CERTIFICATE OF ENROLLMENT
            </h4>
            <div
              style={{
                width: "70%",
                margin: "auto",
                textAlign: "center",
                padding: "20px",
              }}
            >
              <h6 className="ml-fRow ceo-font text-nowrap mt-3">
                This is to certify that according to the records of this office
                <span
                  className="ml-2"
                  style={{ fontWeight: "bold", textTransform: "uppercase" }}
                >
                  {fullName(student?.fullName)}
                </span>
              </h6>
              <h6 className="text-left ml-sRow   ceo-font">
                of Grade-{section?.lvl}
                {section?.strand ? ` , ${section?.strand}` : ""},{" "}
                {section?.name} is enrolled for School Year {batch}
              </h6>

              <h6 className="ml-tRow ceo-font mt-5 ">
                This certification is issued upon the request of the berien
                interested party for whatever
              </h6>

              <h6 className="text-left ml-sRow ceo-font">
                legal purpose it may serve.
              </h6>

              <h6 className="ml-lRow ceo-font mt-5 ">
                Issued this {currentDate()} at Leonor M. Bautista National.
              </h6>
              <div className="adviser-container">
                <h6 className="adviser">
                  {fullName(section?.adviser?.fullName)}
                </h6>
                <h6 className="adviser-label">Adviser</h6>
              </div>
              <h6 className="notedBy">Noted By:</h6>
              <div className="principal-container">
                <h6 className="principal">Ronald Bondoc</h6>
                <h6 className="principal-label">Principal</h6>
              </div>
            </div>
          </MDBCardBody>
        </MDBCard>
      </MDBCol>
    </MDBRow>
  );
};

export default COE;
