const dateConverter = (dateString) => {
  const date = new Date(dateString);
  const now = new Date();

  // Get the start of today and one week ago
  const startOfToday = new Date(now.setHours(0, 0, 0, 0));
  const oneWeekAgo = new Date(startOfToday);
  oneWeekAgo.setDate(oneWeekAgo.getDate() - 7);

  // Check if the date is the same day as today
  const isToday = date.toDateString() === startOfToday.toDateString();
  // Check if the date is more than a week old
  const isOld = date < oneWeekAgo;

  // Format for abbreviated day and time
  const dayFormatter = new Intl.DateTimeFormat("en-US", { weekday: "short" });
  const timeFormatter = new Intl.DateTimeFormat("en-US", {
    hour: "2-digit",
    minute: "2-digit",
    hour12: true,
  });

  // Format for date with month
  const fullDateFormatter = new Intl.DateTimeFormat("en-US", {
    month: "short",
    day: "numeric",
    year: "numeric",
  });

  const day = dayFormatter.format(date);
  const time = timeFormatter.format(date);
  const fullDate = fullDateFormatter.format(date);

  // Return formatted date based on conditions
  if (isToday) {
    return `${time}`; // Only show time if it's today
  } else if (isOld) {
    return `${fullDate} ${time}`; // Show full date and time if it's more than a week old
  } else {
    return `${day} ${time}`; // Show day and time if it's within the past week
  }
};

export default dateConverter;
