import React, { useCallback, useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import {
  MDBBtn,
  MDBCard,
  MDBCardBody,
  MDBCol,
  MDBRow,
  MDBTypography,
} from "mdbreact";
import { BROWSE } from "../../../../services/redux/slices/student/exam";
import Modal from "./modal";
import { formattedDate, formattedTime } from "../../../../services/utilities";
import OnlineTest from "../../../../assets/online-test.jpg";

const EntranceExam = () => {
  const { token, information } = useSelector(({ auth }) => auth),
    { collections } = useSelector(({ exam }) => exam),
    [examForJHS, setExamForJHS] = useState({}),
    [examForSHS, setExamForSHS] = useState({}),
    [selectedExam, setSelectedExam] = useState({}),
    [show, setShow] = useState(false),
    dispatch = useDispatch();

  useEffect(() => {
    dispatch(BROWSE({ token, key: { batches: information?.currentBatches } }));
  }, [token, dispatch, information]);

  const getExamFor = useCallback(
    (progress) => {
      return (
        collections.find(
          ({ progress: p = "" }) => p.toLowerCase() === progress.toLowerCase()
        ) || {}
      );
    },
    [collections]
  );

  useEffect(() => {
    setExamForSHS(getExamFor("SHS"));
    setExamForJHS(getExamFor("JHS"));
  }, [getExamFor, collections]);

  const toggle = () => setShow(!show);

  const handleMessage = (status, start) => {
    switch (status) {
      case "PENDING":
        return `The entrance exam will open on ${formattedDate(
          start.date,
          false
        )}, at ${formattedTime(start.startTime)}.`;
      case "OPEN":
        return `The entrance exam is now open and will close on ${formattedDate(
          start.date,
          false
        )} at ${formattedTime(start.endTime)}.`;
      default:
        return "The entrance exam is now closed. To discuss the possibility of taking the exam, please visit the school and speak with the admissions office for further assistance.";
    }
  };

  const defaultMessage = (progress) =>
    `The entrance exam for ${progress} is not yet available. Please wait for further announcements. We will provide details as soon as possible. Thank you for your patience.`;

  const renderCard = (title, exam) => {
    return (
      <MDBCard
        className="flex-1"
        /* className="w-50 " */
        style={{
          boxShadow: "0px 4px 8px rgba(0, 0, 0, 0.2)",
          borderRadius: "10px",
          border: "1px solid #e0e0e0",
        }}
      >
        <MDBCardBody className="d-flex flex-row">
          <div className="d-flex flex-column" style={{ width: "65%" }}>
            <div className="d-flex align-items-center justify-content-start mb-3">
              {/* <MDBIcon
                icon="diagnoses"
                size="3x"
                className="mr-3"
                style={{ color: "#007bff" }}
              /> */}
              <h1
                className="font-weight-bold"
                style={{
                  fontFamily: "Times New Roman, Times, serif",
                  fontWeight: 500,
                }}
              >
                {title}
              </h1>
            </div>
            <h6 className="text-start mb-4">
              {exam._id
                ? handleMessage(exam.status, { ...exam })
                : defaultMessage(title)}
            </h6>
            {exam?.status === "OPEN" && (
              <div className="text-start">
                <MDBBtn
                  color="primary"
                  onClick={() => {
                    toggle();
                    setSelectedExam(exam);
                  }}
                  style={{ borderRadius: "20px" }}
                >
                  Take
                </MDBBtn>
              </div>
            )}
          </div>
          <div className="ml-4 mb-5" style={{ width: "35%" }}>
            <img
              src={OnlineTest}
              alt="img"
              style={{ height: "100%", objectFit: "cover" }}
              className="img-fluid"
            />
          </div>
        </MDBCardBody>
      </MDBCard>
    );
  };

  return (
    <>
      {!show ? (
        <>
          <MDBCard
            className="mb-4"
            style={{
              marginTop: "8rem",
              borderRadius: "10px",
              border: "1px solid #e0e0e0",
            }}
          >
            <MDBTypography
              className="mb-0 text-black-100"
              noteColor="warning"
              note
              noteTitle="Important Notice: "
              style={{ borderRadius: "10px" }}
            >
              This entrance exam is specifically for students intending to
              enroll in ICT programs. If you are not planning to take ICT
              courses, participating in this exam may lead to unnecessary
              complications. Make sure this is the right exam for you, or you
              might face penalties for incorrect participation.
            </MDBTypography>
          </MDBCard>
          <MDBRow>
            <MDBCol>{renderCard("Junior High School", examForJHS)}</MDBCol>
            <MDBCol>{renderCard("Senior High School", examForSHS)}</MDBCol>
          </MDBRow>
        </>
      ) : (
        <Modal show={show} toggle={toggle} exam={selectedExam} />
      )}
    </>
  );
};

export default EntranceExam;
