import React from "react";
import { MDBAnimation, MDBProgress } from "mdbreact";
const array = new Array(10).fill().map((_, index) => index);

function SidebarLoading() {
  return (
    <>
      {array
        .sort(() => Math.random() - 0.5)
        .map((_, rI) => (
          <div key={`presetCol-${rI}`} className="mt-4 w-100 ">
            <MDBAnimation
              type="flash"
              infinite
              delay={`${rI + 1}00ms`}
              duration="3000ms"
            >
              <MDBProgress
                color="light"
                heigth="200"
                id="progress-table"
              ></MDBProgress>
            </MDBAnimation>
          </div>
        ))}
    </>
  );
}

export default SidebarLoading;
