const currDate = new Date();

const day = currDate.getDate();
const monthIndex = currDate.getMonth();
const year = currDate.getFullYear();

const months = [
  "January",
  "February",
  "March",
  "April",
  "May",
  "June",
  "July",
  "August",
  "September",
  "October",
  "November",
  "December",
];

const getDaySuffix = (day) => {
  if (day >= 11 && day <= 13) {
    return `${day}th`;
  }
  switch (day % 10) {
    case 1:
      return `${day}st`;
    case 2:
      return `${day}nd`;
    case 3:
      return `${day}rd`;
    default:
      return `${day}th`;
  }
};
const date = `${getDaySuffix(day)} day of ${months[monthIndex]} ${year}`;

const currentDate = () => date;

export default currentDate;
