import React, { useEffect, useState } from "react";
import ImageCard from "./imageCard";
import ViewImage from "./modal";

import "./style.css";
import { ENDPOINT } from "../../services/utilities";

/**
 * Image component for displaying and handling image uploads.
 *
 * @param {Object} userDataImage - object of {email, _id, filesData{has2x2, hasPsa, hasCard, hasSignature}}
 * @param {Function} handleChange - function to handle image change
 * @param {boolean} viewOnly - flag to indicate if images are for viewing only
 * @returns JSX element
 */

const Images = ({ userDataImage, handleChange, viewOnly = false, imageTypes = [], lvl = 7, isNewStudent }) => {
    const [modal, setModal] = useState(false);
    const [currentImage, setCurrentImage] = useState(null);
    const [imagePreviews, setImagePreviews] = useState({});

    const openModal = (imageName) => {
        setCurrentImage(imagePreviews[imageName]);
        setModal(true);
        document.body.classList.add("body-no-scroll");
    };

    const closeModal = () => {
        setModal(false);
        setCurrentImage("");
        document.body.classList.remove("body-no-scroll");
    };

    const returnLink = (email, _id, src) => {
        return `${ENDPOINT}/assets/documents/${email}-${_id}/${src}-${email}.jpg`;
    };

    const hasAlreadyFiles = (hasImg) => {
        return hasImg ? true : "";
    };

    useEffect(() => {
        if (!viewOnly) {
            const previews = imageTypes.reduce((acc, type) => {
                const dataImage = userDataImage[type];
                const dataFiles = userDataImage.filesData?.[`has${type.charAt(0).toUpperCase() + type.slice(1)}`];
                if (type === "clearance") {
                    return acc;
                }

                acc[type] = dataImage
                    ? dataImage
                    : hasAlreadyFiles(dataFiles) &&
                    returnLink(userDataImage.email, userDataImage._id, type);

                return acc;
            }, {});

            if (lvl >= 8 && !isNewStudent) {
                const clearanceData = userDataImage.clearance;
                const hasClearance = userDataImage.filesData?.hasClearance;

                previews.clearance = clearanceData
                    ? clearanceData
                    : hasAlreadyFiles(hasClearance) &&
                    returnLink(userDataImage.email, userDataImage._id, "clearance");
            }

            setImagePreviews(previews);
            return;
        }

        if (viewOnly) {
            const previews = imageTypes.reduce((acc, type) => {
                const dataFiles = userDataImage.filesData?.[`has${type.charAt(0).toUpperCase() + type.slice(1)}`];

                if (dataFiles) {
                    acc[type] = returnLink(userDataImage.email, userDataImage._id, type);
                }

                return acc;
            }, {});

            setImagePreviews(previews);
            return;
        }

        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [viewOnly, userDataImage, imageTypes, lvl]);

    const changeHandler = (e) => {
        const { name, files } = e.target;

        if (files.length > 0) {
            const file = files[0];
            const fileUrl = URL.createObjectURL(file);
            setImagePreviews((prevPreviews) => ({
                ...prevPreviews,
                [name]: fileUrl,
            }));
        }
    };

    return (
        <>
            <ViewImage image={currentImage} show={modal} toggle={closeModal} />
            {Object.keys(imagePreviews).map((imgName) => (
                <ImageCard
                    key={imgName}
                    src={imagePreviews[`${imgName}`]}
                    imageName={imgName}
                    onChange={handleChange}
                    setHandleChange={changeHandler}
                    handleModalOpen={openModal}
                    isView={viewOnly}
                />
            ))}
        </>
    );
};

export default Images;
