import React, { useState } from "react";
import {
  MDBAvatar,
  MDBCard,
  MDBCardBody,
  MDBCol,
  MDBIcon,
  MDBRow,
  MDBView,
} from "mdbreact";
/**
 *
 * @param {String} imagePreview - previous image
 * @param {String} imageName - image name
 * @param {function} onChange - function that handles the changes for image
 * @param {function} handleModalOpen - function that handles the opening of modal
 * @param {Boolean} isView - by default false set to true for view only
 * @param {String} size - column size by default size is 3 for md device
 *
 */

const ImageCard = ({
  src,
  imageName,
  onChange,
  setHandleChange,
  handleModalOpen,
  isView,
  size = "3",
}) => {
  const [isHovered, setIsHovered] = useState(false);
  const [notAllowed, setNotAllowed] = useState(false)

  const handleMouseEnter = () => {
    setIsHovered(true);
  };

  const handleMouseLeave = () => {
    setIsHovered(false);
  };

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      const fileType = file.type;
      if (fileType === "image/jpeg" || fileType === "image/jpg" || fileType === "image/png") {
        setNotAllowed(false);
        onChange(e);
        setHandleChange(e);
      } else {
        setNotAllowed(true);
        e.target.value = ""; 
      }
    }
  };

  return (
    <MDBCol md={size} className=" mt-4 mb-4">
      <MDBCard narrow>
        <MDBView cascade className="mdb-color lighten-3 card-header">
          <h6 className="mb-0 font-weight-bold text-center text-white">
            <span className="red-text">*</span>
            {imageName.replace(/([a-z])([A-Z])/g, "$1 $2").toUpperCase()}
          </h6>
        </MDBView>
        <MDBCardBody className="text-center" style={{ height: "300px" }}>
          <MDBRow>
            <MDBCol>
              {!src ? (
                <MDBAvatar
                  className="z-depth-1 mb-3 mx-auto rounded img-without-shadow cursor-pointer"
                  style={{
                    width: "100%",
                    height: "190px",
                    objectFit: "contain",
                  }}
                >
                  <MDBIcon
                    icon="image"
                    className="icon-default"
                    onClick={() =>
                      document.querySelector(`#changeImage${imageName}`).click()
                    }
                  ></MDBIcon>
                </MDBAvatar>
              ) : (
                <MDBAvatar
                  tag="img"
                  src={src}
                  alt={`${imageName} Picture`}
                  className="z-depth-1 mb-3 mx-auto rounded img-without-shadow cursor-pointer"
                  style={{
                    width: "100%",
                    height: "190px",
                    objectFit: "contain",
                  }}
                  {...(!isView && {
                    onMouseEnter: handleMouseEnter,
                    onMouseLeave: handleMouseLeave,
                  })}
                  onClick={() => isView && handleModalOpen(imageName)}
                />
              )}
              {isHovered && (
                <span
                  className="icons"
                  onMouseEnter={handleMouseEnter}
                  onMouseLeave={handleMouseLeave}
                >
                  <MDBIcon
                    icon="eye"
                    className="hover-icon"
                    style={{ color: "dodgerblue" }}
                    onClick={() => handleModalOpen(imageName)}
                  ></MDBIcon>
                  <MDBIcon
                    icon="upload"
                    className="hover-icon"
                    style={{ color: "cornflowerblue" }}
                    onClick={() =>
                      document.querySelector(`#changeImage${imageName}`).click()
                    }
                  ></MDBIcon>
                </span>
              )}
            </MDBCol>
          </MDBRow>
          {!isView && (
            <>
              <MDBRow>
                <MDBCol>
                  <label
                    htmlFor={`changeImage${imageName}`}
                    className="btn btn-info btn-sm btn-rounded images-label"
                    disabled={isHovered}
                  >
                    Upload {imageName.replace(/([a-z])([A-Z])/g, "$1 $2")}
                  </label>
                  <input
                    id={`changeImage${imageName}`}
                    type="file"
                    className="d-none"
                    name={imageName}
                    accept="image/jpeg, image/jpg"
                    onChange={handleFileChange}
                    disabled={isView}
                  />
                </MDBCol>
              </MDBRow>
              {notAllowed && (
                <MDBRow>
                  <MDBCol>
                    <p className="text-danger mt-2">
                      Only JPEG, JPG, and PNG files are allowed.
                    </p>
                  </MDBCol>
                </MDBRow>
              )}
            </>
          )}
        </MDBCardBody>
      </MDBCard>
    </MDBCol>
  );
};

export default ImageCard;
