import React, { useEffect, useState } from "react";
import { MDBBtn, MDBPopover, MDBPopoverBody, MDBTable } from "mdbreact";
import { fullName } from "../../services/utilities";
import { days, times } from "../../services/fakeDb";
import "./schedule.css";
//initial Declare
const Scheduler = ({ array, props, isTeacher = false }) => {
  const [schedules, setSchedules] = useState([]);

  const generateRandomKey = () => {
    const characters =
      "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789";
    let randomKey = "";
    for (let i = 0; i < 10; i++) {
      randomKey += characters.charAt(
        Math.floor(Math.random() * characters.length)
      );
    }
    return randomKey;
  };

  const formatTime = (time) => {
    let hours = Number(time.hours);
    const min = String(time.min);
    const period = time.period;

    if (hours >= 1 && hours <= 5 && period === "PM") {
      hours += 12;
    }

    return { hours, min, period };
  };

  useEffect(() => {
    setSchedules([]);
    for (let parentIndex = 0; parentIndex < array.length; parentIndex++) {
      const element = array[parentIndex];
      const schedules = element.schedules || [];
      for (let index = 0; index < schedules.length; index++) {
        const { days, time, color, scheduleID } = schedules[index];

        for (let daysIndex = 0; daysIndex < days?.length; daysIndex++) {
          const day = days[daysIndex];
          const newSched = {
            day,
            timeStart: formatTime(time.start),
            timeEnd: formatTime(time.end),
            subject: element?.subject?.name || "",
            color,
            instructor: element.isBreakTime
              ? ""
              : fullName(element.instructor?.fullName),
            id: `${day}-${generateRandomKey()}`,
            section: element?.section || {},
            isBreakTime: element.isBreakTime,
            form: { ...element, days, time, scheduleID },
          };

          setSchedules((prev) => [newSched, ...prev]);
        }
      }
    }
  }, [array]);

  const handleHeight = (
    startTimeIndex,
    endedTimeIndex,
    timeIndex,
    startTime,
    endTime,
    color,
    gradient,
    endedGradient
  ) => {
    var _style = {
      marginTop: "0px",
      background: `linear-gradient(to bottom, ${color}, ${color})` /* Adjust colors as needed */,
      height: "100%",
      width: "100%",
      position: "absolute",
      overflow: "visible",
      left: "-6px",
      color: "black",
      fontWeight: "600",
      boxShadow: "0px 0px 0px 0px",
      backgroundSize: "",
    };

    if (timeIndex === endedTimeIndex) {
      if (endTime.min === "15") {
        _style.height = "68px";
        _style.marginTop = "-52px";
        _style.zIndex = 1;
      } else if (endTime.min === "30") {
        _style.marginTop = "-32px";
        _style.height = "61.4px";
      } else if (endTime.min === "45") {
        _style.marginTop = "-32px";
        _style.height = "80px";
        _style.zIndex = 1;
      } else {
        // 33px yan talaga height niya
        if (endedGradient) {
          _style.height = "64px";
          _style.background = `linear-gradient(to bottom, ${endedGradient} 100%,${color} 0%)`;
        } else {
          _style.height = "10px";
          _style.marginTop = "-26px";
        }
      }
    } else {
      _style.height = "65px";

      if (startTime.min === "30") {
        _style.height = "70px";
        _style.marginTop = "-31.5px"; // for 730
      }
    }

    if (startTime.min === "30") {
      _style.marginTop = "-30.8px"; // for 730
    }

    if (startTimeIndex === timeIndex) {
      const { hours } = startTime;
      if (hours === 7 && startTime.min == "0") {
        _style.marginTop = "-32px";
        _style.height = "95px";
      }
    }
    return _style;
  };

  const showSubject = (
    subject,
    timeStart,
    timeEnd,
    section,
    obj,
    isPopover = false
  ) => {
    const { hours: hourStart = 0, min: minStart = 0 } = timeStart;
    const { hours: hourEnd = 0 } = timeEnd;
    const startTime = hourStart > 12 ? hourStart - 12 : hourStart;
    const endTime = hourEnd > 12 ? hourEnd - 12 : hourEnd;
    const { isBreakTime = false } = obj;

    const startTimeFormatted = `${startTime}:${timeStart.min.padStart(
      2,
      "0"
    )} ${timeStart.period}`;
    const endTimeFormatted = `${endTime}:${timeEnd.min.padStart(2, "0")} ${
      timeEnd.period
    }`;

    const subjectName = isTeacher ? section.name : subject;
    const hoursDiff = hourEnd - hourStart;
    var bottomPX = `-${hoursDiff * 22}px`;
    const difference = getDifference(obj);

    if (difference === 60 && hourStart !== 7) {
      bottomPX = "-10px";
    }

    if (difference === 60 && hourStart === 7) {
      bottomPX = "-22px";
    }

    if (difference === 105) {
      bottomPX = "-20";
    }

    if (difference === 120) {
      bottomPX = "-30px";
    }

    return (
      <div
        style={
          !isPopover
            ? {
                position: "absolute",
                left: 10,
                maxHeight: "100%",
                width: "90%",
                zIndex: 2,
                overflow: "visible",
                height: "100%",
                bottom: obj.isBreakTime ? 0 : bottomPX,
                textAlign: "center",
                pointerEvents: "none",
                maxWidth: "100%",
                ...(obj.isBreakTime && {
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  flex: "column",
                }),
              }
            : {}
        }
      >
        <span
          style={{ fontSize: "14px", fontWeight: isPopover ? "600" : "" }}
          className="text-black"
        >
          {isTeacher ? ` G${section.lvl} -` : ""}{" "}
          {obj.isBreakTime ? "Break Time" : subjectName} <br />
          {difference >= 45 || isPopover
            ? `${startTimeFormatted} - ${endTimeFormatted}`
            : ""}
        </span>
        <br />
        {!isPopover && difference >= 120 && !isBreakTime ? (
          <span className="text-black" style={{ fontWeight: "600" }}>
            {isTeacher ? subject : obj.instructor}
          </span>
        ) : (
          ""
        )}
      </div>
    );
  };

  const renderSameStartAndEndHour = ({
    findSameStartHour,
    startTimeIndex,
    endedTimeIndex,
    timeIndex,
    timeStart,
    timeEnd,
    color,
    gradient,
    endedGradient,
  }) => {
    const {
      form,
      subject,
      timeStart: start,
      timeEnd: end,
      section,
      instructor = {},
    } = findSameStartHour;

    return (
      <>
        <MDBPopover placement="right" popover clickable>
          <MDBBtn
            onClick={() => handleSetForm(form)}
            color={color}
            style={handleHeight(
              startTimeIndex,
              endedTimeIndex,
              timeIndex,
              timeStart,
              timeEnd,
              color,
              gradient,
              endedGradient
            )}
          >
            {showSubject(subject, start, end, section, findSameStartHour)}
          </MDBBtn>
          <div>
            <MDBPopoverBody className="text-center">
              {showSubject(
                subject,
                start,
                end,
                section,
                findSameStartHour,
                true
              )}

              {isTeacher ? subject.toUpperCase() : instructor.toUpperCase()}
            </MDBPopoverBody>
          </div>
        </MDBPopover>
      </>
    );
  };

  const renderStartTime45Mins = (
    findThemin,
    startTimeIndex,
    timeIndex,
    endedTimeIndex,
    isExtend = false,
    showHR = false
  ) => {
    const {
      timeEnd,
      timeStart,
      section,
      subject,
      color,
      origTimeStart,
      instructor,
      form,
    } = findThemin;
    const { min: m, hours: hoursEnd } = timeEnd;
    const { hours: hoursStart } = timeStart;
    const timeDifference = hoursEnd - hoursStart;
    const min = Number(m);

    const baseEndIndex = isExtend ? endedTimeIndex - 1 : endedTimeIndex;
    const isEndIndex = timeIndex === endedTimeIndex;

    const marginTop = () => {
      if (timeDifference === 0) return "-17px";
      if (!isEndIndex) return "-16px";
      if (isEndIndex && min === 30) return "-34px";
      if (isEndIndex && min === 0) return "-63px";
      if (isEndIndex && min === 15) return "-47px";
      if (isEndIndex && min === 45) return "-5px";
    };

    const height = () => {
      if (isExtend && endedTimeIndex - 1 === timeIndex) {
        return "80px";
      }
      if (timeDifference === 0) return "64px";
      if (min !== 45) return "64px";
      if (min === 45 && !isEndIndex) return "80px";
      if (min === 45 && isEndIndex) return "52px";
    };

    const bottomHR = () => {
      if (min === 15) {
        const difference = getDifference(findThemin);
        return difference > 60 ? "-70px" : "-2px";
      }

      if (min === 0) {
        return "-52px";
      }

      if (min === 45) {
        return "-34px";
      }
    };
    return (
      <>
        <MDBPopover placement="right" popover clickable>
          <MDBBtn
            onClick={() => handleSetForm(form)}
            style={{
              height: height(),
              width: "100%",
              marginTop: marginTop(),
              position: "absolute",
              left: "-6px",
              color: "black",
              fontWeight: "600",
              overflow: "visible",
              zIndex: timeIndex === startTimeIndex ? 2 : 1,
              boxShadow: "0px 0px 0px 0px",
              background: `linear-gradient(to bottom, ${color}, ${color})`,
            }}
          >
            {timeIndex === startTimeIndex &&
              showSubject(subject, origTimeStart, timeEnd, section, findThemin)}
          </MDBBtn>
          <div>
            <MDBPopoverBody className="text-center">
              {showSubject(
                subject,
                origTimeStart,
                timeEnd,
                section,
                findThemin,
                true
              )}

              {isTeacher ? subject.toUpperCase() : instructor.toUpperCase()}
            </MDBPopoverBody>
          </div>
        </MDBPopover>
        {showHR && timeIndex === baseEndIndex && min !== 30 && (
          <hr
            style={{
              position: "absolute",
              bottom: bottomHR(),
              zIndex: 3,
              left: "0px",
              border: "black solid 1px",
              width: "99%",
              transform: "translateY(-50%)", // Centers the line vertically
            }}
          />
        )}
      </>
    );
  };

  const renderStartTime15Mins = (
    findThemin,
    startTimeIndex,
    timeIndex,
    endedTimeIndex,
    isExtend = false,
    showHR = false
  ) => {
    const { timeEnd, timeStart, section, subject, color, instructor, form } =
      findThemin;
    const { min: m } = timeEnd || {};
    const min = Number(m);
    const baseEndIndex = isExtend ? endedTimeIndex - 1 : endedTimeIndex;

    const isEndIndex = timeIndex === endedTimeIndex;
    const marginTop = () => {
      return "-48px";
    };

    const height = () => {
      if (isEndIndex && min === 30) return "77.5px";
      if (isEndIndex && min === 45) return "95px";
      if (isEndIndex && min === 0) return "50px";
      if (isExtend && endedTimeIndex - 1 === timeIndex) {
        return "112px";
      }
      return "64px";
    };

    const bottomHR = () => {
      if (min === 15) {
        const difference = getDifference(findThemin);
        return difference > 60 ? "-65px" : "-2px";
      }

      if (min === 0) {
        return "-52px";
      }

      if (min === 45) {
        return "-34px";
      }
    };

    const additional = 1;

    return (
      <>
        <MDBPopover placement="right" popover clickable>
          <MDBBtn
            onClick={() => handleSetForm(form)}
            style={{
              height: height(),
              width: "100%",
              marginTop: marginTop(),
              position: "absolute",
              overflow: "visible",
              left: "-6px",
              color: "black",
              fontWeight: "600",
              boxShadow: "0px 0px 0px 0px",
              background: `linear-gradient(to bottom, ${color}, ${color})`,
            }}
          >
            {timeIndex === startTimeIndex + additional &&
              showSubject(subject, timeStart, timeEnd, section, findThemin)}
          </MDBBtn>
          <div>
            <MDBPopoverBody className="text-center">
              {showSubject(
                subject,
                timeStart,
                timeEnd,
                section,
                findThemin,
                true
              )}

              {isTeacher ? subject.toUpperCase() : instructor.toUpperCase()}
            </MDBPopoverBody>
          </div>
        </MDBPopover>

        {showHR && timeIndex === baseEndIndex && min !== 30 && (
          <hr
            style={{
              position: "absolute",
              bottom: bottomHR(),
              zIndex: 3,
              left: "0px",
              border: "black solid 1px",
              width: "99%",
              transform: "translateY(-50%)", // Centers the line vertically
            }}
          />
        )}
      </>
    );
  };

  const renderNot1Hour = (
    findThemin,
    startTimeIndex,
    timeIndex,
    endedTimeIndex,
    showHR
  ) => {
    const {
      timeEnd,
      timeStart,
      origTimeStart,
      section,
      subject,
      color,
      isAdjust = false,
      origTimeEnd,
      instructor,
      form,
    } = findThemin;

    const baseTimeEnd = isAdjust ? origTimeEnd : timeEnd;

    const { min: mEnd, hours: hoursEnd } = baseTimeEnd || {};
    const { hours: hoursStart } = timeStart || {};
    const { min: mStart } = origTimeStart;
    const minStart = Number(mStart);
    const minEnd = Number(mEnd);
    const isEndIndex = timeIndex === endedTimeIndex;
    const is1Hour = hoursEnd - hoursStart;
    const baseEndIndex = minStart === 0 ? endedTimeIndex : endedTimeIndex - 1;

    // Goods 15,45  min start pending 0 7 am nalang problema    and 30
    const marginTop = () => {
      if (minStart == 15) {
        return "15px";
      } else if (minStart === 0 && hoursStart !== 7) {
        // 8:30 8:45
        if (minEnd === 30) return "0px";
        if (minEnd === 45) return "0px";
      } else if (minStart === 0 && hoursStart === 7) {
        return "-32px";
      } else if (minStart === 30) {
        return "32px";
      } else if (minStart === 45) {
        return "46px";
      }
    };
    const height = () => {
      if (minStart === 15) {
        if (minEnd === 45) return "35px";
        return "50px";
      }

      if (minStart === 0 && hoursStart === 7) {
        if (minEnd === 30) return "62px";
        if (minEnd === 45) return "79px";
      }

      if (minStart === 0 && hoursStart !== 7) {
        if (minEnd === 30) return "30px";
        if (minEnd === 45) return "48px";
      }

      if (minStart === 30) {
        if (minEnd === 0) return "33px";
        if (minEnd === 15) return "50px";
      }

      if (minStart === 45) {
        if (minEnd === 15) return "35px";
        if (minEnd === 30) return "47px";
      }
      return "40px";
    };

    const bottomHR = () => {
      if (minEnd === 15) {
        return "-69px";
      }

      if (minEnd === 0) {
        return "-52px";
      }

      if (minEnd === 45) {
        return "-34px";
      }
    };

    return (
      <>
        <MDBPopover placement="right" popover clickable>
          <MDBBtn
            onClick={() => handleSetForm(form)}
            style={{
              height: height(),
              width: "100%",
              marginTop: marginTop(),
              position: "absolute",
              left: "-6px",
              color: "black",
              fontWeight: "600",
              overflow: "visible",
              zIndex: isEndIndex && is1Hour ? -1 : 1,
              boxShadow: "0px 0px 0px 0px",
              background: `linear-gradient(to bottom, ${color}, ${color})`,
            }}
          >
            {timeIndex === startTimeIndex &&
              showSubject(subject, origTimeStart, baseTimeEnd, section, {
                ...findThemin,
                isBreakTime: true,
              })}
          </MDBBtn>
          <div>
            <MDBPopoverBody className="text-center">
              {showSubject(
                subject,
                origTimeStart,
                timeEnd,
                section,
                { ...findThemin, isBreakTime: true },
                true
              )}

              {isTeacher ? subject.toUpperCase() : instructor.toUpperCase()}
            </MDBPopoverBody>
          </div>
        </MDBPopover>
        {showHR && minEnd !== 30 && (
          <hr
            style={{
              position: "absolute",
              bottom: bottomHR(),
              zIndex: 3,
              left: "0px",
              border: "white solid 1px",
              width: "99%",
              transform: "translateY(-50%)", // Centers the line vertically
            }}
          />
        )}
      </>
    );
  };

  // para kapag nag update ng schedule
  const handleSetForm = (form) => {
    if (!props) return false;
    if (props.willCreate) return false;
    const {
      time,
      instructor,
      subject,
      days,
      section,
      scheduleID,
      isBreakTime = false,
    } = form || {};
    const { start, end } = time || {};
    props.setForm((prev) => ({
      ...prev,
      _id: form._id,
      instructor: instructor?._id,
      subject: subject?._id,
      section: section?._id,
      isBreakTime,
      oldDays: days,
      scheduleID,
    }));

    props.setPickDays(days);
    props.setHourStart(Number(start.hours));
    props.setMinStart(Number(start.min));
    props.setPeriodStart(start.period);
    props.setHourEnd(Number(end.hours));
    props.setMinEnd(Number(end.min));
    props.setPeriodEnd(end.period);
  };

  const HR = () => {
    return (
      // <hr
      //   className="schedule-td"
      //   style={{
      //     marginTop: "31.2px",
      //     // marginRight: "-5px",
      //     marginLeft: "-10px",
      //     position: "absolute",
      //     zIndex: 0,
      //     border: "black solid 1px",
      //     width: "100%",
      //   }}
      // />
      ""
    );
  };

  const getDifference = (sched) => {
    const { timeStart = {}, timeEnd = {} } = sched;
    const startTime = timeStart.hours * 60 + parseInt(timeStart.min);
    const endTime = timeEnd.hours * 60 + parseInt(timeEnd.min);
    return endTime - startTime;
  };

  const findSchedule = (array, time) => {
    return array.find((sched) => {
      const { timeStart = {}, timeEnd, isBreakTime = false } = sched;
      const { min = 0 } = timeStart;
      const startTime = timeStart.hours * 60 + parseInt(min);
      const endTime = timeEnd.hours * 60 + parseInt(timeEnd.min);
      const currentTime = time.value * 60;

      const maximumDifference = 45; // in minutes
      const difference = endTime - startTime;
      const isValidRange =
        difference <= maximumDifference &&
        timeStart.hours === time.value &&
        isBreakTime;
      const result = currentTime >= startTime && currentTime <= endTime;

      return isBreakTime ? isValidRange : result;
    });
  };

  const isShowHR = (schedule, _schedules, withoutBreakTimeScheds) => {
    const { timeEnd } = schedule;
    return [..._schedules, ...withoutBreakTimeScheds].some(
      ({ timeStart = {}, origTimeStart = {}, is45Mins = false }) => {
        const _timeStart = is45Mins ? origTimeStart : timeStart;

        return (
          _timeStart.hours === timeEnd.hours && _timeStart.min === timeEnd.min
        );
      }
    );
  };

  const renderScheduleTable = ({
    schedule,
    day,
    _schedules,
    timeIndex,
    baseSchedules = [],
    withoutBreakTimeScheds = [],
  }) => {
    if (schedule) {
      const {
        timeStart = {},
        timeEnd = {},
        subject = "",
        id = 1,
        color = "",
        instructor = "",
        section = {},
        not1Hour = false,
        is45Mins = false,
        is15Mins = false,
        form = {},
      } = schedule;

      // para kahit meron nang 1 to 2 na schedule pwede kapang mag lagay ng 2 to 3
      const findSameEndHour = [..._schedules].find(
        ({ timeEnd: _timeEnd }) => _timeEnd.hours === timeStart.hours
      );

      //para kahit meron nang 1 to 2 na schedule pwede kapang mag lagay ng 12 to 1
      const findSameStartHour = [..._schedules].find(
        ({ timeStart: _timeStart }) => timeEnd.hours === _timeStart.hours
      );

      const gradient = findSameEndHour ? findSameEndHour.color : "white";

      const endedGradient = findSameStartHour
        ? findSameStartHour.timeStart?.min === "0" && findSameStartHour.color
        : "";

      const endedTimeIndex = times.findIndex(
        (time) => time.value === timeEnd.hours
      );
      const startTimeIndex = times.findIndex(
        (time) => time.value === timeStart.hours
      );

      if (not1Hour) {
        const showHR = isShowHR(schedule, _schedules, withoutBreakTimeScheds);

        return renderNot1Hour(
          schedule,
          startTimeIndex,
          timeIndex,
          endedTimeIndex,
          showHR
        );
      }

      if (is45Mins) {
        const showHR = isShowHR(schedule, _schedules, baseSchedules);
        const difference = getDifference(schedule);

        return renderStartTime45Mins(
          schedule,
          startTimeIndex,
          timeIndex,
          endedTimeIndex,
          findSameStartHour && difference > 60 ? true : false, // kapag myung end hour niya is merong kamuka na start hour
          showHR
        );
      }

      if (is15Mins) {
        const showHR = isShowHR(schedule, _schedules, baseSchedules);
        const difference = getDifference(schedule);
        return renderStartTime15Mins(
          schedule,
          startTimeIndex,
          timeIndex,
          endedTimeIndex,
          findSameStartHour && difference > 60 ? true : false, // kapag myung end hour niya is merong kamuka na start hour
          showHR
        );
      }

      if (
        findSameStartHour?.section &&
        endedTimeIndex === timeIndex &&
        findSameStartHour.timeStart?.min === "0"
      ) {
        return renderSameStartAndEndHour({
          findSameStartHour,
          id,
          startTimeIndex,
          endedTimeIndex,
          timeIndex,
          timeStart,
          timeEnd,
          color,
          gradient,
          endedGradient,
          subject,
          schedule,
        });
      }

      const showHR = isShowHR(schedule, _schedules, baseSchedules);
      const baseEndIndex =
        timeEnd.min === "0" ? endedTimeIndex - 1 : endedTimeIndex;

      return (
        <>
          <MDBPopover placement="right" popover clickable>
            <MDBBtn
              onClick={() => handleSetForm(form)}
              style={handleHeight(
                startTimeIndex,
                endedTimeIndex,
                timeIndex,
                timeStart,
                timeEnd,
                color,
                gradient,
                endedGradient
              )}
            >
              {timeStart.min === "30" ? (
                startTimeIndex + 1 === timeIndex ? (
                  showSubject(subject, timeStart, timeEnd, section, schedule)
                ) : (
                  ""
                )
              ) : startTimeIndex === timeIndex ? (
                <>
                  {showSubject(subject, timeStart, timeEnd, section, schedule)}
                </>
              ) : (
                ""
              )}
            </MDBBtn>

            <div>
              <MDBPopoverBody className="text-center">
                {showSubject(
                  subject,
                  timeStart,
                  timeEnd,
                  section,
                  schedule,
                  true
                )}
                {isTeacher ? subject.toUpperCase() : instructor.toUpperCase()}
              </MDBPopoverBody>
            </div>
          </MDBPopover>

          {showHR && baseEndIndex === timeIndex && timeEnd.min !== "30" && (
            <hr
              style={{
                position: "absolute",
                bottom:
                  timeEnd.min === "15"
                    ? "-3px"
                    : timeEnd.min === "0"
                    ? "-50px"
                    : "-34px",
                zIndex: 3,
                left: "0px",
                border: "white solid 1px",
                width: "100%",
                transform: "translateY(-50%)", // Centers the line vertically
              }}
            />
          )}
        </>
      );
    } else {
      return HR(day.value);
    }
  };

  const handleArrangeSchedules = (_schedules, isBreakTime) => {
    return [..._schedules]
      .filter(({ isBreakTime: breakTime = false }) => breakTime === isBreakTime)
      .map((data) => {
        const { timeStart, timeEnd } = data;
        const {
          hours: origHours,
          min: origMin,
          origHours: duplicateHour = 0,
          origMin: duplicateMin = 0,
        } = timeStart;

        const { hours: hourEnd, min: minEnd } = timeEnd;
        const hourStart = duplicateHour || origHours;
        const minStart = duplicateMin || origMin;

        const startTime = hourStart * 60 + parseInt(minStart, 10);
        const endTime = hourEnd * 60 + parseInt(minEnd, 10);

        const not1Hour = endTime - startTime <= 45;

        // Clone the data to avoid mutating the original object
        const updatedData = { ...data };

        if (not1Hour) {
          updatedData.not1Hour = true;
          updatedData.origTimeStart = { ...timeStart };
          updatedData.timeStart = {
            ...timeStart,
            origHours: timeStart?.hours,
            origMin: Number(timeStart?.min),
          };
        }

        if (timeStart?.min === "45" && !not1Hour) {
          updatedData.origTimeStart = { ...timeStart };
          updatedData.timeStart = {
            ...timeStart,
            min: "0",
            hours: (timeStart?.hours || 0) + 1,
          };
          updatedData.is45Mins = true;
          updatedData.not1Hour = false;
        }

        if (updatedData.timeStart?.min === "15" && !not1Hour) {
          updatedData.is15Mins = true;
        }

        return updatedData;
      });
  };

  return (
    <div>
      <MDBTable
        style={{
          backgroundColor: "light-gray",
          border: "2px solid black",
        }}
      >
        <thead>
          <tr
            style={{
              backgroundColor: "#605c5c",
              color: "white",
            }}
          >
            <th
              className="text-black  th-sm text-center "
              style={{
                border: "2px solid white",
                borderLeft: "2px solid black",
                borderTop: "2px solid black",
                fontWeight: "600",
              }}
            >
              Time
            </th>
            {days.map((day, index) => (
              <th
                className="text-center text-black  th-lg"
                key={index}
                style={{
                  fontStyle: "Times New Roman",
                  borderTop: "2px solid black",

                  borderLeft: `2px solid white`,
                  ...(index === days.length - 1 && {
                    borderRight: "2px solid black",
                  }),
                  fontWeight: "600",
                }}
              >
                {day.text.toUpperCase()}
              </th>
            ))}
          </tr>
        </thead>

        <tbody>
          {times.map((time, timeIndex) => (
            <tr
              key={`-${generateRandomKey()}-schedules`}
              style={{
                borderRight: "black solid 2px",
              }}
            >
              <td className="d-flex align-items-center justify-content-center pr-0 schedule-td">
                <h6 className="text-nowrap " style={{ fontWeight: "600" }}>
                  {time.text}
                </h6>
              </td>
              {days.map((day, dayIndex) => {
                const template = schedules
                  .filter(
                    (sched) =>
                      sched.day.toLocaleLowerCase() ===
                      day.value.toLocaleLowerCase()
                  )
                  .map((sched) => ({ ...sched }));

                const schedulesWithoutBreakTime = handleArrangeSchedules(
                  template,
                  false
                );
                const schedulesWithBreakTime = handleArrangeSchedules(
                  template,
                  true
                );

                const scheduleWithoutBreakTime = findSchedule(
                  schedulesWithoutBreakTime,
                  time
                );
                const scheduleWithBreakTime = findSchedule(
                  schedulesWithBreakTime,
                  time
                );

                const baseSchedules = [...template];

                if (scheduleWithBreakTime) {
                  return (
                    <React.Fragment key={generateRandomKey()}>
                      <td
                        className="position-relative"
                        key={generateRandomKey()}
                        style={{
                          borderRight: "2px solid white",
                          borderLeft: "2px solid white",
                        }}
                      >
                        {scheduleWithoutBreakTime &&
                          renderScheduleTable({
                            schedule: scheduleWithoutBreakTime,
                            day,
                            _schedules: schedulesWithoutBreakTime,
                            timeIndex,
                            baseSchedules,
                          })}

                        {renderScheduleTable({
                          schedule: scheduleWithBreakTime,
                          day,
                          _schedules: schedulesWithBreakTime,
                          withoutBreakTimeScheds: schedulesWithoutBreakTime,
                          baseSchedules,
                          timeIndex,
                        })}
                      </td>
                    </React.Fragment>
                  );
                } else {
                  return (
                    <td
                      className="position-relative"
                      key={generateRandomKey()}
                      style={{
                        borderRight: `2px solid ${
                          dayIndex === days.length - 1 ? "black" : "white"
                        }`,
                        borderLeft: "2px solid white",
                      }}
                    >
                      {renderScheduleTable({
                        schedule: scheduleWithoutBreakTime,
                        day,
                        _schedules: schedulesWithoutBreakTime,
                        baseSchedules,
                        timeIndex,
                      })}
                    </td>
                  );
                }
              })}
            </tr>
          ))}
        </tbody>
      </MDBTable>
    </div>
  );
};

export default Scheduler;
