import { MDBNavLink } from "mdbreact";
import React from "react";
import logo from "../../../assets/logo/logo.png";

const TopNavigation = ({ toggleregister, toggleLogin }) => {
  return (
    <div className={`topbar-container `}>
      <div className="slanted-end-left slanted"></div>

      <div className="d-flex flex-column align-items-center w-50 navigation-links-left">
        <div
          className=" w-100 d-flex align-items-center justify-content-center title-navigation"
          style={{ borderBottom: "1px solid gray" }}
        >
          <div className="w-50 d-flex align-items-center justify-content-center">
            <h6 className="text-white mt-1 text-nowrap">
              Lenor M. Bautista National High School
            </h6>
          </div>
        </div>

        <div
          className="d-flex align-items-center justify-content-center w-100 title-navigation-container"
          style={{ gap: "7rem" }}
        >
          <MDBNavLink to="/" className="text-nav mt-1">
            Home
          </MDBNavLink>
          <MDBNavLink
            to="/organizational-chart"
            className="text-nav mt-1 text-nowrap"
          >
            Org Chart
          </MDBNavLink>
          <MDBNavLink to="/faqs" className="text-nav mt-1 text-nowrap">
            FAQ's
          </MDBNavLink>
        </div>
      </div>
      <div className="slanted-start-left slanted"></div>
      <div className="topbar-logo d-flex align-items-center">
        <MDBNavLink to="/">
          <img src={logo} alt="logo" />
        </MDBNavLink>
      </div>
      <div className="slanted-start-right slanted"></div>
      <div className="d-flex flex-column align-items-center  w-50 navigation-links-right">
        <div
          className="d-flex justify-content-center w-100 title-navigation"
          style={{ borderBottom: "1px solid gray" }}
        >
          <h6 className="text-white mt-1">
            Brgy.Pias General Tino Nueva Ecija
          </h6>
        </div>
        <div
          className="d-flex align-items-center justify-content-center w-100 title-navigation-container"
          style={{ gap: "7rem" }}
        >
          <MDBNavLink to="/about-us" className="text-nav mt-1 text-nowrap">
            About
          </MDBNavLink>

          <MDBNavLink to="/" className="text-nav mt-1">
            <span onClick={() => toggleregister()}>Register</span>
          </MDBNavLink>
          <MDBNavLink to="/" className="text-nav mt-1">
            <span onClick={() => toggleLogin()}>Login</span>
          </MDBNavLink>
        </div>
      </div>
      <div className="slanted-end-right slanted"></div>
    </div>
  );
};

export default TopNavigation;
