import React, { useEffect, useState } from "react";
import { useSelector } from "react-redux";
import { MDBCard, MDBCardBody, MDBTypography } from "mdbreact";
import Card from "../../../../widgets/card-grades";

function ReportGrades() {
  const { information } = useSelector(({ auth }) => auth);
  const [grades, setGrades] = useState({});
  const [batches, setBatches] = useState([]);
  const [batch, setBatch] = useState("");
  const status = information?.enrolleeData?.status;
  const _grades = information?.grades || [];

  const getSemesterValue = (semester) => {
    if (semester === "1st") return 1;
    if (semester === "2nd") return 2;
    return 0; // Kung wala o ibang semestre, 0
  };

  useEffect(() => {
    if (_grades?.length > 0) {
      const sortedGrades = _grades.slice().sort((a, b) => {
        let yearA = parseInt(a?.batch?.sy.split("-")[0]);
        let yearB = parseInt(b?.batch?.sy.split("-")[0]);

        if (yearA !== yearB) {
          return yearB - yearA;
        } else {
          let semesterA = a?.batch?.semester
            ? getSemesterValue(a.batch.semester)
            : 0;
          let semesterB = b?.batch?.semester
            ? getSemesterValue(b.batch.semester)
            : 0;

          return semesterB - semesterA;
        }
      });

      const _batches = sortedGrades.map(({ batch }) => ({
        value: batch._id,
        text: `${batch.sy}${
          batch.semester ? ` ${batch.semester.toUpperCase()} SEMESTER` : ""
        }`,
      }));
      setGrades(sortedGrades[0] || {});
      setBatches(_batches);
    }
  }, [information, _grades, status]);

  useEffect(() => {
    if (_grades.length > 0) {
      if (grades && batch) {
        const storageGrades = [..._grades];

        const newGrades = storageGrades.find(
          ({ batch: bt }) => String(bt?._id) === String(batch)
        );

        setGrades(newGrades);
      }
    }
  }, [batch, _grades, status, grades]);

  return (
    <MDBCard narrow className={status === "APPROVED" ? "pb-3" : "text-center"}>
      {status === "APPROVED" ? (
        <MDBCardBody>
          {grades?._id && (
            <Card
              selected={grades}
              isStudent={true}
              batches={batches}
              batch={batch}
              setBatch={setBatch}
            />
          )}
        </MDBCardBody>
      ) : (
        <MDBTypography
          className="mb-0 text-black-100"
          noteColor="warning"
          note
          noteTitle="Reminder: "
        >
          Please wait until your request enrollment form is approved
        </MDBTypography>
      )}
    </MDBCard>
  );
}

export default ReportGrades;
