import React, { useCallback, useEffect, useRef, useState } from "react";
import { MDBRow, MDBTypography, MDBCol, MDBIcon } from "mdbreact";
import converter from "../../../../services/utilities/converter";
import "./matchingType.css";
import coordinates from "./coordinates";
import Lines from "./lines";
import QuestionsAndAnswers from "./questionsAndAnswers";
import shuffle from "../entranceExam/modal/exam/body/shuffle";
import answerIsCorrect from "../../registrar/entranceExam/exam/viewQuestions/type/js/isCorrect";
import isChecked from "../../registrar/entranceExam/exam/viewQuestions/type/js/isChecked";

const colors = [
  "#f5dcdb",
  "#e3ddf0",
  "#faf0e9",
  "#d1e4f4",
  "#c7f9d9",
  "#eaf3df",
  "#d2f1f2",
  "#fdc1c0",
];

const MatchingType = ({
  question,
  setStudentAnswer = () => {},
  isChecking = false,
  index: indexOfChecking,
  haveIndexOfQuestion = false,
  isView = false,
  isAdd = false,
  selectedQuestions = [],
  handleSelectQuestion = () => {},
}) => {
  const [questions, setQuestions] = useState([]),
    [choices, setChoices] = useState([]),
    [lines, setLines] = useState([]),
    [containerPos, setContainerPos] = useState({}),
    [questionIndex, setQuestionIndex] = useState(-1),
    [hasDelayed, setHasDelayed] = useState(false),
    matchingContainerRef = useRef(null),
    questionRefs = useRef([]),
    answerRefs = useRef([]);

  const updateLineCoordinates = useCallback((newContainerPos) => {
    setLines((prevLines) => {
      if (prevLines.length === 0) return prevLines;

      const newLinesCoordinates = prevLines.map((line) => {
        const { answerIndex, questionIndex } = line;
        const { x1, y1, x2, y2 } = coordinates({
          containerPos: newContainerPos,
          questionRefs,
          answerRefs,
          questionIndex,
          matchingContainerRef,
          answerIndex,
          isAdd: false,
        });
        return { ...line, x1, y1, x2, y2 };
      });
      return newLinesCoordinates;
    });
  }, []);

  useEffect(() => {
    const updateContainerPos = () => {
      if (matchingContainerRef.current) {
        const pos = matchingContainerRef.current.getBoundingClientRect();
        updateLineCoordinates(pos);
        setContainerPos({
          top: pos.top + window.scrollY,
          left: pos.left,
          width: pos.width,
          height: pos.height,
        });
      }
    };

    const delayUpdate = setTimeout(() => {
      if (!hasDelayed) {
        updateContainerPos();
        setHasDelayed(true);
      }
    }, 1000);

    const observer = new ResizeObserver(() => {
      updateContainerPos();
    });

    const currentRef = matchingContainerRef.current;

    if (currentRef) {
      observer.observe(currentRef);
    }

    return () => {
      clearTimeout(delayUpdate);
      if (currentRef) {
        observer.unobserve(currentRef);
      }
    };
  }, [updateLineCoordinates, matchingContainerRef, hasDelayed]);

  useEffect(() => {
    setStudentAnswer({
      ...question,
      answers: questions,
      selectedLines: lines,
      choices,
    });
  }, [questions, setStudentAnswer, question, lines, choices]);

  useEffect(() => {
    if (!isChecking) {
      const { choices: baseChoices } = question;
      const choicesWithLetter = (
        isView ? baseChoices : shuffle(baseChoices)
      ).map((choice, index) => ({
        text: choice.textB,
        ...(isView &&
          !choice.isConfusing && {
            color: colors[index],
            letter: converter.indexToLetter(index),
          }),
      }));
      const shuffleQuestions = [...shuffle(baseChoices)];

      const getIsConfusing = (_isConfusing) =>
        (isView ? baseChoices : shuffleQuestions).filter(
          ({ isConfusing }) => isConfusing === _isConfusing
        );

      const notConfusingQuestions = getIsConfusing(false);

      const confusingQuestions = getIsConfusing(true);

      const questionsWithDefaultAnswer = [
        ...notConfusingQuestions,
        ...confusingQuestions,
      ].map((q, index) => {
        const answer = choicesWithLetter[index].text || "";
        return { ...q, answer };
      });

      setChoices(choicesWithLetter);
      setQuestions(questionsWithDefaultAnswer);
    }
  }, [question, isChecking, isView]);

  useEffect(() => {
    const { selectedLines = [], answers = [], choices = [] } = question;
    if (isChecking) {
      setQuestions(answers);
      setChoices(choices);
    }
    if (isChecking || isView) {
      setLines(selectedLines);
    }
  }, [isChecking, question, isView]);

  const chooseChecker = (chooseIndex) => {
    const _choices = [...choices];
    const choose = converter.indexToLetter(chooseIndex);

    const index = _choices.findIndex(({ letter = "" }) => letter === choose);

    if (index < 0) return _choices;

    _choices[index] = { ..._choices[index], letter: "", color: "" };
    return _choices;
  };

  const lineChecker = (answerIndex) => {
    if (questionIndex < 0) return false;
    var _lines = [...lines];

    const filteredLines = _lines.filter(
      ({ answerIndex: ansIndex, questionIndex: qIndex }) =>
        ansIndex !== answerIndex && qIndex !== questionIndex
    );

    handleAddLine(questionIndex, answerIndex, filteredLines);
  };

  const questionChecker = (answer, answerIndex) => {
    lineChecker(answerIndex);
    const _questions = [...questions];
    const index = _questions.findIndex(({ answer: ans }) => ans === answer);

    if (index < 0) return _questions;
    _questions[index] = { ..._questions[index], answer: "" };
    return _questions;
  };

  const handlePick = (index) => {
    if (questionIndex <= -1) return false;

    const answer = choices[index].text;

    const _questions = questionChecker(answer, index);

    const _question = { ..._questions[questionIndex] };

    _questions[questionIndex] = {
      ..._question,
      answer,
    };

    const isCorrect =
      questions[questionIndex]?.textB.replace(/\s+/g, " ") ===
      answer.replace(/\s+/g, " ");

    const _choices = chooseChecker(questionIndex);
    _choices[index] = {
      ..._choices[index],
      color: colors[questionIndex],
      isCorrect,
      letter: converter.indexToLetter(questionIndex),
    };
    setChoices(_choices);
    setQuestions(_questions);
  };

  const handleAddLine = (questionIndex, answerIndex, _lines) => {
    const { x1, y1, x2, y2 } = coordinates({
      containerPos,
      questionRefs,
      answerRefs,
      matchingContainerRef,
      questionIndex,
      answerIndex,
    });

    _lines.push({
      x1,
      y1,
      x2,
      y2,
      isCorrect,
      answerIndex,
      questionIndex,
    });

    setLines(_lines);
  };

  const isCorrect = isChecking ? answerIsCorrect(question) : false;

  return (
    <div
      style={{ position: "relative", marginBottom: isChecking ? "1rem" : "" }}
    >
      {!isChecking && !isView && (
        <MDBTypography
          className="mb-0 text-black-100 "
          noteColor="info"
          note
          tag="h1"
          variant="h1"
          noteTitle="Instruction: "
        >
          Click the question, then select the corresponding answer to match
          them.
        </MDBTypography>
      )}

      <div className="d-flex align-items-center">
        {isAdd && (
          <>
            <input
              className="form-check-input"
              type="checkbox"
              checked={isChecked(question, selectedQuestions)}
              onChange={() => handleSelectQuestion(question)}
              id={`question-${indexOfChecking}`}
            />
            <label
              htmlFor={`question-${indexOfChecking}`}
              className="form-check-label  label-table"
            />
          </>
        )}
        {isChecking && (
          <h5>
            <MDBIcon
              icon={isCorrect ? "check" : "times"}
              style={{ color: isCorrect ? "#30D272" : "red" }}
              className={isCorrect ? "mr-3" : "mr-4"}
            />
            &nbsp;
          </h5>
        )}
        <h5
          style={{
            marginLeft: isChecking ? "0.2rem" : "0.2rem",
            marginTop: haveIndexOfQuestion ? "0.2rem" : "-1.3rem",
          }}
        >
          {haveIndexOfQuestion && <span>{indexOfChecking + 1}.&nbsp;</span>}
        </h5>

        <h5
          className="mt-1"
          style={{
            textIndent: "-0.1rem",
          }}
        >
          <strong>{question.question}</strong>
        </h5>
      </div>
      <MDBRow className="mb-2 mt-4">
        <MDBCol className="text-center">
          <h5 className="font-weight-bold">{question.titleA}</h5>
        </MDBCol>
        <MDBCol className="text-center">
          <h5 className="font-weight-bold">{question.titleB}</h5>
        </MDBCol>
      </MDBRow>
      <div className="matching-container " ref={matchingContainerRef}>
        <Lines lines={lines} containerPos={containerPos} />
        <QuestionsAndAnswers
          refs={questionRefs}
          collections={questions}
          questionIndex={questionIndex}
          handleClick={setQuestionIndex}
          colors={colors}
          isChecking={isChecking}
          disableAction={isChecking || isView}
          handlePick={handlePick}
          isView={isView}
        />

        <QuestionsAndAnswers
          refs={answerRefs}
          collections={choices}
          handleClick={handlePick}
          colors={colors}
          isChecking={isChecking}
          disableAction={isChecking || isView}
          isChoices={true}
          isView={isView}
        />
      </div>
    </div>
  );
};

export default MatchingType;
