import { useState, useEffect } from "react";

function ElapsedTime({ createdAt, isConvo = true }) {
  const [elapsedTime, setElapsedTime] = useState("");
  const getElapsedTime = (createdAt, isConvo) => {
    const now = new Date();
    const createdTime = new Date(createdAt);
    const diff = now - createdTime;

    const seconds = Math.floor(diff / 1000);
    const minutes = Math.floor(seconds / 60);
    const hours = Math.floor(minutes / 60);
    const days = Math.floor(hours / 24);
    const weeks = Math.floor(days / 7);
    const months = Math.floor(days / 30);
    const years = Math.floor(days / 365);

    if (years > 0) {
      return `${isConvo ? "Sent" : ""} ${years}y ${isConvo ? "ago" : ""}`;
    } else if (months > 0) {
      return `${isConvo ? "Sent" : ""} ${months}mo ${isConvo ? "ago" : ""}`;
    } else if (weeks > 0) {
      return `${isConvo ? "Sent" : ""} ${weeks}w ${isConvo ? "ago" : ""}`;
    } else if (days > 0) {
      return `${isConvo ? "Sent" : ""} ${days}d ${isConvo ? "ago" : ""}`;
    } else if (hours > 0) {
      return `${isConvo ? "Sent" : ""} ${hours}h ${isConvo ? "ago" : ""}`;
    } else if (minutes > 0) {
      return `${isConvo ? "Sent" : ""} ${minutes}m ${isConvo ? "ago" : ""}`;
    } else {
      return `${isConvo ? "Sent" : "1m"} `;
    }
  };

  useEffect(() => {
    function updateElapsedTime() {
      setElapsedTime(getElapsedTime(createdAt, isConvo));
    }

    updateElapsedTime(); // Initial call to set the time immediately
    const intervalId = setInterval(updateElapsedTime, 60000); // Update every minute

    return () => clearInterval(intervalId); // Clean up the interval on component unmount
  }, [createdAt, isConvo, setElapsedTime]);

  return elapsedTime;
}

export default ElapsedTime;
