import React, { useCallback, useEffect, useState } from "react";
import { MDBAnimation } from "mdbreact";
import { UPDATE_AUTH } from "../../../../../../services/redux/slices/auth";
import { SAVE } from "../../../../../../services/redux/slices/student/exam";
import checker from "./checker";
import Header from "./header";
import Body from "./body";
import Footer from "./footer";
import CompletedExam from "./completedExam";
import { useDispatch, useSelector } from "react-redux";

const Exam = ({ exam, setTitle = () => {} }) => {
  const { auth, token } = useSelector(({ auth }) => auth),
    [questions, setQuestions] = useState([]),
    [answersOfStudent, setAnswersOfStudent] = useState([]),
    [totalScore, setTotalScore] = useState(0),
    [numberOfQuestions, setNumberOfQuestions] = useState(0),
    [page, setPage] = useState(1),
    [isTabVisible, setIsTabVisible] = useState(true),
    [isFinish, setIsFinish] = useState(false),
    [hasPlusOne, setHasPlusOne] = useState(true),
    dispatch = useDispatch();

  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.visibilityState === "hidden") {
        setIsTabVisible(false); // User opened a new tab or switched tabs
      } else if (document.visibilityState === "visible") {
        setIsTabVisible(true); // User returned to this tab
      }
    };

    // Attach event listener
    document.addEventListener("visibilitychange", handleVisibilityChange);

    // Cleanup function to remove the event listener
    return () => {
      document.removeEventListener("visibilitychange", handleVisibilityChange);
    };
  }, []);

  useEffect(() => {
    setQuestions(exam?.questions);
    setNumberOfQuestions(exam?.questions?.length);
  }, [exam]);

  const handleSubmit = useCallback(() => {
    let _totalScore = 0;
    const _answersOfStudent = [...answersOfStudent];

    _answersOfStudent.forEach((element) => {
      switch (element.type) {
        case "matching":
          _totalScore += checker.matchingType(element);
          break;
        case "mc":
          _totalScore += checker.multipleChoice(element);
          break;
        default:
          _totalScore += checker.identification(element);
      }
    });

    if (auth.hasTakeExam === false) {
      const studentExamInfo = {
        hasTakeExam: true,
        isPassedInExam: _totalScore >= exam.passingScore,
      };
      dispatch(UPDATE_AUTH(studentExamInfo));
      dispatch(
        SAVE({
          token,
          data: {
            student: auth._id,
            exam: exam._id,
            score: _totalScore,
            progress: exam.progress,
            studentExamInfo,
            answers: answersOfStudent,
          },
        })
      );
    }

    setTotalScore(_totalScore);
  }, [answersOfStudent, setTotalScore, exam, dispatch, auth, token]);

  useEffect(() => {
    if (!isTabVisible) {
      if (page > exam?.questions?.length) {
        setIsFinish(true);
      } else {
        if (hasPlusOne) {
          setPage((prev) => prev + 1);
          setHasPlusOne(false);
        }
      }
    }
  }, [isTabVisible, handleSubmit, page, hasPlusOne, exam]);

  useEffect(() => {
    if (isTabVisible) {
      setHasPlusOne(true);
    }
  }, [isTabVisible]);

  useEffect(() => {
    if (isFinish) {
      handleSubmit();
      setTitle("Completed Exam");
    }
  }, [isFinish, handleSubmit, setTitle]);

  return (
    <MDBAnimation type="fadeIn">
      {!isFinish ? (
        <>
          <Header
            page={page}
            exam={exam}
            setIsFinish={setIsFinish}
            setPage={setPage}
            numberOfQuestions={numberOfQuestions}
          />
          <Body
            page={page}
            questions={questions}
            setAnswersOfStudent={setAnswersOfStudent}
          />
          <Footer
            setPage={setPage}
            numberOfQuestions={numberOfQuestions}
            page={page}
            handleSubmit={() => setIsFinish(true)}
          />
        </>
      ) : (
        <>
          <CompletedExam
            totalScore={totalScore}
            passingScore={exam?.passingScore}
          />
        </>
      )}
    </MDBAnimation>
  );
};

export default Exam;
