import React, { useEffect } from "react";
import { MDBCol, MDBInput, MDBRow } from "mdbreact";
import CustomSelect from "../customSelect";
import Tracks from "../../services/fakeDb/track";
function SelectLevel({
  form,
  setForm,
  disableSemester = true,
  hasName = false,
}) {
  const { name, ...rest } = form;
  const key = JSON.stringify(rest);

  useEffect(() => {
    if (form.lvl > 10 && !form.specialization) {
      const tracks = [...Tracks.collections];
      setForm({
        ...form,
        specialization: tracks[0]?.name,
      });
    }
  }, [form, setForm]);

  return (
    <MDBRow className="p-1">
      <MDBCol md={disableSemester ? "" : "4"}>
        <CustomSelect
          label={"Grade Level"}
          key={`${key}-grade-level`}
          choices={[7, 8, 9, 10, 11, 12]}
          preValue={form?.lvl}
          onChange={(level) => setForm({ ...form, lvl: level })}
        />
      </MDBCol>
      {form.lvl > 10 && (
        <>
          <MDBCol md="4">
            <CustomSelect
              label={"Specialization"}
              choices={Tracks.collections}
              key={`${key}-specialization`}
              texts="name"
              values="name"
              preValue={form?.specialization}
              onChange={(specialization) =>
                setForm({ ...form, specialization })
              }
            />
          </MDBCol>
          {form.specialization && (
            <MDBCol md="4">
              <CustomSelect
                label={"Strand"}
                choices={Tracks.getStrand(form.specialization)}
                values="abbr"
                preValue={form?.strand}
                key={`${key}-strand`}
                texts="abbr"
                onChange={(strand) => setForm({ ...form, strand })}
              />
            </MDBCol>
          )}
          {!disableSemester && (
            <MDBCol md="4">
              <CustomSelect
                label={"Semester"}
                preValue={form?.semester}
                key={`${key}-Semester`}
                choices={["1st", "2nd"]}
                onChange={(semester) => setForm({ ...form, semester })}
              />
            </MDBCol>
          )}
        </>
      )}

      {hasName && (
        <MDBCol>
          <MDBInput
            type="text"
            label="Name"
            value={form.name}
            onChange={(e) =>
              setForm({ ...form, name: e.target.value.toUpperCase() })
            }
            required
          />
        </MDBCol>
      )}
    </MDBRow>
  );
}

export default SelectLevel;
