import { MDBBtn, MDBIcon } from "mdbreact";
import React, { useEffect, useState } from "react";
import converter from "../../../../../services/utilities/converter";

const max = 8;
const MultipleChoice = ({
  form = {},
  choices = [],
  setForm = () => {},
  setChoices = () => {},
}) => {
  // const [choices, setChoices] = useState(defaultChoices),
  const [isMax, setIsMax] = useState(false);

  useEffect(() => {
    setIsMax(choices.length === max);
  }, [choices]);

  const handleAddQuestion = () => {
    const _choices = [...choices];
    const newID = converter.indexToLetter(_choices.length);
    _choices.push({ text: "", _id: newID });
    setChoices(_choices);
  };

  const handleRemoveChoice = (index) => {
    const _choices = [...choices];
    _choices.splice(index, 1);
    setChoices(_choices);
  };

  const handleChangeChoice = (choice, index) => {
    const _choices = [...choices];
    _choices[index] = { ..._choices[index], text: choice };
    setChoices(_choices);
  };
  return (
    <div>
      {choices.map((choice, index) => (
        <div key={index} className="d-flex align-items-center mt-2">
          <span className="mr-3 font-weight-bold">{choice._id}.</span>
          <input
            className="form-control"
            required
            value={choice.text}
            placeholder={`Enter a choice for option ${choice._id}`}
            onChange={({ target }) => handleChangeChoice(target.value, index)}
          />
          {choices.length > 2 && (
            <MDBBtn
              rounded
              color="danger"
              size="sm"
              onClick={() => handleRemoveChoice(index)}
            >
              <MDBIcon icon="trash" />
            </MDBBtn>
          )}
        </div>
      ))}
      <div className="d-flex justify-content-end  mt-3">
        <MDBBtn
          color="info"
          size="sm"
          onClick={handleAddQuestion}
          disabled={isMax}
        >
          <MDBIcon icon="plus" className="mr-2" />{" "}
          {!isMax ? "Add choice" : "Choice Limit Reached"}
        </MDBBtn>
      </div>
      <div className="d-flex align-items-center mb-4">
        <span className="mr-2 font-weight-bold">Correct Answer:</span>
        <select
          className="form-control w-25"
          required
          value={form.correctAnswer}
          onChange={({ target }) =>
            setForm({ ...form, correctAnswer: target.value })
          }
        >
          <option value={""} disabled>
            Choose a correct answer
          </option>
          {choices.map(({ text }, index) => {
            return (
              <option key={index} value={text} disabled={!text}>
                {text || "--"}
              </option>
            );
          })}
        </select>
      </div>
    </div>
  );
};

export default MultipleChoice;
