import React, { useCallback, useEffect, useState } from "react";
import { MDBCard, MDBView, MDBCardBody, MDBCol } from "mdbreact";
import { useDispatch, useSelector } from "react-redux";
import { BROWSE } from "../../../../services/redux/slices/teacher/classes";

import Search from "../../../../widgets/search";
import TableLoading from "../../../../widgets/tableLoading";
import Table from "./table";
import Level from "./level";
import { TeacherHeaderBatch } from "../../../../widgets/header";

function Classes() {
  const { auth, information, token } = useSelector(({ auth }) => auth),
    { collections, isLoading } = useSelector(({ classes }) => classes),
    [classes, setClasses] = useState([]),
    [levels, setLevels] = useState([]),
    [sections, setSections] = useState([]),
    [strands, setStrands] = useState([]),
    [form, setForm] = useState({}),
    [isChangeSY, setIsChangeSY] = useState(false),
    [subjects, setSubjects] = useState([]),
    [progress, setProgress] = useState([]),
    [params, setParams] = useState({}),
    [semesters, setSemesters] = useState([]),
    [didSearch, setDidSearch] = useState(false),
    dispatch = useDispatch();

  const handleDefaultParams = useCallback(
    (_sy = "") => {
      const _progress = information.previousBatches
        .filter(({ sy }) => sy === _sy)
        .map(({ progress }) => progress);

      const _uniqueProgress = [...new Set(_progress)];
      setProgress(_uniqueProgress);
      setParams((prevParams) => ({
        progress: _uniqueProgress[0] || "",
        sy: prevParams.sy || _sy,
      }));
      setIsChangeSY(true);
    },
    [information.previousBatches]
  );

  useEffect(() => {
    const defaultSY = information.previousBatches[0]?.sy;
    handleDefaultParams(defaultSY);
  }, [handleDefaultParams, information]);

  useEffect(() => {
    handleDefaultParams(params.sy);
  }, [params.sy, handleDefaultParams]);

  useEffect(() => {
    if (isChangeSY && params.sy && params.progress) {
      const batchID = information.previousBatches
        .filter(
          ({ sy, progress: p }) => sy === params.sy && params.progress === p
        )
        .map(({ _id }) => _id);

      if (batchID) {
        dispatch(
          BROWSE({
            token,
            data: { instructor: auth._id, batches: batchID },
          })
        );
        setIsChangeSY(false);
      }
    }
  }, [auth, information.previousBatches, token, dispatch, params, isChangeSY]);

  useEffect(() => {
    if (collections.length > 0) {
      // to remove duplicate levels
      const _levels = getUniqueProperties(collections, "lvl");
      _levels.sort((a, b) => a - b);
      const _strands = getUniqueProperties(collections, "strand");
      const _sections = removeDuplicate(
        collections?.map(({ section }) => section)
      );

      const defaultSectionId = _sections[0]._id || "";

      const getSpecificCollections = (_collections = [], key = "") => {
        return _collections
          .filter((obj) => obj.section?._id === defaultSectionId)
          .map((obj = "") => obj[key]);
      };

      //para kunin lahat ng subject sa default section
      const _subjects = getSpecificCollections(collections, "section");
      const _semesters = getSpecificCollections(collections, "semester");

      setForm((prev) => ({
        strand: _strands[0] || "",
        section: defaultSectionId || prev.section,
        lvl: !_levels.some((lvl) => lvl === prev.lvl) ? _levels[0] : prev.lvl,
        semester: _semesters[0] || prev.semester,
        subject: _subjects[0] || prev.subject,
      }));
      setLevels(_levels);
      setClasses(collections[0] || { students: [] });
    }
  }, [collections]);

  useEffect(() => {
    const { lvl, subject, strand, section, semester } = form;
    // na dedelay kasi kaya ginanito ko chinecheck ko muna para malaman ko kung nag palit ba ng batch
    const isChangeBatch = collections.some(
      ({ lvl: collectionLvl }) => collectionLvl === lvl
    );

    if (section && lvl && isChangeBatch && subject) {
      const _classes = collections.filter(({ strand: cStrand, lvl: cLvl }) =>
        lvl > 10 ? cLvl === lvl && cStrand === strand : cLvl === lvl
      );

      const isLevelChange = _classes.some(
        ({ section: sec }) => sec._id === section
      );

      const sectionID = isLevelChange ? section : _classes[0]?.section?._id;
      const _strand = lvl > 10 ? _classes[0]?.strand : "";
      const _strands = [
        ...new Set(_classes.map(({ strand: s }) => s).filter(Boolean)),
      ];

      const _semesters = [
        ...new Set(
          _classes
            .filter(({ section: sec }) => sec._id === sectionID)
            .map(({ semester }) => semester)
        ),
      ];

      // para malaman ko kung may avail bang semester  na tulad ng active na semester sa section nayun
      const storageSemesters = _classes.filter(
        ({ section: sec }) => sec._id === sectionID
      );
      const availSemester = storageSemesters.some(
        ({ semester: sem }) => sem === semester
      );
      //

      const _defaultSemester = availSemester ? semester : _semesters[0];
      const _subjects = _classes
        .filter(({ section: sec, semester: sem = "" }) =>
          lvl > 10
            ? sec._id === sectionID && sem === _defaultSemester
            : sec._id === sectionID
        )
        .map(({ subject }) => subject);

      // para lang malaman ko kung nag palit siya ng section
      const isChangeSection = _subjects.some(({ _id }) => _id === subject);
      const subjectID = !isChangeSection ? _subjects[0]?._id : subject;

      // para makuha yung ibang students niya kapag nag palit siya ng level tapos subject tas section
      const anotherClasses = _classes.find(
        ({ section: sec, subject: sub }) =>
          sec._id === sectionID && sub._id === subjectID
      );

      setForm((prev) => {
        const newForm = {
          lvl,
          strand: prev.strand || _strand,
          subject: subjectID,
          semester: _defaultSemester,
          section: sectionID,
        };
        return JSON.stringify(newForm) !== JSON.stringify(prev)
          ? newForm
          : prev;
      });

      setSections(
        removeDuplicate(_classes.map(({ section }) => section)) || []
      );
      setSubjects(removeDuplicate(_subjects) || []);
      setClasses(anotherClasses || []);
      setStrands(_strands || []);
      setSemesters(_semesters || []);
    }
  }, [form, collections]);

  const getUniqueProperties = (_collections = [], key = "") => {
    return [...new Set(_collections.map((obj) => obj[key]))].filter(Boolean);
  };

  const removeDuplicate = (array) => {
    const uniqueData = array.filter((obj, index, self) => {
      return index === self.findIndex((s) => s._id === obj._id);
    });

    return uniqueData;
  };

  const handleSearch = () => {};

  return (
    <MDBCard narrow className="pb-3">
      <MDBView
        cascade
        className="gradient-card-header blue-gradient py-2 mx-4 d-flex justify-content-between align-items-center"
      >
        <span className="ml-3 font-weight-bold">
          <h6>Classes List </h6>
        </span>

        <div className="d-flex align-items-center justify-content-center w-50">
          <TeacherHeaderBatch params={params} setParams={setParams} />
          <MDBCol size="3">
            <select
              className="form-control bg-light"
              value={params.progress}
              onChange={(e) => {
                setParams({ ...params, progress: e.target.value });
                setIsChangeSY(true);
              }}
            >
              {progress.map((p, index) => (
                <option key={index} value={p}>
                  {p.toUpperCase()}
                </option>
              ))}
            </select>
          </MDBCol>
        </div>

        <Search
          didSearch={didSearch}
          handleSearch={handleSearch}
          array={[]}
          setArray={[]}
          setDidSearch={setDidSearch}
          isTeacher={true}
        />
      </MDBView>
      <MDBCardBody>
        {isLoading ? (
          <TableLoading />
        ) : (
          <>
            <Level
              levels={levels}
              strands={strands}
              sections={sections}
              semesters={semesters}
              subjects={subjects}
              form={form}
              setForm={setForm}
            />
            <Table
              students={classes?.students || []}
              subject={classes?.subject}
              classID={classes._id}
              level={form.lvl}
              semester={form.semester}
            />
          </>
        )}
      </MDBCardBody>
    </MDBCard>
  );
}

export default Classes;
