import React, { useEffect, useState } from "react";
import { MDBBadge, MDBListGroup, MDBListGroupItem } from "mdbreact";

function SwitchView({
  active = "jhs",
  titles = [
    { text: "Junior High School", value: "jhs" },
    { text: "Senior High School", value: "shs" },
  ],
  _key = "progress",
  setActive = () => {},
  array = [],
}) {
  const [baseTitles, setBaseTitles] = useState([]);

  useEffect(() => {
    const titlesWithCount = titles
      .map((title) => {
        const values = [...array].filter(
          (obj) => obj[_key].toLowerCase() === title.value.toLocaleLowerCase()
        );

        return { ...title, count: values.length || 0 };
      })
      .filter(({ count }) => count > 0);
    setBaseTitles(titlesWithCount);
  }, [array, _key, titles]);

  return (
    <MDBListGroup
      style={{ height: "40px", overflowX: "auto", whiteSpace: "nowrap" }}
      className="d-flex flex-row"
    >
      {baseTitles.map(({ text, value, count }, index) => {
        const isActive = active === value;
        return (
          <MDBListGroupItem
            onClick={() => setActive(value)}
            key={index}
            style={{ minWidth: "100px" }}
            className={`d-flex justify-content-between  align-items-center rounded py-2 mx-2 h-100 cursor-pointer ${
              isActive && "bg-primary text-white"
            }`}
          >
            <b className="mr-2">{text.toUpperCase()}</b>
            <MDBBadge
              color={isActive ? "light" : "primary"}
              className="pt-1"
              pill
            >
              {count}
            </MDBBadge>
          </MDBListGroupItem>
        );
      })}
    </MDBListGroup>
  );
}

export default SwitchView;
