import React from "react";
import {
  MDBModal,
  MDBModalBody,
  MDBIcon,
  MDBModalHeader,
  MDBRow,
  MDBCol,
  MDBBtn,
} from "mdbreact";
import MultipleChoice from "./type/multipleChoice";
import MatchingType from "../../../../student/matchingType";
import Identification from "./type/identification";
import Swal from "sweetalert2";
import { fullName } from "../../../../../../services/utilities";
import TypesCount from "../typesCount";

export default function ViewQuestions({
  show = false,
  isView = false,
  isChecking = false,
  title = "Selected Questions",
  participant = {},
  questions = [],
  toggle = () => {},
  setQuestions = () => {},
}) {
  const handleDelete = (index) => {
    Swal.fire({
      title: "Are you sure?",
      text: "You won't be able to revert this!",
      icon: "warning",
      showCancelButton: true,
      confirmButtonColor: "#3085d6",
      cancelButtonColor: "#d33",
      confirmButtonText: "Yes, delete it!",
    }).then((result) => {
      if (result.isConfirmed) {
        const _questions = [...questions];
        _questions.splice(index, 1);
        setQuestions(_questions);
      }
    });
  };
  const { exam = {}, score = 0 } = participant || {};
  const isPassed = score >= exam.passingScore;
  return (
    <MDBModal isOpen={show} toggle={toggle} size="xl">
      <MDBModalHeader
        toggle={toggle}
        className="light-blue darken-3 white-text"
      >
        <MDBIcon
          icon={isChecking ? "user" : "clipboard-list"}
          className="mr-2"
        />
        {isChecking ? fullName(participant?.student?.fullName) : title}
      </MDBModalHeader>
      <MDBModalBody className="mb-0">
        {isChecking ? (
          <div className="d-flex align-items-center justify-content-between">
            <h5>
              Total Score:{" "}
              <strong>
                {participant.score} / {questions?.length}
              </strong>
            </h5>
            <h5>
              Passing Score: <strong>{exam.passingScore}</strong>
            </h5>
            <h5>
              Status:{" "}
              <strong className={isPassed ? "text-success" : "text-danger"}>
                {isPassed ? "PASSED" : "FAILED"}
              </strong>
            </h5>
          </div>
        ) : (
          <TypesCount questions={questions} />
        )}
        <hr />
        {!!questions &&
          questions.map((que, index) => (
            <MDBRow key={index}>
              <MDBCol md={isView ? "12" : "10"}>
                {que.type === "mc" ? (
                  <MultipleChoice
                    question={que}
                    index={index}
                    isChecking={isChecking}
                  />
                ) : que.type === "matching" ? (
                  <MatchingType
                    question={que}
                    haveIndexOfQuestion={true}
                    index={index}
                    isView={isView}
                    isChecking={isChecking}
                  />
                ) : (
                  <Identification
                    question={que}
                    index={index}
                    isChecking={isChecking}
                  />
                )}
              </MDBCol>
              {!isView && (
                <MDBCol>
                  <MDBBtn
                    size="sm"
                    rounded
                    color="danger"
                    className="float-right"
                    onClick={() => handleDelete(index)}
                  >
                    <MDBIcon icon="trash" />
                  </MDBBtn>
                </MDBCol>
              )}
            </MDBRow>
          ))}
      </MDBModalBody>
    </MDBModal>
  );
}
