import React, { useState } from "react";
import { MDBTable, MDBBtn, MDBIcon, MDBBtnGroup } from "mdbreact";
import {
  formattedDate,
  formattedTime,
  handlePagination,
} from "../../../../../services/utilities";
import { UPDATE } from "../../../../../services/redux/slices/registrar/entranceExam";
import Rows from "../../../../../widgets/pagination/rows";
import PaginationButtons from "../../../../../widgets/pagination/buttons";
import TableLoading from "../../../../../widgets/tableLoading";
import { useDispatch, useSelector } from "react-redux";
import Swal from "sweetalert2";
import handleMultiSeclect from "../../../../../widgets/multipleSelect";

const Table = ({
  entranceExam,
  isLoading,
  container = [],
  setQuestionView = () => {},
  setContainer = () => {},
}) => {
  const { token } = useSelector(({ auth }) => auth),
    [max, setMax] = useState(5),
    [page, setPage] = useState(1),
    dispatch = useDispatch();

  const handleChangeStatus = (exam) => {
    const { status } = exam;
    var _status =
      status === "PENDING" ? "OPEN" : status === "OPEN" ? "CLOSED" : "";
    const text = status === "PENDING" ? "opened" : "closed";
    Swal.fire({
      title: "Are you sure?",
      text: `You are about to ${
        status === "PENDING" ? "open" : "close"
      } the entrance exam. Once ${text}, you cannot go back!`,
      icon: "warning",
      showCancelButton: true,
      confirmButtonColor: "#3085d6",
      cancelButtonColor: "#d33",
      confirmButtonText: `Yes, ${status === "PENDING" ? "open" : "close"} it!`,
    }).then((result) => {
      if (result.isConfirmed) {
        dispatch(UPDATE({ token, data: { ...exam, status: _status } }));
        Swal.fire(
          status === "PENDING" ? "Opened!" : "Closed!",
          `The entrance exam has been ${text}.`,
          "success"
        );
      }
    });
  };

  return (
    <>
      {!isLoading ? (
        <>
          <MDBTable responsive>
            <thead>
              <tr>
                <th>
                  <input
                    className="form-check-input"
                    type="checkbox"
                    disabled
                    id={`collapse`}
                  />
                  <label
                    htmlFor={`collapse`}
                    className="form-check-label mr-2 label-table"
                  />
                </th>
                <th className="text-center">Batch</th>
                <th className="text-center">Date </th>
                <th className="text-center">Number of questions</th>
                <th className="text-center">Passing Score</th>
                <th className="text-center">Duration</th>
                <th className="text-center">Status</th>
                <th className="text-center">Action</th>
              </tr>
            </thead>
            <tbody>
              {handlePagination(entranceExam, page, max).map((exam, index) => {
                const isChecked = container.some(({ _id }) => _id === exam._id);
                return (
                  <tr key={index}>
                    <td>
                      <input
                        className="form-check-input"
                        type="checkbox"
                        id={exam._id}
                        checked={isChecked}
                        disabled={exam.status !== "PENDING"}
                        onChange={() => {
                          setContainer(
                            handleMultiSeclect(container, exam, false)
                          );
                        }}
                      />
                      <label
                        htmlFor={exam._id}
                        className="form-check-label mr-2 label-table"
                      />
                    </td>
                    <td className="text-center" style={{ fontWeight: 400 }}>
                      {exam.batch.sy}
                    </td>
                    <td className="text-center" style={{ fontWeight: 400 }}>
                      {formattedDate(exam.date, false)}{" "}
                      {formattedTime(exam.startTime)} -{" "}
                      {formattedTime(exam.endTime)}
                    </td>

                    <td
                      className="text-center cursor-pointer"
                      onClick={() => setQuestionView(exam)}
                      style={{ fontWeight: 400 }}
                    >
                      {exam.questions.length}
                    </td>
                    <td className="text-center" style={{ fontWeight: 400 }}>
                      {exam.passingScore}
                    </td>
                    <td className="text-center" style={{ fontWeight: 400 }}>
                      {exam.duration}
                    </td>
                    <td className="text-center" style={{ fontWeight: 500 }}>
                      {exam.status}
                    </td>

                    <td className="text-center ">
                      <MDBBtnGroup>
                        {exam.status !== "CLOSED" && (
                          <MDBBtn
                            onClick={() => handleChangeStatus(exam)}
                            color={exam.status === "OPEN" ? "light" : "success"}
                            size="sm"
                          >
                            {exam.status === "OPEN" ? "CLOSED" : "OPEN"}
                          </MDBBtn>
                        )}
                        <MDBBtn
                          size="sm"
                          color="info"
                          onClick={() => setQuestionView(exam)}
                          title="View Questions"
                        >
                          <MDBIcon icon="clipboard-list" />
                        </MDBBtn>
                      </MDBBtnGroup>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </MDBTable>
          <Rows max={max} setMax={setMax} />
          <PaginationButtons
            page={page}
            setPage={setPage}
            max={max}
            array={entranceExam}
          />
        </>
      ) : (
        <TableLoading />
      )}
    </>
  );
};

export default Table;
