import { MDBCol, MDBInput, MDBRow } from 'mdbreact'
import React from 'react'

import "./learner.css";
const Health = ({ selected }) => {
  const { hasDisability, disabilities, height, weight, bloodType } = selected.healthStatistics;

  return (
    <>
      <MDBRow style={{ backgroundColor: "#0000FF" }}>
        <MDBCol>
          <h5 className="font-weight-bold text-white mt-2 label mb-2 ml-5 section-title">
            II. Health Survey
          </h5>
        </MDBCol>
      </MDBRow>

      <MDBRow className="ml-4 mt-4">
        <MDBCol>          
          <h6><span className="red-text">*</span><strong>Is the child Learner with Disability?</strong></h6>
        </MDBCol>
      </MDBRow>
      <MDBRow className="ml-4">
        <MDBCol className="p-0" md="2">
          <MDBInput 
            label="Yes"
            type="checkbox"
            name="hasDisability"
            checked={hasDisability}
            id="wDisability"
            readOnly
          />
        </MDBCol>
        <MDBCol className="p-0" md="10">
          <MDBInput 
            label="No"
            type="checkbox"
            name="hasDisability"
            checked={!hasDisability}
            id="nDisability"
            readOnly
          />
        </MDBCol>
      </MDBRow>

      <MDBRow className="ml-4 mt-4">
        <MDBCol>          
          <h6><strong>If Yes, specify the type of disability:</strong></h6>
        </MDBCol>
      </MDBRow>

      <MDBRow>
        <MDBCol md='6'>
          <MDBRow className="m-4">
            <MDBCol>          
              <h6><strong>Visual Impairment</strong></h6>
            </MDBCol>
          </MDBRow>
          <MDBRow className="ml-4">
            <MDBCol md="4">
              <MDBInput 
                label="a. Blind"
                type="checkbox"
                value="blind"
                name="visual"
                checked={disabilities.includes("blind") && !disabilities.includes("low vision")}
                id="blind"
                readOnly
              />
            </MDBCol>
          
            <MDBCol md="8">
              <MDBInput 
                label="a. Low vision"
                type="checkbox"
                value="low vision"
                name="visual"
                checked={disabilities.includes("low vision") && !disabilities.includes("blind")}
                id="vision"
                readOnly
              />
            </MDBCol>
          </MDBRow>
        </MDBCol>

        <MDBCol  md='6'>
          <MDBRow className="m-4">
            <MDBCol className="p-0">
              <h6><strong>Special Health Problem/Chronic Disease</strong></h6>
            </MDBCol>
          </MDBRow>
          <MDBRow className="ml-4">
            <MDBCol>
                <MDBInput 
                  label="a. Cancer"
                  type="checkbox"
                  value="cancer"
                  name="diceased"
                  checked={disabilities.includes("cancer")}
                  id="cancer"
                  readOnly
                />
            </MDBCol>
          </MDBRow>

        </MDBCol>
      </MDBRow>

      <MDBRow className="m-4">
        <MDBCol className="p-0" md="3">
          <MDBInput 
            label="Hearing Impairment"
            type="checkbox"
            value="hearing impairment"
            name="diceased"
            checked={disabilities.includes("hearing impairment")}
            id="hearing"
            readOnly
          />
        </MDBCol>

        <MDBCol className="p-0" md="3">
          <MDBInput 
            label="Learning Disability"
            type="checkbox"
            value="learning disability"
            name="diceased"
            checked={disabilities.includes("learning disability")}
            id="learning"
            readOnly
          />
        </MDBCol>

        <MDBCol className="p-0" md="3">
          <MDBInput 
            label="Intelectual Disability"
            type="checkbox"
            value="intelectual disability"
            name="diceased"
            checked={disabilities.includes("intelectual disability")}
            id="intelectual"
            readOnly
          />
        </MDBCol>

        <MDBCol className="p-0" md="3">
          <MDBInput 
            label="Autism Spectrum Disorder"
            type="checkbox"
            value="autism spectrum disorder"
            name="diceased"
            checked={disabilities.includes("autism spectrum disorder")}
            id="autism"
            readOnly
          />
        </MDBCol>
      </MDBRow>

      <MDBRow className="m-4">
        <MDBCol className="p-0" md="3">
          <MDBInput 
            label="Emotional-Behavioral Disorder"
            type="checkbox"
            value="emotional-behavioral disorder"
            name="diceased"
            checked={disabilities.includes("emotional-behavioral disorder")}
            id="emotional"
            readOnly
          />
        </MDBCol>
        
        <MDBCol className="p-0" md="3">
          <MDBInput 
            label="Orthopedic/ Physical Handicap"
            type="checkbox"
            value="orthopedic/physical handicap"
            name="diceased"
            checked={disabilities.includes("orthopedic/physical handicap")}
            id="orthopedic"
            readOnly
          />
        </MDBCol>
        
        <MDBCol className="p-0" md="3">
          <MDBInput 
            label="Speech/ Language Disoder"
            type="checkbox"
            value="speech/language disoder"
            name="diceased"
            checked={disabilities.includes("speech/language disoder")}
            id="speech"
            readOnly
          />
        </MDBCol>
        
        <MDBCol className="p-0" md="3">
          <MDBInput 
            label="Celebral Paisy"
            type="checkbox"
            value="celebral paisy"
            name="diceased"
            checked={disabilities.includes("celebral paisy")}
            id="celebral"
            readOnly
          />
        </MDBCol>
      </MDBRow>
      <MDBRow className="m-4">
        <MDBCol className="p-0" md="3">
          <MDBInput 
            label="Multiple Disorder"
            type="checkbox"
            value="multiple disorder"
            name="diceased"
            checked={disabilities.includes("multiple disorder")}
            id="multiple"
            readOnly
          />
        </MDBCol>
      </MDBRow>

      <MDBRow style={{ backgroundColor: "#0000FF" }}>
        <MDBCol>
          <h5 className="font-weight-bold text-white mt-2 label mb-2 ml-5 section-title">
            II.I Physical Statistics
          </h5>
        </MDBCol>
      </MDBRow>

      <MDBRow className="m-4">
        <MDBCol className="pt-0 pb-0 pl-0 pr-2" sm="6" lg="4">
          <h6 className="mt-4">
            <strong> <span className="red-text">*</span>Height</strong>
          </h6>        
          <input
            type="text"
            placeholder="Height"
            value={height || ""}
            name="height"
            className="form-control lrn"
            readOnly
          />
        </MDBCol>
        <MDBCol className="pt-0 pb-0 pl-0 pr-2" sm="6" lg="4">
          <h6 className="mt-4">
            <strong> <span className="red-text">*</span>Weight</strong>
          </h6>        
          <input
            type="text"
            placeholder="Weight"
            value={weight || ""} 
            name="weight"
            className="form-control lrn"
            readOnly
          />
        </MDBCol>
        <MDBCol className="pt-0 pb-0 pl-0 pr-2" sm="6" lg="4">
          <h6 className="mt-4">
            <strong>Blood type</strong>
          </h6>        
          <input
            type="text"
            placeholder="Blood type"
            value={bloodType || ""}
            name="bloodType"
            className="form-control lrn"
            readOnly
          />
        </MDBCol>
      </MDBRow>
    </>
  )
}

export default Health