import React, { useEffect, useState } from "react";
import OrganizationTable from "./table";
import { useDispatch, useSelector } from "react-redux";
import { BROWSE } from "../../../services/redux/slices/organization";

function OrgChart() {
  const { organization } = useSelector(({ organization }) => organization);
  const [employees, setEmployees] = useState([]);
  const dispatch = useDispatch();

  useEffect(() => {
    dispatch(BROWSE());
  }, [dispatch]);

  useEffect(() => {
    setEmployees(organization);
  }, [organization]);

  useEffect(() => {
    window.scrollTo({ top: 0, behavior: "smooth" });
  }, []);

  return (
    <div style={{ height: "100vh", paddingTop: "5rem" }}>
      <OrganizationTable members={employees} />
    </div>
  );
}

export default OrgChart;
