import React from "react";
import "./default.css";
import { MDBCol, MDBIcon, MDBRow } from "mdbreact";
import { ENDPOINT } from "../../../services/utilities";
import chatSuport from "../../../assets/chatSupport.jpg";

const Default = ({ isAgent, setChatNow, handleSendDefaultMessage }) => {
  const handleChatNow = () => {
    setChatNow(true);
    handleSendDefaultMessage();
  };

  return (
    <div
      className="h-100 w-100 d-flex flex-column justify-content-center align-items-center"
      style={{ borderRadius: "10px" }}
    >
      <div
        className="d-flex flex-column justify-content-center align-items-center center-container"
        style={{ borderRadius: "10px" }}
      >
        {isAgent ? (
          <>
            <MDBRow className="mt-5">
              <MDBCol md="12" className="position-relative">
                <i className="fas fa-comment fa-10x text-primary comment "></i>
                <i className="far fa-envelope fa-6x text-light position-absolute envelope"></i>
                <img src={chatSuport} alt="IMG" style={{ height: "20rem" }} />
              </MDBCol>
            </MDBRow>
            <MDBRow>
              <MDBCol md="12">
                <h3>No messages here yet...</h3>
                <p>
                  Send a message by tapping on an account on the right side.
                </p>
              </MDBCol>
            </MDBRow>
          </>
        ) : (
          <>
            <MDBRow>
              <img
                src={`${ENDPOINT}/assets/gif/purplebeaver_agaduw4aampkeeo.gif`}
                alt="beaver"
                className="beaver"
              />
            </MDBRow>
            <MDBRow>
              <MDBCol md="12">
                <h3 className="name-label">Help Desk here!</h3>
                <p className="m-0">
                  Hello!{" "}
                  <span role="img" aria-label="waving hand">
                    👋
                  </span>
                  . How can I assist you today?
                </p>
                <p className="text-desktop">
                  Whether you have questions about enrollment, class schedules,
                  or anything else, I'm here to help! If you need immediate
                  assistance, feel free to ask.{" "}
                  <span role="img" aria-label="smilling face">
                    😊
                  </span>
                </p>
              </MDBCol>
            </MDBRow>
            <MDBRow className="mt-4">
              <MDBCol md="12">
                <div
                  className="rounded d-flex flex-row p-3 cursor-pointer"
                  style={{ gap: "1rem", background: "#d9d9d9" }}
                  onClick={handleChatNow}
                >
                  <p className="m-0 h6">Chat now</p>
                  <MDBIcon icon="paper-plane" style={{ color: "blue" }} />
                </div>
              </MDBCol>
            </MDBRow>
          </>
        )}
      </div>
    </div>
  );
};

export default Default;
