import React from "react";
import { MDBRow, MDBCol, MDBInput } from "mdbreact";
import { getAge } from "../../../../../services/utilities";
import AddressSelect from "../../../../../components/addressSelect";
import CustomSelect from "../../../../../components/customSelect";
const Information = ({ handleChange, form }) => {
  return (
    <>
      <MDBRow className="d-flex">
        <MDBCol>
          <MDBInput
            type="text"
            label="Position"
            value={form.position}
            required
            onChange={(e) =>
              handleChange("position", e.target.value.toUpperCase())
            }
          />
        </MDBCol>
        <MDBCol>
          <CustomSelect
            choices={[
              { name: "Teacher", _id: "65eb2eb58c6b7e03972248a0" },
              { name: "Registrar", _id: "65c10d39be3826c17b450cf3" },
              { name: "Help Desk", _id: "66aa9040495963b36ff59e81" },
            ]}
            label={"Role"}
            texts="name"
            values="_id"
            preValue={form.role}
            onChange={(value) => handleChange("role", value)}
          />
        </MDBCol>

        <MDBCol>
          <MDBInput
            type="number"
            label="Mobile No. +63 "
            value={form.mobile}
            onChange={(e) =>
              handleChange("mobile", e.target.value.toUpperCase())
            }
            required
          />
        </MDBCol>
      </MDBRow>
      {form.role === "65eb2eb58c6b7e03972248a0" && (
        <MDBRow className="mb-2">
          <MDBCol>
            <div className="d-flex">
              Would you like to grant access to the enrollment?
              <input
                className="form-check-input"
                type="checkbox"
                id="yes-haveAccess"
                checked={form?.haveEnrollmentAccess}
                onChange={(e) =>
                  handleChange("haveEnrollmentAccess", e.target.checked)
                }
              />
              <label
                className="form-check-label ml-3 mr-4"
                htmlFor="yes-haveAccess"
              >
                Yes
              </label>
              <input
                className="form-check-input"
                type="checkbox"
                id="no-haveAccess"
                checked={!form?.haveEnrollmentAccess}
                onChange={(e) =>
                  handleChange("haveEnrollmentAccess", !e.target.checked)
                }
              />
              <label className="form-check-label " htmlFor="no-haveAccess">
                No
              </label>
            </div>
          </MDBCol>
        </MDBRow>
      )}
      <MDBRow>
        <MDBCol md="6" className="border border-black">
          <MDBInput
            label="Last Name"
            type="text"
            value={form.fullName?.lname}
            onChange={(e) =>
              handleChange("fullName", e.target.value.toUpperCase(), "lname")
            }
            required
          />
          <MDBInput
            label="Middle Name (Optional)"
            type="text"
            value={form.fullName?.mname}
            onChange={(e) =>
              handleChange("fullName", e.target.value.toUpperCase(), "mname")
            }
          />
          <MDBRow>
            <MDBCol md="8">
              <MDBInput
                label="First Name"
                type="text"
                value={form.fullName?.fname}
                onChange={(e) =>
                  handleChange(
                    "fullName",
                    e.target.value.toUpperCase(),
                    "fname"
                  )
                }
                required
              />
            </MDBCol>
            <MDBCol>
              <CustomSelect
                choices={["N/A", "JR", "III", "IV", "V", "SR"]}
                label="Suffix"
                preValue={form.suffix}
                onChange={(value) => handleChange("suffix", value)}
              />
            </MDBCol>
          </MDBRow>
        </MDBCol>
        <MDBCol md="6">
          <MDBInput
            label="Mother Toungue(ex: Tagalog, English)"
            value={form?.motherTounge}
            onChange={(e) =>
              handleChange("motherTounge", e.target.value.toUpperCase())
            }
            required
          />
          <MDBRow>
            <MDBCol md="4">
              <MDBInput
                type="date"
                label="Date of Birth"
                value={form?.dob}
                onChange={(e) =>
                  handleChange("dob", e.target.value.toUpperCase())
                }
                required
              />
            </MDBCol>
            <MDBCol md="4">
              <MDBInput
                type="text"
                label="Age"
                readOnly
                value={getAge(form.dob)}
              />
            </MDBCol>
            <MDBCol md="4">
              <CustomSelect
                choices={["Single", "Married"]}
                label={"Civil Status"}
                value={form?.civil}
                onChange={(value) => handleChange("civil", value)}
              />
            </MDBCol>
          </MDBRow>
          <MDBRow className="d-flex align-items-center">
            <MDBCol md="3">
              <div className="form-check">
                <input
                  className="form-check-input"
                  type="checkbox"
                  id="Male"
                  checked={form?.isMale}
                  onChange={(e) => handleChange("isMale", e.target.checked)}
                />
                <label className="form-check-label" htmlFor="Male">
                  Male
                </label>
              </div>
              <div className="form-check">
                <input
                  className="form-check-input"
                  type="checkbox"
                  id="Female"
                  checked={!form?.isMale}
                  onChange={(e) => handleChange("isMale", !e.target.checked)}
                />
                <label className="form-check-label" htmlFor="Female">
                  Female
                </label>
              </div>
            </MDBCol>
            <MDBCol>
              <MDBInput
                label="Place of Birth (Municipality/City)"
                value={form?.birthplace}
                onChange={(e) =>
                  handleChange("birthplace", e.target.value.toUpperCase())
                }
                required
              />
            </MDBCol>
          </MDBRow>
        </MDBCol>
      </MDBRow>
      <MDBRow className="mt-5">
        <MDBCol md="12">
          <AddressSelect
            label="Current Address"
            address={form.address?.current}
            handleChange={(key, value) => handleChange(key, value, "current")}
          />
        </MDBCol>
      </MDBRow>
      <MDBRow className="mt-2">
        <MDBCol md="12" className="d-flex">
          <label>
            Is your permanent address is same with your current address?
          </label>
          <div className="form-check">
            <input
              className="form-check-input"
              type="checkbox"
              id="yes"
              checked={form.address?.isSame}
              onChange={({ target }) =>
                handleChange("address", target.checked, "isSame")
              }
            />
            <label className="form-check-label" htmlFor="yes">
              Yes
            </label>
          </div>
          <div className="form-check">
            <input
              className="form-check-input"
              type="checkbox"
              id="no"
              checked={!form.address?.isSame}
              onChange={({ target }) =>
                handleChange("address", !target.checked, "isSame")
              }
            />
            <label className="form-check-label" htmlFor="no">
              No
            </label>
          </div>
        </MDBCol>
      </MDBRow>
      <hr />
      {!form.address?.isSame && (
        <MDBRow>
          <MDBCol md="12">
            <AddressSelect
              label="Permanent Address"
              address={form.address?.permanent}
              handleChange={(key, value) =>
                handleChange(key, value, "permanent")
              }
            />
          </MDBCol>
        </MDBRow>
      )}
      ;
    </>
  );
};

export default Information;
