import React, { useEffect, useState } from "react";
import {
  MDBCard,
  MDBCardBody,
  MDBCol,
  MDBContainer,
  MDBRow,
  MDBIcon,
  MDBProgress,
  MDBView,
} from "mdbreact";
import {
  AllStudentsLength,
  BROWSE,
} from "../../../../services/redux/slices/registrar/students";
import { useDispatch, useSelector } from "react-redux";

import { Bar, Doughnut } from "react-chartjs-2";
import Table from "./table";

export default function Dashboard() {
  const { token, information } = useSelector(({ auth }) => auth),
    { collections, AllStudents } = useSelector(({ students }) => students),
    [batch, setBatch] = useState({ progress: "", sy: "", semester: "" }),
    [polarChartData, setPolarChartData] = useState({
      labels: ["Boys", "Girls"],
      datasets: [
        {
          data: [],
          backgroundColor: ["#66b2ff", "#46BFBD"],
          hoverBackgroundColor: ["#66b2ff", "#5AD3D1"],
        },
      ],
    }),
    [barChartData, setBarChartData] = useState({
      labels: [
        "Drop",
        "Active",
        "Enrollees",
        "Transferee",
        "Returnee",
        "Rejected",
      ],
      datasets: [
        {
          label: "# of Students",
          data: [],
          backgroundColor: [
            "rgba(255, 99, 132, 0.2)",
            "rgba(54, 162, 235, 0.2)",
            "rgba(255, 206, 86, 0.2)",
            "rgba(75, 192, 192, 0.2)",
            "rgba(153, 102, 255, 0.2)",
            "rgba(255, 159, 64, 0.2)",
          ],
          borderColor: [
            "rgba(255,99,132,1)",
            "rgba(54, 162, 235, 1)",
            "rgba(255, 206, 86, 1)",
            "rgba(75, 192, 192, 1)",
            "rgba(153, 102, 255, 1)",
            "rgba(255, 159, 64, 1)",
          ],
          borderWidth: 1,
        },
      ],
    }),
    [studentsData, setStudentsData] = useState({
      totalStudents: 0,
      totalEnrollees: 0,
      totalTeachers: 0,
      rejectedStudents: 0,
    }),
    dispatch = useDispatch();

  useEffect(() => {
    const currentBatch = information?.previousBatches.find(
      ({ status }) => status === "ACTIVE" || status === "INACTIVE"
    );
    setBatch({ ...currentBatch, progress: "jhs" });
  }, [information]);

  useEffect(() => {
    const { previousBatches } = information;
    const { progress, sy, semester } = batch;

    if (
      sy &&
      progress &&
      (progress === "jhs" || (progress === "shs" && semester))
    ) {
      const _batch = previousBatches.find(
        (prev) =>
          prev.progress === progress &&
          prev.sy === sy &&
          (progress === "jhs" || prev.semester === semester)
      );

      if (_batch) {
        dispatch(BROWSE({ token, data: { batch: [_batch._id] } }));
      }
    }
  }, [dispatch, token, information, batch]);

  useEffect(() => {
    if (token) {
      dispatch(AllStudentsLength({ token }));
    }
  }, [token]);

  useEffect(() => {
    if (AllStudents) {
      setStudentsData((prev) => ({ ...prev, totalStudents: AllStudents }));
    }
  }, [AllStudents]);

  useEffect(() => {
    if (collections) {
      console.log(collections);

      const maleStudents = collections.filter(
        (stud) => stud.student?.isMale === true
      );
      const feMaleStudents = collections.filter(
        (stud) => stud.student?.isMale === false
      );

      const returneeStudents = collections.filter(
        (student) => student.returnee === true
      ).length;

      const transfereeStudents = collections.filter(
        (student) => student.transferee === true
      ).length;

      const newStudents = collections.filter(
        (student) =>
          student.lvl === 7 &&
          !(student.returnee === true || student.transferee === true)
      ).length;

      const oldStudents = collections.filter(
        (student) =>
          student.lvl > 7 &&
          !(student.returnee === true || student.transferee === true)
      ).length;

      const rejectedStudents = collections.filter(
        (student) => student.status === "REJECT"
      ).length;

      const dropStudents = collections.filter(
        (student) => student.status === "DROP"
      ).length;

      setPolarChartData({
        ...polarChartData,
        datasets: [
          {
            ...polarChartData.datasets[0],
            data: [maleStudents.length, feMaleStudents.length],
          },
        ],
      });

      setBarChartData({
        ...barChartData,
        datasets: [
          {
            ...barChartData.datasets[0],
            data: [
              dropStudents,
              studentsData.totalStudents,
              newStudents,
              transfereeStudents,
              returneeStudents,
              rejectedStudents,
            ],
          },
        ],
      });

      setStudentsData((prev) => ({
        ...prev,
        totalEnrollees: collections.length,
        totalTeachers: 22,
        totalRejected: rejectedStudents,
      }));
    }
  }, [collections, studentsData.totalStudents]);

  return (
    <>
      <MDBContainer fluid>
        <section>
          <MDBRow>
            <MDBCol xl="3" md="6" className="mb-2">
              <MDBCard cascade className="cascading-admin-card">
                <div className="admin-up">
                  <MDBIcon
                    icon="users"
                    className="primary-color mr-3 z-depth-2"
                  />
                  <div className="data">
                    <p>Total Students</p>
                    <h4 className="font-weight-bold dark-grey-text">
                      {studentsData.totalStudents}
                    </h4>
                  </div>
                </div>
                <MDBCardBody cascade>
                  <MDBProgress
                    value={studentsData.totalStudents}
                    barClassName="bg-primary"
                    height="6px"
                    wrapperStyle={{ opacity: ".7" }}
                    className="mb-3"
                  />
                </MDBCardBody>
              </MDBCard>
            </MDBCol>

            <MDBCol xl="3" md="6" className="mb-5">
              <MDBCard cascade className="cascading-admin-card">
                <div className="admin-up">
                  <MDBIcon icon="users" className="warning-color" />
                  <div className="data">
                    <p>Total Teachers</p>
                    <h4 className="font-weight-bold dark-grey-text">
                      {studentsData.totalTeachers || "22"}
                    </h4>
                  </div>
                </div>
                <MDBCardBody cascade>
                  <MDBProgress
                    value={22}
                    barClassName="red accent-2"
                    height="6px"
                    wrapperStyle={{ opacity: ".7" }}
                    className="mb-3"
                  />
                </MDBCardBody>
              </MDBCard>
            </MDBCol>

            <MDBCol xl="3" md="6" className="mb-4">
              <MDBCard cascade className="cascading-admin-card">
                <div className="admin-up">
                  <MDBIcon icon="users" className="light-blue lighten-1" />
                  <div className="data">
                    <p>Total Enrollees</p>
                    <h4 className="font-weight-bold dark-grey-text">
                      {studentsData.totalEnrollees}
                    </h4>
                  </div>
                </div>

                <MDBCardBody cascade>
                  <MDBProgress
                    value={studentsData.totalEnrollees}
                    barClassName="red accent-2"
                    height="6px"
                    wrapperStyle={{ opacity: ".7" }}
                    className="mb-3"
                  />
                </MDBCardBody>
              </MDBCard>
            </MDBCol>

            <MDBCol xl="3" md="6" className="mb-4">
              <MDBCard cascade className="cascading-admin-card">
                <div className="admin-up">
                  <MDBIcon icon="user-alt-slash" className="red lighten-1" />
                  <div className="data">
                    <p>Total Rejected</p>
                    <h4 className="font-weight-bold dark-grey-text">
                      {studentsData.totalRejected}
                    </h4>
                  </div>
                </div>

                <MDBCardBody cascade>
                  <MDBProgress
                    value={studentsData.totalRejected}
                    barClassName="red accent-2"
                    height="6px"
                    wrapperStyle={{ opacity: ".7" }}
                    className="mb-3"
                  />
                </MDBCardBody>
              </MDBCard>
            </MDBCol>
          </MDBRow>
        </section>

        <MDBRow>
          <MDBCol md="5">
            <MDBCard narrow className="h-100">
              <MDBCardBody>
                <h5 className="font-weight-bold">Total Students by Gender</h5>
                <div className="d-flex justify-content-center align-items-center w-100 h-100">
                  <Doughnut data={polarChartData} height={200} />
                </div>
              </MDBCardBody>
            </MDBCard>
          </MDBCol>

          <MDBCol md="7">
            <MDBCard narrow className="h-100">
              <MDBCardBody>
                <h5 className="mb-2 font-weight-bold">All Students</h5>
                <Bar data={barChartData} height={200} />
              </MDBCardBody>
            </MDBCard>
          </MDBCol>
        </MDBRow>

        <MDBRow className="mt-5">
          <MDBCol>
            <MDBCard narrow>
              <MDBView
                cascade
                className="gradient-card-header blue-gradient py-2 mx-4 d-flex justify-content-between align-items-center"
              >
                <span className="ml-3 ">Section List</span>
              </MDBView>
              <MDBCardBody>
                <Table />
              </MDBCardBody>
            </MDBCard>
          </MDBCol>
        </MDBRow>
      </MDBContainer>
    </>
  );
}
