import { MDBBtn, MDBIcon } from "mdbreact";
import React, { useEffect, useState } from "react";
const TypesCount = ({ questions, toggle = () => {}, isAdd = false }) => {
  const [types, setTypes] = useState({});
  useEffect(() => {
    const _types = [...questions].reduce((acc, curr) => {
      const key = curr.type;
      if (acc.hasOwnProperty(key)) {
        acc[key] = acc[key] + 1;
      } else {
        acc[key] = 1;
      }
      return acc;
    }, {});

    setTypes({ ..._types });
  }, [questions]);

  const getTypesAcronym = (type) => {
    switch (type) {
      case "mc":
        return "Multiple Choice: ";
      case "matching":
        return "Matching Type: ";
      case "identification":
        return "Identification: ";

      default:
        return "no type";
    }
  };

  return (
    <div className="d-flex justify-content-between align-items-center">
      {Object.entries(types).map(([key, value], index) => (
        <span key={index}>
          {getTypesAcronym(key).toUpperCase()}{" "}
          <strong>
            {value} {value > 1 ? "items" : "item"}
          </strong>
        </span>
      ))}
      <div>
        <span>
          TOTAL ITEM{questions.length > 1 ? "S" : ""}:{" "}
          <strong>{questions.length}</strong>
        </span>
        {isAdd && (
          <MDBBtn
            color="info"
            size="sm"
            rounded
            className="ml-3"
            onClick={() => toggle()}
          >
            <MDBIcon icon="plus" />
          </MDBBtn>
        )}
      </div>
    </div>
  );
};

export default TypesCount;
