import React, { useEffect, useState } from "react";
import { MDBBadge, MDBBtn, MDBBtnGroup, MDBIcon, MDBTable } from "mdbreact";
import PaginationButtons from "../../../../widgets/pagination/buttons";
import handlePagination from "../../../../widgets/pagination";
import Rows from "../../../../widgets/pagination/rows";
import handleMultiSeclect from "../../../../widgets/multipleSelect";
import { fullName } from "../../../../services/utilities";

function Table({
  advisories,
  setOrderIndex,
  orderIndex,
  setContainer,
  container,
  setIsViewCard,
  setSelected,
  handleCardExcel,
}) {
  const [page, setPage] = useState(1),
    [max, setMax] = useState(5),
    [isSelectAll, setIsSelectAll] = useState(false);

  useEffect(() => {
    if (isSelectAll) {
      setContainer(advisories);
    } else {
      setContainer((prev) => (prev.length === advisories.length ? [] : prev));
    }
  }, [isSelectAll, advisories, setContainer]);

  return (
    <>
      <MDBTable responsive hover>
        <thead>
          <tr>
            <th>
              <input
                className="form-check-input"
                type="checkbox"
                disabled
                checked={isSelectAll}
                onChange={() => setIsSelectAll(!isSelectAll)}
                id="checkbox"
              />
              <label
                htmlFor="checkbox"
                className="form-check-label mr-2 label-table"
              />
            </th>
            <th className="th-lg">LRN</th>

            <th
              className="th-lg cursor-pointer"
              onClick={() =>
                setOrderIndex((prev) => {
                  if (prev > 1) return 0;

                  return prev + 1;
                })
              }
            >
              Name&nbsp;
              <MDBIcon
                icon="sort"
                title="Sort by Name"
                className={`${!!orderIndex && "text-primary"}`}
              />
            </th>

            <th className="th-lg text-center">Action</th>
          </tr>
        </thead>
        <tbody>
          {advisories.length > 0 ? (
            handlePagination(advisories, page, max).map((advisory, index) => {
              const {
                _id,
                student,
                grades,
                wasDrop = false,
                LRN = "",
              } = advisory;
              return (
                <tr
                  key={_id}
                  style={{
                    textDecoration: wasDrop ? "line-through" : "none",
                    textDecorationColor: wasDrop ? "red" : "initial",
                  }}
                >
                  <td>
                    <input
                      className="form-check-input"
                      type="checkbox"
                      id={index}
                      checked={
                        isSelectAll
                          ? true
                          : container.some(({ _id }) => _id === advisory._id)
                      }
                      onChange={() => {
                        setContainer(handleMultiSeclect(container, advisory));
                        setIsSelectAll(false);
                      }}
                    />
                    <label
                      htmlFor={index}
                      className="form-check-label mr-2 label-table"
                    />
                  </td>
                  <td style={{ fontWeight: 400 }}>{LRN}</td>
                  <td style={{ fontWeight: 400 }}>
                    {fullName(student.fullName).toUpperCase()}{" "}
                    {wasDrop && (
                      <MDBBadge color="red" pill>
                        Drop
                      </MDBBadge>
                    )}
                  </td>
                  <td className="text-center">
                    <MDBBtnGroup>
                      <MDBBtn
                        color="warning"
                        size="sm"
                        rounded
                        title="Card"
                        onClick={() => {
                          setSelected({
                            ...advisory,
                            LRN,
                            transcript: { grades },
                          });
                          setIsViewCard(true);
                        }}
                      >
                        <MDBIcon icon="credit-card" />
                      </MDBBtn>
                      <MDBBtn
                        size="sm"
                        color="primary"
                        rounded
                        onClick={() => handleCardExcel({ ...advisory, grades })}
                      >
                        <MDBIcon icon="file-excel" />
                      </MDBBtn>
                    </MDBBtnGroup>
                  </td>
                </tr>
              );
            })
          ) : (
            <tr>
              <td>No Records</td>
            </tr>
          )}
        </tbody>
      </MDBTable>
      {advisories.length > 0 && (
        <>
          <Rows setMax={setMax} max={max} />
          <PaginationButtons
            page={page}
            setPage={setPage}
            array={advisories}
            max={max}
          />
        </>
      )}
    </>
  );
}

export default Table;
