import { MDBTypography } from "mdbreact";
import React from "react";

const WarningMessage = ({ isValid }) => {
  const handleMessage = (_isValid) => {
    if (!_isValid.time) {
      return "The minimum difference between the start time and end time is 1 hour.";
    }
    if (!_isValid.duration) {
      return "Each question should have a minimum duration of 30 seconds.";
    }
    if (!_isValid.passingScore) {
      return "The passing score must be at least 50% of the total items.";
    }
    return "";
  };
  return (
    <MDBTypography
      variant="h2"
      className="mb-0 text-black-100"
      noteColor="danger"
      note
      noteTitle="Warning: "
    >
      {handleMessage(isValid)}
    </MDBTypography>
  );
};

export default WarningMessage;
