import React from "react";
import Images from "../../widgets/Image";
import { MDBRow, MDBCol } from "mdbreact";

function Credentials({ selected }) {

  return (
    <>
      <MDBRow className="mt-5" style={{ backgroundColor: "#0000FF" }}>
        <MDBCol>
          <h5 className="font-weight-bold text-white mt-2 label mb-2 ml-5">
            IV. CREDENTIALS
          </h5>
        </MDBCol>
      </MDBRow>
      <MDBRow>
        <Images
          userDataImage={{
            email: selected.student?.email,
            _id: selected.student?._id,
            filesData: selected.files,
          }}
          imageTypes={Object.keys(selected.files)
            .filter(key => selected.files[key] === true )
            .map(key => {
              const cleanKey = key.replace('has', '');
              return cleanKey === 'PSA' ? cleanKey : cleanKey.replace(/^./, char => char.toLowerCase());
            })
            }
          viewOnly={true}
        />
      </MDBRow>
    </>
  );
}

export default Credentials;
