const normalizeAnswer = (answer) => answer.toLowerCase().replace(/\s+/g, "");

const checker = {
  multipleChoice: (question) => {
    const { answer = "", correctAnswer = "" } = question;
    const isCorrect =
      normalizeAnswer(answer) === normalizeAnswer(correctAnswer);

    console.log(isCorrect, question);

    return isCorrect ? 1 : 0;
  },

  identification: (question) => {
    const { answer = "", correctAnswer = "" } = question;
    const isCorrect =
      normalizeAnswer(answer) === normalizeAnswer(correctAnswer);
    console.log(isCorrect, question);

    return isCorrect ? 1 : 0;
  },

  matchingType: (question) => {
    const { answers = [] } = question;
    var points = 0;
    const withoutConfusing = answers.filter(({ isConfusing }) => !isConfusing);
    withoutConfusing.forEach((element) => {
      const { textB = "", answer = "" } = element;
      const isCorrect = normalizeAnswer(answer) === normalizeAnswer(textB);
      points += isCorrect ? 1 : 0;
    });

    console.log(points);

    return withoutConfusing.length === points ? 1 : 0;
  },
};

export default checker;
