import answerSanitizer from "../../../../services/utilities/answerSanitizer";

const validate = {
  question: (questions, form, oldQuestion = "") => {
    return !questions.some(
      ({ progress = "", question: q }) =>
        answerSanitizer(q) === answerSanitizer(form.question) &&
        form.progress === progress &&
        answerSanitizer(form.question) !== answerSanitizer(oldQuestion)
    );
  },
  choices: (choices) => {
    const _choices = choices.flatMap((choice) => {
      const { _id = "", ...res } = choice || {};
      console.log(_id);
      return Object.values(res);
    });
    const sanitizedChoices = _choices
      .map((choice) => (choice ? answerSanitizer(choice) : false))
      .filter(Boolean);

    return sanitizedChoices.length === new Set(sanitizedChoices).size;
  },
};

export default validate;
