import React from "react";
import { MDBRow, MDBCol } from "mdbreact";
import CustomSelect from "../../components/customSelect";
function level({
  form,
  setForm,
  disableSemester,
  disabedICT = false,
  isRegistrar = false,
  disableSemesterInRegistar = false,
}) {
  const { levels, specializations, semesters, strands, sections, ...rest } =
    form;

  const sortedSections =
    !!sections && sections.sort((a, b) => a.isICT - b.isICT);
  const key = JSON.stringify({
    ...rest,
  });

  return (
    <MDBRow className="mt-2" key={`${key}-row-level`}>
      <MDBCol>
        <CustomSelect
          choices={[...levels]}
          _key={`${key}-level`}
          label={"Grade Level"}
          addTextLeft="Grade -"
          className="m-0 p-0"
          preValue={form?.level}
          onChange={(value) => setForm({ ...form, level: Number(value) })}
        />
      </MDBCol>
      {/* {form.level <= 10 && !disabedICT && (
        <MDBCol md="1" className="mt-3">
          <input
            className="form-check-input ml-2"
            type="checkbox"
            id="ictOnly"
            checked={form.ictOnly}
            onChange={() => setForm({ ...form, ictOnly: !form.ictOnly })}
          />
          <label
            htmlFor="ictOnly"
            className="form-check-label mr-4 label-table"
          >
            ICT
          </label>
        </MDBCol>
      )} */}
      {form.level > 10 && (
        <>
          <MDBCol>
            <CustomSelect
              choices={specializations}
              _key={`${key}-specializations`}
              label={"Specialization"}
              className="m-0 p-0"
              onChange={(value) => setForm({ ...form, specialization: value })}
              preValue={form.specialization}
            />
          </MDBCol>
          <MDBCol>
            <CustomSelect
              choices={strands}
              _key={`${key}-strand`}
              label={"Strand"}
              className="m-0 p-0"
              onChange={(value) => setForm({ ...form, strand: value })}
              preValue={form.strand}
            />
          </MDBCol>
          {!disableSemester && (
            <MDBCol>
              <CustomSelect
                choices={semesters}
                _key={`${key}-semester`}
                label={"Semester"}
                addTextRight="Semester"
                className="m-0 p-0"
                onChange={(value) => setForm({ ...form, semester: value })}
                preValue={form.semester}
              />
            </MDBCol>
          )}
        </>
      )}
      {isRegistrar && (
        <>
          <MDBCol>
            <CustomSelect
              choices={sortedSections.map((section) => ({
                ...section,
                name: section?.isICT ? `${section?.name} - ICT` : section?.name,
              }))}
              _key={`${key}-section`}
              label={"Section"}
              values="_id"
              texts="name"
              className="m-0 p-0"
              onChange={(value) => setForm({ ...form, section: value })}
              preValue={form.section}
            />
          </MDBCol>
          {!disableSemesterInRegistar && form.level > 10 && (
            <MDBCol>
              <CustomSelect
                choices={semesters}
                label={"Semester"}
                addTextRight="Semester"
                _key={`${key}-registrar-semesters`}
                className="m-0 p-0"
                onChange={(value) => setForm({ ...form, semester: value })}
                preValue={form.semester}
              />
            </MDBCol>
          )}
        </>
      )}
    </MDBRow>
  );
}

export default level;
