import { MDBAnimation } from "mdbreact";
import React from "react";

const CountDown = ({ timeLeft }) => {
  return (
    <div className="mb-5 mt-2" style={{ height: "12rem" }}>
      <MDBAnimation type="bounceOut" key={timeLeft}>
        <h1 className="text-center font-weight-bold display-2 text-primary">
          {timeLeft === 1 ? "GO!" : timeLeft - 1}
        </h1>
      </MDBAnimation>
      <h3 className="text-center font-weight-bold">
        Take a deep breath and keep going. You’re almost there. Do your best!
      </h3>
    </div>
  );
};

export default CountDown;
