import React from "react";
import { MDBCol, MDBBtn } from "mdbreact";

const DAYS = [
  { text: "monday", value: "M" },
  { text: "tuesday", value: "T" },
  { text: "wednesday", value: "W" },
  { text: "thursday", value: "TH" },
  { text: "friday", value: "F" },
];

function Days({ pickDays, handlePick }) {
  return (
    <MDBCol md="12">
      <span>Days</span>
      <div className="d-flex justify-content-center">
        {DAYS.map(({ value }, index) => {
          const isExist = pickDays.some((d) => d === value);
          return (
            <MDBCol md="2" className="m-0 p-0" key={index}>
              <MDBBtn
                onClick={() => handlePick(value)}
                outline={isExist ? false : true}
                floating
                color="primary"
              >
                {value}
              </MDBBtn>
            </MDBCol>
          );
        })}
      </div>
    </MDBCol>
  );
}

export default Days;
