import React, { useEffect, useState } from "react";
import { MDBBtn, MDBCard, MDBCardBody, MDBView } from "mdbreact";
import { useDispatch, useSelector } from "react-redux";
import Card from "../../../../widgets/card-grades";
import excel from "../../../../services/utilities/downloadExcel/excel";
import {
  BROWSE,
  DESTROY,
} from "../../../../services/redux/slices/teacher/advisory";
import { useToasts } from "react-toast-notifications";
import Search from "../../../../widgets/search";
import Table from "./table";
import MultipleDestroy from "../../../../widgets/multipleDestroy";
import TableLoading from "../../../../widgets/tableLoading";
import { fullName, getAge } from "../../../../services/utilities";
import SF1 from "../../../../services/utilities/downloadExcel/SF1";
import SF8 from "../../../../services/utilities/downloadExcel/SF8";
import grades from "../../../../services/utilities/grades";
import CardExcel from "../../../../services/utilities/downloadExcel/card";
import SF10 from "../../../../services/utilities/downloadExcel/sf10";

export default function Advisory() {
  const { token, information, auth } = useSelector(({ auth }) => auth),
    { collections, message, isSuccess, isLoading } = useSelector(
      ({ advisory }) => advisory
    ),
    [advisories, setAdvisories] = useState([]),
    [container, setContainer] = useState([]),
    [show, setShow] = useState(false),
    [orderIndex, setOrderIndex] = useState(0),
    [isViewCard, setIsViewCard] = useState(false),
    [selected, setSelected] = useState({}),
    [didSearch, setDidSearch] = useState(false),
    dispatch = useDispatch(),
    { addToast } = useToasts();

  useEffect(() => {
    if (message) {
      addToast(message, {
        appearance: isSuccess ? "success" : "error",
      });
    }
  }, [isSuccess, message, addToast]);

  useEffect(() => {
    const { advisory = { _id: "" }, batches = [] } = information || {};
    if (token && advisory?._id) {
      dispatch(BROWSE({ token, data: { section: advisory?._id, batches } }));
    }
  }, [dispatch, token, information]);

  useEffect(() => {
    if (!show) {
      setContainer([]);
    }
  }, [show]);

  useEffect(() => {
    setAdvisories(() => {
      if (!orderIndex) return collections;

      return [...collections].sort((a, b) => {
        if (orderIndex === 1) return a.name?.localeCompare(b.name);

        return b.name?.localeCompare(a.name);
      });
    });
  }, [orderIndex, collections]);

  const handleUpdate = () => {
    if (container.length === 1) {
      setSelected(container[0]);
      setShow(true);
    } else {
      addToast("Please Select 1 Item", {
        appearance: "warning",
      });
    }
  };

  const handleSearch = (e) => {
    e.preventDefault();

    const key = e.target.searchKey.value.toUpperCase();

    setAdvisories(
      collections.filter(({ name }) => name.toUpperCase().includes(key))
    );

    setDidSearch(true);
  };

  const handleDelete = () => {
    MultipleDestroy(
      dispatch,
      DESTROY,
      token,
      container,
      addToast,
      setContainer
    );
  };

  const handleExcel = () => {
    const students = advisories.map(({ student }) => ({
      ...student,
      fullName: fullName(student.fullName),
    }));
    const options = {
      sheet: "SHSF-8",
      filename: "SF-Form-8",
      title:
        "School Form 8 Learner's Basic Health and Nutrition Report for Senior  High School (SF8-SHS)",
      "School Name": "Leonor M. Bautista National High School",
      "School ID": "",
      District: "",
      Division: "",
      Region: "",

      Semester: "",
      "School Year": "2023-2024",

      "Grade Level": "7",
      Section: "Mangga",
      "Track and Strand": "",
      "Course/s (only for TVL)": "",
    };
    excel({ array: students, options });
  };

  const fullNameChecker = (name) => {
    const hasFullName = Object.values(name).filter(Boolean);
    if (hasFullName.length === 0) return "-";
    const { fname = "", mname = "", lname = "", suffix = "" } = name;
    return `${lname}\n${fname},${mname} ${suffix}`;
  };

  const handleSF1 = () => {
    const students = advisories.map(({ student, credential, ...rest }) => {
      const { wasDrop = false } = rest;
      const { address } = student;
      const { current } = address;
      const { barangay, city, province } = current || {};
      const { LRN, father, mother, guardian } = credential || {};
      return {
        LRN,
        fullName: fullName(student.fullName),
        isMale: student.isMale,
        sex: student.isMale ? "M" : "F",
        dob: student.dob,
        AGE: getAge(student.dob),
        address: { house: "0526", barangay, city, province },
        parents: {
          father: fullNameChecker(father.fullName),
          mother: fullNameChecker(mother.fullName),
        },
        guardian: {
          name: fullNameChecker(guardian.fullName),
          relationshiop: "",
        },
        learning: "Face to Face",
        wasDrop,
      };
    });
    const options = {
      sheet: "SHSF-1",
      filename: "SF-Form-1",
      title: "School Form 1 (SF 1) School Register",
      school: "Leonor M. Bautista National High School",
      schoolID: "306809",
      division: "Nueva Ecija",
      region: "III",
      schoolYear: "2023-2024",
      level: 7,
      section: "Mangga",
      signatures: {
        PrepareBy: "Ric Darrel Pajarillaga",
      },
    };
    SF1({ array: students, options });
  };

  const handleSF8 = () => {
    const students = advisories.map(
      ({ student, credential, ...rest }, index) => {
        const { wasDrop = false } = rest;
        const { LRN = "" } = credential || {};

        return {
          LRN,
          fullName: fullName(student.fullName),
          isMale: student.isMale,
          sex: student.isMale ? "M" : "F",
          dob: student.dob,
          AGE: getAge(student.dob),
          weight: `${index}1.2${index}`,
          height: `${index + 1}1.2${index + 1}`,
          height2: `${index + 2 / 0.2}1.2${index + 1}`,
          nutrional: {
            bmi: `${index + 3 / 0.5}1.2${index + 1}`,
            category: "Normal",
          },
          heightForAge: "Normal",
          REMARKS: "",
          wasDrop,
        };
      }
    );

    const options = {
      sheet: "SHSF-8",
      filename: "SF-Form-8",
      title: "School Form 8 (SF8) Learner's Basic Health and Nutrition Report ",
      school: "Leonor M. Bautista National High School",
      schoolID: "306809",
      division: "Nueva Ecija",
      region: "III",
      schoolYear: "2023-2024",
      level: 7,
      section: "Mangga",
      signatures: {
        PrepareBy: "Ric Darrel Pajarillaga",
      },
    };
    SF8({ array: students, options });
  };

  const handleCardExcel = (advisory) => {
    const { student, strand = "", section, lvl } = advisory;
    const advisoryWithRemarks = grades.remarks(advisory);
    const average = grades.average(advisoryWithRemarks);
    CardExcel({
      grades: advisoryWithRemarks.grades,
      average,
      studentInfo: {
        name: fullName(student?.fullName),
        strand,
        lvl: Number(lvl),
        section: section.name,
        age: getAge(student?.dob),
        sex: student.isMale ? "M" : "F",
        schoolYear: "2023 - 2024",
      },
      adviser: fullName(auth.fullName),
    });
  };

  const handleSF10 = () => {
    
    if(container.length <= 0) {
      return console.log("no student selected");
    }

    const student = container.map(({ student, credential, grades }) => {
      console.log(student);
      console.log(credential);
      console.log(grades);
      const { LRN = "" } = credential || {};
      return {
        LRN,
        fullName: student.fullName,
        isMale: student.isMale,
        sex: student.isMale ? "M" : "F",
        dob: student.dob,
        AGE: getAge(student.dob),
        REMARKS: "",
        grades: grades,
        elemSchool : {
          isElementaryCompleter: true,
          generalAvg: 85,
          citation: "",
          schoolName: "PATINDIG ARAW ELEMENTARY SCHOOL",
          schoolId: "1053711",
          schoolAddress: "SITIO SAUDI, PIAS, GENERAL TINIO, NUEVA ECIJA", 
        }
      };
    });

    const options = {
      sheet: "SHSF-10",
      filename: "SF-Form-10",
      title: "Learner Permanent Record for Junior High School (SF10-JHS)",
      heading1: "Republic of the Philippines",
      heading2: "Department of Education",
      subHeading: "(Formerly Form 137)",
      school: "Leonor M. Bautista NHS",
      schoolID: "306809",
      division: "Nueva Ecija",
      district: "General Tinio",
      region: "III",
      schoolYear: "2023-2024",
      level: 7,
      section: "Mangga",
      signatures: {
        PrepareBy: "Hennryx R. Samson",
      },
      adviser: fullName(auth.fullName)
    };
    console.log(student);
    SF10({ array: student, options });
  };

  const { advisory } = information;
  return (
    <>
      {!isViewCard ? (
        <MDBCard narrow className="pb-3">
          <MDBView
            cascade
            className="gradient-card-header blue-gradient py-2 mx-4 d-flex justify-content-between align-items-center"
          >
            <span className="ml-3 ">
              <h5>
                Grade {advisory.lvl} , {advisory.name}
              </h5>
            </span>

            <Search
              didSearch={didSearch}
              handleExcel={handleExcel}
              handleSearch={handleSearch}
              setShow={setShow}
              array={collections}
              setArray={setAdvisories}
              setDidSearch={setDidSearch}
              handleUpdate={handleUpdate}
              handleDelete={handleDelete}
              isTeacher={true}
            />
          </MDBView>
          <MDBCardBody>
            {isLoading ? (
              <TableLoading />
            ) : (
              <>
                <MDBBtn
                  size="md"
                  color="primary"
                  className="font-weight-bold"
                  onClick={handleSF1}
                  outline
                  rounded
                >
                  SF1
                </MDBBtn>
                <MDBBtn
                  size="md"
                  className="font-weight-bold"
                  color="primary"
                  onClick={handleSF8}
                  outline
                  rounded
                >
                  SF8
                </MDBBtn>
                <MDBBtn
                  size="md"
                  className="font-weight-bold"
                  color="primary"
                  onClick={handleSF10}
                  outline
                  rounded
                >
                  SF10
                </MDBBtn>

                <Table
                  advisories={advisories}
                  setIsViewCard={setIsViewCard}
                  setSelected={setSelected}
                  setOrderIndex={setOrderIndex}
                  orderIndex={orderIndex}
                  handleCardExcel={handleCardExcel}
                  container={container}
                  setContainer={setContainer}
                />
              </>
            )}
          </MDBCardBody>
        </MDBCard>
      ) : (
        <Card
          selected={{
            ...selected,
            section: advisory,
            batch: { sy: "2024-2025" },
          }}
          isViewCard={isViewCard}
          setIsViewCard={setIsViewCard}
          isViewAdviser={true}
        />
      )}
    </>
  );
}
