import React, { useState } from "react";
import { MDBBtn, MDBIcon, MDBTable } from "mdbreact";
import { handlePagination } from "../../../../services/utilities";
import handleMultiSeclect from "../../../../widgets/multipleSelect";
import Rows from "../../../../widgets/pagination/rows";
import PaginationButtons from "../../../../widgets/pagination/buttons";
import ViewQuestion from "./viewQuestion";

const Table = ({
  questionBank = [],
  container = [],
  setContainer = () => {},
}) => {
  const [selected, setSelected] = useState({}),
    [page, setPage] = useState(1),
    [max, setMax] = useState(5),
    [show, setShow] = useState(false);

  const handleType = (type) => {
    switch (type) {
      case "mc":
        return "Multiple Choice";
      case "matching":
        return "Matching Type";
      default:
        return "Identification";
    }
  };
  return (
    <>
      <MDBTable>
        <thead>
          <tr>
            <th className="th-sm">
              <input
                className="form-check-input"
                type="checkbox"
                checked={false}
                disabled
                id={`question`}
              />
              <label
                htmlFor={`question`}
                className="form-check-label mr-2 label-table"
              />
            </th>
            <th>Question</th>
            <th>Type</th>
            <th className="text-center">Action</th>
          </tr>
        </thead>
        <tbody>
          {handlePagination(questionBank, page, max).map((bank, index) => {
            const isChecked = container.some(({ _id }) => _id === bank._id);
            return (
              <tr key={index}>
                <td>
                  <input
                    className="form-check-input"
                    type="checkbox"
                    id={`${bank._id}`}
                    checked={isChecked}
                    onChange={() => {
                      setContainer(handleMultiSeclect(container, bank, false));
                    }}
                  />
                  <label
                    htmlFor={`${bank._id}`}
                    className="form-check-label mr-2 label-table"
                  />
                </td>
                <td style={{ maxWidth: "300px", fontWeight: 400 }}>
                  {bank.question}
                </td>
                <td style={{ fontWeight: 400 }}>{handleType(bank.type)}</td>
                <td className="text-center">
                  <MDBBtn
                    color="warning"
                    size="sm"
                    rounded
                    onClick={() => {
                      setSelected(bank);
                      setShow(true);
                    }}
                  >
                    <MDBIcon icon="eye" />
                  </MDBBtn>
                </td>
              </tr>
            );
          })}
        </tbody>
      </MDBTable>
      <Rows max={max} setMax={setMax} />
      <PaginationButtons
        page={page}
        setPage={setPage}
        max={max}
        array={questionBank}
      />
      <ViewQuestion
        show={show}
        toggle={() => setShow(false)}
        selected={selected}
      />
    </>
  );
};

export default Table;
