import { MDBIcon } from "mdbreact";
import React from "react";
import isChecked from "./js/isChecked";
import answerIsCorrect from "./js/isCorrect";

const Identification = ({
  index = 0,
  isAdd = false,
  isMultiple = true,
  isChecking = false,
  question = {},
  selectedQuestions = [],
  handleSelectQuestion = () => {},
}) => {
  const isCorrect = answerIsCorrect(question);
  return (
    <>
      <div className="d-flex align-items-center ">
        {isAdd && (
          <>
            <input
              className="form-check-input"
              type="checkbox"
              checked={isChecked(question, selectedQuestions)}
              onChange={() => handleSelectQuestion(question)}
              id={`question-${index}`}
            />
            <label
              htmlFor={`question-${index}`}
              className="form-check-label  label-table"
            />
          </>
        )}

        {isChecking && (
          <h5>
            <MDBIcon
              icon={isCorrect ? "check" : "times"}
              style={{
                color: isCorrect ? "#30D272" : "red",
                marginRight: "1.4rem",
              }}
            />
          </h5>
        )}
        <h5 className={isAdd ? "mt-2" : ""}>
          {isMultiple && (
            <>
              {isChecking && !isCorrect && <>&nbsp;</>}
              {index + 1}.&nbsp;
            </>
          )}
          <strong>{question.question}</strong> <br />
        </h5>
      </div>

      <h5
        style={{
          marginTop: "-0.2rem",
          marginLeft: isAdd || isChecking ? "4rem" : "1.8rem",
        }}
      >
        <span className="p-1 ">
          <small>{!isChecking && "Correct"} Answer:</small>&nbsp;
          <strong style={{ fontSize: "1.1rem" }}>
            {question[isChecking ? "answer" : "correctAnswer"]}
          </strong>
        </span>
        {isChecking && !isCorrect && (
          <span className="ml-4">
            <small>Correct Answer:</small>&nbsp;
            <strong style={{ fontSize: "1.1rem" }}>
              {question["correctAnswer"]}
            </strong>
          </span>
        )}
      </h5>
    </>
  );
};

export default Identification;
