import React, { useEffect, useState } from "react";
import QuestionType from "./questionType";
import { MDBAnimation } from "mdbreact";

const renderQuestions = (page, questions) => {
  const _questions = [...questions];
  if (page > _questions.length) return false;
  return _questions[page - 1];
};

const Body = ({ page, questions = [], setAnswersOfStudent = () => {} }) => {
  const [studentAnswer, setStudentAnswer] = useState({});

  useEffect(() => {
    if (studentAnswer._id) {
      setAnswersOfStudent((prev) => {
        const index = [...prev].findIndex(
          ({ _id }) => _id === studentAnswer._id
        );

        if (index > -1) {
          prev[index] = studentAnswer;
        } else {
          prev.push(studentAnswer);
        }
        return prev;
      });
    }
  }, [page, studentAnswer, setAnswersOfStudent]);

  return (
    <div className="mb-3 mt-3" key={page}>
      <MDBAnimation type={page === 1 ? "" : "zoomIn"} key={page}>
        <QuestionType
          question={renderQuestions(page, questions)}
          setStudentAnswer={setStudentAnswer}
        />
      </MDBAnimation>
    </div>
  );
};

export default Body;
