import {
  MDBBtn,
  MDBBtnGroup,
  MDBCard,
  MDBCardBody,
  MDBIcon,
  MDBTable,
  MDBView,
} from "mdbreact";
import React, { useEffect, useState } from "react";
import { fullName } from "../../../../services/utilities";

function SchedTable({ array = [], props, form, willCreate }) {
  const [schedules, setSchedules] = useState([]);

  useEffect(() => {
    const container = [];

    for (let i = 0; i < array.length; i++) {
      const element = array[i];
      const _schedules = element.schedules;

      if (_schedules?.length > 0) {
        _schedules.forEach((schedule) => {
          container.push({
            ...element,
            schedules: schedule,
            scheduleID: schedule.scheduleID,
          });
        });
      }
    }

    setSchedules(container);
  }, [props.willCreate, array]);

  useEffect(() => {
    if (!willCreate) {
      setSchedules((prevSchedules) => {
        const sortedSchedules = [...prevSchedules];

        sortedSchedules.sort((a, b) => {
          if (a.scheduleID === form.scheduleID) return -1; // Ilalagay ang matching ID sa unahan
          if (b.scheduleID === form.scheduleID) return 1;
          return 0; // Panatilihin ang ibang items sa original order
        });

        return sortedSchedules;
      });
    }
  }, [willCreate, form]);

  const handleUpdate = (
    _id,
    instructor = "",
    subject = "",
    days,
    startTime,
    endTime,
    scheduleID,
    isBreakTime = false
  ) => {
    props.setForm((prev) => ({
      ...prev,
      instructor,
      subject,
      _id,
      oldDays: days,
      isBreakTime,
      scheduleID,
    }));

    props.setPickDays(days);
    props.setHourStart(startTime.hours);
    props.setMinStart(startTime.min);
    props.setHourEnd(endTime.hours);
    props.setMinEnd(endTime.min);
  };

  return (
    <MDBCard narrow>
      <MDBView
        cascade
        className="gradient-card-header blue-gradient py-2 mx-4 d-flex justify-content-between align-items-center"
      >
        List of your selected Schedule
      </MDBView>
      <MDBCardBody
        style={{
          maxHeight: props.willCreate || props?.form?._id ? "398px" : "746px",
          overflowY: "auto",
        }}
      >
        <MDBTable>
          <thead>
            <tr>
              <th>#</th>
              <th>Instructor</th>
              <th>Subject</th>
              <th>Day</th>
              <th className="text-center">Time</th>
              <th className="text-center">Action</th>
            </tr>
          </thead>
          <tbody>
            {schedules.map(
              (
                {
                  instructor,
                  subject,
                  isBreakTime = false,
                  schedules,
                  _id = "",
                },
                index
              ) => {
                const { time, scheduleID } = schedules;
                const { start, end } = time || {};
                return (
                  <tr key={index}>
                    <td> {index + 1}</td>
                    <td style={{ fontWeight: 400 }}>
                      {isBreakTime
                        ? "Break Time"
                        : fullName(instructor.fullName)}
                    </td>
                    <td style={{ fontWeight: 400 }}>
                      {isBreakTime ? "--" : subject?.name}
                    </td>
                    <td style={{ fontWeight: 400 }}>
                      {schedules.days.join(",")}
                    </td>
                    <td className="text-center" style={{ fontWeight: 400 }}>
                      {start.hours}: {start.min === 0 ? "00" : start.min}{" "}
                      {start.period} - {end.hours}:{" "}
                      {end.min === 0 ? "00" : end.min} {end.period}
                    </td>
                    <td className="text-center">
                      <MDBBtnGroup>
                        <MDBBtn
                          size="sm"
                          color="danger"
                          rounded
                          onClick={() =>
                            props.handleRemoveSchedule({
                              subject: isBreakTime ? "" : subject._id,
                              instructor: isBreakTime ? "" : instructor._id,
                              _id,
                              scheduleID,
                              days: schedules.days,
                            })
                          }
                        >
                          <MDBIcon
                            icon="trash"
                            size="1x"
                            className="cursor-pointer"
                          />
                        </MDBBtn>
                        {!props.willCreate && (
                          <MDBBtn
                            size="sm"
                            color="primary"
                            rounded
                            onClick={() =>
                              handleUpdate(
                                _id,
                                instructor?._id,
                                subject?._id,
                                schedules.days,
                                start,
                                end,
                                scheduleID,
                                isBreakTime
                              )
                            }
                          >
                            <MDBIcon
                              icon="pencil-alt"
                              size="1x"
                              className="cursor-pointer"
                            />
                          </MDBBtn>
                        )}
                      </MDBBtnGroup>
                    </td>
                  </tr>
                );
              }
            )}
          </tbody>
        </MDBTable>
      </MDBCardBody>
    </MDBCard>
  );
}

export default SchedTable;
