import React, { useState, useEffect } from "react";
import {
  MDBContainer,
  MDBRow,
  MDBCol,
  MDBCard,
  MDBCardBody,
  MDBAvatar,
  MDBBtn,
  MDBInput,
  MDBSelectOptions,
  MDBSelectInput,
  MDBSelectOption,
  MDBSelect,
  MDBSpinner,
  MDBProgress,
} from "mdbreact";
import { useDispatch, useSelector } from "react-redux";
import {
  PresetImage,
  //   fullAddress,
  //   fullName,
  isJpegOrJpgFile,
} from "../../services/utilities";
import { IMAGE, UPLOAD } from "../../services/redux/slices/auth";
import { useToasts } from "react-toast-notifications";
import { UPDATE } from "../../services/redux/slices/users";
import PasswordInput from "../passwordInput";

export default function ViewProfile() {
  const { auth, image, token, progressBar } = useSelector(({ auth }) => auth);
  const { isSuccess, message } = useSelector(({ users }) => users);
  const [confirmPass, setConfirmPass] = useState("");
  const [showPass, setShowPass] = useState("password");
  const [showPassConfirm, setShowPassConfirm] = useState("password");
  const [file, setFile] = useState(null);
  const [form, setForm] = useState({
    fullName: {
      fname: "",
      mname: "",
      lname: "",
      suffix: "",
    },
    password: "",
    address: {
      current: {
        street: "",
        barangay: "",
        city: "",
        region: "",
        province: "",
      },
    },
    dob: "",
    mobile: "",
    isMale: false,
    bio: "",
  });

  const [isPasswordWeak, setIsPasswordWeak] = useState(true)
  const { addToast } = useToasts();
  const dispatch = useDispatch();

  const handleImageChange = (e) => {
    const file = e.target.files[0];

    if (file && isJpegOrJpgFile(file)) {
      const reader = new FileReader();

      reader.onload = (e) => {
        const img = new Image();

        img.src = e.target.result;

        img.onload = function () {
          if (this.width <= 100 && this.height <= 100) {
            setFile(file);
            dispatch(
              UPLOAD({
                data: {
                  path: `profile`,
                  base64: reader.result.split(",")[1],
                  name: `${auth.email}.jpg`,
                },
                token,
              })
            );
          } else {
            // Create a canvas element to resize the image
            const canvas = document.createElement("canvas");
            const ctx = canvas.getContext("2d");

            // Set canvas dimensions
            canvas.width = 100;
            canvas.height = 100;

            // Draw the image onto the canvas with the new dimensions
            ctx.drawImage(img, 0, 0, 100, 100);

            // Convert canvas to blob and then to a File object
            canvas.toBlob(function (blob) {
              // Convert blob to base64
              const reader = new FileReader();
              reader.readAsDataURL(blob);
              reader.onloadend = function () {
                const base64data = reader.result.split(",")[1];
                const resizedImageFile = new File([blob], `${auth.email}.jpg`, {
                  type: "image/jpeg",
                  lastModified: Date.now(),
                });
                setFile(resizedImageFile);
                // Dispatch the upload action with the resized image
                dispatch(
                  UPLOAD({
                    data: {
                      path: `profile`,
                      base64: base64data,
                      name: `${auth.email}.jpg`,
                    },
                    token,
                  })
                );
              };
            }, "image/jpeg");
          }
        };
      };

      reader.readAsDataURL(file);
    } else {
      addToast(
        "Please select a valid JPG image file with dimensions below or equal to 100 pixels.",
        {
          appearance: "warning",
        }
      );
    }
  };

  useEffect(() => {
    if (form.password === "") {
      setIsPasswordWeak(false);
    }
  }, [form]);

  useEffect(() => {
    if (file && progressBar === 100) {
      dispatch(IMAGE(URL.createObjectURL(file)));
      setFile(null);
      addToast("Image Updated Successfully.", {
        appearance: "success",
      });
    }
  }, [progressBar, file, dispatch, addToast]);

  useEffect(() => {
    if (auth._id) {
      setTimeout(() => {
        setForm(auth);
      }, 1000);
    }
  }, [auth]);

  useEffect(() => {
    if (message) {
      addToast(message, {
        appearance: isSuccess ? "success" : "error",
      });
    }

    if (isSuccess) {
      setForm((prev) => ({
        ...prev,
        password: "",
      }));
      setConfirmPass("");
    }
  }, [isSuccess, message, addToast]);

  const handleSubmit = (e) => {
    e.preventDefault();

    if((form.hasOwnProperty("password") && form?.password !== "") && confirmPass === "") {
      return addToast("Confirm password is empty!", {
        appearance: "warning",
      });
    }

    if (
      form.hasOwnProperty("password") &&
      form?.password !== "" &&
      form.password !== confirmPass
    ) {
      return addToast("Confirm password is incorrect!", {
        appearance: "warning",
      });
    }

    const _form = { ...form };
    delete _form.role;

    dispatch(
      UPDATE({
        data: _form,
        token,
      })
    );
  };

  const handleChange = (key, value) => setForm({ ...form, [key]: value });
  const handleObjChange = (obj, key, value) => {
    const _obj = { ...form[obj] };
    _obj[key] = value.toUpperCase();
    setForm({ ...form, [obj]: _obj });
  };

  const handleAddressChange = (obj, key, value) => {
    const updatedAddress = {
      ...form.address,
      [obj]: {
        ...form.address[obj],
        [key]: value.toUpperCase(),
      },
    };

    setForm({
      ...form,
      address: updatedAddress,
    });
  };

  return (
    <MDBContainer fluid>
      <MDBCard className="mb-4">
        <MDBCardBody className="text-center">
          <MDBRow>
            <MDBCol md="4">
              <h5
                className="mb-0 font-weight-bold"
                style={{ textAlign: "start" }}
              >
                Edit Photo
              </h5>
              <MDBCard
                narrow
                style={{ boxShadow: "none", border: "2px solid #0003" }}
              >
                <MDBCardBody className="text-center">
                  <MDBAvatar
                    tag="img"
                    src={image}
                    onError={(e) => (e.target.src = PresetImage(auth.isMale))}
                    alt={`preview-${auth._id}`}
                    className="z-depth-1 mb-3 mx-auto rounded"
                  />

                  {progressBar >= 0 && (
                    <MDBProgress value={progressBar} animated />
                  )}
                  <p className="text-muted">
                    <small>
                      {progressBar > -1
                        ? "Please wait while we update your profile photo"
                        : "Profile photo will be changed automatically"}
                    </small>
                  </p>
                  <label
                    htmlFor="changeImage"
                    className="btn btn-info btn-sm btn-rounded"
                  >
                    Upload New Photo
                  </label>
                  <input
                    id="changeImage"
                    onChange={handleImageChange}
                    type="file"
                    className="d-none"
                    accept="image/jpeg, image/jpg"
                  />
                </MDBCardBody>
              </MDBCard>

              <div className="mt-4">
                <h5
                  className="mb-0 font-weight-bold"
                  style={{ textAlign: "start" }}
                >
                  Change Password
                </h5>
                <MDBCard
                  narrow
                  style={{ boxShadow: "none", border: "2px solid #0003" }}
                >
                  <MDBCardBody>
                    <MDBRow>
                      <MDBCol md="12">
                        <PasswordInput 
                          password={form?.password || ""}
                          setPassword={(val) => {
                            handleChange("password", val)
                          }}
                          isLocked={showPass === "text" ? false : true}
                          setIsLocked={(val) => {
                            setShowPass(val ? "password" : "text")
                          }}
                          setPasswordStatus={setIsPasswordWeak}
                          hasIcon={true}
                          label="New password"
                          isProfile={true}

                        />
                      </MDBCol>
                      <MDBCol md="12">
                        <MDBInput
                          type={showPassConfirm}
                          value={confirmPass}
                          onChange={(e) => {
                            const trimmedValue = e.target.value.trim();
                            setConfirmPass(trimmedValue);
                          }}
                          label="Confirm password"
                          style={{ position: "relative", width: "85%" }}
                        >
                          <span
                            style={{
                              position: "absolute",
                              textDecoration: "underline",
                              textDecorationColor: "#ced4da",
                              top: "22px",
                              right: "10px",
                              cursor: "pointer",
                            }}
                            onClick={() =>
                              setShowPassConfirm((prev) =>
                                prev === "text" ? "password" : "text"
                              )
                            }
                          >
                            show
                          </span>
                        </MDBInput>
                      </MDBCol>
                    </MDBRow>
                  </MDBCardBody>
                </MDBCard>
              </div>
            </MDBCol>

            <MDBCol md="8">
              <h5
                className="mb-0 font-weight-bold"
                style={{ textAlign: "start" }}
              >
                Edit Profile
              </h5>
              <MDBCard
                narrow
                style={{ boxShadow: "none", border: "2px solid #0003" }}
              >
                <MDBCardBody>
                  {form._id ? (
                    <>
                      <MDBRow>
                        <MDBCol md="4">
                          <MDBInput
                            type="text"
                            value={form.fullName?.fname}
                            onChange={(e) =>
                              handleObjChange(
                                "fullName",
                                "fname",
                                e.target.value
                              )
                            }
                            label="First name"
                            required
                          />
                        </MDBCol>
                        <MDBCol md="2">
                          <MDBInput
                            type="text"
                            value={form.fullName?.mname}
                            onChange={(e) =>
                              handleObjChange(
                                "fullName",
                                "mname",
                                e.target.value
                              )
                            }
                            label="Middle name"
                          />
                        </MDBCol>
                        <MDBCol md="4">
                          <MDBInput
                            type="text"
                            value={form.fullName?.lname}
                            onChange={(e) =>
                              handleObjChange(
                                "fullName",
                                "lname",
                                e.target.value
                              )
                            }
                            label="Last name"
                            required
                          />
                        </MDBCol>
                        <MDBCol md="2">
                          <MDBSelect
                            className="colorful-select dropdown-primary hidden-md-down text-left"
                            label="Suffix"
                            getValue={(e) =>
                              handleObjChange(
                                "fullName",
                                "suffix",
                                e[0] === "N/A" ? "" : e[0]
                              )
                            }
                          >
                            <MDBSelectInput />
                            <MDBSelectOptions>
                              <MDBSelectOption
                                selected={!form.fullName.suffix}
                                value="N/A"
                              >
                                N/A
                              </MDBSelectOption>
                              <MDBSelectOption
                                selected={form.fullName.suffix === "JR"}
                                value="JR"
                              >
                                JR
                              </MDBSelectOption>
                              <MDBSelectOption
                                selected={form.fullName.suffix === "III"}
                                value="III"
                              >
                                III
                              </MDBSelectOption>
                              <MDBSelectOption
                                selected={form.fullName.suffix === "IV"}
                                value="IV"
                              >
                                IV
                              </MDBSelectOption>
                              <MDBSelectOption
                                selected={form.fullName.suffix === "V"}
                                value="V"
                              >
                                V
                              </MDBSelectOption>
                              <MDBSelectOption
                                selected={form.fullName.suffix === "SR"}
                                value="SR"
                              >
                                SR
                              </MDBSelectOption>
                            </MDBSelectOptions>
                          </MDBSelect>
                        </MDBCol>
                      </MDBRow>

                      <MDBRow>
                        <MDBCol md="4">
                          <MDBInput
                            type="text"
                            value={form.address?.current?.region}
                            onChange={(e) =>
                              handleAddressChange(
                                "current",
                                "region",
                                e.target.value
                              )
                            }
                            label="Region"
                            required
                          />
                        </MDBCol>
                        <MDBCol md="4">
                          <MDBInput
                            type="text"
                            value={form.address?.current?.province}
                            onChange={(e) =>
                              handleAddressChange(
                                "current",
                                "province",
                                e.target.value
                              )
                            }
                            label="Province"
                            required
                          />
                        </MDBCol>
                        <MDBCol md="4">
                          <MDBInput
                            type="text"
                            value={form.address?.current?.city}
                            onChange={(e) =>
                              handleAddressChange(
                                "current",
                                "city",
                                e.target.value
                              )
                            }
                            label="City/Municipality"
                            required
                          />
                        </MDBCol>
                      </MDBRow>
                      <MDBRow>
                        <MDBCol md="6">
                          <MDBInput
                            type="text"
                            value={form.address?.current?.barangay}
                            onChange={(e) =>
                              handleAddressChange(
                                "current",
                                "barangay",
                                e.target.value
                              )
                            }
                            label="Barangay"
                          />
                        </MDBCol>
                        <MDBCol md="6">
                          <MDBInput
                            type="text"
                            value={form.address?.current?.street}
                            onChange={(e) =>
                              handleAddressChange(
                                "current",
                                "street",
                                e.target.value
                              )
                            }
                            label="Street"
                          />
                        </MDBCol>
                      </MDBRow>
                      <MDBRow>
                        <MDBCol md="4">
                          <MDBInput
                            type="date"
                            value={form.dob}
                            onChange={(e) =>
                              handleChange("dob", e.target.value)
                            }
                            required
                            label="Birthdate"
                          />
                        </MDBCol>
                        <MDBCol md="4">
                          <MDBInput
                            type="text"
                            value={form.mobile}
                            onChange={(e) =>
                              handleChange(
                                "mobile",
                                e.target.value.replace(/\D/g, "")
                              )
                            }
                            required
                            label="Mobile (+63)"
                            maxLength={10}
                          />
                        </MDBCol>

                        <MDBCol md="4">
                          <MDBSelect
                            className="colorful-select dropdown-primary hidden-md-down text-left"
                            label="Gender"
                            getValue={(e) =>
                              handleChange("isMale", e[0] === "true")
                            }
                          >
                            <MDBSelectInput />
                            <MDBSelectOptions>
                              <MDBSelectOption
                                selected={form.isMale}
                                value="true"
                              >
                                Male
                              </MDBSelectOption>
                              <MDBSelectOption
                                selected={!form.isMale}
                                value="false"
                              >
                                Female
                              </MDBSelectOption>
                            </MDBSelectOptions>
                          </MDBSelect>
                        </MDBCol>
                      </MDBRow>
                      <MDBInput
                        type="textarea"
                        value={form.bio}
                        onChange={(e) => handleChange("bio", e.target.value)}
                        label="Biography"
                      />
                    </>
                  ) : (
                    <MDBSpinner />
                  )}
                </MDBCardBody>
              </MDBCard>
            </MDBCol>
          </MDBRow>

          <MDBRow className="mt-4">
            <MDBCol className="d-flex justify-content-end">
              <MDBBtn
                color="info"
                type="submit"
                rounded
                disabled={isPasswordWeak}
                onClick={(e) => handleSubmit(e)}
              >
                Update account
              </MDBBtn>
            </MDBCol>
          </MDBRow>
        </MDBCardBody>
      </MDBCard>
    </MDBContainer>
  );
}
