import React, { useState } from "react";
import { MDBIcon, MDBTable } from "mdbreact";
import Rows from "../../../../widgets/pagination/rows";
import PaginationButtons from "../../../../widgets/pagination/buttons";
import handlePagination from "../../../../widgets/pagination";
import { fullName } from "../../../../services/utilities";
import Reason from "./reason";

const Table = ({ lvlKey, students = [] }) => {
  const [max, setMax] = useState(5),
    [showReason, setShowReason] = useState(false),
    [selected, setSelected] = useState({}),
    [page, setPage] = useState(1);

  const toggleReason = () => setShowReason(!showReason);

  return (
    <>
      <MDBTable responsive hover key={`collapse-${lvlKey}`}>
        <thead>
          <tr>
            <th key={lvlKey}>
              <input
                className="form-check-input"
                type="checkbox"
                disabled
                id={`collapse-${lvlKey}`}
              />
              <label
                htmlFor={`collapse-${lvlKey}`}
                className="form-check-label mr-2 label-table"
              />
            </th>
            <th className="th-lg cursor-pointer">
              Name&nbsp;
              <MDBIcon icon="sort" title="Sort by Name" />
            </th>
            <th className="th-lg">Grade Level</th>
            {/* {didSearch && (
              <>
                <th className="th-lg">Grade Level</th>
              </>
            )} */}
            <th className="th-lg">Date</th>
            <th className="th-lg">Reason</th>
            <th className="th-lg">Drop By</th>
          </tr>
        </thead>
        <tbody>
          {students.length > 0 ? (
            handlePagination(students, page, max)?.map((stud, index) => {
              /* const { student, lvl, strand, drop, reasonForDrop = "" } = stud; */
              const { student, lvl, strand, drop, isICT = false } = stud;
              return (
                <tr key={index}>
                  <td>
                    <input
                      className="form-check-input"
                      type="checkbox"
                      disabled
                      id={index}
                    />
                    <label
                      htmlFor={index}
                      className="form-check-label mr-2 label-table"
                    />
                  </td>
                  <td style={{ fontWeight: 400 }}>
                    {fullName(student.fullName).toUpperCase()}
                  </td>
                  <td style={{ fontWeight: 400 }}>{`Grade - ${lvl} ${
                    isICT ? ", ICT" : ""
                  } ${lvl > 10 ? `, ${strand}` : ""}`}</td>

                  <td style={{ fontWeight: 400 }}>{drop.date}</td>
                  <td>
                    <MDBIcon
                      icon="comment-alt"
                      className="cursor-pointer"
                      size="2x"
                      style={{ color: "green" }}
                      onClick={() => {
                        toggleReason();
                        setSelected(stud);
                      }}
                    />
                  </td>
                  <td style={{ fontWeight: 400 }}>
                    {fullName(drop.by?.fullName)}
                  </td>
                </tr>
              );
            })
          ) : (
            <tr>
              <td>No Record</td>
            </tr>
          )}
        </tbody>
      </MDBTable>
      {students.length > 0 && (
        <>
          <Rows max={max} setMax={setMax} />
          <PaginationButtons
            max={max}
            page={page}
            setPage={setPage}
            array={students}
          />
        </>
      )}
      <Reason show={showReason} toggle={toggleReason} selected={selected} />
    </>
  );
};

export default Table;
