import React, { useEffect, useState } from "react";
import {
  MDBBtn,
  MDBModal,
  MDBModalBody,
  MDBIcon,
  MDBModalHeader,
  MDBInput,
} from "mdbreact";
import { useToasts } from "react-toast-notifications";
import { useDispatch, useSelector } from "react-redux";
import { UPDATE } from "../../../../services/redux/slices/admission/employees";
import { isEqual } from "lodash";
import CustomSelect from "../../../../components/customSelect";
import { fullName } from "../../../../services/utilities";

const _form = {
  name: "",
  description: "",
  capacity: 50,
  access: "",
  haveEnrollmentAccess: false,
  role: "",
};

export default function ChangeRole({
  show,
  toggle,
  selected,
  willCreate = false,
}) {
  const { token } = useSelector(({ auth }) => auth),
    [form, setForm] = useState(_form),
    dispatch = useDispatch(),
    { addToast } = useToasts();

  useEffect(() => {
    if (show) {
      if (!willCreate && selected._id)
        setForm({ ...selected, role: selected?.role?._id });
    }
  }, [show, willCreate, selected]);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!willCreate) {
      if (isEqual(form, selected)) {
        addToast("No changes found, skipping update.", {
          appearance: "info",
        });
      } else {
        dispatch(
          UPDATE({
            data: form,
            token,
          })
        );
      }
    }

    setForm(_form);
    toggle();
  };

  const handleClose = () => {
    setForm(_form);
    toggle();
  };

  const activeRole = show ? form.role || selected.role?._id : "";
  return (
    <MDBModal isOpen={show} toggle={toggle} backdrop disableFocusTrap={false}>
      <MDBModalHeader
        toggle={handleClose}
        className="light-blue darken-3 white-text"
      >
        <MDBIcon icon="user" className="mr-2" />
        {fullName(selected?.fullName)}
      </MDBModalHeader>
      <MDBModalBody className="mb-0">
        <form onSubmit={handleSubmit}>
          <MDBInput
            label="Position"
            value={form.position}
            onChange={({ target }) =>
              setForm({ ...form, position: target.value })
            }
          />
          <CustomSelect
            choices={[
              { name: "Teacher", _id: "65eb2eb58c6b7e03972248a0" },
              { name: "Registrar", _id: "65c10d39be3826c17b450cf3" },
              { name: "Agent", _id: "66aa9040495963b36ff59e81" },
            ]}
            // label={"Platofrm | Website Access"}
            labe="Role"
            texts="name"
            values="_id"
            key={form?._id || ""}
            preValue={form?.role}
            onChange={(value) => setForm({ ...form, role: value })}
          />

          {activeRole === "65eb2eb58c6b7e03972248a0" && (
            <div className="d-flex mt-4">
              Give you access to Enrollment teacher?
              <input
                className="form-check-input"
                type="checkbox"
                key={form._id}
                id="yes-haveAccess"
                checked={form?.haveEnrollmentAccess}
                onChange={(e) =>
                  setForm({ ...form, haveEnrollmentAccess: e.target.checked })
                }
              />
              <label
                className="form-check-label ml-3 mr-4"
                htmlFor="yes-haveAccess"
              >
                Yes
              </label>
              <input
                className="form-check-input"
                type="checkbox"
                id="no-haveAccess"
                checked={!form?.haveEnrollmentAccess}
                onChange={(e) =>
                  setForm({ ...form, haveEnrollmentAccess: !e.target.checked })
                }
              />
              <label className="form-check-label " htmlFor="no-haveAccess">
                No
              </label>
            </div>
          )}
          <div className="text-center mb-1-half mt-4">
            <MDBBtn
              type="submit"
              color="primary"
              className="mb-2 float-right"
              size="md"
            >
              {!willCreate ? "Update" : "Submit"}
            </MDBBtn>
          </div>
        </form>
      </MDBModalBody>
    </MDBModal>
  );
}
