import React, { useEffect, useState } from "react";
import "./question.css";
import shuffle from "../shuffle";
import { MDBCard, MDBCardBody } from "mdbreact";

const MultipleChoice = ({ question, setStudentAnswer }) => {
  const [choices, setChoices] = useState([]),
    [answer, setAnswer] = useState(""),
    [isHovered, setIsHovered] = useState(-1);

  useEffect(() => {
    setStudentAnswer({ ...question, answer });
  }, [answer, question, setStudentAnswer]);

  useEffect(() => {
    const choicesWithLetterLetter = [
      ...shuffle(question.choices).map((choice, index) => ({
        _id: String.fromCharCode(65 + index),
        ...choice,
      })),
    ];
    setChoices(choicesWithLetterLetter);
  }, [question]);

  return (
    <div>
      <h3 className="question font-weight-bold ml-1">
        <strong>{question?.question}</strong>
      </h3>

      <div className="mt-3">
        {choices.map((choice, index) => {
          const isSelected = answer === choice.text;
          return (
            <label className="custom-radio" key={index}>
              <MDBCard
                className="w-100 mc-card"
                onClick={() => setAnswer(index)}
                onMouseEnter={() => setIsHovered(index)}
                onMouseLeave={() => setIsHovered(index)}
                style={{
                  backgroundColor: isSelected ? "#08B4DF" : "#f0f0f0",
                  display: "flex",
                  cursor: "pointer",
                  boxShadow: "0px 0px 0px 0px",
                }}
              >
                <MDBCardBody className="d-flex align-items-center">
                  <input
                    type="radio"
                    name="multiple-choice"
                    value={choice.text}
                    className="custom-radio-input"
                    onChange={({ target }) => setAnswer(target.value)}
                  />
                  <span
                    className="custom-radio-circle"
                    style={{
                      border: `solid 2px ${
                        isSelected
                          ? "white"
                          : isHovered === index
                          ? "#08B4DF"
                          : "black"
                      }`,
                    }}
                  ></span>
                  <span
                    className={`ml-4 mc-choice-txt ${
                      isSelected ? "text-white" : ""
                    }`}
                    style={{ color: isHovered === index ? "#08B4DF" : "" }}
                  >
                    <strong>{choice?.text}</strong>
                  </span>
                </MDBCardBody>
                {isSelected && (
                  <div
                    style={{
                      position: "absolute",
                      top: 2,
                      right: 2,
                      width: "40px",
                      height: "70%",
                      backgroundColor: "white",
                      borderTopRightRadius: "3px",
                      clipPath: "polygon(100% 0, 0 0, 100% 100%)",
                    }}
                  ></div>
                )}
              </MDBCard>
            </label>

            // <div key={`choice-${index}`} style={{ marginBottom: "8px" }}>
            //   <label className="custom-radio">
            //     <input
            //       type="radio"
            //       name="multiple-choice"
            //       value={choice.text}
            //       className="custom-radio-input"
            //       onChange={({ target }) => setAnswer(target.value)}
            //     />
            //     <span className="custom-radio-circle"></span>
            //     <span>
            //       <strong>{`${indexToString(index)}. ${choice?.text}`}</strong>
            //     </span>
            //   </label>
            // </div>
          );
        })}
      </div>
    </div>
  );
};

export default MultipleChoice;
