import React from "react";
import { MDBCol, MDBIcon, MDBRow } from "mdbreact";
import isChecked from "./js/isChecked";
import answerSanitizer from "../../../../../../../services/utilities/answerSanitizer";
import answerIsCorrect from "./js/isCorrect";
const MultipleChoice = ({
  question,
  index,
  isChecking = false,
  isAdd = false,
  isMultiple = true,
  selectedQuestions = [],
  handleSelectQuestion = () => {},
}) => {
  const isCorrect = answerIsCorrect(question);

  const handleChecked = (text, question) => {
    const { correctAnswer = "", answer = "" } = question;
    if (!isChecking) {
      return {
        isChecked: answerSanitizer(text) === answerSanitizer(correctAnswer),
        additionClassName: "correct",
      };
    } else {
      if (isCorrect) {
        return { isChecked: answerSanitizer(text) === answerSanitizer(answer) };
      } else {
        if (answerSanitizer(text) === answerSanitizer(answer)) {
          return { isChecked: true, additionClassName: "wrong" };
        }

        if (answerSanitizer(correctAnswer) === answerSanitizer(text)) {
          return { isChecked: true, additionClassName: "correct" };
        }
      }
    }

    return { isChecked: false };
  };

  return (
    <div className="mt-2">
      <div className="d-flex align-items-center">
        {isAdd && (
          <>
            <input
              className="form-check-input"
              type="checkbox"
              checked={isChecked(question, selectedQuestions)}
              onChange={() => handleSelectQuestion(question)}
              id={`question-${index}`}
            />
            <label
              htmlFor={`question-${index}`}
              className="form-check-label  label-table"
            />
          </>
        )}

        {isChecking && (
          <h5>
            <MDBIcon
              icon={isCorrect ? "check" : "times"}
              style={{
                color: isCorrect ? "#30D272" : "red",
                marginRight: isCorrect ? "1.38rem" : "1.7rem",
              }}
            />
          </h5>
        )}
        <h5 className={isAdd ? "mt-2" : ""}>
          {isMultiple && <> {index + 1}. </>}
          <strong>{question.question}</strong>
        </h5>
      </div>
      <MDBRow style={{ marginLeft: isAdd || isChecking ? "3rem" : "1rem" }}>
        {question?.choices.map(({ text }, choiceIndex) => {
          const { isChecked = false, additionClassName = "" } =
            handleChecked(text, question) || {};

          return (
            <MDBCol key={choiceIndex} md="6">
              <input
                type="radio"
                id={text}
                className={`form-check-input ${additionClassName}`}
                readOnly
                checked={isChecked}
              />
              <label htmlFor={text}>
                <strong>{text}</strong>
              </label>
            </MDBCol>
          );
        })}
      </MDBRow>
    </div>
  );
};

export default MultipleChoice;
