import React, { useCallback, useEffect, useState } from "react";
import {
  MDBBtn,
  MDBModal,
  MDBModalBody,
  MDBIcon,
  MDBModalHeader,
  MDBInput,
  MDBRow,
  MDBCol,
  MDBModalFooter,
  MDBTypography,
} from "mdbreact";
// import { useToasts } from "react-toast-notifications";
import { useDispatch, useSelector } from "react-redux";
import {
  SAVE,
  UPDATE,
} from "../../../../services/redux/slices/registrar/questionBank";
import CustomSelect from "../../../../components/customSelect";
// import { isEqual } from "lodash";
import MultipleChoice from "./type/mc";
import MatchingType from "./type/matchingType";
import Identification from "./type/identification";
import validate from "./validate";
const defaultMatchingChoice = new Array(4).fill({
  textA: "",
  textB: "",
  isConfusing: false,
});

const defaultMultipleChoice = new Array(2).fill(null).map((_, index) => ({
  text: "",
  _id: index === 0 ? "A" : "B", // Assign "A" for the first item and "B" for the second item
}));

const _form = {
  question: "",
  type: "mc",
  titleA: "",
  titleB: "",
  choices: [],
  correctAnswer: "",
  progress: "JHS",
};

export default function Modal({
  activeProgress = "",
  show = false,
  willCreate = false,
  selected = {},
  collections = [],
  toggle = () => {},
  setContainer = () => {},
  setActiveProgress = () => {},
}) {
  const { token, auth } = useSelector(({ auth }) => auth),
    { isLoading } = useSelector(({ questionBank }) => questionBank),
    [choices, setChoices] = useState([]),
    [confusingChoices, setConfusingChoices] = useState([]), //this is for matching type only
    [form, setForm] = useState(_form),
    [valid, setValid] = useState({ question: true, choices: true }),
    dispatch = useDispatch();
  // { addToast } = useToasts();

  const filterMatchingChoices = useCallback((_choices, isConfusing) => {
    return [..._choices].filter(({ isConfusing: i }) => i === isConfusing);
  }, []);

  useEffect(() => {
    if (willCreate && activeProgress) {
      setForm((prev) => ({ ...prev, progress: activeProgress || "JHS" }));
    }
  }, [willCreate, activeProgress]);

  useEffect(() => {
    if (!willCreate && selected._id) {
      if (selected.type === "matching") {
        const _confusingChoices = filterMatchingChoices(selected.choices, true);
        const _choices = filterMatchingChoices(selected.choices, false);
        setConfusingChoices(_confusingChoices);
        setChoices(_choices);
      } else if (selected.type === "mc") {
        setChoices(selected.choices);
      }
      setForm(selected);
    }
  }, [willCreate, selected, filterMatchingChoices]);

  useEffect(() => {
    setValid((prev) => ({
      ...prev,
      choices: validate.choices([...choices, ...confusingChoices]),
    }));
  }, [choices, confusingChoices]);

  useEffect(() => {
    setValid((prev) => ({
      ...prev,
      question: validate.question(collections, form, selected.question || ""),
    }));
  }, [willCreate, form, selected, collections]);

  const selectedLines = () => {
    return choices.map((_, index) => ({
      questionIndex: index,
      answerIndex: index,
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    const isMatchingType = form?.type === "matching";
    const lines = selectedLines();
    if (!willCreate) {
      // if (isEqual(form, selected)) {
      //   addToast("No changes found, skipping update.", {
      //     appearance: "info",
      //   });
      // } else {
      dispatch(
        UPDATE({
          data: {
            ...form,
            choices: isMatchingType
              ? [...choices, ...confusingChoices]
              : choices,
            ...(isMatchingType && { selectedLines: lines }),
          },
          token,
        })
      );
      // }
    } else {
      dispatch(
        SAVE({
          data: {
            ...form,
            choices: isMatchingType
              ? [...choices, ...confusingChoices]
              : choices,
            createdBy: auth._id,
            ...(isMatchingType && { selectedLines: lines }),
          },
          token,
        })
      );
    }
    setActiveProgress(form.progress);
    setForm(_form);
    toggle();
    setContainer([]);
  };

  const handleClose = () => {
    setForm(_form);
    toggle();
  };

  const isDuplicate = Object.values(valid).includes(false);
  return (
    <MDBModal
      isOpen={show}
      toggle={toggle}
      backdrop
      disableFocusTrap={false}
      size="xl"
    >
      <MDBModalHeader
        toggle={handleClose}
        className="light-blue darken-3 white-text"
      >
        <MDBIcon icon="clipboard-list" className="mr-2" />
        {!willCreate ? "Update" : "Create"} a question
      </MDBModalHeader>
      <MDBModalBody className="mb-0">
        <form onSubmit={handleSubmit}>
          <MDBRow>
            <MDBCol>
              <CustomSelect
                choices={[
                  { text: "Junior High", value: "JHS" },
                  { text: "Senior High", value: "SHS" },
                ]}
                label={"Department"}
                preValue={form.progress}
                texts="text"
                values="value"
                disabledAllExceptSelected={!willCreate}
                onChange={(value) => setForm({ ...form, progress: value })}
              />
            </MDBCol>

            <MDBCol>
              <CustomSelect
                choices={[
                  { text: "Multiple Choice", value: "mc" },
                  { text: "Matching Type", value: "matching" },
                  { text: "Identification", value: "identification" },
                ]}
                label={"Type"}
                disabledAllExceptSelected={!willCreate}
                preValue={form.type}
                texts="text"
                values="value"
                onChange={(value) => {
                  if (willCreate) setChoices([]);
                  setForm({ ...form, type: value });
                }}
              />
            </MDBCol>
          </MDBRow>
          <MDBInput
            label="Question"
            value={form.question}
            onChange={({ target }) =>
              setForm({ ...form, question: target.value })
            }
          />
          {form.type === "mc" ? (
            <MultipleChoice
              choices={choices.length > 0 ? choices : defaultMultipleChoice}
              setChoices={setChoices}
              form={form}
              setForm={setForm}
            />
          ) : form.type === "matching" ? (
            <MatchingType
              choices={choices.length > 0 ? choices : defaultMatchingChoice}
              setChoices={setChoices}
              confusingChoices={confusingChoices}
              form={form}
              setForm={setForm}
              setConfusingChoices={setConfusingChoices}
            />
          ) : form.type === "identification" ? (
            <Identification form={form} setForm={setForm} />
          ) : (
            ""
          )}
          <MDBModalFooter
            className={`d-flex justify-content-${
              isDuplicate ? "between" : "end"
            }`}
          >
            {isDuplicate && (
              <MDBTypography
                variant="h2"
                className="mb-0 text-black-100"
                noteColor="danger"
                note
                noteTitle="Warning: "
              >
                {!valid.question
                  ? " Sorry But this question is Already Exist"
                  : "Sorry but you have  duplicate choices"}
              </MDBTypography>
            )}
            <MDBBtn
              type="submit"
              disabled={isLoading || isDuplicate}
              color="primary"
              className="float-right"
            >
              {!willCreate ? "Update" : "Submit"}
            </MDBBtn>
          </MDBModalFooter>
        </form>
      </MDBModalBody>
    </MDBModal>
  );
}
