import React, { useEffect, useState } from "react";
import { MDBIcon, MDBCard, MDBCardHeader, MDBCardBody } from "mdbreact";
import Rules from "./rules";
import CountDown from "./countDown";
import Exam from "./exam";

export default function Modal({ toggle, exam }) {
  const [title, setTitle] = useState("Entrance Exam Rules"),
    [hasStart, setHasStart] = useState(false),
    [timeLeft, setTimeLeft] = useState(6);

  useEffect(() => {
    if (hasStart) {
      if (timeLeft <= 0) return;

      const interval = setInterval(() => {
        setTimeLeft((prevTime) => prevTime - 1);
      }, 1000);

      return () => clearInterval(interval);
    }
  }, [timeLeft, hasStart]);

  useEffect(() => {
    if (hasStart) {
      setTitle("Entrance Exam");
    }
  }, [hasStart]);

  return (
    <MDBCard>
      <MDBCardHeader className="light-blue darken-3 white-text d-flex align-items-center justify-content-between">
        <div>
          <MDBIcon icon="clipboard-list" className="mr-2" />
          {title}
        </div>
        {!hasStart && (
          <div>
            <MDBIcon
              icon="times"
              onClick={() => toggle()}
              className="cursor-pointer"
            />
          </div>
        )}
      </MDBCardHeader>
      <MDBCardBody className="mb-0">
        {!hasStart ? (
          <Rules setHasStart={setHasStart} exam={exam} />
        ) : (
          <>
            {timeLeft >= 1 ? (
              <CountDown timeLeft={timeLeft} />
            ) : (
              <Exam exam={exam} title={title} setTitle={setTitle} />
            )}
          </>
        )}
      </MDBCardBody>
    </MDBCard>
  );
}
