import React, { useState } from "react";
import {
  MDBCardBody,
  MDBRow,
  MDBCol,
  MDBBtn,
  MDBIcon,
  MDBAvatar,
} from "mdbreact";
import dateConverter from "../dateConverter";
import ReplyMessage from "./replyMessage";
import Message from "./message";
import ElapsedTime from "../../ellapsedTime";
import Default from "../noMessage/default";
import ViewImage from "../../Image/modal";
const Content = ({
  chatContainerRef,
  messages,
  haveMessages,
  isTyping,
  isScrolling,
  scrollToReplyMessage,
  messageRef,
  handleScrollToBottom,
  bounceMessage,
  setIsReplied,
  setSelectedMsg,
  auth,
  setChatNow,
  chatNow,
  handleSendDefaultMessage,
}) => {
  const [timeIndex, setTimeIndex] = useState(-1);
  const [imgView, setImgView] = useState(null);
  const [toggleImgView, setToggleImgView] = useState(false);

  return (
    <div
      style={{
        height: "auto",
        overflowY: !haveMessages ? "hidden" : "auto",
        overflowX: "hidden",
        minHeight: "50%",
        flex: "1 1 80%",
        borderRadius: "10px",
      }}
      ref={chatContainerRef}
    >
      <ViewImage
        image={imgView}
        show={toggleImgView}
        toggle={() => setToggleImgView(false)}
      />
      <MDBCardBody className="text-center m-0 p-0">
        <MDBRow>
          <MDBCol className="mt-lg-0 ">
            <div
              className="pl-4 pr-4 pt-4 white " /* 
              style={{ maxHeight: isSendImage ?  `calc(${height - 115}px - 4rem)` : height - 115, overflowY: "auto" }} */
              style={{ height: "100%" }}
            >
              {haveMessages ? (
                <>
                  {messages.map((message, index) => {
                    const { sender, replied, _id, isImage } = message;
                    const messageByYou = auth._id === sender?._id;
                    const hasReply = replied?._id;

                    return (
                      <div
                        key={index}
                        data-message-id={_id}
                        className={`row-message ${isImage && "mb-3"}`}
                      >
                        {message.showDate && (
                          <div className="text-center mb-3 mt-3">
                            <small>{dateConverter(message.createdAt)}</small>
                          </div>
                        )}
                        <div
                          className={`d-flex align-items-center chat-row justify-content-${
                            messageByYou ? "end" : "start media "
                          }`}
                          style={{ position: "relative" }}
                        >
                          {!messageByYou && message.showProfile && (
                            <MDBAvatar
                              src="https://mdbootstrap.com/img/Photos/Avatars/adach.jpg"
                              alt="User mugshot"
                              tag="img"
                              circle
                              className="float-left mr-3 avatar  profile-msg"
                            />
                          )}

                          <div
                            className={
                              hasReply
                                ? !messageByYou
                                  ? "message-receiver-wrapper"
                                  : "message-sender-wrapper"
                                : ""
                            }
                          >
                            {hasReply && (
                              <ReplyMessage
                                messageByYou={messageByYou}
                                message={message}
                                scrollToReplyMessage={scrollToReplyMessage}
                              />
                            )}

                            <Message
                              messageByYou={messageByYou}
                              message={message}
                              bounceMessage={bounceMessage}
                              setIsReplied={setIsReplied}
                              setSelectedMsg={setSelectedMsg}
                              messageRef={messageRef}
                              timeIndex={timeIndex}
                              index={index}
                              setTimeIndex={setTimeIndex}
                              setToggleImgView={setToggleImgView}
                              setImgView={setImgView}
                            />
                          </div>
                        </div>
                        {!message?.isSeen && message?.showSent && (
                          <p
                            className="sent-message"
                            style={
                              !message?.isImage
                                ? { marginTop: "-14px", marginRight: "8px" }
                                : {}
                            }
                          >
                            <ElapsedTime createdAt={message.createdAt} />
                          </p>
                        )}
                        {message.isSeen && message.showProfileSeen && (
                          <div className="d-flex justify-content-end w-100 m-0 p-0 mb-3">
                            <MDBAvatar
                              src="https://mdbootstrap.com/img/Photos/Avatars/adach.jpg"
                              alt="User mugshot"
                              tag="img"
                              circle
                              className="float-right mr-3 avatar profile-seen"
                            />
                          </div>
                        )}
                      </div>
                    );
                  })}
                  <MDBBtn
                    rounded
                    color="white"
                    onClick={handleScrollToBottom}
                    className={`scroll-btn ${
                      !toggleImgView && isScrolling ? "" : "hide-scrollbtn"
                    }`}
                    size="sm"
                    floating
                  >
                    <MDBIcon
                      icon="long-arrow-alt-down"
                      style={{ color: "blue" }}
                    />
                  </MDBBtn>
                  {isTyping && (
                    <div className="typing-indicator">
                      <div>
                        <MDBAvatar
                          src="https://mdbootstrap.com/img/Photos/Avatars/adach.jpg"
                          alt="User mugshot"
                          tag="img"
                          circle
                          className="float-right mr-1 avatar profile-typing"
                        />
                      </div>
                      <span className="dot"></span>
                      <span className="dot"></span>
                      <span className="dot"></span>
                    </div>
                  )}
                </>
              ) : (
                <Default
                  isAgent={auth.role?.name === "AGENT"}
                  setChatNow={setChatNow}
                  chatNow={chatNow}
                  handleSendDefaultMessage={handleSendDefaultMessage}
                />
              )}
            </div>
          </MDBCol>
        </MDBRow>
      </MDBCardBody>
    </div>
  );
};

export default Content;
